def _make_threaded_wsgi_server(host: str, port: int, app: Any) -> Any:
  return make_server(host, port, app, server_class=_ThreadedOperatorConsoleWSGIServer)


def _json_response(start_response: Callable[..., Any], payload: JSONDict, *, status: str = '200 OK') -> list[bytes]:
  enriched_payload = _with_notification_source_metadata(payload)
  body = json.dumps(enriched_payload, indent=2, default=str).encode('utf-8')
  start_response(
    status,
    [
      ('Content-Type', 'application/json; charset=utf-8'),
      ('Cache-Control', 'no-store'),
    ],
  )
  return [body]

def _html_response(start_response: Callable[..., Any], body: str, *, status: str = '200 OK') -> list[bytes]:
  encoded = body.encode('utf-8')
  start_response(
    status,
    [
      ('Content-Type', 'text/html; charset=utf-8'),
      ('Content-Length', str(len(encoded))),
      ('Cache-Control', 'no-store'),
    ],
  )
  return [encoded]


def _path_tail(value: object | None) -> str | None:
  if value in {None, ''}:
    return None
  return Path(str(value)).name or str(value)


def _path_hint(value: object | None) -> str:
  if value in {None, ''}:
    return ''
  path = Path(str(value))
  parts = list(path.parts)
  if not parts:
    return str(value)
  if len(parts) == 1:
    return parts[0]
  return '/'.join(parts[-2:])


def _candidate_identity_component(value: Any) -> str:
  return re.sub(r'\s+', ' ', str(value or '').strip())


def _candidate_review_uid(candidate: JSONDict, index: int) -> str:
  # Lane 0 (CANDIDATE_PERSISTENCE_UNIFORM_CONTRACT_BMAP_2026-06-19): delegate to the
  # single canonical candidate identity so cards and candidate-math rows share keys.
  # The legacy positional fallback is retained only for a candidate with no intrinsic
  # identity at all (never a real candidate — all carry a ticker).
  has_identity = any(
    _candidate_identity_component(candidate.get(_field))
    for _field in (
      'candidate_uid', 'ticker', 'event_ticker', 'contract_label', 'selection_label',
      'yes_sub_title', 'no_sub_title', 'market_title', 'title', 'event_title',
    )
  )
  return _canonical_candidate_uid(candidate) if has_identity else f'candidate-{index + 1}'


def _candidate_review_key(candidate: JSONDict, index: int) -> str:
  return _candidate_review_uid(candidate, index)


def _lane_tag_for_path(path_value: object | None) -> str | None:
  if path_value in {None, ''}:
    return None
  try:
    parts = [segment.strip().lower() for segment in Path(str(path_value)).parts if str(segment).strip()]
  except Exception:
    return None
  if any(part in {'demo', 'demo-api', 'sandbox'} for part in parts):
    return 'sandbox'
  if any(part in {'live', 'prod', 'production'} for part in parts):
    return 'live'
  return None


def _api_key_id_tail(value: object | None) -> str:
  token = str(value or '').strip()
  if not token:
    return ''
  if len(token) <= 6:
    return token
  return f"...{token[-6:]}"


def _websocket_label(value: object | None) -> str:
  text = str(value or '').strip()
  if not text:
    return 'unconfigured'
  parsed = urlparse(text)
  if not parsed.netloc:
    return text
  return '{host}{path}'.format(host=parsed.netloc, path=parsed.path or '')


def _human_key_source_label(value: str | None) -> str:
  normalized = str(value or '').strip()
  if not normalized:
    return 'Not selected'
  return normalized


def _request_body_bytes(environ: dict[str, Any]) -> bytes:
  cached = environ.get('_pv_cached_request_body_bytes')
  if isinstance(cached, bytes):
    return cached
  try:
    content_length = int(str(environ.get('CONTENT_LENGTH', '0') or '0'))
  except ValueError:
    content_length = 0
  if content_length <= 0:
    environ['_pv_cached_request_body_bytes'] = b''
    return b''
  stream = environ.get('wsgi.input')
  if stream is None:
    environ['_pv_cached_request_body_bytes'] = b''
    return b''
  body_bytes = stream.read(content_length)
  environ['_pv_cached_request_body_bytes'] = body_bytes
  return body_bytes


def _request_json_body(environ: dict[str, Any]) -> JSONDict:
  body = _request_body_bytes(environ)
  if not body:
    return {}
  try:
    payload = json.loads(body.decode('utf-8'))
  except (UnicodeDecodeError, json.JSONDecodeError):
    return {}
  return payload if isinstance(payload, dict) else {}


def _build_run_response_projection(payload: dict[str, Any] | None) -> dict[str, Any]:
  # Whitelist-shaped, names-only / counts-only projection of the /api/run response payload.
  # Charter R2; Polymath invariants #3 (names-only) and #4 (secret-safe).
  safe = payload if isinstance(payload, dict) else {}
  allowed_actions = safe.get('allowed_actions')
  ec = safe.get('execution_chronology')
  ec_enabled = bool(isinstance(ec, dict) and ec.get('enabled'))
  ec_terminal_state = str(ec.get('terminal_state') or '') if isinstance(ec, dict) else ''
  ec_profile = str(ec.get('profile') or '') if isinstance(ec, dict) else ''
  return {
    'decision': str(safe.get('decision') or ''),
    'command_family': str(safe.get('command_family') or ''),
    'mode': str(safe.get('mode') or ''),
    'dry_run': bool(safe.get('dry_run', True)),
    'market_count': safe.get('market_count') if isinstance(safe.get('market_count'), int) else None,
    'candidate_count': safe.get('candidate_count') if isinstance(safe.get('candidate_count'), int) else None,
    'planned_pair_count': safe.get('planned_pair_count') if isinstance(safe.get('planned_pair_count'), int) else None,
    'failure_class': str(safe.get('failure_class')) if safe.get('failure_class') is not None else None,
    'allowed_action_count': len(allowed_actions) if isinstance(allowed_actions, list) else None,
    'next_action_present': bool(str(safe.get('next_action') or '').strip()),
    'execution_chronology_enabled': ec_enabled,
    'execution_terminal_state': ec_terminal_state or None,
    'execution_profile': ec_profile or None,
  }


def _resolve_candidate_reference(value: str | None, *, preferred_root: Path | None = None) -> Path | None:
  raw_value = str(value or '').strip()
  if not raw_value:
    return None

  candidate = Path(raw_value).expanduser()
  project_parent = PROJECT_ROOT.parent
  project_grandparent = project_parent.parent if project_parent.parent != project_parent else None
  preferred_parent = preferred_root.parent if preferred_root is not None and preferred_root.parent != preferred_root else None
  roots: list[Path | None] = [
    preferred_root.resolve() if preferred_root is not None else None,
    preferred_parent.resolve() if preferred_parent is not None else None,
    Path.cwd().resolve(),
    PROJECT_ROOT,
    project_parent,
    project_grandparent,
  ]
  checked: list[Path] = []

  if candidate.is_absolute():
    checked.append(candidate)
  else:
    checked.append(candidate)
    for root in roots:
      if root is None:
        continue
      checked.append((root / candidate).resolve())
  seen: set[Path] = set()
  for candidate_path in checked:
    if candidate_path in seen:
      continue
    seen.add(candidate_path)
    if candidate_path.exists() and candidate_path.is_file():
      return candidate_path.resolve()

  fallback = checked[-1] if checked else None
  return fallback.resolve() if fallback is not None else None


def _approved_private_key_roots(*, project_root: Path = PROJECT_ROOT) -> list[tuple[Path, str]]:
  project_root = project_root.resolve()
  roots: list[tuple[Path, str]] = []
  seen: set[Path] = set()

  def register(root: Path | None, label: str) -> None:
    if root is None:
      return
    resolved = root.resolve()
    if resolved in seen:
      return
    seen.add(resolved)
    roots.append((resolved, label))

  project_parent = project_root.parent
  project_grandparent = project_parent.parent if project_parent.parent != project_parent else None
  register(project_root / 'secrets', 'Project secrets')
  register(project_parent / 'secrets', 'Workspace secrets')
  if project_grandparent is not None:
    register(project_grandparent / 'secrets', 'Workspace-adjacent secrets')

  return roots


def _discover_private_key_candidates(*, project_root: Path = PROJECT_ROOT) -> list[JSONDict]:
  candidates: list[JSONDict] = []
  seen_paths: set[Path] = set()

  def register(path: Path | None, source_label: str) -> None:
    if path is None:
      return
    resolved = path.resolve()
    if not resolved.exists() or not resolved.is_file():
      return
    if resolved.suffix.lower() not in APPROVED_PRIVATE_KEY_SUFFIXES:
      return
    if resolved in seen_paths:
      return
    try:
      load_private_key(resolved)
    except Exception:
      return
    seen_paths.add(resolved)
    candidates.append(
      {
        'resolved_path': str(resolved),
        'path_tail': _path_tail(resolved),
        'source_label': source_label,
      }
    )

  live_env_candidates = [
    (PRIVATE_KEY_FILE_ENV_VAR, os.environ.get(PRIVATE_KEY_FILE_ENV_VAR)),
    (LEGACY_PRIVATE_KEY_ENV_VAR, os.environ.get(LEGACY_PRIVATE_KEY_ENV_VAR)),
  ]
  for env_name, env_value in live_env_candidates:
    register(_resolve_candidate_reference(env_value), f'Live env • {env_name}')

  for root, root_label in _approved_private_key_roots(project_root=project_root):
    if not root.exists() or not root.is_dir():
      continue
    for path in root.rglob('*'):
      if not path.is_file() or path.suffix.lower() not in APPROVED_PRIVATE_KEY_SUFFIXES:
        continue
      register(path, root_label)

  candidates.sort(key=lambda item: (str(item.get('source_label', '')), str(item.get('path_tail', ''))))
  return candidates


@contextmanager
def _private_key_file_env_overlay(path_value: str | None, lock: threading.Lock | None = None):
  if not path_value:
    yield
    return

  active_lock = lock or threading.Lock()
  previous_present = PRIVATE_KEY_FILE_ENV_VAR in os.environ
  previous_value = os.environ.get(PRIVATE_KEY_FILE_ENV_VAR)
  with active_lock:
    os.environ[PRIVATE_KEY_FILE_ENV_VAR] = path_value
  try:
    yield
  finally:
    with active_lock:
      if previous_present and previous_value is not None:
        os.environ[PRIVATE_KEY_FILE_ENV_VAR] = previous_value
      else:
        os.environ.pop(PRIVATE_KEY_FILE_ENV_VAR, None)


def _sort_pair_rows(rows: list[JSONDict]) -> list[JSONDict]:
  return sorted(
    rows,
    key=lambda pair: (
      PAIR_STATE_PRIORITY.get(str(pair.get('state', '')).upper(), 99),
      str(pair.get('pair_id', '')),
      str(pair.get('ticker', '')),
    ),
  )


def _no_go_payload(reason: str, message: str, next_action: str) -> JSONDict:
  return {
    'decision': 'no-go',
    'reason': reason,
    'message': message,
    'next_action': next_action,
  }


def _infer_message_origin(*, reason: str | None, message: str | None) -> str:
  normalized_reason = _normalize_reason_token(reason or '') if reason is not None else ''
  normalized_message = str(message or '').strip().lower()
  external_reasons = {
    'auth_fail',
    'auth_failed',
    'credential_acceptance_failed',
    'credential_acceptance_timeout',
    'credential_environment_mismatch',
    'rate_limited',
    'http_request_failed',
    'network_timeout',
    'timeout',
    'websocket_connection_failed',
    'websocket_service_unavailable',
    'bad_request',
    'conflict',
  }
  if normalized_reason in external_reasons:
    return ORIGIN_KALSHI
  if 'kalshi' in normalized_message:
    return ORIGIN_KALSHI
  if 'platform rejected credentials' in normalized_message:
    return ORIGIN_KALSHI
  return ORIGIN_POLYVENTURE


def _annotate_result_origin(
  result_payload: JSONDict,
  *,
  fallback_reason: str | None = None,
  fallback_message: str | None = None,
) -> JSONDict:
  if not isinstance(result_payload, dict):
    return result_payload
  projected = dict(result_payload)
  existing_origin = str(projected.get('origin') or '').strip().lower()
  if existing_origin:
    projected['origin'] = existing_origin
    return projected
  projected['origin'] = _infer_message_origin(
    reason=str(projected.get('reason') or fallback_reason or ''),
    message=str(projected.get('message') or fallback_message or ''),
  )
  return projected


def _with_notification_source_metadata(payload: JSONDict) -> JSONDict:
  if not isinstance(payload, dict):
    return payload
  projected = dict(payload)
  inferred_origin = _infer_message_origin(
    reason=str(projected.get('reason') or ''),
    message=str(projected.get('message') or ''),
  )
  projected['notification_source'] = {
    'origin': inferred_origin,
    'is_external': inferred_origin != ORIGIN_POLYVENTURE,
    'badge_label': inferred_origin.upper(),
  }
  nested_origins: list[str] = []
  key_management = projected.get('key_management')
  if isinstance(key_management, dict):
    km_copy = dict(key_management)
    last_result = km_copy.get('last_result')
    if isinstance(last_result, dict):
      lr_copy = _annotate_result_origin(
        last_result,
        fallback_reason=str(projected.get('reason') or km_copy.get('credential_validation_reason') or ''),
      )
      nested_origins.append(str(lr_copy.get('origin') or '').strip().lower())
      km_copy['last_result'] = lr_copy
    projected['key_management'] = km_copy
  websocket_management = projected.get('websocket_management')
  if isinstance(websocket_management, dict):
    wm_copy = dict(websocket_management)
    last_result = wm_copy.get('last_result')
    if isinstance(last_result, dict):
      lr_copy = _annotate_result_origin(
        last_result,
        fallback_reason=str(projected.get('reason') or ''),
        fallback_message=str(projected.get('message') or ''),
      )
      nested_origins.append(str(lr_copy.get('origin') or '').strip().lower())
      wm_copy['last_result'] = lr_copy
    projected['websocket_management'] = wm_copy
  data_management = projected.get('data_management')
  if isinstance(data_management, dict):
    dm_copy = dict(data_management)
    last_result = dm_copy.get('last_result')
    if isinstance(last_result, dict):
      lr_copy = _annotate_result_origin(
        last_result,
        fallback_reason=str(projected.get('reason') or ''),
        fallback_message=str(projected.get('message') or ''),
      )
      nested_origins.append(str(lr_copy.get('origin') or '').strip().lower())
      dm_copy['last_result'] = lr_copy
    projected['data_management'] = dm_copy
  session_overlay = projected.get('session_overlay')
  if isinstance(session_overlay, dict):
    session_copy = dict(session_overlay)
    for section_name in ('runtime', 'context', 'automation'):
      section_payload = session_copy.get(section_name)
      if not isinstance(section_payload, dict):
        continue
      section_copy = dict(section_payload)
      last_result = section_copy.get('last_result')
      if isinstance(last_result, dict):
        lr_copy = _annotate_result_origin(
          last_result,
          fallback_reason=str(projected.get('reason') or ''),
          fallback_message=str(projected.get('message') or ''),
        )
        nested_origins.append(str(lr_copy.get('origin') or '').strip().lower())
        section_copy['last_result'] = lr_copy
      session_copy[section_name] = section_copy
    projected['session_overlay'] = session_copy
  if inferred_origin == ORIGIN_POLYVENTURE:
    for nested_origin in nested_origins:
      if nested_origin and nested_origin != ORIGIN_POLYVENTURE:
        projected['notification_source'] = {
          'origin': nested_origin,
          'is_external': True,
          'badge_label': nested_origin.upper(),
        }
        break
  return projected


def _request_header(environ: dict[str, Any], header_name: str) -> str:
  normalized = header_name.strip().upper().replace('-', '_')
  key = f'HTTP_{normalized}'
  return str(environ.get(key, '') or '').strip()


def _resolve_local_artifact_path(raw_path: object | None, *, project_root: Path = PROJECT_ROOT) -> Path | None:
  path_text = str(raw_path or '').strip()
  if not path_text:
    return None

  candidate = Path(path_text).expanduser()
  try:
    resolved = candidate.resolve() if candidate.is_absolute() else (project_root / candidate).resolve()
  except OSError:
    return None

  try:
    resolved.relative_to(project_root.resolve())
  except ValueError:
    return None

  if not resolved.exists() or not resolved.is_file():
    return None
  return resolved


def _open_file_location_in_explorer(target_path: Path) -> tuple[bool, str]:
  if os.name != 'nt':
    return False, 'Explorer reveal is only available on Windows hosts.'
  try:
    subprocess.Popen(['explorer.exe', f'/select,{str(target_path)}'])
  except Exception as exc:
    return False, f'Could not open Explorer for {target_path.name}: {exc}'
  return True, f'Opened Explorer and selected {target_path.name}.'


@lru_cache(maxsize=1)
def _inline_logo_data_uri() -> str | None:
  if not POLYVENTURE_LOGO_PATH.exists():
    return None
  encoded = base64.b64encode(POLYVENTURE_LOGO_PATH.read_bytes()).decode('ascii')
  return f'data:image/png;base64,{encoded}'


