def _brand_logo_markup() -> str:
  logo_src = _inline_logo_data_uri() or _fallback_logo_data_uri()
  return f'<img class="brand-logo" src="{logo_src}" alt="Polyventure logo">'


def _asset_content_type(path: Path) -> str:
  suffix = path.suffix.lower()
  if suffix == '.svg':
    return 'image/svg+xml'
  if suffix == '.png':
    try:
      preview = path.read_text(encoding='utf-8')[:128].lstrip()
      if preview.startswith('<svg'):
        return 'image/svg+xml'
    except Exception:
      pass
    return 'image/png'
  if suffix in {'.jpg', '.jpeg'}:
    return 'image/jpeg'
  if suffix == '.webp':
    return 'image/webp'
  if suffix == '.gif':
    return 'image/gif'
  return 'application/octet-stream'


def _asset_response(start_response: Callable[..., Any], asset_path: Path) -> list[bytes]:
  start_response(
    '200 OK',
    [
      ('Content-Type', _asset_content_type(asset_path)),
      ('Cache-Control', 'no-cache'),
    ],
  )
  return [asset_path.read_bytes()]


def _system_log_scroll_policy() -> JSONDict:
  return {
    'default_reset_target': 'lead',
    'suppression_activation': 'user-scroll',
    'suppression_refreshes': 3,
  }


def _human_mode_label(mode: str | None) -> str:
  key = str(mode or '').lower()
  labels = {
    'a_targeted': 'Focus A',
    'b_targeted': 'Focus B',
  }
  return labels.get(key, key.replace('_', ' ').title())


def _api_version_label(api_base_url: str | None) -> str:
  return _path_tail(api_base_url) or str(api_base_url or '--')


def _configuration_issue_family(
  settings: Any,
  *,
  environment_error: Exception | None,
  credential_error: Exception | None,
) -> str | None:
  if environment_error is not None:
    return 'environment_mismatch'
  if credential_error is None:
    return None
  if settings.private_key_inline:
    return 'inline_private_key_blocked'
  if isinstance(credential_error, FileNotFoundError):
    return 'missing_private_key_file'
  message = str(credential_error).lower()
  if 'missing private key file path' in message:
    return 'missing_private_key_file'
  if 'does not point to an existing file' in message:
    return 'invalid_private_key_reference'
  return 'configuration_error'


def _environment_detail(settings: Any, environment_error: Exception | None) -> str:
  env_label = str(getattr(settings, 'kalshi_env', '--') or '--').upper()
  api_label = _api_version_label(getattr(settings, 'api_base_url', None))
  if environment_error is None:
    return f'env={env_label} :: api={api_label}'
  return f'env={env_label} :: endpoint alignment blocked'


def _is_offline_lane_membership_only_error(settings: Any, error: Exception | None) -> bool:
  if error is None:
    return False
  operation_lane = str(getattr(settings, 'operation_lane', '') or '').strip().lower()
  if operation_lane != 'offline':
    return False
  return str(error).strip() == 'Configured operation lane must be sandbox or live.'


def _credential_detail(
  settings: Any,
  *,
  api_key_present: bool,
  credential_reference_present: bool,
  private_key_file_exists: bool,
) -> str:
  api_key_label = 'present' if api_key_present else 'missing'
  reference_tail = _path_tail(getattr(settings, 'private_key_file', None) or getattr(settings, 'private_key_path_legacy', None)) or 'key reference'
  if getattr(settings, 'private_key_inline', None):
    return f'api_key={api_key_label} :: inline key blocked'
  if not credential_reference_present:
    return f'api_key={api_key_label} :: key reference missing'
  if not private_key_file_exists:
    return f'api_key={api_key_label} :: key file missing on disk ({reference_tail})'
  return f'api_key={api_key_label} :: private_key_file=present'


def _load_shell_settings_context(
  *,
  env_override: str | None = None,
  subaccount_override: int | None = None,
  settings_override: Any | None = None,
) -> tuple[JSONDict, Exception | None]:
  try:
    settings = (
      settings_override
      if settings_override is not None
      else _resolve_settings(
        None,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
    )
  except Exception as exc:
    return ({'settings_ready': False}, exc)

  api_key_present = bool(settings.api_key_id)
  credential_reference_present = bool(settings.private_key_file or settings.private_key_path_legacy)
  settings_payload = {
    **safe_settings_summary(settings),
    'private_key_path_tail': _path_tail(settings.private_key_file or settings.private_key_path_legacy),
    'state_db_path_tail': _path_tail(settings.state_db_path),
    'active_websocket_url_tail': _websocket_label(settings.active_websocket_url),
    'available_websocket_urls': {
      'sandbox': _websocket_label(settings.sandbox_websocket_url),
      'live': _websocket_label(settings.live_websocket_url),
    },
    'environment_ready': False,
    'environment_detail': _environment_detail(settings, None),
    'credential_reference_present': credential_reference_present,
    'private_key_file_exists': False,
    'credential_ready': False,
    'credential_detail': _credential_detail(
      settings,
      api_key_present=api_key_present,
      credential_reference_present=credential_reference_present,
      private_key_file_exists=False,
    ),
    'configuration_issue_family': None,
    'configuration_issue_detail': None,
    'settings_ready': False,
  }

  environment_error: Exception | None = None
  credential_error: Exception | None = None
  try:
    _validate_env_alignment(settings)
    settings_payload['environment_ready'] = True
  except Exception as exc:
    if _is_offline_lane_membership_only_error(settings, exc):
      settings_payload['environment_ready'] = True
    else:
      environment_error = exc

  try:
    private_key_path = resolve_private_key_path(settings)
    settings_payload.update(
      {
        'private_key_path_tail': _path_tail(private_key_path),
        'private_key_file_present': True,
        'private_key_file_exists': private_key_path.exists(),
      }
    )
  except Exception as exc:
    credential_error = exc
    if isinstance(exc, FileNotFoundError):
      missing_tail = _path_tail(getattr(exc, 'filename', None) or settings.private_key_file or settings.private_key_path_legacy)
      if missing_tail:
        settings_payload['private_key_path_tail'] = missing_tail

  settings_payload['environment_detail'] = _environment_detail(settings, environment_error)
  settings_payload['credential_detail'] = _credential_detail(
    settings,
    api_key_present=api_key_present,
    credential_reference_present=credential_reference_present,
    private_key_file_exists=bool(settings_payload.get('private_key_file_exists')),
  )
  settings_payload['credential_ready'] = bool(
    api_key_present
    and credential_reference_present
    and settings_payload.get('private_key_file_exists')
    and not settings.private_key_inline
  )
  settings_payload['configuration_issue_family'] = _configuration_issue_family(
    settings,
    environment_error=environment_error,
    credential_error=credential_error,
  )
  settings_payload['configuration_issue_detail'] = (
    settings_payload['environment_detail']
    if environment_error is not None
    else settings_payload['credential_detail']
  ) if (environment_error is not None or credential_error is not None) else None
  settings_payload['settings_ready'] = bool(
    settings_payload.get('environment_ready')
    and settings_payload.get('credential_ready')
  )

  if environment_error is not None or credential_error is not None:
    return (settings_payload, environment_error or credential_error)
  return (settings_payload, None)


def _action_failure_payload(action_name: str, exc: Exception) -> JSONDict:
  if isinstance(exc, ScanCanceledError):
    return {
      'decision': 'planned',
      'reason': 'scan_canceled',
      'message': 'Scan canceled by user.',
      'next_action': 'Find candidates when you are ready.',
    }
  if isinstance(exc, FileNotFoundError):
    missing_file = _path_tail(getattr(exc, 'filename', None) or str(exc)) or 'required local file'
    if 'key' in missing_file.lower() or missing_file.lower().endswith('.pem'):
      return {
        **_no_go_payload(
          'missing_private_key_file',
          f'The configured private key file is missing: {missing_file}.',
          'Fix the credential posture in the startup readiness lane before retrying this dry-run action.',
        ),
        'error_evidence': {'missing_file': missing_file},
      }
    return {
      **_no_go_payload(
        'missing_local_file',
        f'A required local file is missing: {missing_file}.',
        'Restore the missing local file and retry this operator action.',
      ),
      'error_evidence': {'missing_file': missing_file},
    }

  message = str(exc).strip() or exc.__class__.__name__
  normalized_message = message.lower()
  if (
    action_name == 'scan'
    and (
      'authenticated request' in normalized_message
      or 'authentication' in normalized_message
      or 'unauthorized' in normalized_message
      or 'forbidden' in normalized_message
      or 'invalid token' in normalized_message
    )
  ):
    return _no_go_payload(
      'credential_acceptance_failed',
      message,
      'Reload credential posture and validate the active key reference before retrying candidate search.',
    )
  return _no_go_payload(
    f'{action_name}_failed',
    message,
    'Review the reported issue before retrying this operator action.',
  )


def _route_failure_detail(
  route_path: str,
  action_name: str,
  exc: Exception,
  *,
  scan_snapshot: JSONDict | None = None,
  websocket_snapshot: JSONDict | None = None,
) -> JSONDict:
  normalized_scan_snapshot: JSONDict = dict(scan_snapshot or {})
  normalized_websocket_snapshot: JSONDict = dict(websocket_snapshot or {})
  return {
    'route_path': route_path,
    'action_name': action_name,
    'exception_class': exc.__class__.__name__,
    'message': str(exc).strip() or exc.__class__.__name__,
    'scan_runtime_status': str(normalized_scan_snapshot.get('status') or ''),
    'scan_runtime_stage': str(normalized_scan_snapshot.get('stage') or ''),
    'scan_runtime_active': bool(normalized_scan_snapshot.get('active')),
    'scan_session_id': str(normalized_scan_snapshot.get('scan_session_id') or ''),
    'lane_session_id': str(normalized_scan_snapshot.get('lane_session_id') or normalized_websocket_snapshot.get('lane_session_id') or ''),
    'websocket_runtime_status': str(normalized_websocket_snapshot.get('status') or ''),
    'websocket_connected': bool(normalized_websocket_snapshot.get('websocket_connected')),
  }


def _probe_key_reference_acceptance(
  settings: Any,
  *,
  key_path: str | Path | None = None,
  client_factory: Callable[[Any, object], Any] = KalshiHttpClient,
) -> JSONDict:
  resolved_key_path = str(key_path or '').strip() or str(
    getattr(settings, 'private_key_file', None) or ''
  ).strip()
  if not resolved_key_path:
    return {
      'ok': False,
      'reason': 'format_error',
      'message': 'No local key reference was provided for platform validation.',
      'next_action': 'Stage and validate a local key file before loading it into this shell session.',
    }

  try:
    probe_settings = replace(
      settings,
      private_key_file=resolved_key_path,
      private_key_path_legacy=None,
      private_key_inline=None,
    )
  except Exception:
    probe_settings = settings

  try:
    private_key = load_private_key(resolved_key_path)
  except Exception:
    return {
      'ok': False,
      'reason': 'format_error',
      'message': 'The selected key file could not be parsed as a valid RSA PEM key.',
      'next_action': 'Choose a valid PEM private key file and retry validation.',
    }

  expected_env = 'live' if str(getattr(probe_settings, 'operation_lane', '')).strip().lower() == 'live' else 'demo'
  probe_environments = tuple(
    (env_name, url)
    for env_name, url in (
      ('demo', derive_rest_api_base_url(getattr(probe_settings, 'sandbox_websocket_url', '') or '')),
      ('live', derive_rest_api_base_url(getattr(probe_settings, 'live_websocket_url', '') or '')),
    )
    if url
  )
  status_by_env: dict[str, str] = {}
  for env_name, api_base_url in probe_environments:
    try:
      env_settings = replace(probe_settings, api_base_url=api_base_url)
      client = client_factory(env_settings, private_key)
      client.get_markets(status='open', limit=1)
      client.get_account_api_limits()
      if env_name != expected_env:
        return {
          'ok': False,
          'reason': 'credential_environment_mismatch',
          'message': (
            'Credential validated, but it belongs to a different Kalshi environment than the selected lane.'
          ),
          'next_action': (
            'Use demo credentials for sandbox mode or switch to the live lane before loading this key.'
            if expected_env == 'demo'
            else 'Use live credentials for live mode or switch to sandbox lane before loading this key.'
          ),
          'detected_environment': env_name,
          'expected_environment': expected_env,
          'status_by_environment': status_by_env,
        }
      return {
        'ok': True,
        'reason': 'pass',
        'message': 'Key file valid and platform accepted authenticated requests.',
        'next_action': 'Load the validated key reference into this shell session.',
        'detected_environment': env_name,
        'expected_environment': expected_env,
        'status_by_environment': status_by_env,
      }
    except KalshiHttpError as exc:
      reason_code = str(getattr(exc, 'reason_code', '') or '').lower()
      if reason_code == 'auth_failed':
        status_by_env[env_name] = 'auth_fail'
        continue
      if reason_code in {'network_timeout'}:
        status_by_env[env_name] = 'timeout'
        return {
          'ok': False,
          'reason': 'timeout',
          'message': 'Credential validation timed out before the platform acceptance checks completed.',
          'next_action': 'Verify connectivity and retry validation.',
          'status_by_environment': status_by_env,
        }
      status_by_env[env_name] = 'error'
      return {
        'ok': False,
        'reason': 'error',
        'message': str(exc) or 'Platform credential validation failed unexpectedly.',
        'next_action': getattr(exc, 'next_action', 'Review platform connectivity and retry validation.'),
        'status_by_environment': status_by_env,
      }
    except Exception:
      status_by_env[env_name] = 'error'
      return {
        'ok': False,
        'reason': 'error',
        'message': 'Credential validation failed before platform acceptance checks completed.',
        'next_action': 'Review credential posture and retry validation.',
        'status_by_environment': status_by_env,
      }

  return {
    'ok': False,
    'reason': 'auth_fail',
    'message': 'Platform rejected credentials on authenticated account checks.',
    'next_action': 'Verify API key id and private key pairing for the selected environment, then retry validation.',
    'status_by_environment': status_by_env,
  }


def _with_runtime_auth_acceptance_projection(action: str, payload: JSONDict) -> JSONDict:
  projected = dict(payload)
  normalized_reason = _normalize_reason_token(projected.get('reason', ''))
  posture = projected.get('credential_posture') if isinstance(projected.get('credential_posture'), dict) else None
  if posture is None:
    posture = {
      'acceptance_ready': None,
      'platform_validated': None,
      'validation_reason': None,
      'validation_timestamp': '',
      'acceptance_detail': 'Runtime account-auth acceptance is not yet verified for this shell state.',
    }
  posture_copy = dict(posture)
  posture_copy.setdefault('acceptance_ready', None)
  posture_copy.setdefault('acceptance_detail', 'Runtime account-auth acceptance is not yet verified for this shell state.')
  if action == 'scan' and normalized_reason == 'credential_acceptance_failed':
    posture_copy['acceptance_ready'] = False
    posture_copy['acceptance_detail'] = (
      'Runtime account-auth acceptance failed on account endpoints. '
      'Local key reference may be present, but the platform rejected the authenticated account request.'
    )
  if normalized_reason == 'credential_environment_mismatch':
    posture_copy['acceptance_ready'] = False
    posture_copy['acceptance_detail'] = (
      'Credential environment mismatch detected. '
      'The active key is valid, but it was issued for a different Kalshi environment than the selected lane.'
    )
  projected['credential_posture'] = posture_copy
  return projected


def _recommended_step_for_no_go(action: str, payload: JSONDict) -> str:
  reason = str(payload.get('reason', '')).lower()
  normalized_reason = _normalize_reason_token(reason)
  message = str(payload.get('message', '')).lower()
  if reason in {'bootstrap_failed', 'bootstrap_state_failed', 'missing_private_key_file', 'missing_local_file'}:
    return 'review_configuration'
  if normalized_reason in {
    'credential_acceptance_failed',
    'credential_environment_mismatch',
    'mode_change_preconditions_failed',
    'invalid_key_file',
    'websocket_connection_failed',
    'websocket_service_unavailable',
  }:
    return 'review_configuration'
  if action == 'scan' and (
    normalized_reason == 'scan_failed'
    or 'authenticated request' in message
    or 'authentication' in message
    or 'unauthorized' in message
    or 'forbidden' in message
  ):
    return 'review_configuration'
  if 'unmatched_exposure' in reason:
    return 'reconcile'
  if 'candidate' in reason:
    return 'scan'
  return action


def _recommended_step_for_run_no_go(payload: JSONDict) -> str:
  blocked_reason = str(payload.get('blocked_reason') or '').strip()
  if blocked_reason in {'no_saved_set', 'saved_set_empty'}:
    return 'select_candidates'
  settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else None
  if settings_payload is not None and not bool(settings_payload.get('settings_ready')):
    return 'review_configuration'

  context = _fix_configuration_context(settings_payload)
  if not bool(context.get('credential_ready')) or not bool(context.get('has_any_websocket_url')):
    return 'review_configuration'

  reason_tokens = {
    _normalize_reason_token(payload.get('reason', '')),
    _normalize_reason_token(payload.get('blocked_reason', '')),
  }
  reason_tokens.discard('')

  if any(
    token in {
      'bootstrap_failed',
      'bootstrap_state_failed',
      'missing_private_key_file',
      'missing_local_file',
      'mode_change_preconditions_failed',
      'credential_acceptance_failed',
      'credential_environment_mismatch',
      'websocket_connection_failed',
      'websocket_service_unavailable',
      'invalid_key_file',
    }
    for token in reason_tokens
  ):
    return 'review_configuration'

  if any('exposure' in token or 'pair' in token for token in reason_tokens):
    return 'reconcile'

  return 'reconcile'


def _normalize_reason_token(reason: str) -> str:
  token = re.sub(r'[^a-z0-9]+', '_', str(reason or '').strip().lower())
  return token.strip('_')


def _reason_indicates_failure(reason: str) -> bool:
  normalized = _normalize_reason_token(reason)
  return normalized.endswith('_failed') if normalized else False


def _default_next_actionable_step(recommended_step: str, *, step_kind: str) -> str:
  step = str(recommended_step or 'bootstrap').lower() or 'bootstrap'
  kind = str(step_kind or 'execute').lower() or 'execute'
  if kind == 'fix_configuration':
    return 'load_api_key'
  if kind == 'review' and step == 'report':
    return '-'
  return step


FIX_CONFIGURATION_NEXT_STEP_SCHEMA: tuple[JSONDict, ...] = (
  {
    'id': 'mode_change_required',
    'when': {
      'credential_ready': True,
      'has_any_websocket_url': True,
      'mode_selected': False,
    },
    'next_actionable_step': 'mode_change',
  },
  {
    'id': 'credential_ready_and_websocket_missing',
    'when': {
      'credential_ready': True,
      'environment_ready': False,
      'has_any_websocket_url': False,
    },
    'next_actionable_step': 'set_websocket_url',
  },
  {
    'id': 'credential_not_ready',
    'when': {
      'credential_ready': False,
    },
    'next_actionable_step': 'load_api_key',
  },
)


def _websocket_url_is_configured(value: Any) -> bool:
  normalized = str(value or '').strip().lower()
  return bool(normalized and normalized != 'unconfigured')


def _fix_configuration_context(settings_payload: JSONDict | None) -> JSONDict:
  settings_payload = settings_payload or {}
  available_urls = settings_payload.get('available_websocket_urls')
  if not isinstance(available_urls, dict):
    available_urls = {}
  has_any_websocket_url = any(
    _websocket_url_is_configured(candidate)
    for candidate in (
      available_urls.get('sandbox'),
      available_urls.get('live'),
      settings_payload.get('sandbox_websocket_url'),
      settings_payload.get('live_websocket_url'),
      settings_payload.get('active_websocket_url'),
    )
  )
  return {
    'credential_ready': bool(settings_payload.get('credential_ready')),
    'environment_ready': bool(settings_payload.get('environment_ready')),
    'has_any_websocket_url': has_any_websocket_url,
    'mode_selected': bool(_settings_mode_selected(settings_payload)),
  }


def _payload_mode_selected(payload: JSONDict | None) -> bool:
  normalized_payload: JSONDict = payload or {}
  settings_candidate = normalized_payload.get('settings')
  settings_payload = cast(JSONDict, settings_candidate) if isinstance(settings_candidate, dict) else {}
  settings_mode = _settings_mode_selected(settings_payload)
  if settings_mode is not None:
    return settings_mode
  connection_posture_candidate = normalized_payload.get('connection_posture')
  connection_posture = cast(JSONDict, connection_posture_candidate) if isinstance(connection_posture_candidate, dict) else {}
  if 'mode_selected' in connection_posture:
    return bool(connection_posture.get('mode_selected'))
  return False


def _settings_mode_selected(settings_payload: JSONDict | None) -> bool | None:
  settings_payload = settings_payload or {}
  if 'mode_selected' in settings_payload:
    return bool(settings_payload.get('mode_selected'))
  return None


def _is_mode_change_ready(settings_payload: JSONDict | None) -> bool:
  """Check if both credentials and websocket URLs are available for mode selection."""
  context = _fix_configuration_context(settings_payload)
  return bool(
    context.get('credential_ready')
    and context.get('has_any_websocket_url')
  )


def _resolve_fix_configuration_next_actionable_step(settings_payload: JSONDict | None) -> str:
  if not bool((settings_payload or {}).get('credential_ready')):
    return 'load_api_key'
  context = _fix_configuration_context(settings_payload)
  for rule in FIX_CONFIGURATION_NEXT_STEP_SCHEMA:
    when = rule.get('when') if isinstance(rule, dict) else None
    if not isinstance(when, dict):
      continue
    if all(context.get(key) is value for key, value in when.items()):
      next_step = str(rule.get('next_actionable_step') or '').strip().lower()
      if next_step:
        return next_step
  return 'load_api_key'


def _configured_websocket_count(settings_payload: JSONDict | None) -> int:
  settings_payload = settings_payload or {}
  available_urls = settings_payload.get('available_websocket_urls')
  if not isinstance(available_urls, dict):
    available_urls = {}
  return sum(
    1
    for value in (
      available_urls.get('sandbox'),
      available_urls.get('live'),
    )
    if _websocket_url_is_configured(value)
  )


def _is_waiting_for_key_input(settings_payload: JSONDict | None) -> bool:
  settings_payload = settings_payload or {}
  if bool(settings_payload.get('credential_ready')):
    return False
  credential_reference_present = bool(settings_payload.get('credential_reference_present'))
  private_key_file_exists = bool(settings_payload.get('private_key_file_exists'))
  api_key_present = bool(settings_payload.get('api_key_id_present'))
  credential_detail = str(settings_payload.get('credential_detail') or '').strip().lower()
  if 'missing on disk' in credential_detail:
    return False
  if not credential_reference_present:
    return True
  if private_key_file_exists and not api_key_present:
    return True
  return False


def _is_waiting_for_websocket_input(settings_payload: JSONDict | None) -> bool:
  settings_payload = settings_payload or {}
  if bool(settings_payload.get('environment_ready')):
    return False
  return _configured_websocket_count(settings_payload) == 0


def _is_non_error_readiness_waiting_state(settings_payload: JSONDict | None) -> bool:
  settings_payload = settings_payload or {}
  if bool(settings_payload.get('settings_ready')):
    return False
  issue_family = str(settings_payload.get('configuration_issue_family') or '').strip().lower()
  if issue_family in {'inline_private_key_blocked', 'invalid_private_key_reference'}:
    return False
  return _is_waiting_for_key_input(settings_payload) or _is_waiting_for_websocket_input(settings_payload)


def _waiting_readiness_workflow(settings_payload: JSONDict | None, *, operator_message: str | None = None) -> JSONDict | None:
  if not _is_non_error_readiness_waiting_state(settings_payload):
    return None
  resting_state_id = _resting_state_id(settings_payload)
  contract = resolve_transition_view_contract(
    prev_state_id='unknown',
    action_name='*',
    outcome='success',
    resting_state_id=resting_state_id,
  )
  if contract is None:
    return None
  signed_envelope = build_signed_contract_envelope(
    _normalize_transition_key('unknown', '*', 'success', resting_state_id),
    contract,
    settings_payload,
  )
  return _workflow_state(
    contract.recommended_step,
    auto_sequence=list(contract.auto_sequence),
    headline=contract.headline,
    operator_message=operator_message or contract.operator_message,
    step_kind=contract.step_kind,
    can_run_next_step=contract.can_run_next_step,
    next_actionable_step=contract.next_actionable_step,
    focus_target=contract.focus_target,
    focus_tone=contract.focus_tone,
    deck_view=contract.deck_view,
    signed_envelope=signed_envelope,
    signature_required=True,
    signature_settings_payload=settings_payload,
  )


def _workflow_state(
  recommended_step: str,
  *,
  auto_sequence: list[str] | None,
  headline: str,
  operator_message: str,
  step_kind: str | None = None,
  can_run_next_step: bool | None = None,
  next_actionable_step: str | None = None,
  focus_target: str | None = None,
  focus_tone: str | None = None,
  deck_view: str | None = None,
  button_emphasis_tone: str | None = None,
  signed_envelope: SignedContractEnvelope | None = None,
  signature_required: bool = False,
  signature_settings_payload: JSONDict | None = None,
) -> JSONDict:
  step = str(recommended_step or 'bootstrap').lower() or 'bootstrap'
  resolved_step_kind = str(
    step_kind or ('fix_configuration' if step == 'review_configuration' else 'execute')
  ).lower()
  resolved_can_run_next_step = (
    bool(can_run_next_step)
    if can_run_next_step is not None
    else resolved_step_kind == 'execute'
  )
  resolved_next_actionable_step = str(
    next_actionable_step or _default_next_actionable_step(step, step_kind=resolved_step_kind)
  ).lower() or 'bootstrap'

  if focus_target is None:
    if resolved_step_kind == 'fix_configuration':
      focus_target = 'readiness-section'
    elif resolved_step_kind == 'review':
      focus_target = 'evidence-section' if step == 'report' else 'notification-band-section'

  if focus_tone is None:
    focus_tone = 'focus-no-go' if resolved_step_kind == 'fix_configuration' else 'focus-info'

  if deck_view is None:
    if resolved_step_kind == 'fix_configuration':
      deck_view = 'operator'
    elif resolved_step_kind == 'review':
      deck_view = 'review'
    elif step in {'scan', 'run', 'reconcile'}:
      deck_view = 'workflow'
    else:
      deck_view = 'workflow'

  if button_emphasis_tone is None:
    button_emphasis_tone = 'ok' if resolved_can_run_next_step else ''

  workflow_payload: JSONDict = {
    'recommended_step': step,
    'auto_sequence': list(auto_sequence or []),
    'headline': headline,
    'operator_message': operator_message,
    'step_kind': resolved_step_kind,
    'can_run_next_step': resolved_can_run_next_step,
    'next_actionable_step': resolved_next_actionable_step,
    'focus_target': focus_target,
    'focus_tone': focus_tone,
    'deck_view': deck_view,
    'button_emphasis_tone': button_emphasis_tone,
  }
  # Lane L4: the view/transition contract is a Class-1 signed surface; this is the authorization
  # gate. A present envelope is verified (incl. policy check #6 against the active context). On any
  # verification failure the §C4 MANDATORY FAIL-SAFE applies: never mutate runtime state, fall back
  # to a safe no-go projection, surface the pinned string + failure code, and log names-only. A None
  # envelope means this shell instance has no signing key provisioned -> explicit, operator-visible,
  # non-enforcing 'unsigned' (verification still protects a present-but-tampered envelope; the live
  # operator path is not bricked merely because the private key is absent here). L5 blocks
  # key-absent on the retained money/evidence artifacts.
  if signature_required:
    if signed_envelope is None:
      workflow_payload['signature_status'] = 'unsigned'
    else:
      verification = verify_envelope_signature(
        signed_envelope,
        settings_payload=signature_settings_payload,
      )
      if verification.valid:
        workflow_payload['signature_status'] = 'verified'
      else:
        failure_code = verification.failure_code or 'invalid'
        print(
          '[WARN] Signed-contract verification failed at the authorization gate :: '
          f'failure={failure_code} :: key_id={signed_envelope.signer_key_id} :: '
          f'scope={signed_envelope.policy_scope_id} :: step={step} :: safe fallback projection applied'
        )
        workflow_payload['can_run_next_step'] = False
        workflow_payload['button_emphasis_tone'] = ''
        workflow_payload['operator_message'] = SIGNED_CONTRACT_FALLBACK_MESSAGE
        workflow_payload['signature_status'] = failure_code
  return workflow_payload


def _load_validation_workflow_summary(*, project_root: Path = PROJECT_ROOT) -> JSONDict:
  del project_root
  return {
    'present': False,
    'default_lanes': [],
    'lane_policy': {},
    'operator_policy': 'Validation workflow data is not surfaced in the operator shell.',
    'definition_count': 0,
    'latest_runs': [],
    'active_run_count': 0,
    'project_aggregate_available': False,
    'project_aggregate_path': None,
    'pass_count': 0,
    'failed_count': 0,
    'latest_accepted_run': None,
    'latest_failed_run': None,
    'historical_failed_runs': [],
  }


def _diagnostics_governance_context(*, project_root: Path = PROJECT_ROOT) -> JSONDict:
  return {
    'channel': 'diagnostics_governance',
    'validation_summary': _load_validation_workflow_summary(project_root=project_root),
  }


def _production_runtime_context(payload: JSONDict) -> JSONDict:
  evidence = payload.get('evidence_browser') if isinstance(payload.get('evidence_browser'), dict) else {}
  return {
    'channel': 'production_runtime',
    'retained_validation': {
      'active_run_count': int(evidence.get('active_run_count', 0) or 0),
      'pass_count': int(evidence.get('pass_count', 0) or 0),
      'failed_count': int(evidence.get('failed_count', 0) or 0),
      'latest_accepted_present': bool(evidence.get('latest_accepted_run')),
      'aggregate_available': bool(evidence.get('project_aggregate_available')),
    },
  }


def _mode_change_discovery_hold_active(
  *,
  hold_state: JSONDict | None,
  context_overlay: JSONDict | None,
  settings_payload: JSONDict | None,
  report_payload: JSONDict | None,
  reconcile_payload: JSONDict | None,
  mode_selected: bool,
) -> bool:
  hold_state = hold_state or {}
  context_overlay = context_overlay or {}
  normalize_lane = lambda value: str(value or '').strip().lower() if str(value or '').strip().lower() in {'sandbox', 'live'} else None
  hold_lane = normalize_lane(hold_state.get('lane'))
  current_lane = normalize_lane(context_overlay.get('operation_lane')) or normalize_lane((settings_payload or {}).get('operation_lane'))
  if hold_lane is None or current_lane is None or hold_lane != current_lane or not bool(mode_selected):
    return False
  latest_terminal = report_payload.get('latest_scan_terminal') if isinstance(report_payload, dict) else None
  if isinstance(latest_terminal, dict) and latest_terminal:
    return False
  if reconcile_payload:
    active_attention = [
      pair for pair in reconcile_payload.get('pairs', [])
      if isinstance(pair, dict) and str(pair.get('public_state_id') or pair.get('state') or '').strip().upper() not in PAIR_ACTIVE_PROJECTION_EXCLUDED_STATES
    ]
    if active_attention:
      return False
  return True


def _mode_change_discovery_hold_workflow() -> JSONDict:
  return _workflow_state(
    'scan',
    auto_sequence=[],
    headline='Mode selection is complete. Find candidates to continue; review evidence remains available as context.',
    operator_message='Find candidates is the next executable step for this connected lane.',
    step_kind='execute',
    can_run_next_step=True,
    next_actionable_step='scan',
    focus_target='pairs-section',
    focus_tone='focus-ok',
    deck_view='workflow',
  )


def _bootstrap_workflow(
  settings_ready: bool,
  report_payload: JSONDict | None,
  reconcile_payload: JSONDict | None,
  *,
  next_action: str,
  settings_payload: JSONDict | None = None,
  mode_selected: bool = False,
  mode_change_hold_state: JSONDict | None = None,
  context_overlay_state: JSONDict | None = None,
) -> JSONDict:
  if not settings_ready:
    waiting_workflow = _waiting_readiness_workflow(settings_payload, operator_message=next_action)
    if waiting_workflow is not None:
      return waiting_workflow
    _pending_ctx = _fix_configuration_context(settings_payload)
    _all_config_ready = (
      bool(_pending_ctx.get('credential_ready'))
      and bool(_pending_ctx.get('has_any_websocket_url'))
      and (bool(_pending_ctx.get('mode_selected')) or bool(mode_selected))
    )
    if not _all_config_ready:
      return _workflow_state(
        'review_configuration',
        auto_sequence=[],
        headline='Configuration must be fixed before the shell can advance.',
        operator_message=next_action,
        step_kind='fix_configuration',
        can_run_next_step=False,
        next_actionable_step=_resolve_fix_configuration_next_actionable_step(settings_payload),
        focus_target='readiness-section',
        focus_tone='focus-no-go',
        deck_view='operator',
      )
    # All credentials and configuration ready; fall through to operational routing

  if not bool(mode_selected):
    _pending_ctx = _fix_configuration_context(settings_payload)
    _config_ready_for_mode = bool(_pending_ctx.get('credential_ready')) and bool(_pending_ctx.get('has_any_websocket_url'))
    if _config_ready_for_mode:
      return _workflow_state(
        'change_mode',
        auto_sequence=[],
        headline='Credentials and websocket configuration are ready; choose the operating mode before runtime actions.',
        operator_message='Select Change mode to continue.',
        step_kind='review',
        can_run_next_step=False,
        next_actionable_step='mode_change',
        focus_target='readiness-section',
        focus_tone='focus-info',
        deck_view='operator',
      )
    return _workflow_state(
      'review_configuration',
      auto_sequence=[],
      headline='Configuration must be fixed before the shell can advance.',
      operator_message=next_action,
      step_kind='fix_configuration',
      can_run_next_step=False,
      next_actionable_step=_resolve_fix_configuration_next_actionable_step(settings_payload),
      focus_target='readiness-section',
      focus_tone='focus-no-go',
      deck_view='operator',
    )

  pair_count = int(reconcile_payload.get('pair_count', 0)) if reconcile_payload else 0
  active_attention = []
  if reconcile_payload:
    active_attention = [
      pair for pair in reconcile_payload.get('pairs', [])
      if _pair_requires_reconcile_attention(pair)
    ]

  if _mode_change_discovery_hold_active(
    hold_state=mode_change_hold_state,
    context_overlay=context_overlay_state,
    settings_payload=settings_payload,
    report_payload=report_payload,
    reconcile_payload=reconcile_payload,
    mode_selected=mode_selected,
  ):
    return _mode_change_discovery_hold_workflow()

  latest_heartbeat = report_payload.get('latest_heartbeat') if report_payload else None
  pair_plans = 0
  if report_payload:
    pair_plans = int(report_payload.get('table_counts', {}).get('pair_plans', 0))

  if active_attention:
    return _workflow_state(
      'reconcile',
      auto_sequence=[],
      headline='Existing local pair state needs review before a new dry-run cycle.',
      operator_message='Open reconcile first so the shell does not hide a real decision point.',
      step_kind='execute',
      can_run_next_step=True,
      focus_target='pairs-section',
      focus_tone='focus-warn',
      deck_view='workflow',
    )

  if pair_count == 0 and pair_plans == 0 and latest_heartbeat is None:
    return _workflow_state(
      'scan',
      auto_sequence=['scan', 'run'],
      headline='No prior local runtime state was found, so the shell can safely auto-forward through scan and one dry-run cycle.',
      operator_message='Auto-forward is off by default; enable it only if you want the first scan and dry-run cycle to continue automatically.',
      step_kind='execute',
      can_run_next_step=True,
      focus_target='notification-band-section',
      focus_tone='focus-ok',
      deck_view='workflow',
    )

  return _workflow_state(
    'report',
    auto_sequence=[],
    headline='Existing local runtime state is holding on an evidence review boundary.',
    operator_message='Evidence is already in view; choose the next executable action directly unless the shell needs a manual refresh.',
    step_kind='review',
    can_run_next_step=True,
    next_actionable_step='scan',
    focus_target='evidence-section',
    focus_tone='focus-info',
    deck_view='review',
  )


def _scan_follow_on_workflow(payload: JSONDict) -> JSONDict:
  if str(payload.get('reason') or '').strip().lower() == 'scan_canceled':
    return _workflow_state(
      'scan',
      auto_sequence=[],
      headline='Scan canceled by user.',
      operator_message=payload.get('next_action', 'Find candidates when you are ready.'),
      step_kind='execute',
      can_run_next_step=True,
      next_actionable_step='scan',
      focus_target='notification-band-section',
      focus_tone='focus-info',
      deck_view='workflow',
    )
  _sfow_posture = payload.get('connection_posture') if isinstance(payload.get('connection_posture'), dict) else {}
  _sfow_has_candidates = (
    int(payload.get('candidate_count', 0)) > 0
    or int(payload.get('sandbox_extended_count', 0)) > 0
  )
  if (
    _sfow_has_candidates
    and str(_sfow_posture.get('operation_lane') or '').strip().lower() == 'offline'
  ):
    return _workflow_state(
      'change_mode',
      auto_sequence=[],
      headline='Offline mode is active; a trading mode must be selected before finding candidates.',
      operator_message='Select Change mode to switch to sandbox or live mode before running Find candidates.',
      step_kind='review',
      can_run_next_step=False,
      next_actionable_step='mode_change',
      focus_target='readiness-section',
      focus_tone='focus-info',
      deck_view='operator',
    )
  candidate_count = int(payload.get('candidate_count', 0))
  sandbox_extended_count = int(payload.get('sandbox_extended_count', 0))
  if candidate_count > 0 or sandbox_extended_count > 0:
    return _workflow_state(
      'select_candidates',
      auto_sequence=[],
      headline='The scan found candidates and the shell is holding on candidate review.',
      operator_message='Select candidates in the review panel to define the working set for this review hold.',
      step_kind='review',
      can_run_next_step=False,
      next_actionable_step='select_candidates',
      focus_target='pairs-section',
      focus_tone='focus-ok',
      deck_view='operator',
    )
  return _workflow_state(
    'scan',
    auto_sequence=[],
    headline='No viable candidates were found, and the shell is holding the empty scan result.',
    operator_message=str(payload.get('next_action') or _empty_scan_operator_message(payload)),
    step_kind='execute',
    can_run_next_step=True,
    next_actionable_step='scan',
    focus_target='pairs-section',
    focus_tone='focus-ok',
    deck_view='workflow',
  )


def _processing_scan_runtime_snapshot(payload: JSONDict | None) -> JSONDict | None:
  normalized_payload = payload or {}
  execution_state = normalized_payload.get('execution_state')
  if isinstance(execution_state, dict):
    if (
      str(execution_state.get('kind') or '').strip().lower() == 'processing'
      and str(execution_state.get('action') or '').strip().lower() == 'scan'
    ):
      return {
        'status': 'processing',
        'stage': str(execution_state.get('stage') or 'processing'),
        'message': str(execution_state.get('message') or 'Find candidates is processing in the background.'),
        'started_at_utc': execution_state.get('started_at_utc'),
        'last_progress_at_utc': execution_state.get('last_progress_at_utc'),
      }

  scan_runtime = normalized_payload.get('scan_runtime')
  if isinstance(scan_runtime, dict) and str(scan_runtime.get('status') or '').strip().lower() in {'processing', 'canceling'}:
    return {
      'status': str(scan_runtime.get('status') or 'processing'),
      'stage': str(scan_runtime.get('stage') or 'processing'),
      'message': str(scan_runtime.get('message') or 'Find candidates is processing in the background.'),
      'started_at_utc': scan_runtime.get('started_at_utc'),
      'last_progress_at_utc': scan_runtime.get('last_progress_at_utc'),
    }
  return None


def _payload_scan_processing_active(payload: JSONDict | None) -> bool:
  return _processing_scan_runtime_snapshot(payload) is not None


def _pair_has_live_interaction_hold(row: JSONDict | None) -> bool:
  normalized_row = row if isinstance(row, dict) else {}
  public_state_id = str(normalized_row.get('public_state_id') or normalized_row.get('state') or '').strip().upper()
  if public_state_id in PAIR_ACTIVE_PROJECTION_EXCLUDED_STATES:
    return False

  if str(normalized_row.get('submit_response_id') or '').strip():
    return True

  interaction_public_states = {
    'SUBMITTING',
    'RESTING_BOTH',
    'RESTING_ONE_SIDE',
    'PARTIAL_ONE_SIDE',
    'PARTIAL_BOTH',
    'ASYMMETRIC_EXPOSURE',
    'REPAIR_LIVE',
    'EXPOSURE_CAPPED',
    'RECONCILE_REQUIRED',
    'SUBMIT_FAILED_RETRYABLE',
    'SUBMIT_FAILED_TERMINAL',
  }
  if public_state_id in interaction_public_states:
    return True

  interaction_actions = {
    'WAIT',
    'RECONCILE',
    'RETRY_SUBMIT',
    'CANCEL_PAIR',
    'ESCALATE_OPERATOR',
    'AUTO_CANCEL',
  }
  allowed_actions = normalized_row.get('allowed_actions') if isinstance(normalized_row.get('allowed_actions'), list) else []
  return any(str(action or '').strip().upper() in interaction_actions for action in allowed_actions)


def _pair_requires_reconcile_attention(row: JSONDict | None) -> bool:
  normalized_row = row if isinstance(row, dict) else {}
  public_state_id = str(normalized_row.get('public_state_id') or normalized_row.get('state') or '').strip().upper()
  if public_state_id in {''} | PAIR_ACTIVE_PROJECTION_EXCLUDED_STATES:
    return False
  if public_state_id in {'PROCESSING', 'SCANNING', 'DISCOVERING', 'LOADING'}:
    return False
  return True


def _coerce_scan_shape_int(summary: Mapping[str, Any], key: str) -> int:
  raw_value = summary.get(key)
  try:
    return int(raw_value or 0)
  except (TypeError, ValueError):
    return 0


def _scan_shape_operator_summary_line(scan_shape_summary: Mapping[str, Any] | None, candidate_count: int | None = None) -> str:
  summary = dict(scan_shape_summary or {})
  if not summary:
    return ''
  loaded_count = _coerce_scan_shape_int(summary, 'loaded_market_count')
  binary = summary.get('binary_suitability') if isinstance(summary.get('binary_suitability'), dict) else {}
  binary_eligible = int(binary.get('binary_suitability_eligible_count') or summary.get('entry_window_eligible_market_count') or 0)
  binary_rejected = int(binary.get('binary_suitability_rejected_count') or 0)
  rejection_reasons = binary.get('binary_suitability_rejection_reasons') if isinstance(binary.get('binary_suitability_rejection_reasons'), dict) else {}
  multivariate_rejected = int(rejection_reasons.get('multivariate_event') or binary_rejected or 0)
  final_count = int(candidate_count if candidate_count is not None else summary.get('final_candidate_count') or 0)
  if loaded_count <= 0 and binary_eligible <= 0 and final_count <= 0:
    return ''
  return (
    f'{loaded_count} markets loaded, {binary_eligible} binary-eligible, '
    f'{multivariate_rejected} rejected as multivariate, {final_count} scan final candidates.'
  )


def _build_scan_diagnostics_payload(scan_shape_summary: Mapping[str, Any] | None) -> JSONDict:
  summary = dict(scan_shape_summary or {})
  if not summary:
    return {
      'available': False,
      'headline': '',
      'detail_line': '',
      'support_line': '',
      'operator_message': '',
    }
  loaded_market_count = _coerce_scan_shape_int(summary, 'loaded_market_count')
  orderbook_review_market_count = _coerce_scan_shape_int(summary, 'orderbook_review_market_count')
  quote_ready_market_count = _coerce_scan_shape_int(summary, 'quote_ready_market_count')
  profitability_pass_market_count = _coerce_scan_shape_int(summary, 'profitability_pass_market_count')
  websocket_orderbook_count = _coerce_scan_shape_int(summary, 'websocket_orderbook_count')
  rest_fallback_count = _coerce_scan_shape_int(summary, 'rest_fallback_count')
  orderbook_enrichment_failure_count = _coerce_scan_shape_int(summary, 'orderbook_enrichment_failure_count')
  headline = 'No candidates were found in this pass.'
  detail_line = (
    'Loaded {loaded}; {reviewed} reached orderbook review; {quote_ready} were quote-ready; {profitability} passed profitability.'.format(
      loaded=loaded_market_count,
      reviewed=orderbook_review_market_count,
      quote_ready=quote_ready_market_count,
      profitability=profitability_pass_market_count,
    )
  )
  support_parts = []
  if websocket_orderbook_count > 0:
    support_parts.append(f'websocket books {websocket_orderbook_count}')
  if rest_fallback_count > 0:
    support_parts.append(f'REST fallback {rest_fallback_count}')
  if orderbook_enrichment_failure_count > 0:
    support_parts.append(f'enrichment failures {orderbook_enrichment_failure_count}')
  support_line = '; '.join(support_parts)
  operator_message = ' '.join(
    part
    for part in (
      headline,
      detail_line,
      f'{support_line}.' if support_line else '',
      'Review the empty result or find candidates again when you are ready.',
    )
    if part
  ).strip()
  return {
    'available': True,
    'headline': headline,
    'detail_line': detail_line,
    'support_line': support_line,
    'operator_message': operator_message,
  }


def _empty_scan_operator_message(payload: Mapping[str, Any]) -> str:
  scan_shape_summary = payload.get('scan_shape_summary') if isinstance(payload.get('scan_shape_summary'), dict) else {}
  diagnostics = _build_scan_diagnostics_payload(scan_shape_summary)
  if diagnostics.get('available'):
    return str(diagnostics.get('operator_message') or '')
  return 'No candidates were found in this pass. Review the empty result or find candidates.'


def _automation_follow_on_workflow(payload: JSONDict) -> JSONDict | None:
  settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else None
  if settings_payload is None or payload.get('decision') == 'no-go':
    return None
  if not bool(settings_payload.get('settings_ready')):
    return None
  automation_posture = payload.get('_automation_posture') if isinstance(payload.get('_automation_posture'), dict) else {}
  automation_enabled = bool(automation_posture.get('enabled'))
  automation_paused = bool(automation_posture.get('paused'))
  if automation_enabled and automation_paused:
    return _workflow_state(
      'scan',
      auto_sequence=[],
      headline='Automation is paused.',
      operator_message='Resume bounded automation to continue the scan cycle.',
      step_kind='review',
      can_run_next_step=False,
      next_actionable_step='resume_automation',
      focus_target='notification-band-section',
      focus_tone='focus-warn',
      deck_view='operator',
    )
  if automation_enabled:
    return _workflow_state(
      'scan',
      auto_sequence=[],
      headline='Bounded automation is active and the backend scheduler owns the scan cycle.',
      operator_message='The backend scheduler will scan for candidates and submit eligible pairs automatically within the configured policy bounds.',
      step_kind='execute',
      can_run_next_step=True,
      next_actionable_step='scan',
      focus_target='pairs-section',
      focus_tone='focus-ok',
      deck_view='workflow',
    )
  return _workflow_state(
    'scan',
    auto_sequence=[],
    headline='Automation policy updated.',
    operator_message='Find candidates when you are ready to continue.',
    step_kind='execute',
    can_run_next_step=True,
    next_actionable_step='scan',
    focus_target='notification-band-section',
    focus_tone='focus-ok',
    deck_view='workflow',
  )


_EXECUTION_HOLD_NON_FINAL_STATES = frozenset({
  'SUBMITTING',
  'RESTING_BOTH',
  'PARTIAL_ONE_SIDE',
  'PARTIAL_BOTH',
  'ASYMMETRIC_EXPOSURE',
  'REPAIR_LIVE',
  'EXPOSURE_CAPPED',
  'RECONCILE_REQUIRED',
})


def _payload_has_live_interaction_hold(payload: JSONDict | None) -> bool:
  normalized_payload = payload or {}
  execution_chronology = normalized_payload.get('execution_chronology')
  if isinstance(execution_chronology, dict) and bool(execution_chronology.get('enabled')):
    terminal_state = str(execution_chronology.get('terminal_state') or '')
    if terminal_state in _EXECUTION_HOLD_NON_FINAL_STATES:
      return True

  runtime_rows = normalized_payload.get('pair_runtime_summary')
  if not isinstance(runtime_rows, list):
    return False

  current_lane_session_id = str(
    (normalized_payload.get('review_selection') if isinstance(normalized_payload.get('review_selection'), dict) else {}).get('persisted_lane_session_id')
    or (normalized_payload.get('scan_runtime') if isinstance(normalized_payload.get('scan_runtime'), dict) else {}).get('lane_session_id')
    or (normalized_payload.get('report') if isinstance(normalized_payload.get('report'), dict) else {}).get('lane_session_id')
    or normalized_payload.get('lane_session_id')
    or ''
  ).strip()
  for row in runtime_rows:
    row_lane_session_id = str(row.get('lane_session_id') or '').strip() if isinstance(row, dict) else ''
    if current_lane_session_id and row_lane_session_id and row_lane_session_id != current_lane_session_id:
      continue
    if _pair_has_live_interaction_hold(row):
      return True
  return False


def _decimal_from_any(value: Any) -> Decimal | None:
  normalized = str(value or '').strip()
  if not normalized:
    return None
  try:
    return Decimal(normalized)
  except (InvalidOperation, TypeError, ValueError):
    return None


def _decimal_json_string(value: Decimal | None) -> str | None:
  if value is None:
    return None
  normalized = format(value, 'f')
  if '.' in normalized:
    normalized = normalized.rstrip('0').rstrip('.')
  return normalized or '0'


def _funds_as_of_age_ms(available_funds_as_of: str | None, *, now: datetime | None = None) -> float | None:
  # FB-7: real age of a funds reading from its as_of timestamp. Used so the header
  # banner carries a funds value forward only while the BACKEND would still call it
  # fresh — never on an arbitrary wall-clock window. Returns None if unparseable
  # (fail closed: an unknown age is treated as not-bridgeable by the caller).
  raw = str(available_funds_as_of or '').strip()
  if not raw:
    return None
  try:
    as_of_dt = datetime.fromisoformat(raw.replace('Z', '+00:00'))
  except ValueError:
    return None
  if as_of_dt.tzinfo is None:
    as_of_dt = as_of_dt.replace(tzinfo=timezone.utc)
  effective_now = (now or datetime.now(timezone.utc)).astimezone(timezone.utc)
  return (effective_now - as_of_dt.astimezone(timezone.utc)).total_seconds() * 1000.0


def _header_runtime_rows(payload: JSONDict) -> list[JSONDict]:
  report_payload = payload.get('report') if isinstance(payload.get('report'), dict) else None
  if report_payload is not None and isinstance(report_payload.get('pair_runtime_summary'), list):
    return [row for row in report_payload.get('pair_runtime_summary', []) if isinstance(row, dict)]
  if isinstance(payload.get('pair_runtime_summary'), list):
    return [row for row in payload.get('pair_runtime_summary', []) if isinstance(row, dict)]
  return []


def _header_funds_posture(payload: JSONDict) -> JSONDict:
  report_payload = payload.get('report') if isinstance(payload.get('report'), dict) else None
  if report_payload is not None and isinstance(report_payload.get('funds_posture'), dict):
    return dict(report_payload.get('funds_posture', {}))
  if isinstance(payload.get('funds_posture'), dict):
    return dict(payload.get('funds_posture', {}))
  return {}


def _header_operation_lane(payload: JSONDict) -> str:
  connection_posture = payload.get('connection_posture') if isinstance(payload.get('connection_posture'), dict) else None
  connection_lane = str((connection_posture or {}).get('operation_lane') or '').strip().lower()
  if connection_lane:
    return connection_lane
  report_payload = payload.get('report') if isinstance(payload.get('report'), dict) else None
  report_lane = str((report_payload or {}).get('operation_lane') or '').strip().lower()
  if report_lane:
    return report_lane
  settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else None
  return str((settings_payload or {}).get('operation_lane') or '').strip().lower()


def _build_header_amount_summary(
  payload: JSONDict,
  *,
  durable_operation_lane: str | None = None,
  durable_funds_cache: dict | None = None,
) -> JSONDict:
  runtime_rows = _header_runtime_rows(payload)
  funds_posture = _header_funds_posture(payload)
  operation_lane = durable_operation_lane or _header_operation_lane(payload)
  net_profit = sum(
    (
      _decimal_from_any(row.get('net_projected_dollars')) or Decimal('0')
      for row in runtime_rows
    ),
    Decimal('0'),
  )
  # Account gross is liquid cash plus the value of still-in-flight positions, less
  # their estimated fees. Terminal pairs (settled, canceled, failed) have already
  # resolved into the cash balance and must not be re-counted as deployed value.
  # This is the human-convenience aggregate only; the authoritative Kalshi balance
  # used for backend pricing is a separate path and is never derived from here.
  in_flight_runtime_rows = [
    row for row in runtime_rows if not str(row.get('terminal_state') or '').strip()
  ]
  gross_position_value = sum(
    (
      _decimal_from_any(row.get('gross_dollars')) or Decimal('0')
      for row in in_flight_runtime_rows
    ),
    Decimal('0'),
  )
  in_flight_estimated_fees = sum(
    (
      _decimal_from_any(row.get('fees_dollars')) or Decimal('0')
      for row in in_flight_runtime_rows
    ),
    Decimal('0'),
  )
  available_funds = _decimal_from_any(funds_posture.get('available_funds_snapshot'))
  own_fresh = available_funds is not None and str(funds_posture.get('funds_refresh_status') or '').strip().lower() == 'fresh'
  # FB-7: the header money figure is derived from the funds block of the current
  # rebuild payload, but scan-driven rebuilds carry no funds block — which made the
  # banner blank on every scan during automation. Carry the most recent *fresh*
  # funds value forward across funds-less rebuilds, but ONLY while the backend
  # itself would still consider it fresh: the carryover is bounded by the same
  # staleness grace and measured against the real as_of timestamp, not a wall
  # clock. Money is therefore never shown older than the backend's own freshness
  # threshold; past it, the banner fails closed to "unavailable".
  funds_bridged = False
  if durable_funds_cache is not None:
    if own_fresh:
      durable_funds_cache['available_funds'] = available_funds
      durable_funds_cache['available_funds_as_of'] = funds_posture.get('available_funds_as_of')
    elif available_funds is None:
      _cached_funds = durable_funds_cache.get('available_funds')
      _cached_age_ms = _funds_as_of_age_ms(durable_funds_cache.get('available_funds_as_of'))
      if (
        _cached_funds is not None
        and _cached_age_ms is not None
        and _cached_age_ms <= BALANCE_STALENESS_GRACE_MS
      ):
        available_funds = _cached_funds
        funds_bridged = True
  money_authorized = operation_lane == 'live' and available_funds is not None
  funds_authorization_state = (
    'authorized' if money_authorized
    else ('live_unavailable' if operation_lane == 'live' else 'inactive')
  )
  total_assets = (available_funds + gross_position_value - in_flight_estimated_fees) if money_authorized else None
  # Lane C: the banner gross-assets figure is a user-facing DISPLAY ESTIMATE, not a
  # money-truth value. Carry the last computed total forward across funds-less / stale
  # rebuilds so the banner stays STEADY (no blank, no indicator) — UI stability is the
  # concern here, and the evidence panel already carries freshness/connection state.
  # The strict gating value above (money_authorized / available_funds_snapshot /
  # net_profit) is UNCHANGED and still fails closed at the staleness grace; this display
  # cache is never read by any gating or submit path. This is the load-bearing
  # distinction that keeps the carry charter-compliant: a labeled estimate, not truth.
  total_assets_display = total_assets
  if durable_funds_cache is not None:
    if total_assets is not None:
      durable_funds_cache['total_assets_display'] = _decimal_json_string(total_assets)
    elif durable_funds_cache.get('total_assets_display') is not None:
      total_assets_display = _decimal_from_any(durable_funds_cache.get('total_assets_display'))
  total_assets_display_available = total_assets_display is not None
  return {
    'contract_version': 'header_amount_summary.v1',
    'money_authorized': money_authorized,
    'funds_authorization_state': funds_authorization_state,
    'funds_bridged': funds_bridged,
    'net_profit_dollars': _decimal_json_string(net_profit) if money_authorized else None,
    'gross_position_value_dollars': _decimal_json_string(gross_position_value),
    'available_funds_snapshot': _decimal_json_string(available_funds),
    # total_assets_dollars / total_assets_available are the stable DISPLAY estimate
    # (carried). The strict authorization remains in money_authorized above.
    'total_assets_dollars': _decimal_json_string(total_assets_display),
    'total_assets_available': total_assets_display_available,
    'left_tooltip': 'net',
    'right_tooltip': 'gross',
  }


def _follow_on_workflow(action: str, payload: JSONDict) -> JSONDict:
  settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else None
  mode_selected = _payload_mode_selected(payload)

  def _success_resting_state_id() -> str:
    if settings_payload is None:
      return _resting_state_id(settings_payload)
    normalized_action = str(action or '').strip().lower()
    operation_lane = str(
      ((payload.get('connection_posture') or {}).get('operation_lane') if isinstance(payload.get('connection_posture'), dict) else None)
      or settings_payload.get('operation_lane')
      or ''
    ).strip().lower()
    if normalized_action == 'change_mode' and operation_lane == 'offline' and not bool(mode_selected):
      return '1'
    return _resting_state_id(settings_payload)

  success_transition_contract: ViewContractRecord | None = None
  success_transition_key: TransitionKey | None = None
  if (
    settings_payload is not None
    and str(payload.get('transition_outcome') or '').strip().lower() == 'success'
  ):
    success_transition_key = _normalize_transition_key(
      str(payload.get('prev_resting_state_id', 'unknown') or 'unknown'),
      action,
      'success',
      _success_resting_state_id(),
    )
    success_transition_contract = resolve_transition_view_contract(
      prev_state_id=str(payload.get('prev_resting_state_id', 'unknown') or 'unknown'),
      action_name=action,
      outcome='success',
      resting_state_id=_success_resting_state_id(),
    )
  if (
    success_transition_contract is None
    and settings_payload is not None
    and not bool(settings_payload.get('settings_ready'))
    and str(payload.get('transition_outcome') or '').strip().lower() == 'success'
    and str(action or '').strip().lower() in SUCCESS_READINESS_TRANSITION_ACTIONS
  ):
    success_transition_key = _normalize_transition_key('unknown', action, 'success', _success_resting_state_id())
    success_transition_contract = resolve_transition_view_contract(
      prev_state_id='unknown',
      action_name=action,
      outcome='success',
      resting_state_id=_success_resting_state_id(),
    )
  if success_transition_contract is not None:
    success_envelope = build_signed_contract_envelope(
      success_transition_key,
      success_transition_contract,
      settings_payload,
    ) if success_transition_key is not None else None
    return _workflow_state(
      success_transition_contract.recommended_step,
      auto_sequence=list(success_transition_contract.auto_sequence),
      headline=success_transition_contract.headline,
      operator_message=success_transition_contract.operator_message,
      step_kind=success_transition_contract.step_kind,
      can_run_next_step=success_transition_contract.can_run_next_step,
      next_actionable_step=success_transition_contract.next_actionable_step,
      focus_target=success_transition_contract.focus_target,
      focus_tone=success_transition_contract.focus_tone,
      deck_view=success_transition_contract.deck_view,
      signed_envelope=success_envelope,
      signature_required=True,
      signature_settings_payload=settings_payload,
    )
  processing_scan = _processing_scan_runtime_snapshot(payload)
  if processing_scan is not None:
    stage_label = str(processing_scan.get('stage') or 'processing').replace('_', ' ')
    message = str(processing_scan.get('message') or 'Find candidates is processing in the background.')
    return _workflow_state(
      'processing',
      auto_sequence=[],
      headline='Find candidates is running in the background and streaming progress into the shell.',
      operator_message=f'{message} (stage: {stage_label}).',
      step_kind='review',
      can_run_next_step=False,
      next_actionable_step='processing',
      focus_target='boundary-panel',
      focus_tone='focus-info',
      deck_view='operator',
      button_emphasis_tone='warn',
    )
  if action == 'automation' and payload.get('decision') != 'no-go':
    automation_workflow = _automation_follow_on_workflow(payload)
    if automation_workflow is not None:
      return automation_workflow
  if action == 'scan' and payload.get('decision') != 'no-go':
    return _scan_follow_on_workflow(payload)
  if action == 'run' and (
    str(payload.get('blocked_reason') or '').strip() == 'saved_set_not_eligible'
    or _payload_has_live_interaction_hold(payload)
  ):
    return _workflow_state(
      'scan',
      auto_sequence=[],
      headline='Submit order was routed to the eligibility queue.',
      operator_message='Candidates have been submitted to the queue and are awaiting execution. No operator action is required.',
      step_kind='review',
      can_run_next_step=False,
      next_actionable_step='scan',
      focus_target='live-interaction-section',
      focus_tone='focus-info',
      deck_view='operator',
    )
  if action == 'run' and payload.get('decision') != 'no-go':
    _run_automation_posture = payload.get('_automation_posture') if isinstance(payload.get('_automation_posture'), dict) else {}
    if bool(_run_automation_posture.get('enabled')):
      automation_workflow = _automation_follow_on_workflow(payload)
      if automation_workflow is not None:
        return automation_workflow
  if settings_payload is not None and payload.get('decision') != 'no-go':
    waiting_workflow = _waiting_readiness_workflow(
      settings_payload,
      operator_message=str(payload.get('next_action') or '').strip() or None,
    )
    if waiting_workflow is not None:
      return waiting_workflow
  if action == 'run':
    _run_blocked_reason = str(payload.get('blocked_reason') or '').strip()
    if _run_blocked_reason in {'no_saved_set', 'saved_set_empty'}:
      return _workflow_state(
        'select_candidates',
        auto_sequence=[],
        headline='Submit order is blocked until a non-empty candidate set is saved.',
        operator_message='Select candidates and save candidates before retrying submit order.',
        step_kind='review',
        can_run_next_step=False,
        next_actionable_step='select_candidates',
        focus_target='pairs-section',
        focus_tone='focus-warn',
        deck_view='operator',
        button_emphasis_tone='warn',
      )
  if settings_payload is not None and not bool(settings_payload.get('settings_ready')):
    _pending_ctx = _fix_configuration_context(settings_payload)
    _all_ready = (
      bool(_pending_ctx.get('credential_ready'))
      and bool(_pending_ctx.get('has_any_websocket_url'))
      and (bool(_pending_ctx.get('mode_selected')) or bool(mode_selected))
    )
    if not _all_ready:
      return _workflow_state(
        'review_configuration',
        auto_sequence=[],
        headline='Configuration must be fixed before the shell can advance.',
        operator_message=payload.get('next_action', 'Fix the configuration posture before continuing.'),
        step_kind='fix_configuration',
        can_run_next_step=False,
        next_actionable_step=_resolve_fix_configuration_next_actionable_step(settings_payload),
        focus_target='readiness-section',
        focus_tone='focus-no-go',
        deck_view='operator',
      )

  if payload.get('decision') == 'no-go':
    reason_value = str(payload.get('reason', '') or '')
    normalized_reason = _normalize_reason_token(reason_value)
    no_go_contract: ViewContractRecord | None = None
    no_go_transition_key: TransitionKey | None = None
    if _reason_indicates_failure(reason_value):
      no_go_transition_key = _normalize_transition_key(
        str(payload.get('prev_resting_state_id', 'unknown') or 'unknown'),
        action,
        'no-go',
        _resting_state_id(settings_payload),
      )
      no_go_contract = resolve_transition_view_contract(
        prev_state_id=str(payload.get('prev_resting_state_id', 'unknown') or 'unknown'),
        action_name=action,
        outcome='no-go',
        resting_state_id=_resting_state_id(settings_payload),
      )
    recommended_step = _recommended_step_for_no_go(action, payload)
    if action == 'run' and no_go_contract is None:
      recommended_step = _recommended_step_for_run_no_go(payload)
    if no_go_contract is not None:
      recommended_step = no_go_contract.recommended_step
    step_kind = 'fix_configuration' if recommended_step == 'review_configuration' else 'execute'
    if no_go_contract is not None:
      step_kind = no_go_contract.step_kind
    focus_target = 'readiness-section' if step_kind == 'fix_configuration' else ('pairs-section' if recommended_step == 'reconcile' else 'notification-band-section')
    focus_tone = 'focus-no-go' if step_kind == 'fix_configuration' else 'focus-warn'
    deck_view = 'operator' if step_kind == 'fix_configuration' else 'workflow'
    can_run_next_step = step_kind == 'execute'
    if no_go_contract is not None:
      focus_target = no_go_contract.focus_target
      focus_tone = no_go_contract.focus_tone
      deck_view = no_go_contract.deck_view
      can_run_next_step = no_go_contract.can_run_next_step
    next_actionable_step = (
      _resolve_fix_configuration_next_actionable_step(payload.get('settings') if isinstance(payload.get('settings'), dict) else None)
      if step_kind == 'fix_configuration'
      else None
    )
    if no_go_contract is not None:
      next_actionable_step = no_go_contract.next_actionable_step
    if step_kind == 'fix_configuration' and normalized_reason in {
      'missing_private_key_file',
      'credential_acceptance_failed',
      'credential_environment_mismatch',
      'invalid_key_file',
    }:
      next_actionable_step = 'load_api_key'
    if step_kind == 'fix_configuration' and normalized_reason == 'websocket_connection_failed':
      next_actionable_step = 'set_websocket_url'
    headline = (
      no_go_contract.headline
      if no_go_contract is not None
      else payload.get('message', 'The requested action reported a no-go state.')
    )
    operator_message = (
      no_go_contract.operator_message
      if no_go_contract is not None
      else payload.get('next_action', 'Review the no-go message before continuing.')
    )
    if action == 'change_mode' and normalized_reason in {
      'credential_acceptance_failed',
      'credential_acceptance_timeout',
      'credential_environment_mismatch',
      'websocket_connection_failed',
      'websocket_service_unavailable',
      'mode_change_preconditions_failed',
    }:
      headline = str(payload.get('message') or headline)
      operator_message = str(payload.get('next_action') or operator_message)
    no_go_envelope = (
      build_signed_contract_envelope(no_go_transition_key, no_go_contract, settings_payload)
      if no_go_contract is not None and no_go_transition_key is not None
      else None
    )
    return _workflow_state(
      recommended_step,
      auto_sequence=[],
      headline=headline,
      operator_message=operator_message,
      step_kind=step_kind,
      can_run_next_step=can_run_next_step,
      next_actionable_step=next_actionable_step,
      focus_target=focus_target,
      focus_tone=focus_tone,
      deck_view=deck_view,
      signed_envelope=no_go_envelope,
      signature_required=no_go_contract is not None,
      signature_settings_payload=settings_payload,
    )

  if action == 'scan':
    return _scan_follow_on_workflow(payload)

  if action == 'run':
    if int(payload.get('planned_pair_count', 0)) > 0:
      interaction_hold_active = _payload_has_live_interaction_hold(payload)
      in_flight_active = int(payload.get('_in_flight_candidate_count') or 0) > 0
      hold_active = interaction_hold_active or in_flight_active
      return _workflow_state(
        'report',
        auto_sequence=[],
        headline='A dry-run pair plan was created, so the shell is holding on the resulting evidence.',
        operator_message=(
          'Live interaction is already in view; refresh only if the shell looks stale.'
          if hold_active
          else 'Evidence is already in view; choose the next executable action directly unless the shell needs a manual refresh.'
        ),
        step_kind='review',
        can_run_next_step=False,
        next_actionable_step='-',
        focus_target='live-interaction-section' if hold_active else 'evidence-section',
        focus_tone='focus-info' if hold_active else 'focus-ok',
        deck_view='review',
      )
    blocked_reason = payload.get('blocked_reason')
    if blocked_reason in {'no_saved_set', 'saved_set_empty'}:
      return _workflow_state(
        'select_candidates',
        auto_sequence=[],
        headline='Submit order is blocked until a non-empty candidate set is saved.',
        operator_message='Select candidates and save candidates before retrying submit order.',
        step_kind='review',
        can_run_next_step=False,
        next_actionable_step='select_candidates',
        focus_target='pairs-section',
        focus_tone='focus-warn',
        deck_view='operator',
        button_emphasis_tone='warn',
      )
    if blocked_reason == 'bridge_authorization_failed':
      return _workflow_state(
        'change_mode',
        auto_sequence=[],
        headline='Submit order requires sandbox mode. Switch to sandbox to proof the submission path.',
        operator_message='Connect in sandbox mode and confirm readiness before retrying submit order. Live lane submission will be enabled after sandbox acceptance gates are satisfied.',
        step_kind='review',
        can_run_next_step=True,
        next_actionable_step='mode_change',
        focus_target='readiness-section',
        focus_tone='focus-warn',
        deck_view='operator',
        button_emphasis_tone='warn',
      )
    if blocked_reason == 'unmatched_exposure_timeout':
      return _workflow_state(
        'reconcile',
        auto_sequence=[],
        headline='The runtime cycle hit the unmatched exposure boundary and stopped where an operator decision is required.',
        operator_message='Open reconcile to inspect the affected pair state before continuing.',
        step_kind='execute',
        can_run_next_step=True,
        focus_target='pairs-section',
        focus_tone='focus-warn',
        deck_view='workflow',
      )
    return _workflow_state(
      'report',
      auto_sequence=[],
      headline='The dry-run cycle completed without a new planned pair, so the shell is holding on the resulting evidence.',
      operator_message='Evidence is already in view; choose the next executable action directly unless the shell needs a manual refresh.',
      step_kind='review',
      can_run_next_step=False,
      focus_target='evidence-section',
      focus_tone='focus-info',
      deck_view='review',
    )

  if action == 'cancel-all':
    interaction_hold_active = _payload_has_live_interaction_hold(payload)
    return _workflow_state(
      'report',
      auto_sequence=[],
      headline='Cancel-all completed and the shell is holding on the updated runtime posture.',
      operator_message=(
        'Live interaction remains backend-owned in this state; refresh only if the shell looks stale.'
        if interaction_hold_active
        else 'Review the updated pair posture, then find candidates when you are ready for the next runtime cycle.'
      ),
      step_kind='review',
      can_run_next_step=False,
      next_actionable_step='-' if interaction_hold_active else 'scan',
      focus_target='live-interaction-section' if interaction_hold_active else 'pairs-section',
      focus_tone='focus-info' if interaction_hold_active else 'focus-ok',
      deck_view='review',
    )

  if action == 'report' and _payload_has_live_interaction_hold(payload):
    return _workflow_state(
      'report',
      auto_sequence=[],
      headline='The shell is holding on the current live interaction summary.',
      operator_message='Live interaction is backend-owned in this state; refresh only if the shell looks stale.',
      step_kind='review',
      can_run_next_step=False,
      next_actionable_step='-',
      focus_target='live-interaction-section',
      focus_tone='focus-info',
      deck_view='review',
    )

  if action in (DECK_ACTION_GROUPS.get('data_management', set()) | DECK_ACTION_GROUPS.get('websocket_management', set())):
    return _bootstrap_workflow(
      bool(settings_payload.get('settings_ready')) if settings_payload is not None else False,
      payload.get('report') if isinstance(payload.get('report'), dict) else None,
      payload.get('reconcile') if isinstance(payload.get('reconcile'), dict) else None,
      next_action=str(payload.get('next_action') or '').strip() or 'Continue with the recommended next step.',
      settings_payload=settings_payload,
      mode_selected=bool(mode_selected),
    )

  return _workflow_state(
    action,
    auto_sequence=[],
    headline='The requested action completed and the shell is waiting at the next real decision boundary.',
    operator_message=payload.get('next_action', 'Review the current result before continuing.'),
    step_kind='review' if action == 'report' else 'execute',
    can_run_next_step=action != 'report',
    next_actionable_step='mode_change' if (action == 'report' and _is_mode_change_ready(settings_payload) and not bool(mode_selected)) else None,
    focus_target='evidence-section' if action == 'report' else None,
    focus_tone='focus-info',
    deck_view='review' if action == 'report' else 'workflow',
  )

  return {
    'recommended_step': action,
    'auto_sequence': [],
    'headline': 'The requested action completed and the shell is waiting at the next real decision boundary.',
    'operator_message': payload.get('next_action', 'Review the current result before continuing.'),
  }


def _build_startup_wizard_payload(payload: JSONDict) -> JSONDict | None:
  settings = payload.get('settings')
  if not isinstance(settings, dict) or not settings:
    return None

  workflow = payload.get('workflow', {}) if isinstance(payload.get('workflow'), dict) else {}
  connection_posture = payload.get('connection_posture') if isinstance(payload.get('connection_posture'), dict) else {}
  local_shell_disclosure = payload.get('local_shell_disclosure') if isinstance(payload.get('local_shell_disclosure'), dict) else {}
  local_shell_blocked = bool(local_shell_disclosure.get('active'))
  report_payload = payload.get('report') if isinstance(payload.get('report'), dict) else None
  latest_heartbeat = report_payload.get('latest_heartbeat') if report_payload else None
  waiting_state = _is_non_error_readiness_waiting_state(settings)
  offline_resting_posture = (
    str(connection_posture.get('operation_lane') or '').strip().lower() == 'offline'
    and bool(connection_posture.get('is_offline'))
    and not bool(connection_posture.get('mode_selected'))
  )
  readiness_status = 'blocked' if (payload.get('decision') == 'no-go' or local_shell_blocked) else ('pending' if waiting_state else 'ready')
  proof_status = 'blocked' if (payload.get('decision') == 'no-go' or local_shell_blocked) else ('ready' if latest_heartbeat is not None else 'pending')

  def _step(step_id: str, label: str, status: str, detail: str) -> JSONDict:
    return {
      'id': step_id,
      'label': label,
      'status': status,
      'detail': detail,
    }

  env_status = 'ready' if settings.get('environment_ready', settings.get('settings_ready', True)) else ('pending' if _is_waiting_for_websocket_input(settings) else 'blocked')
  credential_posture: JSONDict = payload.get('credential_posture') if isinstance(payload.get('credential_posture'), dict) else {}
  local_credential_ready = bool(
    settings.get(
      'credential_ready',
      bool(settings.get('api_key_id_present')) and bool(settings.get('private_key_file_present')),
    )
  )
  credential_acceptance_ready = credential_posture.get('acceptance_ready')
  credential_ready = local_credential_ready and credential_acceptance_ready is not False
  credential_status = (
    'ready'
    if offline_resting_posture and payload.get('decision') != 'no-go' and credential_acceptance_ready is not False
    else ('ready' if credential_ready else ('pending' if _is_waiting_for_key_input(settings) and credential_acceptance_ready is not False else 'blocked'))
  )

  runtime_summary = (
    f"scan={settings.get('scan_interval_ms', '--')}ms :: "
    f"min_edge=${settings.get('min_edge_dollars', '--')} :: "
    f"max_open_pairs={settings.get('max_open_pairs', '--')}"
  )
  mode_label = _human_mode_label(settings.get('mode', 'ab_guarded'))
  proof_detail = (
    str(local_shell_disclosure.get('detail'))
    if local_shell_blocked and str(local_shell_disclosure.get('detail') or '').strip()
    else (
      f"latest heartbeat={latest_heartbeat.get('status')}"
      if latest_heartbeat is not None
      else (workflow.get('headline') or payload.get('next_action') or 'Run bootstrap proof before advancing.')
    )
  )

  return {
    'readiness_status': readiness_status,
    'headline': (
      str(local_shell_disclosure.get('headline'))
      if local_shell_blocked and str(local_shell_disclosure.get('headline') or '').strip()
      else workflow.get('headline', 'Startup readiness remains inside the dry-run contract.')
    ),
    'steps': [
      _step(
        'environment',
        'Environment check',
        env_status,
        str(settings.get('environment_detail') or f"env={str(settings.get('kalshi_env', '--')).upper()} :: api={_path_tail(settings.get('api_base_url')) or settings.get('api_base_url', '--')}") ,
      ),
      _step(
        'credentials',
        'Credential posture',
        credential_status,
        str(
          'Offline mode selected. Credential validation is parked until sandbox or live mode is selected.'
          if offline_resting_posture and payload.get('decision') != 'no-go' and credential_acceptance_ready is not False
          else (
            credential_posture.get('acceptance_detail')
            if credential_acceptance_ready is False
            else (
              settings.get('credential_detail')
              or (
                f"api_key={'present' if settings.get('api_key_id_present') else 'missing'} :: "
                f"private_key_file={'present' if settings.get('private_key_file_present') else 'missing'}"
              )
            )
          )
        ),
      ),
      _step('runtime', 'Runtime settings review', 'ready', runtime_summary),
      _step('mode', 'Approach', 'ready', f'default approach={mode_label}'),
      _step('proof', 'Dry-run proof', proof_status, proof_detail),
    ],
  }


_STAGE_COLUMNS_EMPTY: list[dict] = [
  {'stage_id': 'queued',    'stage_label': 'Queued',    'items': []},
  {'stage_id': 'filled',    'stage_label': 'Filled',    'items': []},
  {'stage_id': 'cancelled', 'stage_label': 'Cancelled', 'items': []},
]

_SAVED_SET_RETIRED_ACTIONABILITY_STATUSES = {'submitted_terminal'}
_PAIR_FILLED_PROJECTION_STATES = {'LOCKED', 'FILLED', 'SETTLED_EXPOSURE'}
_PAIR_TERMINAL_PROJECTION_STATES = _PAIR_FILLED_PROJECTION_STATES | {'SETTLED', 'CANCELED', 'ERROR'}


def _candidate_row_saved_set_retired(row: dict) -> bool:
  # Fork D1 (2026-07-02): single retirement predicate shared by the card builder and
  # the scan-runtime result-count override, so count == cards in every phase. A
  # canonical row is retired from the operator surface when its latest saved-set
  # evaluation ended the set, its visibility is history-only, or its pair projection
  # reached a terminal state. The retry gate reads the separate active (non-terminal)
  # count and is NOT filtered by saved-set retirement.
  return (
    str(row.get('saved_set_actionability_status') or '').strip().lower() in _SAVED_SET_RETIRED_ACTIONABILITY_STATUSES
    or str(row.get('saved_set_visibility_status') or '').strip().lower() == 'history_only'
    or str(row.get('pair_state') or '').strip().upper() in _PAIR_TERMINAL_PROJECTION_STATES
  )


def _safe_json_object(raw: object) -> dict:
  if isinstance(raw, dict):
    return raw
  try:
    loaded = json.loads(str(raw or '{}'))
  except Exception:
    return {}
  return loaded if isinstance(loaded, dict) else {}


def _decimal_from_projection(value: object) -> Decimal:
  try:
    return Decimal(str(value or '0'))
  except Exception:
    return Decimal('0')


def _pair_projection_is_fill_bearing(pair_state: str, pair_detail: dict) -> bool:
  normalized = str(pair_state or '').strip().upper()
  if normalized in _PAIR_FILLED_PROJECTION_STATES:
    return True
  if normalized != 'SETTLED':
    return False
  if str(pair_detail.get('terminal_reason') or pair_detail.get('reason') or '').strip() == 'kalshi_alignment_no_exposure':
    return False
  return (
    _decimal_from_projection(pair_detail.get('yes_filled_contracts')) > 0
    or _decimal_from_projection(pair_detail.get('no_filled_contracts')) > 0
  )


def _cancelled_projection_cause(pair_state: str, terminal_cause: str, pair_detail: dict) -> str:
  normalized = str(pair_state or '').strip().upper()
  reason = str(pair_detail.get('terminal_reason') or pair_detail.get('reason') or '').strip()
  if normalized == 'SETTLED' and reason == 'kalshi_alignment_no_exposure':
    return 'no_exposure'
  if normalized == 'SETTLED':
    return 'settled_no_fill'
  if normalized == 'ERROR':
    return 'failed'
  if normalized == 'CANCELED':
    return str(reason or 'canceled')
  if str(terminal_cause or '').strip() == 'reconciled':
    return 'reconciled_no_fill'
  return str(terminal_cause or '').strip()


def _sync_saved_set_candidate_lifecycle_from_execution(connection: Any, *, saved_set_id: str, run_id: str) -> None:
  if not saved_set_id or not run_id:
    return
  table_columns = {
    str(row[1] or '')
    for row in connection.execute('PRAGMA table_info(candidate_review_candidates)').fetchall()
  }
  required_columns = {'run_id', 'ticker', 'lifecycle_stage'}
  if not required_columns <= table_columns:
    return

  def update_candidate(ticker: str, cause: str, subcause: str, terminal_at_utc: str) -> None:
    if not ticker or not cause:
      return
    assignments = ['lifecycle_stage = ?']
    params: list[Any] = ['terminal']
    if 'terminal_cause' in table_columns:
      assignments.append('terminal_cause = ?')
      params.append(cause)
    if 'terminal_subcause' in table_columns:
      assignments.append('terminal_subcause = ?')
      params.append(subcause)
    if 'terminal_at_utc' in table_columns:
      assignments.append('terminal_at_utc = ?')
      params.append(terminal_at_utc)
    params.extend([run_id, ticker])
    connection.execute(
      f"UPDATE candidate_review_candidates SET {', '.join(assignments)}"
      " WHERE run_id = ? AND ticker = ? AND lifecycle_stage != 'terminal'",
      tuple(params),
    )

  try:
    blocked_rows = connection.execute(
      """
      SELECT recorded_at_utc, detail_json
      FROM runtime_events
      WHERE event_type = 'submit_bridge_blocked'
      ORDER BY id
      """
    ).fetchall()
  except Exception:
    blocked_rows = []
  for blocked_row in blocked_rows:
    detail = _safe_json_object(blocked_row[1] if len(blocked_row) > 1 else '{}')
    if str(detail.get('saved_set_id') or '').strip() != saved_set_id:
      continue
    if bool(detail.get('orders_created')):
      continue
    update_candidate(
      str(detail.get('ticker') or '').strip(),
      'rejected',
      str(detail.get('blocked_reason') or detail.get('reason') or '').strip(),
      str(blocked_row[0] or _utc_now_iso()),
    )

  try:
    pair_rows = connection.execute(
      """
      SELECT ps.state, ps.recorded_at_utc, ps.detail_json,
             COALESCE(pp.ticker, json_extract(ps.detail_json, '$.ticker')) AS ticker
      FROM pair_states ps
      LEFT JOIN pair_plans pp ON pp.pair_id = ps.pair_id
      WHERE json_extract(ps.detail_json, '$.saved_set_id') = ?
      ORDER BY ps.id DESC
      """,
      (saved_set_id,),
    ).fetchall()
  except Exception:
    pair_rows = []

  seen_tickers: set[str] = set()
  for pair_row in pair_rows:
    state = str(pair_row[0] or '').strip().upper()
    ticker = str(pair_row[3] or '').strip()
    if not ticker or ticker in seen_tickers:
      continue
    seen_tickers.add(ticker)
    detail = _safe_json_object(pair_row[2] or '{}')
    reason = str(detail.get('terminal_reason') or detail.get('reason') or '').strip()
    if state == 'FILLED':
      update_candidate(ticker, 'reconciled', 'filled', str(pair_row[1] or _utc_now_iso()))
    elif state == 'LOCKED':
      update_candidate(ticker, 'reconciled', 'locked', str(pair_row[1] or _utc_now_iso()))
    elif state == 'SETTLED_EXPOSURE':
      update_candidate(ticker, 'reconciled', 'settled_exposure', str(pair_row[1] or _utc_now_iso()))
    elif state == 'SETTLED' and reason == 'kalshi_alignment_no_exposure':
      update_candidate(ticker, 'canceled', 'no_exposure', str(pair_row[1] or _utc_now_iso()))
    elif state == 'CANCELED':
      update_candidate(ticker, 'canceled', reason, str(pair_row[1] or _utc_now_iso()))
    elif state == 'ERROR':
      update_candidate(ticker, 'failed', reason, str(pair_row[1] or _utc_now_iso()))


def _query_canonical_candidates(lane_session_id: str, state_db_path: str) -> list[dict]:
  # Lane 1 SSOT: single canonical active-candidate set for a lane session.
  # Filters: qualifier_tier != 'near_miss'; lifecycle_stage IN (...). All surfaces
  # (cards, stage columns, execution panel, result count) derive from this.
  #
  # Dedup by ticker keeps, per ticker, the IRREVERSIBLE-CLOSE terminal if one exists,
  # else the newest row (P1 / lifecycle-precedence). The scan re-persists a candidate
  # under a new per-cycle run_id every cycle, so a ticker accumulates many rows; a plain
  # newest-row dedup let a freshly re-persisted 'discovered' row mask the 'terminal' row
  # the engine had already written, so expired cards never showed cancelled (and blinked).
  # Only `expired_unfilled` (a Kalshi close — the market never re-lists under the same
  # ticker) unconditionally wins; a reversible `auto_cancel` (operator halt) does NOT beat
  # a newer re-discovery of a still-open market in the same (websocket-scoped) session.
  if not lane_session_id or not state_db_path:
    return []
  query_t0 = time.monotonic()
  try:
    # Read-only: rendering the canonical candidate surface must not initialize schema or trigger a
    # rotation/archival sweep as a side effect of a read (that side-effect is also what masked the
    # real result behind the broad except below).
    connection = connect_readonly(state_db_path, timeout=INTERACTIVE_REBUILD_DB_TIMEOUT_SEC)
    table_names = {
      str(row[0] or '')
      for row in connection.execute("SELECT name FROM sqlite_master WHERE type='table'").fetchall()
    }
    table_columns: dict[str, set[str]] = {}
    for table_name in ('candidate_saved_set_members', 'candidate_saved_set_evaluations', 'pair_plans', 'pair_states'):
      if table_name in table_names:
        table_columns[table_name] = {
          str(row[1] or '')
          for row in connection.execute(f'PRAGMA table_info({table_name})').fetchall()
        }
      else:
        table_columns[table_name] = set()
    if {'candidate_saved_set_members', 'candidate_saved_set_evaluations'} <= table_names:
      saved_set_actionability_select = """
             (
               SELECT e.actionability_status
               FROM candidate_saved_set_members m
               JOIN candidate_saved_set_evaluations e ON e.saved_set_id = m.saved_set_id
               WHERE m.candidate_key = c.candidate_key
               ORDER BY e.id DESC
               LIMIT 1
             ) AS saved_set_actionability_status"""
      saved_set_visibility_select = """
             (
               SELECT e.visibility_status
               FROM candidate_saved_set_members m
               JOIN candidate_saved_set_evaluations e ON e.saved_set_id = m.saved_set_id
               WHERE m.candidate_key = c.candidate_key
               ORDER BY e.id DESC
               LIMIT 1
             ) AS saved_set_visibility_status"""
      saved_set_id_select = """
             (
               SELECT m.saved_set_id
               FROM candidate_saved_set_members m
               WHERE m.candidate_key = c.candidate_key
               ORDER BY m.id DESC
               LIMIT 1
             ) AS saved_set_id"""
    else:
      saved_set_actionability_select = "'' AS saved_set_actionability_status"
      saved_set_visibility_select = "'' AS saved_set_visibility_status"
      saved_set_id_select = "'' AS saved_set_id"
    pair_state_select = "'' AS pair_state"
    pair_state_detail_select = "'' AS pair_state_detail_json"
    pair_conditions: list[str] = []
    pair_join = ''
    if 'pair_states' in table_names:
      if 'pair_plans' in table_names and {'pair_id', 'ticker'} <= table_columns.get('pair_plans', set()):
        pair_join = 'LEFT JOIN pair_plans pp ON pp.pair_id = ps.pair_id'
        pair_conditions.append('pp.ticker = c.ticker')
      if 'detail_json' in table_columns.get('pair_states', set()):
        pair_conditions.append("json_extract(ps.detail_json, '$.ticker') = c.ticker")
      if pair_conditions:
        pair_state_select = f"""
             (
               SELECT ps.state
               FROM pair_states ps
               {pair_join}
               WHERE {' OR '.join(pair_conditions)}
               ORDER BY ps.id DESC
               LIMIT 1
             ) AS pair_state"""
        pair_state_detail_select = f"""
             (
               SELECT ps.detail_json
               FROM pair_states ps
               {pair_join}
               WHERE {' OR '.join(pair_conditions)}
               ORDER BY ps.id DESC
               LIMIT 1
             ) AS pair_state_detail_json"""
    cursor = connection.execute(
      f'''
      SELECT c.lifecycle_stage, c.terminal_cause, c.ticker, c.qualifier_tier,
             c.detail_json, c.candidate_uid, c.candidate_key,
              {saved_set_actionability_select},
              {saved_set_visibility_select},
              {saved_set_id_select},
              {pair_state_select},
              {pair_state_detail_select}
      FROM candidate_review_candidates c
      JOIN candidate_review_runs r ON r.run_id = c.run_id
      WHERE r.lane_session_id = ?
        AND c.lifecycle_stage IN ('discovered', 'in_flight', 'terminal')
        AND c.qualifier_tier != 'near_miss'
      ORDER BY
        (CASE WHEN c.lifecycle_stage = 'terminal'
                   AND c.terminal_cause IN ('expired_unfilled', 'auto_cancel')
              THEN 0 ELSE 1 END) ASC,
        c.rowid DESC
      ''',
      (lane_session_id,),
    )
    seen_tickers: set[str] = set()
    rows: list[dict] = []
    for raw in cursor.fetchall():
      ticker = str(raw[2] or '').strip()
      if ticker and ticker not in seen_tickers:
        seen_tickers.add(ticker)
        try:
          detail = json.loads(raw[4]) if raw[4] else {}
        except Exception:
          detail = {}
        rows.append({
          'lifecycle_stage': str(raw[0] or '').strip(),
          'terminal_cause':  str(raw[1] or '').strip(),
          'ticker':          ticker,
          'qualifier_tier':  str(raw[3] or '').strip(),
          'detail':          detail,
          'candidate_uid':   str(raw[5] or '').strip(),
          'candidate_key':   str(raw[6] or '').strip(),
          'saved_set_actionability_status': str(raw[7] or '').strip(),
          'saved_set_visibility_status': str(raw[8] or '').strip(),
          'saved_set_id': str(raw[9] or '').strip(),
          'pair_state': str(raw[10] or '').strip().upper(),
          'pair_state_detail': _safe_json_object(raw[11] or '{}'),
        })
    _LAST_CANONICAL_CANDIDATE_QUERY_STATUS.update({
      'ok': True,
      'reason': '',
      'elapsed_ms': round((time.monotonic() - query_t0) * 1000.0, 1),
    })
    return rows
  except Exception as exc:
    # Not silent: a real DB/schema problem must be visible (it would otherwise render as an empty
    # candidate surface on the live shell). Names-only; degrade to empty for read resilience.
    print(f'[WARN] Canonical candidate query failed; surfacing empty :: {type(exc).__name__}: {exc}')
    exc_text = str(exc).lower()
    reason = 'rebuild_db_read_busy' if 'locked' in exc_text or 'busy' in exc_text else 'canonical_candidate_query_failed'
    _LAST_CANONICAL_CANDIDATE_QUERY_STATUS.update({
      'ok': False,
      'reason': reason,
      'elapsed_ms': round((time.monotonic() - query_t0) * 1000.0, 1),
    })
    return []


def _fetch_stage_columns(payload: JSONDict) -> dict:
  try:
    review_selection = payload.get('review_selection') if isinstance(payload.get('review_selection'), dict) else {}
    scan_runtime_payload = payload.get('scan_runtime') if isinstance(payload.get('scan_runtime'), dict) else {}
    lane_session_id = str(
      review_selection.get('persisted_lane_session_id')
      or scan_runtime_payload.get('lane_session_id')
      or ''
    ).strip()
    settings = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    if str(settings.get('operation_lane') or '').strip().lower() == 'offline':
      return {'stage_columns': _STAGE_COLUMNS_EMPTY, 'in_flight_candidate_count': 0, 'total_stage_candidate_count': 0, 'active_stage_candidate_count': 0}
    if not lane_session_id:
      return {'stage_columns': _STAGE_COLUMNS_EMPTY, 'in_flight_candidate_count': 0, 'total_stage_candidate_count': 0, 'active_stage_candidate_count': 0}
    state_db_path = str(settings.get('state_db_path') or '').strip()
    if not state_db_path:
      return {'stage_columns': _STAGE_COLUMNS_EMPTY, 'in_flight_candidate_count': 0, 'total_stage_candidate_count': 0, 'active_stage_candidate_count': 0}
    rows = _query_canonical_candidates(lane_session_id, state_db_path)
    # Read-only: the execution-panel stage projection reads live pair states; it must not mutate or
    # rotate the operator DB as a render side effect.
    connection = connect_readonly(state_db_path)
    in_flight_tickers = [r['ticker'] for r in rows if r['lifecycle_stage'] == 'in_flight']
    live_pair_state_by_ticker: dict[str, str] = {}
    # Live-state enrichment is best-effort: if the pair-state lookup is unavailable, in_flight
    # candidates degrade to the queued column (visible) rather than blanking the entire panel.
    try:
      for _t in in_flight_tickers:
        _live_row = connection.execute(
          '''
          SELECT ps.state
          FROM pair_states ps
          JOIN pair_plans pp ON ps.pair_id = pp.pair_id
          WHERE pp.ticker = ?
          ORDER BY ps.id DESC LIMIT 1
          ''',
          (_t,),
        ).fetchone()
        if _live_row:
          live_pair_state_by_ticker[_t] = str(_live_row[0] or '').strip().upper()
    except Exception as exc:
      print(f'[WARN] Stage-column live-state enrichment unavailable; in_flight defaults to queued :: {type(exc).__name__}: {exc}')
    queued: list[dict] = []
    filled: list[dict] = []
    cancelled: list[dict] = []
    active_pair_backed_count = 0
    for row in rows:
      lifecycle_stage = row['lifecycle_stage']
      terminal_cause  = row['terminal_cause']
      ticker          = row['ticker']
      qualifier_tier  = row['qualifier_tier']
      candidate_key   = str(row.get('candidate_key') or row.get('candidate_uid') or '').strip()
      detail          = row['detail']
      live_state      = str(row.get('pair_state') or live_pair_state_by_ticker.get(ticker, '')).strip().upper()
      pair_detail     = row.get('pair_state_detail') if isinstance(row.get('pair_state_detail'), dict) else {}
      close_time = str(
        detail.get('close_time_utc') or detail.get('market_close_time_utc')
        or detail.get('close_time') or detail.get('closeTime') or ''
      ).strip()
      saved_set_actionability_status = str(row.get('saved_set_actionability_status') or '').strip().lower()
      saved_set_visibility_status = str(row.get('saved_set_visibility_status') or '').strip().lower()
      saved_set_retired = (
        saved_set_actionability_status in _SAVED_SET_RETIRED_ACTIONABILITY_STATUSES
        or saved_set_visibility_status == 'history_only'
      )
      item = {
        'ticker': ticker,
        'qualifier_tier': qualifier_tier,
        'close_time': close_time,
        'lifecycle_stage': lifecycle_stage,
        'candidate_uid': str(row.get('candidate_uid') or '').strip(),
        'saved_set_id': str(row.get('saved_set_id') or '').strip(),
        'saved_set_actionability_status': saved_set_actionability_status,
        'saved_set_visibility_status': saved_set_visibility_status,
        'pair_state': live_state,
        'pair_state_label': PAIR_STATE_PUBLIC_LABELS.get(live_state, ''),
        'pair_state_detail': pair_detail,
        'terminal_cause': '',
        'detail': detail,
      }
      if candidate_key:
        item['candidate_key'] = candidate_key
      if live_state and _pair_projection_is_fill_bearing(live_state, pair_detail):
        filled.append({**item, 'stage_id': 'filled', 'stage_label': 'Filled'})
        if not saved_set_retired:
          active_pair_backed_count += 1
      elif live_state in {'SETTLED', 'CANCELED', 'ERROR'}:
        cancelled.append({**item, 'stage_id': 'cancelled', 'stage_label': 'Cancelled', 'terminal_cause': _cancelled_projection_cause(live_state, terminal_cause, pair_detail)})
      elif saved_set_retired:
        # The candidate's own row is the authoritative reason when it already reached its own
        # terminal state (e.g. expired_unfilled) — a saved set can retire (visibility ->
        # history_only) for a member that expired on its own, which is not the same thing as
        # that member having been submitted. Only fall back to the saved-set's own actionability
        # status when the candidate row itself never reached a terminal cause.
        _retired_cause = terminal_cause if lifecycle_stage == 'terminal' and terminal_cause else (saved_set_actionability_status or 'submitted_terminal')
        cancelled.append({**item, 'stage_id': 'cancelled', 'stage_label': 'Cancelled', 'terminal_cause': _retired_cause})
      elif lifecycle_stage == 'discovered':
        queued.append({**item, 'stage_id': 'queued', 'stage_label': 'Queued'})
      elif lifecycle_stage == 'in_flight':
        queued.append({**item, 'stage_id': 'queued', 'stage_label': 'Queued'})
        if live_state:
          active_pair_backed_count += 1
      elif lifecycle_stage == 'terminal' and terminal_cause == 'reconciled':
        cancelled.append({**item, 'stage_id': 'cancelled', 'stage_label': 'Cancelled', 'terminal_cause': 'reconciled_no_fill'})
      elif lifecycle_stage == 'terminal':
        cancelled.append({**item, 'stage_id': 'cancelled', 'stage_label': 'Cancelled', 'terminal_cause': terminal_cause})
    stage_columns = [
      {'stage_id': 'queued',    'stage_label': 'Queued',    'items': queued},
      {'stage_id': 'filled',    'stage_label': 'Filled',    'items': filled},
      {'stage_id': 'cancelled', 'stage_label': 'Cancelled', 'items': cancelled},
    ]
    return {
      'stage_columns': stage_columns,
      'in_flight_candidate_count': len(queued),
      'total_stage_candidate_count': len(queued) + len(filled) + len(cancelled),
      # CP-B: surface-visibility gate must count only non-terminal candidates.
      # Cancelled candidates remain in the columns for audit, but they must not
      # keep the EXECUTION panel "IN FLIGHT" — otherwise an operator stop that
      # cancels every candidate (CP-L) leaves the panel open with a fully
      # cancelled set. queued + filled are the live, non-terminal stages
      # (a queued candidate is live even before it is pair-backed).
      'active_stage_candidate_count': len(queued) + len(filled),
    }
  except Exception as exc:
    # Not silent: surface a real DB/schema failure instead of rendering empty stage columns.
    print(f'[WARN] Stage-column projection failed; surfacing empty :: {type(exc).__name__}: {exc}')
    return {'stage_columns': _STAGE_COLUMNS_EMPTY, 'in_flight_candidate_count': 0, 'total_stage_candidate_count': 0, 'active_stage_candidate_count': 0}


def _halt_mark_lifecycle_candidates_terminal(
  lane_session_id: str,
  state_db_path: str,
) -> int:
  # On operator halt, mark every non-terminal lifecycle candidate for the lane
  # session as terminal/auto_cancel. This is the pre-bridge-submit cancellation
  # path — pair_states may be empty at halt time; the lifecycle rows are the
  # authoritative source for the EXECUTION panel queued count.
  if not lane_session_id or not state_db_path:
    return 0
  try:
    conn = open_database(state_db_path)
    ts = _utc_now_iso()
    with conn:
      cursor = conn.execute(
        "UPDATE candidate_review_candidates"
        " SET lifecycle_stage = 'terminal',"
        "     terminal_cause = 'auto_cancel',"
        "     terminal_at_utc = ?"
        " WHERE run_id IN ("
        "   SELECT run_id FROM candidate_review_runs WHERE lane_session_id = ?"
        " ) AND lifecycle_stage NOT IN ('terminal')",
        (ts, lane_session_id),
      )
      return cursor.rowcount
  except Exception as exc:
    # Not silent: a halt that cannot mark candidates terminal must be visible (operator stop
    # integrity). Names-only; return 0 so the teardown response still completes.
    print(f'[WARN] Halt mark-terminal failed; marked 0 :: {type(exc).__name__}: {exc}')
    return 0


def _run_operator_teardown(
  *,
  active_settings: Any,
  lane_session_id: str,
  env_override: str | None = None,
  subaccount_override: int | None = None,
) -> tuple[JSONDict | None, int]:
  # STOP-3 SA: the shared teardown core used by the STOP button, the browser close, and
  # every offline transition. Gated solely on cancel_on_pause (the caller decides it is a
  # teardown). Returns (cancel_all_pairs summary, halt-mark lifecycle count). When
  # cancel_on_pause is false (or settings unresolved) orders + candidates are left in
  # play — (None, 0). Each leg is wrapped so a hiccup cannot break the teardown response.
  cancel_summary: JSONDict | None = None
  lifecycle_cancelled = 0
  if active_settings is not None and bool(getattr(active_settings, 'cancel_on_pause', False)):
    try:
      cancel_summary = cancel_all_pairs(
        active_settings,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
    except Exception:
      cancel_summary = None
    _teardown_db = str(getattr(active_settings, 'state_db_path', None) or '').strip()
    lifecycle_cancelled = _halt_mark_lifecycle_candidates_terminal(
      str(lane_session_id or '').strip(), _teardown_db,
    )
  return cancel_summary, lifecycle_cancelled


def _build_pair_monitor_payload(payload: JSONDict) -> JSONDict:
  reconcile_payload = payload.get('reconcile') if isinstance(payload.get('reconcile'), dict) else None
  report_payload = payload.get('report') if isinstance(payload.get('report'), dict) else None
  # Lane 2 SSOT: candidate cards derive from the canonical DB query so every
  # surface agrees and cards carry lifecycle_stage (stage progression).
  # Fail closed: if the session or DB path is unresolvable, no ephemeral surrogate.
  _review_sel = payload.get('review_selection') if isinstance(payload.get('review_selection'), dict) else {}
  _scan_rt    = payload.get('scan_runtime')     if isinstance(payload.get('scan_runtime'), dict)     else {}
  _settings   = payload.get('settings')         if isinstance(payload.get('settings'), dict)         else {}
  _lane_session_id = str(
    _review_sel.get('persisted_lane_session_id')
    or _scan_rt.get('lane_session_id')
    or (report_payload or {}).get('lane_session_id')
    or ''
  ).strip()
  _state_db_path = str(_settings.get('state_db_path') or '').strip()
  if not _state_db_path:
    _state_db_path = str(os.environ.get('KALSHI_STATE_DB_PATH') or '').strip()
  if not _state_db_path:
    try:
      _state_db_path = str(getattr(_effective_shell_settings(None, None), 'state_db_path', '') or '').strip()
    except Exception:
      _state_db_path = ''
  if str(_settings.get('operation_lane') or '').strip().lower() == 'offline':
    _canonical_rows = []
  elif (
    str(_review_sel.get('state_id') or '').strip().lower() == 'review_hold_empty_selection'
    and str(_review_sel.get('saved_set_status') or '').strip().lower() == 'historical_only'
  ):
    # An EXPLICIT empty save (operator cleared the selection; prior set is historical
    # only) must not be resurrected by report/bootstrap projections re-reading the
    # canonical store. Bare review_hold_empty_selection without the historical marker
    # is the default resting state (e.g. fresh scan, nothing saved yet) and projects
    # normally.
    _canonical_rows = []
  else:
    _canonical_rows = _query_canonical_candidates(_lane_session_id, _state_db_path)
  candidate_rows = []
  for index, row in enumerate(_canonical_rows):
    if _candidate_row_saved_set_retired(row):
      continue
    candidate_uid = row['candidate_uid'] or _candidate_review_uid(row['detail'], index)
    candidate_key = row['candidate_key'] or row['candidate_uid'] or _candidate_review_uid(row['detail'], index)
    candidate_row = {
      **row['detail'],
      'ticker':          row['ticker'],
      'qualifier_tier':  row['qualifier_tier'],
      'lifecycle_stage': row['lifecycle_stage'],
      'candidate_uid':   candidate_uid,
      'candidate_key':   candidate_key,
    }
    if str(row['lifecycle_stage']).strip().lower() == 'terminal':
      candidate_row['review_row_origin'] = 'saved_prior_hidden_expired'
    candidate_rows.append(candidate_row)

  pair_rows: list[JSONDict] = []
  if reconcile_payload is not None:
    pair_rows = list(reconcile_payload.get('pairs', []))
  elif isinstance(payload.get('pairs'), list):
    pair_rows = list(payload.get('pairs', []))
  elif isinstance(payload.get('reconciled_pairs'), list):
    pair_rows = list(payload.get('reconciled_pairs', []))

  runtime_rows: list[JSONDict] = []
  if report_payload is not None:
    runtime_rows = list(report_payload.get('pair_runtime_summary', []))
  elif isinstance(payload.get('pair_runtime_summary'), list):
    runtime_rows = list(payload.get('pair_runtime_summary', []))
  if _lane_session_id:
    runtime_rows = [
      row for row in runtime_rows
      if not isinstance(row, dict)
      or not str(row.get('lane_session_id') or '').strip()
      or str(row.get('lane_session_id') or '').strip() == _lane_session_id
    ]

  pair_rows = _sort_pair_rows(pair_rows)

  pair_state_by_ticker = {
    str(p.get('ticker', '')).strip(): str(p.get('state', '')).lower()
    for p in pair_rows
    if p.get('ticker')
  }
  candidate_rows = [
    {**c, 'runtime_stage': pair_state_by_ticker.get(str(c.get('ticker', '')).strip(), '')}
    for c in candidate_rows
  ]

  attention_pairs = [
    pair for pair in pair_rows
    if str(pair.get('public_state_id') or pair.get('state') or '').strip().upper() not in PAIR_ACTIVE_PROJECTION_EXCLUDED_STATES
  ]
  state_counts: dict[str, int] = {}
  for pair in pair_rows:
    state_name = str(pair.get('state', 'UNKNOWN')).upper()
    state_counts[state_name] = state_counts.get(state_name, 0) + 1

  funds_posture = {}
  if report_payload is not None and isinstance(report_payload.get('funds_posture'), dict):
    funds_posture = dict(report_payload.get('funds_posture', {}))
  elif isinstance(payload.get('funds_posture'), dict):
    funds_posture = dict(payload.get('funds_posture', {}))

  connection_state = report_payload.get('connection_state') if report_payload is not None and isinstance(report_payload.get('connection_state'), dict) else {}
  latest_heartbeat = report_payload.get('latest_heartbeat') if report_payload is not None and isinstance(report_payload.get('latest_heartbeat'), dict) else {}

  sizing_overview = next(
    (
      {
        'pair_id': row.get('pair_id'),
        'dynamic_pair_notional_pct': row.get('dynamic_pair_notional_pct'),
        'effective_density': row.get('effective_density'),
        'binding_limiter': row.get('binding_limiter'),
        'dynamic_max_contracts': row.get('dynamic_max_contracts'),
        'contract_count': row.get('contract_count'),
      }
      for row in runtime_rows
      if row.get('dynamic_pair_notional_pct') not in {None, ''}
    ),
    None,
  )

  execution_chronology = payload.get('execution_chronology') if isinstance(payload.get('execution_chronology'), dict) else {}
  chronology_map = execution_chronology.get('chronology') if isinstance(execution_chronology.get('chronology'), dict) else {}
  event_packet = execution_chronology.get('event_packet') if isinstance(execution_chronology.get('event_packet'), list) else []
  chronology_order = ('submit', 'fill', 'reconcile', 'cancel')
  ordered_steps = [
    {
      'step_id': step_id,
      'as_of_time': str(step_payload.get('as_of_time') or ''),
      'seq': str(step_payload.get('seq') or ''),
      'ts_ms': int(step_payload.get('ts_ms') or 0),
      'event_type': str(step_payload.get('event_type') or ''),
      'execution_status': str(step_payload.get('execution_status') or ''),
      'market_ticker': str(step_payload.get('market_ticker') or ''),
      'order_id': str(step_payload.get('order_id') or ''),
      'client_order_id': str(step_payload.get('client_order_id') or ''),
      'trade_id': str(step_payload.get('trade_id') or ''),
      'outcome_side': str(step_payload.get('outcome_side') or ''),
      'book_side': str(step_payload.get('book_side') or ''),
      'user_data_timestamp': int(step_payload.get('user_data_timestamp') or 0),
      'use_yes_price': step_payload.get('use_yes_price'),
    }
    for step_id in chronology_order
    for step_payload in [chronology_map.get(step_id)]
    if isinstance(step_payload, dict)
  ]
  projected_event_packet = [
    {
      'event_type': str(step.get('event_type') or ''),
      'execution_status': str(step.get('execution_status') or ''),
      'profile': str(step.get('profile') or ''),
      'operation_lane': str(step.get('operation_lane') or ''),
      'lane_session_id': str(step.get('lane_session_id') or ''),
      'market_ticker': str(step.get('market_ticker') or ''),
      'market_id': step.get('market_id'),
      'order_id': str(step.get('order_id') or ''),
      'client_order_id': str(step.get('client_order_id') or ''),
      'trade_id': str(step.get('trade_id') or ''),
      'seq': str(step.get('seq') or ''),
      'ts_ms': int(step.get('ts_ms') or 0),
      'as_of_time': str(step.get('as_of_time') or ''),
      'user_data_timestamp': int(step.get('user_data_timestamp') or 0),
      'outcome_side': str(step.get('outcome_side') or ''),
      'book_side': str(step.get('book_side') or ''),
      'use_yes_price': step.get('use_yes_price'),
    }
    for step in event_packet
    if isinstance(step, dict)
  ]
  manual_execution = {
    'status': 'available' if bool(execution_chronology.get('enabled')) else 'unavailable',
    'profile': str(execution_chronology.get('profile') or ''),
    'terminal_state': str(execution_chronology.get('terminal_state') or ''),
    'sequence_count': int(execution_chronology.get('sequence_count') or 0),
    'contract_version': str(execution_chronology.get('contract_version') or ''),
    'required_event_fields': [
      str(field)
      for field in execution_chronology.get('required_event_fields', [])
      if isinstance(field, str)
    ],
    'ordered_steps': ordered_steps,
    'event_packet': projected_event_packet,
  }

  failure_class_rank = {
    'HARD_STOP': 0,
    'RETRYABLE': 1,
    'INFO': 2,
    '': 99,
  }
  interaction_rows = [row for row in runtime_rows if isinstance(row, dict)]
  active_runtime_rows = [
    row for row in interaction_rows
    if str(row.get('public_state_id') or row.get('state') or '').strip().upper() not in {''} | PAIR_ACTIVE_PROJECTION_EXCLUDED_STATES
  ]
  unresolved_runtime_rows = [
    row for row in active_runtime_rows
    if str(row.get('failure_class') or '').strip().upper() in {'HARD_STOP', 'RETRYABLE'}
    or str(row.get('mobility_overlay_state') or '').strip().upper() not in {'', 'AUTO_CANCEL_IDLE'}
    or str(row.get('public_state_id') or '').strip().upper() in {'RECONCILE_REQUIRED', 'RESTING_ONE_SIDE', 'PARTIAL_ONE_SIDE', 'PARTIAL_BOTH', 'ASYMMETRIC_EXPOSURE', 'REPAIR_LIVE', 'EXPOSURE_CAPPED', 'SUBMIT_FAILED_RETRYABLE', 'SUBMIT_FAILED_TERMINAL'}
  ]
  highest_priority_row = next(
    iter(
      sorted(
        active_runtime_rows or interaction_rows,
        key=lambda row: (
          failure_class_rank.get(str(row.get('failure_class') or '').strip().upper(), 50),
          0 if str(row.get('mobility_overlay_state') or '').strip().upper() not in {'', 'AUTO_CANCEL_IDLE'} else 1,
          0 if str(row.get('public_state_id') or '').strip().upper() == 'RECONCILE_REQUIRED' else 1,
          str(row.get('pair_id') or ''),
        ),
      )
    ),
    None,
  )
  highest_priority_condition = (
    str((highest_priority_row or {}).get('mobility_overlay_state') or '').strip()
    or str((highest_priority_row or {}).get('public_state_id') or (highest_priority_row or {}).get('state') or '').strip()
    or 'IDLE'
  )
  highest_priority_failure_class = str((highest_priority_row or {}).get('failure_class') or '').strip() or 'NONE'
  highest_priority_failure_scope = str((highest_priority_row or {}).get('failure_scope') or '').strip() or 'none'
  allowed_actions = [
    str(action).strip().upper()
    for action in ((highest_priority_row or {}).get('allowed_actions') or [])
    if str(action).strip()
  ]
  manual_interaction_count = 1 if manual_execution['status'] == 'available' else 0
  automation_interaction_count = 1 if str(payload.get('shell_action') or '').strip().lower() == 'automation' else 0
  in_flight_candidate_count = int(payload.get('_in_flight_candidate_count') or 0)
  _settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
  if str(_settings_payload.get('operation_lane') or '').strip().lower() == 'offline':
    in_flight_candidate_count = 0
  total_stage_candidate_count = int(payload.get('_total_stage_candidate_count') or 0)
  # CP-B: the surface-visibility gate counts only non-terminal stage candidates
  # (queued + filled). Cancelled candidates stay in the columns for audit but
  # must not keep the EXECUTION panel open — once an operator stop cancels every
  # candidate (CP-L), the panel collapses to IDLE. Falls back to the total count
  # for payloads produced before this field was populated.
  active_stage_candidate_count = int(
    payload.get('_active_stage_candidate_count', total_stage_candidate_count) or 0
  )
  active_interaction_count = max(len(active_runtime_rows), in_flight_candidate_count)
  _surface_active_count = max(len(active_runtime_rows), active_stage_candidate_count)
  unresolved_interaction_count = max(len(unresolved_runtime_rows), len(attention_pairs))
  funds_refresh_status = str(funds_posture.get('funds_refresh_status') or 'unknown').strip() or 'unknown'
  funds_refresh_as_of = str(funds_posture.get('available_funds_as_of') or '').strip()
  stale_blocks_submit = bool(funds_posture.get('stale_blocks_submit'))
  if stale_blocks_submit:
    policy_posture = 'submit_blocked_stale_funds'
  elif highest_priority_condition == 'AUTO_CANCEL_RECONCILE_REQUIRED':
    policy_posture = 'reconcile_required'
  elif active_interaction_count > 0:
    policy_posture = 'active_monitoring'
  else:
    policy_posture = 'idle_monitoring'
  if manual_interaction_count > 0 and automation_interaction_count > 0:
    executor_posture = 'shared_manual_and_automation'
  elif manual_interaction_count > 0:
    executor_posture = 'manual_execution'
  elif automation_interaction_count > 0:
    executor_posture = 'automation_execution'
  else:
    executor_posture = 'runtime_summary_only'
  if unresolved_interaction_count > 0:
    activity_status = 'unresolved_attention'
  elif active_interaction_count > 0:
    activity_status = 'active'
  else:
    activity_status = 'idle'
  if highest_priority_row is not None:
    current_stage_summary = ' :: '.join(
      part for part in (
        str(highest_priority_row.get('pair_id') or highest_priority_row.get('ticker') or '').strip(),
        str(highest_priority_row.get('public_state_id') or highest_priority_row.get('state') or '').strip(),
        str(highest_priority_row.get('mobility_overlay_state') or '').strip(),
      )
      if part
    ) or 'Runtime attention is present.'
  elif manual_execution['status'] == 'available':
    current_stage_summary = ' :: '.join(
      part for part in (
        str(manual_execution.get('profile') or '').strip(),
        str(manual_execution.get('terminal_state') or '').strip(),
      )
      if part
    ) or 'Manual interaction chronology is available.'
  else:
    current_stage_summary = 'No active or unresolved live interaction is currently projected.'
  next_backend_action_summary = ' / '.join(allowed_actions[:2]) if allowed_actions else str(
    payload.get('next_action')
    or (report_payload or {}).get('next_action')
    or 'Observe runtime state.'
  )
  latest_authoritative_handshake_summary = ' :: '.join(
    part for part in (
      f"connection={str(connection_state.get('status') or 'unknown').strip() or 'unknown'}",
      f"heartbeat={str(latest_heartbeat.get('status') or 'unavailable').strip() or 'unavailable'}",
    ) if part
  )
  workflow = payload.get('workflow') if isinstance(payload.get('workflow'), dict) else {}
  scheduler_snapshot = payload.get('scheduler_snapshot') if isinstance(payload.get('scheduler_snapshot'), dict) else {}
  halt_projection = scheduler_snapshot.get('halt_projection') if isinstance(scheduler_snapshot.get('halt_projection'), dict) else {}
  scheduler_owner_normalized = str(scheduler_snapshot.get('owner') or '').strip().lower()
  scheduler_submit_state_normalized = str(scheduler_snapshot.get('submit_state') or '').strip().lower()
  scheduler_inflight_active = bool(
    scheduler_owner_normalized in {'submit_bridge', 'scan', 'cancel'}
    or scheduler_submit_state_normalized == 'submitting'
  )
  submit_failure_halt = (
    bool(halt_projection.get('active'))
    and str(halt_projection.get('kind') or '').strip().lower() == 'submit_failed_halted'
  )
  scan_shape_summary = payload.get('scan_shape_summary') if isinstance(payload.get('scan_shape_summary'), dict) else {}
  scan_shape_operator_summary = (
    str(halt_projection.get('scan_shape_operator_summary') or '').strip()
    or _scan_shape_operator_summary_line(scan_shape_summary, int(payload.get('candidate_count') or 0) if payload.get('candidate_count') is not None else None)
  )
  operator_handoff_target = str(
    workflow.get('next_actionable_step')
    or workflow.get('recommended_step')
    or payload.get('shell_action')
    or 'report'
  ).strip() or 'report'
  interaction_hold_visible = _payload_has_live_interaction_hold(payload)
  normalized_reason = _normalize_reason_token(payload.get('reason', ''))
  suppress_live_interaction_surface = bool(
    str(payload.get('decision') or '').strip().lower() == 'no-go'
    and str(payload.get('shell_action') or '').strip().lower() == 'change_mode'
    and normalized_reason in {
      'credential_acceptance_failed',
      'credential_acceptance_timeout',
      'credential_environment_mismatch',
      'websocket_connection_failed',
      'websocket_service_unavailable',
      'mode_change_preconditions_failed',
    }
  )
  surface_visible = bool(
    not suppress_live_interaction_surface
    and (_surface_active_count > 0 or unresolved_interaction_count > 0 or interaction_hold_visible or submit_failure_halt or scheduler_inflight_active)
  )
  if not surface_visible and not suppress_live_interaction_surface:
    # Clean resting posture: the EXECUTION surface is a pair-level handoff, not the
    # global next-step recommender (that lives in workflow.recommended_step). With
    # nothing in flight and nothing unresolved there is nothing to hand off — '-'.
    # A mode-change-failure boundary keeps the workflow step as the handoff target.
    operator_handoff_target = '-'
  if submit_failure_halt:
    surface_status_label = 'SUBMIT FAILED'
    surface_status_tone = 'no-go'
    headline = 'Submit failed before order placement.'
    _phase = str(halt_projection.get('failure_phase') or 'submit_dispatch').strip()
    _reason = str(halt_projection.get('reason') or 'submit_bridge_service_failed').strip()
    detail = f'{_phase}: {_reason}'
  elif unresolved_interaction_count > 0:
    surface_status_label = 'ATTENTION' if highest_priority_failure_class == 'HARD_STOP' else 'WATCH'
    surface_status_tone = 'no-go' if highest_priority_failure_class == 'HARD_STOP' else 'warn'
    headline = 'Live interaction requires attention.'
    detail = 'Backend is holding on grouped runtime truth while one or more interactions remain unresolved. Refresh only if the shell looks stale.'
  elif surface_visible:
    surface_status_label = 'IN FLIGHT'
    surface_status_tone = 'ok'
    if manual_execution['status'] == 'available' and highest_priority_row is None:
      headline = 'Live interaction summary is available.'
      detail = 'Backend is holding on the grouped manual execution summary while current interaction truth remains in view. Refresh only if the shell looks stale.'
    elif interaction_hold_visible and highest_priority_row is None:
      headline = 'Live interaction summary remains in view.'
      detail = 'Backend is holding on the grouped interaction summary long enough for the current lane truth to remain visible. Refresh only if the shell looks stale.'
    else:
      headline = 'Live interaction is active.'
      detail = 'Backend is holding on grouped runtime truth while current interaction activity remains in flight. Refresh only if the shell looks stale.'
  else:
    surface_status_label = 'IDLE'
    surface_status_tone = 'ok'
    headline = 'No live interaction is currently active.'
    detail = (
      'Mode-change failure is owning the current shell boundary, so the transient live interaction surface stays collapsed.'
      if suppress_live_interaction_surface
      else 'The lane is in clean resting posture, so the transient live interaction surface stays collapsed.'
    )

  _stage_cols = payload.get('_stage_columns') or _STAGE_COLUMNS_EMPTY
  _stage_by_id = {col['stage_id']: col for col in _stage_cols if isinstance(col, dict)}
  _queued_count = len((_stage_by_id.get('queued') or {}).get('items') or [])
  _filled_count = len((_stage_by_id.get('filled') or {}).get('items') or [])
  _cancelled_count = len((_stage_by_id.get('cancelled') or {}).get('items') or [])
  summary_cards = [
    {'label': 'Policy', 'value': f'{activity_status} :: {policy_posture}'},
    {'label': 'Executor', 'value': executor_posture},
    {'label': 'Counts', 'value': f'active={active_interaction_count} :: unresolved={unresolved_interaction_count} :: queued={_queued_count} :: filled={_filled_count} :: cancelled={_cancelled_count}'},
    {'label': 'Funds', 'value': f'{funds_refresh_status} :: as_of={funds_refresh_as_of or "--"}'},
    {'label': 'Handshake', 'value': latest_authoritative_handshake_summary},
    {'label': 'Handoff', 'value': operator_handoff_target},
  ]
  observed = [
    entry for entry in (
      scan_shape_operator_summary,
      f"Submit handoff: {halt_projection.get('handoff_id')}" if submit_failure_halt and halt_projection.get('handoff_id') else '',
      f'Priority: {highest_priority_condition} :: {highest_priority_failure_class} :: {highest_priority_failure_scope}'
      if highest_priority_condition != 'IDLE' or highest_priority_failure_class != 'NONE'
      else '',
      f'Stage: {current_stage_summary}' if current_stage_summary else '',
      f'Backend next: {next_backend_action_summary}' if next_backend_action_summary else '',
    )
    if entry
  ]
  live_interaction = {
    'title': 'EXECUTION',
    'contract_version': 'live_interaction_summary.v1',
    'policy_posture': policy_posture,
    'policy_state': policy_posture,
    'executor_posture': executor_posture,
    'executor_state': executor_posture,
    'activity_status': activity_status,
    'surface_family': 'transient_runtime_card',
    'surface_visible': surface_visible,
    'materialization_state': 'visible' if surface_visible else 'hidden',
    'materialization_reason': (
      'active_or_unresolved_interaction'
      if surface_visible
      and not scheduler_inflight_active
      else 'boundary_owns_mode_change_failure'
      if suppress_live_interaction_surface
      else 'scheduler_owner_active'
      if scheduler_inflight_active
      else 'clean_resting_posture'
    ),
    'surface_status_label': surface_status_label,
    'surface_status_tone': surface_status_tone,
    'headline': headline,
    'detail': detail,
    'active_interaction_count': active_interaction_count,
    'unresolved_interaction_count': unresolved_interaction_count,
    'highest_priority_condition': highest_priority_condition,
    'highest_priority_failure_class': highest_priority_failure_class,
    'highest_priority_failure_scope': highest_priority_failure_scope,
    'current_stage_summary': current_stage_summary,
    'next_backend_action_summary': next_backend_action_summary,
    'manual_interaction_count': manual_interaction_count,
    'automation_interaction_count': automation_interaction_count,
    'in_flight_candidate_count': in_flight_candidate_count,
    'stage_columns': payload.get('_stage_columns') or _STAGE_COLUMNS_EMPTY,
    'funds_refresh_status': funds_refresh_status,
    'funds_refresh_as_of': funds_refresh_as_of,
    'last_update_at': funds_refresh_as_of,
    'latest_authoritative_handshake_summary': latest_authoritative_handshake_summary,
    'operator_handoff_target': operator_handoff_target,
    'summary_cards': summary_cards,
    'observed': observed,
    'summary_rows': [
      {'label': 'Status', 'value': f'{activity_status} :: {policy_posture}'},
      {'label': 'Counts', 'value': f'active={active_interaction_count} :: unresolved={unresolved_interaction_count} :: queued={_queued_count} :: filled={_filled_count} :: cancelled={_cancelled_count}'},
      {'label': 'Priority', 'value': f'{highest_priority_condition} :: {highest_priority_failure_class} :: {highest_priority_failure_scope}'},
      {'label': 'Stage', 'value': current_stage_summary},
      {'label': 'Backend next', 'value': next_backend_action_summary},
      {'label': 'Funds', 'value': f'{funds_refresh_status} :: as_of={funds_refresh_as_of or "--"}'},
      {'label': 'Handshake', 'value': latest_authoritative_handshake_summary},
      {'label': 'Handoff', 'value': operator_handoff_target},
    ],
  }
  scan_diagnostics = _build_scan_diagnostics_payload(scan_shape_summary)

  return {
    'pair_count': int(reconcile_payload.get('pair_count', len(pair_rows))) if reconcile_payload is not None else len(pair_rows),
    'candidate_count': len(candidate_rows),
    'candidate_rows': sorted(
      candidate_rows,
      key=lambda candidate: (
        int(candidate.get('rank', 9999) or 9999),
        str(candidate.get('ticker', '')),
      ),
    ),
    'attention_count': len(attention_pairs),
    'attention_pairs': attention_pairs,
    'pairs': pair_rows,
    'state_counts': state_counts,
    'priority_order': list(PAIR_STATE_PRIORITY.keys()),
    'runtime_summary': runtime_rows,
    'sizing_overview': sizing_overview,
    'scan_shape_summary': dict(scan_shape_summary),
    'scan_diagnostics': scan_diagnostics,
    'manual_execution': manual_execution,
    'live_interaction': live_interaction,
    'next_action': (
      (reconcile_payload or report_payload or payload).get('next_action')
      if isinstance(reconcile_payload or report_payload or payload, dict)
      else 'Review pair state before continuing.'
    ),
  }


def _build_evidence_browser_payload(payload: JSONDict) -> JSONDict:
  diagnostics_context = payload.get('diagnostics_governance_context') if isinstance(payload.get('diagnostics_governance_context'), dict) else {}
  diagnostics_summary = diagnostics_context.get('validation_summary') if isinstance(diagnostics_context.get('validation_summary'), dict) else {}
  validation_workflow = diagnostics_summary
  latest_runs = list(validation_workflow.get('latest_runs', []))
  latest_accepted = validation_workflow.get('latest_accepted_run') if isinstance(validation_workflow.get('latest_accepted_run'), dict) else next(
    (run for run in latest_runs if str(run.get('result', '')).lower() in {'pass', 'passed'}),
    None,
  )
  latest_failed = validation_workflow.get('latest_failed_run') if isinstance(validation_workflow.get('latest_failed_run'), dict) else next(
    (run for run in latest_runs if str(run.get('result', '')).lower() in {'fail', 'failed'}),
    None,
  )
  historical_failed_runs = list(validation_workflow.get('historical_failed_runs', [])) or [
    run for run in latest_runs
    if str(run.get('result', '')).lower() in {'fail', 'failed'}
  ]
  pass_count = int(validation_workflow.get('pass_count', sum(1 for run in latest_runs if str(run.get('result', '')).lower() in {'pass', 'passed'})))
  failed_count = int(validation_workflow.get('failed_count', len(historical_failed_runs)))
  aggregate_available = bool(validation_workflow.get('project_aggregate_available'))

  if latest_accepted is not None and latest_failed is not None:
    interpretation = 'Current state follows the latest accepted retained run. Earlier failed runs remain visible for review.'
  elif latest_accepted is not None:
    interpretation = 'The latest accepted retained run is the current evidence anchor for this shell view.'
  else:
    interpretation = 'No active post-rename retained runs are present yet, so this shell should treat evidence regeneration as the next control obligation.'

  return {
    'status': 'ready' if latest_accepted is not None else 'missing-active-evidence',
    'active_run_count': int(validation_workflow.get('active_run_count', len(latest_runs))),
    'pass_count': pass_count,
    'failed_count': failed_count,
    'default_lanes': list(validation_workflow.get('default_lanes', [])),
    'latest_accepted_run': latest_accepted,
    'latest_failed_run': latest_failed,
    'historical_failed_runs': historical_failed_runs,
    'project_aggregate_available': aggregate_available,
    'project_aggregate_path': validation_workflow.get('project_aggregate_path'),
    'interpretation': interpretation,
    'accepted_state_summary': (
      'Current state is anchored to the latest accepted retained run.'
      if latest_accepted is not None
      else 'No active retained run is available yet, so current state cannot claim accepted evidence.'
    ),
    'latest_runs': latest_runs,
  }


@dataclass(frozen=True)
class TransitionKey:
  prev_state_id: str
  action_name: str
  outcome: str
  resting_state_id: str


@dataclass(frozen=True)
class ViewContractRecord:
  recommended_step: str
  headline: str
  operator_message: str
  step_kind: str
  can_run_next_step: bool
  next_actionable_step: str
  focus_target: str
  focus_tone: str
  deck_view: str
  button_emphasis_tone: str
  auto_sequence: tuple[str, ...]
  boundary_reason: str | None
  boundary_message: str | None
  boundary_next_action: str | None
  rule_id: str
  contract_version: str


@dataclass(frozen=True)
class SignedContractEnvelope:
  schema_version: str
  transition_key: TransitionKey
  contract_record: ViewContractRecord
  contract_hash_sha256: str
  signature_alg: str
  signature_b64: str
  signer_key_id: str
  issued_at_utc: str
  expires_at_utc: str
  nonce: str
  policy_scope_id: str
  policy_snapshot_sha256: str


@dataclass(frozen=True)
class SignatureVerificationResult:
  valid: bool
  failure_code: str | None
  signer_key_id: str | None
  verified_at_utc: str


