  def _analysis_recalculation_payload() -> JSONDict:
    active_result = analysis_recalculation_state.get('active_result')
    pending_result = analysis_recalculation_state.get('pending_result')
    last_result = analysis_recalculation_state.get('last_result')
    return {
      'always_visible': True,
      'request_label': 'Recalculate analysis',
      'request_short_label': 'Recalc',
      'presentation': 'compact_icon_short_label_chip',
      'active_result': dict(active_result) if isinstance(active_result, dict) else None,
      'pending_result': dict(pending_result) if isinstance(pending_result, dict) else None,
      'last_result': dict(last_result) if isinstance(last_result, dict) else None,
    }

  def _record_analysis_recalculation_action(
    action_name: str,
    settings: Any,
    *,
    detail: JSONDict,
  ) -> None:
    try:
      connection = open_database(getattr(settings, 'state_db_path'))
      persist_operator_action(
        connection,
        action=action_name,
        recorded_at_utc=_utc_now_iso(),
        operation_lane=str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox'),
        lane_session_id=str(detail.get('lane_session_id') or ''),
        detail=detail,
      )
    except Exception:
      pass

  def _websocket_runtime_utc_now() -> str:
    return time.strftime('%Y-%m-%dT%H:%M:%SZ', time.gmtime())

  def _set_websocket_runtime_state(**updates: Any) -> None:
    with websocket_runtime_lock:
      websocket_runtime_state.update(updates)

  def _websocket_runtime_snapshot() -> JSONDict:
    with websocket_runtime_lock:
      snapshot = dict(websocket_runtime_state)
      last_heartbeat = snapshot.get('last_heartbeat')
      if isinstance(last_heartbeat, dict):
        snapshot['last_heartbeat'] = dict(last_heartbeat)
    # W1: a first-boot connect that is still 'connecting' (not yet connected) past the
    # grace surfaces connecting_slow so the deck shows a "slow connect / retry" affordance
    # while the connect/reconnect keeps trying. Only meaningful for the unconnected
    # 'connecting' state; never for a live session.
    snapshot['connecting_slow'] = False
    if str(snapshot.get('status') or '') == 'connecting' and not bool(snapshot.get('websocket_connected')):
      _connecting_since = snapshot.get('connecting_since')
      if _connecting_since:
        try:
          _cs_dt = datetime.fromisoformat(str(_connecting_since).replace('Z', '+00:00'))
          if _cs_dt.tzinfo is None:
            _cs_dt = _cs_dt.replace(tzinfo=timezone.utc)
          _elapsed = (datetime.now(timezone.utc) - _cs_dt).total_seconds()
          snapshot['connecting_slow'] = _elapsed > WS_CONNECTING_SLOW_GRACE_SEC
        except Exception:
          snapshot['connecting_slow'] = False
    return snapshot

  def _persist_websocket_runtime_heartbeat(
    settings: Any,
    *,
    lane_session_id: str,
    status: str,
    websocket_connected: bool,
    message_count: int = 0,
    funds_detail: JSONDict | None = None,
  ) -> JSONDict:
    heartbeat_payload = {
      'component': 'websocket-session',
      'status': status,
      'operation_lane': str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox'),
      'lane_session_id': lane_session_id,
      'recorded_at_utc': _websocket_runtime_utc_now(),
      'active_websocket_url_tail': _websocket_label(getattr(settings, 'active_websocket_url', None)),
      'websocket_connected': bool(websocket_connected),
      'message_count': int(message_count),
    }
    _detail: JSONDict = {
      'active_websocket_url_tail': heartbeat_payload['active_websocket_url_tail'],
      'websocket_connected': heartbeat_payload['websocket_connected'],
      'message_count': heartbeat_payload['message_count'],
    }
    # Funds ride on the websocket heartbeat: as long as the socket is connected
    # and beating, each beat carries the live balance. funds_detail is None when
    # the balance fetch was skipped or failed (fail-closed); the banner's own
    # staleness grace then governs how the figure is displayed.
    if isinstance(funds_detail, dict) and funds_detail.get('available_funds_snapshot') is not None:
      _detail.update(funds_detail)
      heartbeat_payload.update(funds_detail)
    try:
      connection = open_database(getattr(settings, 'state_db_path'))
      persist_service_heartbeat(
        connection,
        component='websocket-session',
        status=status,
        recorded_at_utc=str(heartbeat_payload['recorded_at_utc']),
        operation_lane=str(heartbeat_payload['operation_lane']),
        lane_session_id=lane_session_id,
        detail=_detail,
      )
    except Exception:
      pass
    _set_websocket_runtime_state(last_heartbeat=heartbeat_payload)
    return heartbeat_payload

  def _persist_websocket_runtime_event(
    settings: Any,
    *,
    lane_session_id: str,
    level: str,
    event_type: str,
    detail: JSONDict,
  ) -> None:
    try:
      connection = open_database(getattr(settings, 'state_db_path'))
      persist_runtime_event(
        connection,
        level=level,
        event_type=event_type,
        recorded_at_utc=_websocket_runtime_utc_now(),
        operation_lane=str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox'),
        lane_session_id=lane_session_id,
        detail=detail,
      )
    except Exception:
      pass

  def _websocket_runtime_projection(active_lane: str | None, *, mode_selected: bool) -> JSONDict | None:
    snapshot = _websocket_runtime_snapshot()
    projected_lane = str(active_lane or '').strip().lower()
    if not mode_selected or projected_lane not in {'sandbox', 'live'}:
      return None
    if str(snapshot.get('operation_lane') or '').strip().lower() != projected_lane:
      return None
    return snapshot

  def _apply_websocket_runtime_projection(
    payload: JSONDict,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> None:
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    report_payload = payload.get('report') if isinstance(payload.get('report'), dict) else None
    effective_settings = _active_settings(env_override, subaccount_override)
    active_lane = str(
      getattr(effective_settings, 'operation_lane', None)
      or settings_payload.get('operation_lane')
      or context_overlay_state.get('operation_lane')
      or 'offline'
    ).strip().lower()
    runtime_snapshot = _websocket_runtime_projection(
      active_lane,
      mode_selected=_resolved_connection_posture_mode_selected(payload),
    )
    if runtime_snapshot is None:
      return
    if report_payload is None:
      report_payload = {}
      payload['report'] = report_payload
    report_payload['connection_state'] = {
      'status': str(runtime_snapshot.get('status') or 'waiting'),
      'websocket_connected': bool(runtime_snapshot.get('websocket_connected')),
    }
    if runtime_snapshot.get('lane_session_id'):
      report_payload['lane_session_id'] = str(runtime_snapshot['lane_session_id'])
    if runtime_snapshot.get('active_websocket_url_tail'):
      report_payload['active_websocket_url_tail'] = str(runtime_snapshot['active_websocket_url_tail'])
    last_heartbeat = runtime_snapshot.get('last_heartbeat')
    if isinstance(last_heartbeat, dict):
      report_payload['latest_heartbeat'] = dict(last_heartbeat)

  def _stop_websocket_runtime(*, reason: str = 'stopped') -> None:
    nonlocal websocket_runtime_thread, websocket_runtime_stop_event, websocket_runtime_ready_event
    stop_event = websocket_runtime_stop_event
    runtime_thread = websocket_runtime_thread
    if stop_event is not None:
      stop_event.set()
    if runtime_thread is not None and runtime_thread.is_alive() and threading.current_thread() is not runtime_thread:
      runtime_thread.join(timeout=2.0)
    websocket_runtime_thread = None
    websocket_runtime_stop_event = None
    websocket_runtime_ready_event = None
    _set_websocket_runtime_state(
      status='waiting',
      websocket_connected=False,
      reason_code=reason,
      message='Authenticated websocket session is not currently active.',
      config_fingerprint=None,
    )

  def _scan_runtime_utc_now() -> str:
    return datetime.now(timezone.utc).isoformat(timespec='milliseconds').replace('+00:00', 'Z')

  def _persist_operator_shell_route_failure(
    route_path: str,
    action_name: str,
    exc: Exception,
    *,
    settings_override: Any | None,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> None:
    settings_candidate = settings_override
    if settings_candidate is None:
      try:
        settings_candidate = _effective_shell_settings(env_override, subaccount_override)
      except Exception:
        settings_candidate = None
    if settings_candidate is None:
      try:
        settings_candidate = _resolve_settings(
          None,
          env_override=env_override,
          subaccount_override=subaccount_override,
        )
      except Exception:
        settings_candidate = None
    state_db_path = str(getattr(settings_candidate, 'state_db_path', '') or '').strip()
    if not state_db_path:
      return
    detail = _route_failure_detail(
      route_path,
      action_name,
      exc,
      scan_snapshot=_scan_runtime_snapshot(),
      websocket_snapshot=_websocket_runtime_snapshot(),
    )
    try:
      connection = open_database(state_db_path)
      persist_runtime_event(
        connection,
        level='WARN',
        event_type='operator_shell_route_failed',
        recorded_at_utc=_scan_runtime_utc_now(),
        operation_lane=str(getattr(settings_candidate, 'operation_lane', 'sandbox') or 'sandbox'),
        lane_session_id=str(detail.get('lane_session_id') or ''),
        detail=detail,
      )
    except Exception:
      pass

  def _build_route_failure_payload(
    action_name: str,
    route_path: str,
    exc: Exception,
    *,
    env_override: str | None,
    subaccount_override: int | None,
    settings_override: Any | None,
  ) -> JSONDict:
    _persist_operator_shell_route_failure(
      route_path,
      action_name,
      exc,
      settings_override=settings_override,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    payload = _action_failure_payload(action_name, exc)
    payload['route_failure'] = _route_failure_detail(
      route_path,
      action_name,
      exc,
      scan_snapshot=_scan_runtime_snapshot(),
      websocket_snapshot=_websocket_runtime_snapshot(),
    )
    try:
      if 'settings' not in payload:
        with _private_key_file_env_overlay(str(key_management_state.get('overlay_key_path') or ''), lock=overlay_lock):
          payload['settings'] = _load_shell_settings_context(
            env_override=env_override,
            subaccount_override=subaccount_override,
            settings_override=settings_override,
          )[0]
      if isinstance(payload.get('settings'), dict):
        payload['credential_posture'] = _build_credential_posture_payload(payload['settings'])
      _attach_connection_posture(
        payload,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      payload['workflow'] = _follow_on_workflow(action_name, payload)
      merged_payload = _merge_preserved_review_hold_payload(action_name, payload)
      merged_payload = _merge_saved_candidate_rows_for_processing_scan(merged_payload)
      payload = _augment_shell_payload(
        action_name,
        merged_payload,
        env_override=env_override,
        subaccount_override=subaccount_override,
        runtime_overlay=runtime_overlay_state,
        working_default_values=_runtime_working_default_values(
          env_override=env_override,
          subaccount_override=subaccount_override,
        ),
        working_default_state=runtime_working_default_state,
        working_default_sources=runtime_working_default_sources,
        analysis_recalculation=_analysis_recalculation_payload(),
        durable_overlay=context_overlay_state,
        durable_funds_cache=_header_funds_cache,
        operator_review_session_id=str(review_selection_state.get('persisted_lane_session_id') or '').strip() or None,
      )
      payload['key_management'] = _key_management_payload(payload)
      payload['data_management'] = _data_management_payload(payload)
      payload['session_overlay'] = _session_overlay_payload(
        payload,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      payload['connection_posture'] = _build_connection_posture_payload(
        payload,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      _apply_scan_runtime_payload(action_name, payload)
      _apply_review_selection_projection(payload)
      _review_projection = payload.get('review_selection') if isinstance(payload.get('review_selection'), dict) else {}
      if _review_projection:
        _review_projection['saved_set_id'] = str(review_selection_state.get('saved_set_id') or '')
        _review_projection['candidate_signature'] = str(
          _review_projection.get('candidate_signature')
          or review_selection_state.get('candidate_signature')
          or ''
        )
        _consumed_submit_terminal = (
          dict(review_selection_state.get('consumed_submit_terminal'))
          if isinstance(review_selection_state.get('consumed_submit_terminal'), dict)
          else None
        )
        _review_projection['consumed_submit_terminal'] = _consumed_submit_terminal
        _review_projection['failed_submit_attempt'] = (
          dict(review_selection_state.get('failed_submit_attempt'))
          if isinstance(review_selection_state.get('failed_submit_attempt'), dict)
          else None
        )
        if _consumed_submit_terminal:
          _current_saved_set_id = str(_review_projection.get('saved_set_id') or '').strip()
          _current_candidate_signature = str(_review_projection.get('candidate_signature') or '').strip()
          if (
            _current_saved_set_id
            and _current_candidate_signature
            and str(_consumed_submit_terminal.get('consumed_saved_set_id') or '').strip() == _current_saved_set_id
            and str(_consumed_submit_terminal.get('consumed_candidate_signature') or '').strip() == _current_candidate_signature
          ):
            _review_projection['submit_ready'] = False
            _review_projection['saved_set_status'] = 'submitted_terminal'
            _review_projection['saved_set_status_reason'] = (
              str(review_selection_state.get('saved_set_status_reason') or '')
              or 'Saved set was submitted and retired from current automation routing.'
            )
      _apply_orchestrator_highlight_envelope(action_name, payload)
      return payload
    except Exception:
      try:
        _apply_scan_runtime_payload(action_name, payload)
      except Exception:
        pass
      return payload

  def _set_scan_runtime_state(**updates: Any) -> None:
    with scan_runtime_lock:
      scan_runtime_state.update(updates)

  def _parse_runtime_timestamp(value: Any) -> datetime | None:
    raw = str(value or '').strip()
    if not raw:
      return None
    try:
      parsed = datetime.fromisoformat(raw.replace('Z', '+00:00'))
    except ValueError:
      return None
    if parsed.tzinfo is None:
      parsed = parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)

  def _scan_timeout_failure_payload(stage: str, reason_code: str) -> JSONDict:
    stage_label = str(stage or 'processing').replace('_', ' ')
    if reason_code == 'outer_timeout':
      message = 'Find candidates exceeded the outer safety cap before completion.'
    else:
      message = f'Find candidates timed out during {stage_label}.'
    return {
      'decision': 'planned',
      'reason': 'stage_timeout',
      'message': message,
      'next_action': 'Find candidates again when you are ready.',
      'candidate_count': 0,
      'candidates': [],
      'sandbox_extended_count': 0,
      'sandbox_candidates_extended': [],
      'exit_contract': {
        'reason_code': 'stage_timeout',
      },
      'orchestration': {
        'terminal_trigger': reason_code,
      },
    }

  def _mark_scan_runtime_timed_out(snapshot: JSONDict, *, reason_code: str) -> JSONDict:
    if str(snapshot.get('status') or '').lower() == 'failed':
      return _scan_runtime_snapshot()
    failure_payload = _scan_timeout_failure_payload(str(snapshot.get('stage') or 'processing'), reason_code)
    now_utc = _scan_runtime_utc_now()
    if scan_runtime_cancel_event is not None:
      scan_runtime_cancel_event.set()
    _set_scan_runtime_state(
      status='failed',
      active=False,
      stage='failed',
      message=str(failure_payload.get('message') or 'Find candidates failed.'),
      completed_at_utc=now_utc,
      last_progress_at_utc=now_utc,
      cancel_requested=True,
      result_payload=failure_payload,
      error_payload=failure_payload,
      hydrated_from_persistence=False,
      replay_candidate_source_available=False,
      hydration_state_db_path='',
    )
    return _scan_runtime_snapshot()

  def _persistable_scan_terminal_payload(result_payload: JSONDict | None) -> JSONDict:
    if not isinstance(result_payload, dict):
      return {}
    projected = _annotate_result_origin(result_payload)
    candidate_rows = projected.get('sandbox_candidates_extended') if isinstance(projected.get('sandbox_candidates_extended'), list) else None
    if candidate_rows is None:
      candidate_rows = projected.get('candidates') if isinstance(projected.get('candidates'), list) else None
    if candidate_rows is None:
      pair_monitor = projected.get('pair_monitor') if isinstance(projected.get('pair_monitor'), dict) else {}
      candidate_rows = pair_monitor.get('candidate_rows') if isinstance(pair_monitor.get('candidate_rows'), list) else []
    candidate_rows = [dict(row) for row in list(candidate_rows or []) if isinstance(row, dict)]
    direct_candidates = projected.get('candidates') if isinstance(projected.get('candidates'), list) else []
    direct_candidates = [dict(row) for row in list(direct_candidates or []) if isinstance(row, dict)]
    candidate_count = max(int(projected.get('candidate_count', 0) or 0), len(direct_candidates), len(candidate_rows))
    sandbox_extended_count = max(int(projected.get('sandbox_extended_count', 0) or 0), len(candidate_rows))
    persisted_payload: JSONDict = {
      'decision': str(projected.get('decision') or 'planned'),
      'reason': str(projected.get('reason') or 'planned'),
      'message': str(projected.get('message') or ''),
      'next_action': str(projected.get('next_action') or ''),
      'candidate_count': candidate_count,
      'sandbox_extended_count': sandbox_extended_count,
      'candidates': direct_candidates or list(candidate_rows),
      'sandbox_candidates_extended': list(candidate_rows),
      'origin': str(projected.get('origin') or ''),
    }
    if isinstance(projected.get('scan_shape_summary'), dict):
      persisted_payload['scan_shape_summary'] = dict(projected.get('scan_shape_summary') or {})
    if isinstance(projected.get('exit_contract'), dict):
      persisted_payload['exit_contract'] = dict(projected.get('exit_contract') or {})
    if isinstance(projected.get('orchestration'), dict):
      persisted_payload['orchestration'] = dict(projected.get('orchestration') or {})
    return persisted_payload

  def _rehydrate_persisted_scan_result_payload(detail: JSONDict, *, event_type: str) -> JSONDict:
    persisted_payload = detail.get('result_payload') if isinstance(detail.get('result_payload'), dict) else None
    if isinstance(persisted_payload, dict) and persisted_payload:
      result_payload = _annotate_result_origin(
        persisted_payload,
        fallback_reason=str(detail.get('result_reason') or detail.get('reason') or ''),
        fallback_message=str(detail.get('result_message') or detail.get('message') or ''),
      )
      candidates = result_payload.get('sandbox_candidates_extended') if isinstance(result_payload.get('sandbox_candidates_extended'), list) else None
      if candidates is None:
        candidates = result_payload.get('candidates') if isinstance(result_payload.get('candidates'), list) else []
      candidates = [dict(candidate) for candidate in list(candidates or []) if isinstance(candidate, dict)]
      direct_candidates = result_payload.get('candidates') if isinstance(result_payload.get('candidates'), list) else []
      direct_candidates = [dict(candidate) for candidate in list(direct_candidates or []) if isinstance(candidate, dict)]
      result_payload['candidates'] = direct_candidates or list(candidates)
      result_payload['sandbox_candidates_extended'] = list(candidates)
      result_payload['candidate_count'] = max(int(result_payload.get('candidate_count', 0) or 0), len(result_payload['candidates']), len(candidates))
      result_payload['sandbox_extended_count'] = max(int(result_payload.get('sandbox_extended_count', 0) or 0), len(candidates))
      if isinstance(result_payload.get('scan_shape_summary'), dict):
        result_payload['scan_shape_summary'] = dict(result_payload.get('scan_shape_summary') or {})
      if isinstance(result_payload.get('scan_retry'), dict):
        result_payload['scan_retry'] = dict(result_payload.get('scan_retry') or {})
      result_payload.setdefault('decision', str(detail.get('result_decision') or 'planned'))
      result_payload.setdefault('reason', str(detail.get('result_reason') or detail.get('reason') or ('scan_canceled' if event_type == 'scan_canceled' else 'scan_failed')))
      result_payload.setdefault('message', str(detail.get('result_message') or detail.get('message') or ''))
      result_payload.setdefault('next_action', str(detail.get('result_next_action') or ('Find candidates when you are ready.' if event_type == 'scan_canceled' else 'Find candidates again when you are ready.')))
      return result_payload

    if event_type == 'scan_background_completed':
      candidates = list(detail.get('sandbox_candidates_extended') or detail.get('candidates') or [])
      return {
        'decision': str(detail.get('result_decision') or 'planned'),
        'reason': str(detail.get('result_reason') or 'planned'),
        'message': str(detail.get('result_message') or 'The scan found candidates and the shell is holding on candidate review in Pairs.'),
        'next_action': str(detail.get('result_next_action') or 'Review candidates in Pairs.'),
        'candidate_count': int(detail.get('candidate_count', len(candidates)) or 0),
        'sandbox_extended_count': int(detail.get('sandbox_extended_count', len(candidates)) or 0),
        'candidates': candidates,
        'sandbox_candidates_extended': list(candidates),
        'scan_shape_summary': dict(detail.get('scan_shape_summary') or {}) if isinstance(detail.get('scan_shape_summary'), dict) else {},
      }

    persisted_reason = str((detail or {}).get('reason') or '').strip().lower()
    if not persisted_reason:
      persisted_reason = 'scan_canceled' if event_type == 'scan_canceled' else 'scan_failed'
    result_payload = {
      'decision': 'planned',
      'reason': persisted_reason,
      'message': str((detail or {}).get('message') or ('Scan canceled by user.' if event_type == 'scan_canceled' else 'Find candidates failed.')),
      'next_action': 'Find candidates when you are ready.' if event_type == 'scan_canceled' else 'Find candidates again when you are ready.',
      'candidate_count': 0,
      'candidates': [],
      'sandbox_extended_count': 0,
      'sandbox_candidates_extended': [],
    }
    if persisted_reason == 'stage_timeout':
      result_payload['exit_contract'] = {'reason_code': 'stage_timeout'}
      result_payload['orchestration'] = {'terminal_trigger': 'stage_timeout'}
    return result_payload

  def _hydrate_persisted_scan_runtime(env_override: str | None, subaccount_override: int | None) -> None:
    snapshot = _scan_runtime_snapshot()
    active_settings = _effective_shell_settings(env_override, subaccount_override)
    if active_settings is None:
      active_settings = _resolve_settings(
        None,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
    if not _lane_boundary_mode_selected(
      env_override=env_override,
      subaccount_override=subaccount_override,
      settings_override=active_settings,
    ):
      return
    if not _persistence_hydration_allowed(active_settings):
      return
    persisted_lane = _normalize_key_lane(getattr(active_settings, 'operation_lane', None))
    state_db_path = str(getattr(active_settings, 'state_db_path', '') or '').strip()
    if bool(snapshot.get('active')):
      return
    if snapshot.get('result_payload') is not None:
      snapshot_state_db_path = str(snapshot.get('hydration_state_db_path') or '').strip()
      if _scan_runtime_matches_lane(snapshot, persisted_lane) and snapshot_state_db_path == state_db_path:
        return
      _clear_scan_runtime_terminal_replay_state()
    if not state_db_path:
      return
    try:
      connection = open_database(state_db_path)
      if persisted_lane in {'sandbox', 'live'}:
        row = connection.execute(
          '''
          SELECT recorded_at_utc, operation_lane, lane_session_id, event_type, detail_json
          FROM runtime_events
          WHERE event_type IN ('scan_background_completed', 'scan_background_failed', 'scan_canceled')
            AND operation_lane = ?
          ORDER BY id DESC
          LIMIT 1
          ''',
          (persisted_lane,),
        ).fetchone()
      else:
        row = connection.execute(
          '''
          SELECT recorded_at_utc, operation_lane, lane_session_id, event_type, detail_json
          FROM runtime_events
          WHERE event_type IN ('scan_background_completed', 'scan_background_failed', 'scan_canceled')
          ORDER BY id DESC
          LIMIT 1
          '''
        ).fetchone()
    except Exception:
      return
    if row is None:
      return
    detail = json.loads(row['detail_json']) if row['detail_json'] else {}
    event_type = str(row['event_type'] or '')
    if event_type == 'scan_background_completed':
      result_payload = _rehydrate_persisted_scan_result_payload(detail, event_type=event_type)
      status = 'completed'
      stage = 'complete'
      message = 'Find candidates finished and returned a shell payload.'
      error_payload = None
    else:
      result_payload = _rehydrate_persisted_scan_result_payload(detail, event_type=event_type)
      status = 'canceled' if event_type == 'scan_canceled' else 'failed'
      stage = status
      message = str(result_payload.get('message') or '')
      error_payload = result_payload if status == 'failed' else None
    replay_candidate_source_available = _payload_has_review_candidates(result_payload)
    # Gate: found-but-unsaved candidates must not survive a session restart.
    # Only candidates explicitly saved to a saved set should be visible after
    # hydration.  The gate uses the live member-row count (not the stale
    # saved_key_count header field, which can be out of date after member
    # removal).  On gate-pass the candidate list is replaced with exactly the
    # saved-set member entries so the panel reflects the saved subset only.
    if int(result_payload.get('candidate_count', 0) or 0) > 0 or int(result_payload.get('sandbox_extended_count', 0) or 0) > 0:
      try:
        _hydrate_lane = str(row['operation_lane'] or persisted_lane or 'sandbox')
        _saved_set = fetch_latest_candidate_saved_set(connection, operation_lane=_hydrate_lane)
        _saved_members = list(_saved_set.get('members') or []) if isinstance(_saved_set, dict) else []
        _has_saved = len(_saved_members) > 0
      except Exception:
        _saved_members = []
        _has_saved = False
      result_payload = dict(result_payload)
      if not _has_saved:
        # No live saved-set members — clear all found candidates.
        result_payload['candidates'] = []
        result_payload['sandbox_candidates_extended'] = []
        result_payload['candidate_count'] = 0
        result_payload['sandbox_extended_count'] = 0
      else:
        # Saved members exist — restrict visible candidates to the saved subset.
        # Build a lookup from the scan-event candidates keyed by candidate_key so
        # richer scan-event metadata is preserved where available.
        _scan_candidates = list(result_payload.get('candidates') or [])
        _scan_extended = list(result_payload.get('sandbox_candidates_extended') or [])
        _by_key = {
          str(c.get('candidate_key') or c.get('ticker') or ''): dict(c)
          for c in (_scan_extended or _scan_candidates)
          if isinstance(c, dict)
        }
        _filtered = []
        for _member in _saved_members:
          _mkey = str(_member.get('candidate_key') or '')
          if _mkey and _mkey in _by_key:
            _filtered.append(_by_key[_mkey])
          else:
            _mdetail = dict(_member.get('detail') or {}) if isinstance(_member.get('detail'), dict) else {}
            _entry = dict(_mdetail)
            if _mkey:
              _entry.setdefault('candidate_key', _mkey)
            _filtered.append(_entry)
        result_payload['candidates'] = list(_filtered)
        result_payload['sandbox_candidates_extended'] = list(_filtered)
        result_payload['candidate_count'] = len(_filtered)
        result_payload['sandbox_extended_count'] = len(_filtered)
      if error_payload is not None:
        error_payload = result_payload
    _set_scan_runtime_state(
      status=status,
      active=False,
      scan_session_id=str(detail.get('scan_session_id') or ''),
      lane_session_id=str(row['lane_session_id'] or ''),
      operation_lane=str(row['operation_lane'] or getattr(active_settings, 'operation_lane', 'sandbox') or 'sandbox'),
      stage=stage,
      message=message,
      progress_percent=1.0 if status == 'completed' else 0.0,
      started_at_utc=row['recorded_at_utc'],
      completed_at_utc=row['recorded_at_utc'],
      last_progress_at_utc=row['recorded_at_utc'],
      cancel_requested=(status == 'canceled'),
      result_payload=result_payload,
      error_payload=error_payload,
      hydrated_from_persistence=True,
      replay_candidate_source_available=replay_candidate_source_available,
      hydration_state_db_path=state_db_path,
    )

  def _scan_runtime_snapshot() -> JSONDict:
    with scan_runtime_lock:
      snapshot = dict(scan_runtime_state)
      result_payload = snapshot.get('result_payload')
      if isinstance(result_payload, dict):
        snapshot['result_payload'] = dict(result_payload)
      error_payload = snapshot.get('error_payload')
      if isinstance(error_payload, dict):
        snapshot['error_payload'] = dict(error_payload)
    status = str(snapshot.get('status') or '').lower()
    if status in {'processing', 'canceling'}:
      now = datetime.now(timezone.utc)
      last_progress = _parse_runtime_timestamp(snapshot.get('last_progress_at_utc')) or _parse_runtime_timestamp(snapshot.get('started_at_utc'))
      started_at = _parse_runtime_timestamp(snapshot.get('started_at_utc')) or last_progress
      stage = str(snapshot.get('stage') or 'processing')
      if last_progress is not None:
        soft_timeout = float(SCAN_STAGE_SOFT_TIMEOUTS_SEC.get(stage, 0.0) or 0.0)
        hard_timeout = float(SCAN_STAGE_HARD_TIMEOUTS_SEC.get(stage, 0.0) or 0.0)
        elapsed_since_progress = (now - last_progress).total_seconds()
        elapsed_since_start = (now - started_at).total_seconds() if started_at is not None else 0.0
        if hard_timeout and elapsed_since_progress > hard_timeout:
          snapshot = _mark_scan_runtime_timed_out(snapshot, reason_code='stage_timeout')
          status = str(snapshot.get('status') or '').lower()
        elif SCAN_OUTER_SAFETY_CAP_SEC and elapsed_since_start >= float(SCAN_OUTER_SAFETY_CAP_SEC):
          snapshot = _mark_scan_runtime_timed_out(snapshot, reason_code='outer_timeout')
          status = str(snapshot.get('status') or '').lower()
        else:
          snapshot['orchestration'] = {
            'terminal_trigger': '',
            'stall_observation': (
              {
                'classification': 'soft_stall',
                'stage': stage,
                'elapsed_sec': round(elapsed_since_progress, 3),
              }
              if soft_timeout and elapsed_since_progress >= soft_timeout
              else {
                'classification': 'healthy',
                'stage': stage,
                'elapsed_sec': round(elapsed_since_progress, 3),
              }
            ),
          }
          snapshot['exit_contract'] = {
            'reason_code': 'soft_stall' if soft_timeout and elapsed_since_progress >= soft_timeout else 'processing',
          }
    return snapshot

  def _public_scan_runtime_snapshot() -> JSONDict:
    snapshot = _scan_runtime_snapshot()
    internal_status = str(snapshot.get('status') or 'idle')
    public_status = 'cancelled' if internal_status == 'canceled' else internal_status
    result_payload = snapshot.get('result_payload') if isinstance(snapshot.get('result_payload'), dict) else {}
    retry_state = result_payload.get('scan_retry') if isinstance(result_payload.get('scan_retry'), dict) else {}
    if bool(snapshot.get('cancel_requested')) or internal_status in {'canceling', 'canceled'}:
      retry_state = {}
    orchestration = snapshot.get('orchestration') if isinstance(snapshot.get('orchestration'), dict) else {}
    if not orchestration and isinstance(result_payload.get('orchestration'), dict):
      orchestration = dict(result_payload.get('orchestration') or {})
    exit_contract = snapshot.get('exit_contract') if isinstance(snapshot.get('exit_contract'), dict) else {}
    if not exit_contract and isinstance(result_payload.get('exit_contract'), dict):
      exit_contract = dict(result_payload.get('exit_contract') or {})
    return {
      'status': public_status,
      'active': bool(snapshot.get('active')),
      'scan_session_id': str(snapshot.get('scan_session_id') or ''),
      'lane_session_id': str(snapshot.get('lane_session_id') or ''),
      'operator_lane_session_id': str(snapshot.get('operator_lane_session_id') or snapshot.get('lane_session_id') or ''),
      'scan_runtime_lane_session_id': str(snapshot.get('scan_runtime_lane_session_id') or ''),
      'operation_lane': str(snapshot.get('operation_lane') or 'sandbox'),
      'stage': str(snapshot.get('stage') or 'idle'),
      'message': str(snapshot.get('message') or ''),
      'progress_percent': float(snapshot.get('progress_percent') or 0.0),
      'started_at_utc': snapshot.get('started_at_utc'),
      'completed_at_utc': snapshot.get('completed_at_utc'),
      'last_progress_at_utc': snapshot.get('last_progress_at_utc'),
      'cancel_requested': bool(snapshot.get('cancel_requested')),
      'result_decision': str(result_payload.get('decision') or ''),
      'result_reason': str(result_payload.get('reason') or ''),
      'result_next_action': str(result_payload.get('next_action') or ''),
      'result_candidate_count': int(result_payload.get('candidate_count', 0) or 0),
      # S1: actionable (non-terminal) candidate count. Seeds equal to the result
      # count (a fresh scan's candidates are non-terminal); the Lane 3 override below
      # refines it to the non-terminal canonical count so the zero-found-retry gate
      # sees "0 actionable" once every surfaced candidate has gone terminal.
      'result_active_candidate_count': int(result_payload.get('candidate_count', 0) or 0),
      'retry_state': dict(retry_state or {}),
      'orchestration': orchestration,
      'exit_contract': {
        'reason_code': str(
          exit_contract.get('reason_code')
          or result_payload.get('exit_contract', {}).get('reason_code')
          or ('stage_timeout' if str(result_payload.get('reason') or '') == 'stage_timeout' else '')
        ),
      },
    }

  def _scan_runtime_allows_cancel(snapshot: JSONDict | None = None) -> bool:
    runtime_snapshot = snapshot if snapshot is not None else _scan_runtime_snapshot()
    status = str(runtime_snapshot.get('status') or '').lower()
    stage = str(runtime_snapshot.get('stage') or '').lower()
    return (bool(runtime_snapshot.get('active')) and status in {'processing', 'canceling'}) or (
      stage == 'retry_wait' and status in {'processing', 'completed'}
    )

  def _scan_canceled_result_payload(
    settings: Any,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict:
    with _private_key_file_env_overlay(str(getattr(settings, 'private_key_file', None) or ''), lock=overlay_lock):
      settings_payload, _ = _load_shell_settings_context(
        env_override=env_override,
        subaccount_override=subaccount_override,
        settings_override=settings,
      )
    return {
      'decision': 'planned',
      'reason': 'scan_canceled',
      'message': 'Scan canceled by user.',
      'next_action': 'Find candidates when you are ready.',
      'command_family': 'polyventure scan-once',
      'mode': 'ab_guarded',
      'dry_run': True,
      'dry_run_explanation': 'No order was submitted.',
      'candidate_count': 0,
      'candidates': [],
      'sandbox_extended_count': 0,
      'sandbox_candidates_extended': [],
      'settings': settings_payload,
    }

  def _synthesize_zero_found_retry_payload(
    payload: JSONDict | None,
    *,
    lane_session_id: str,
  ) -> JSONDict | None:
    # SCHEDULER_ELIGIBILITY_THRESHOLD_REALIGNMENT_BMAP_2026-06-29 (supersedes the empty-window
    # exception of FIND_CANDIDATES_ZERO_FOUND_RETRY_DECISION_SSOT_BMAP_2026-06-25): the scan engine
    # emits scan_retry metadata for every completed scan with zero qualifying live candidates, cause
    # irrelevant. This consumer must only HONOR an engine-emitted scan_retry block; it must never
    # re-derive a retry from candidate_count alone. Routing (retry vs cadence) is owned by the
    # scheduler, not here. Absence of an engine scan_retry block (e.g. a failed/non-zero scan) is
    # authoritative: this consumer adds nothing.
    normalized_payload = dict(payload or {}) if isinstance(payload, dict) else {}
    if not normalized_payload:
      return None
    if isinstance(normalized_payload.get('scan_retry'), dict):
      return normalized_payload
    return None

  def _scan_processing_workflow(snapshot: JSONDict) -> JSONDict:
    stage_label = str(snapshot.get('stage') or 'processing').replace('_', ' ')
    message = str(snapshot.get('message') or 'Find candidates is processing in the background.')
    return _workflow_state(
      'processing',
      auto_sequence=[],
      headline='Find candidates is running in the background and streaming progress into the shell.',
      operator_message=f'{message} (stage: {stage_label}).',
      step_kind='review',
      can_run_next_step=False,
      next_actionable_step='processing',
      focus_target='boundary-panel',
      focus_tone='focus-info',
      deck_view='operator',
      button_emphasis_tone='warn',
    )

  def _apply_scan_runtime_payload(action_name: str, payload: JSONDict) -> None:
    snapshot = _scan_runtime_snapshot()
    payload['scan_runtime'] = _public_scan_runtime_snapshot()
    # Lane 3 SSOT: override result_candidate_count with the canonical DB count so
    # every surface reads the same truth regardless of scan state.
    # Use persisted_lane_session_id (operator session) when present — same scope as
    # the card query in Lane 2 — so count and card count agree across all phases
    # including post-cancel. Fall back to scan_runtime.lane_session_id only when
    # the operator session is not yet established (first cycle before first persist).
    # Fork D1 (2026-07-02): the count applies the SAME saved-set retirement filter as
    # the Lane 2 card builder — a retired-set member is not a surfaced candidate, so
    # count == cards holds after a blocked submit retires the set and for
    # cross-session carryover rows whose latest saved set is already retired.
    _sr = payload['scan_runtime']
    _sr_settings = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    _sr_review   = payload.get('review_selection') if isinstance(payload.get('review_selection'), dict) else {}
    _sr_db_path  = str(_sr_settings.get('state_db_path') or '').strip()
    _sr_lsid     = (
      str(_sr_review.get('persisted_lane_session_id') or '').strip()
      or str(_sr.get('lane_session_id') or '').strip()
    )
    if _sr_lsid and _sr_db_path:
      try:
        _canon_rows = _query_canonical_candidates(_sr_lsid, _sr_db_path)
        _sr['result_candidate_count'] = sum(
          1 for _r in _canon_rows if not _candidate_row_saved_set_retired(_r)
        )
        # S1: the zero-found-retry gate must see "0 actionable" when every surfaced
        # candidate has gone terminal (expired_unfilled / auto_cancel) -- otherwise the
        # retry never refires (no countdown) even though there is nothing left to act on
        # and the deck wedges in Retry Wait. The retry gate reads this non-terminal
        # count over the UNFILTERED canonical rows (unchanged by fork D1): retirement
        # is a display contract, and the gate must still see lifecycle truth.
        _sr['result_active_candidate_count'] = sum(
          1 for _r in _canon_rows if str(_r.get('lifecycle_stage') or '') != 'terminal'
        )
      except Exception:
        pass
    if str(snapshot.get('status') or '').lower() not in {'processing', 'canceling'}:
      return
    payload['execution_state'] = {
      'kind': 'processing',
      'action': 'scan',
      'scan_session_id': str(snapshot.get('scan_session_id') or ''),
      'lane_session_id': str(snapshot.get('lane_session_id') or ''),
      'stage': str(snapshot.get('stage') or 'processing'),
      'message': str(snapshot.get('message') or 'Find candidates is processing in the background.'),
      'progress_percent': float(snapshot.get('progress_percent') or 0.0),
      'started_at_utc': snapshot.get('started_at_utc'),
      'last_progress_at_utc': snapshot.get('last_progress_at_utc'),
    }
    payload['workflow'] = _scan_processing_workflow(snapshot)
    payload['next_action'] = str(
      payload.get('next_action')
      or snapshot.get('message')
      or 'Wait for the current candidate scan to complete.'
    )
    if str(action_name or '').strip().lower() == 'scan' and payload.get('decision') != 'no-go':
      payload['decision'] = 'planned'

  def _scan_call_accepts_keyword(call: Callable[..., Any], keyword: str) -> bool:
    try:
      signature = inspect.signature(call)
    except (TypeError, ValueError):
      return False
    for parameter in signature.parameters.values():
      if parameter.kind == inspect.Parameter.VAR_KEYWORD:
        return True
    return keyword in signature.parameters

  def _persist_scan_runtime_event(
    settings: Any,
    *,
    lane_session_id: str,
    level: str,
    event_type: str,
    detail: JSONDict,
  ) -> None:
    try:
      connection = open_database(getattr(settings, 'state_db_path'))
      persist_runtime_event(
        connection,
        level=level,
        event_type=event_type,
        recorded_at_utc=_scan_runtime_utc_now(),
        operation_lane=str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox'),
        lane_session_id=lane_session_id,
        detail=detail,
      )
    except Exception:
      pass

  def _persist_run_response_projection_event(
    settings: Any,
    payload: dict[str, Any],
    *,
    lane_session_id: str,
  ) -> None:
    # Charter R2: persist a names-only projection of every /api/run response
    # as a runtime_events row of event_type='run_response_projection'.
    try:
      connection = open_database(getattr(settings, 'state_db_path'))
      persist_runtime_event(
        connection,
        level='INFO',
        event_type='run_response_projection',
        recorded_at_utc=_scan_runtime_utc_now(),
        operation_lane=str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox'),
        lane_session_id=lane_session_id,
        detail=_build_run_response_projection(payload),
      )
    except Exception:
      pass

  def _scheduler_utc_now() -> str:
    return datetime.now(timezone.utc).isoformat(timespec='milliseconds').replace('+00:00', 'Z')

  def _scheduler_parse_utc(value: Any) -> datetime | None:
    if value in {None, ''}:
      return None
    try:
      parsed = datetime.fromisoformat(str(value).replace('Z', '+00:00'))
      if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
      return parsed.astimezone(timezone.utc)
    except Exception:
      return None

  def _scheduler_source_from_request(
    request_payload: JSONDict | None,
    *,
    default_source: str,
  ) -> str:
    payload = request_payload if isinstance(request_payload, dict) else {}
    raw_source = (
      payload.get('scheduler_source')
      or payload.get('source')
      or payload.get('intent_source')
      or default_source
    )
    source = str(raw_source or default_source).strip().lower()
    aliases = {
      'auto_find_cadence': 'automation_cadence',
      'auto_cadence': 'automation_cadence',
      'cadence': 'automation_cadence',
      'retry': 'zero_found_retry',
      'zero_retry': 'zero_found_retry',
      'scan_refire': 'client_scan_refire',
      'client_refire': 'client_scan_refire',
      'manual': 'manual_scan',
    }
    return aliases.get(source, source or default_source)

  def _scheduler_operation_lane(settings: Any | None = None) -> str:
    return str(
      getattr(settings, 'operation_lane', None)
      or context_overlay_state.get('operation_lane')
      or 'offline'
    ).strip().lower() or 'offline'

  def _scheduler_mode_selected() -> bool:
    return bool(context_overlay_state.get('mode_selected')) or (
      bool(automation_overlay_state.get('enabled')) and not bool(automation_overlay_state.get('paused'))
    )

  def _scheduler_socket_snapshot(settings: Any | None = None) -> JSONDict:
    operation_lane = _scheduler_operation_lane(settings)
    mode_selected = _scheduler_mode_selected()
    websocket_snapshot = _websocket_runtime_snapshot()
    runtime_lane = str(websocket_snapshot.get('operation_lane') or '').strip().lower()
    raw_status = str(websocket_snapshot.get('status') or 'waiting').strip().lower()
    connected = bool(websocket_snapshot.get('websocket_connected'))
    if not mode_selected or operation_lane not in {'sandbox', 'live'}:
      socket_state = 'disconnected'
      operative = False
    elif runtime_lane and runtime_lane != operation_lane:
      socket_state = 'disconnected'
      operative = False
    elif connected and raw_status in {'connected', 'reconnected'}:
      socket_state = 'connected'
      operative = True
    elif raw_status in {'connecting', 'reconnecting', 'auth_failed'}:
      socket_state = raw_status
      operative = False
    elif connected:
      socket_state = 'connected'
      operative = True
    elif raw_status in {'waiting', 'stopped', 'restart_required'}:
      socket_state = 'disconnected'
      operative = False
    else:
      socket_state = raw_status or 'unknown'
      operative = False
    return {
      'socket_state': socket_state,
      'socket_operative': bool(operative),
      'mode_selected': bool(mode_selected),
      'operation_lane': operation_lane,
      'lane_session_id': str(websocket_snapshot.get('lane_session_id') or ''),
      'websocket_status': raw_status,
      'websocket_connected': bool(connected),
      'reason_code': str(websocket_snapshot.get('reason_code') or ''),
    }

  def _scheduler_submit_ready() -> bool:
    state_id = str(review_selection_state.get('state_id') or '').strip().lower()
    saved_set_id = str(review_selection_state.get('saved_set_id') or '').strip()
    candidate_signature = str(review_selection_state.get('candidate_signature') or '').strip()
    consumed = review_selection_state.get('consumed_submit_terminal') if isinstance(review_selection_state.get('consumed_submit_terminal'), dict) else {}
    if (
      saved_set_id
      and candidate_signature
      and str(consumed.get('consumed_saved_set_id') or '').strip() == saved_set_id
      and str(consumed.get('consumed_candidate_signature') or '').strip() == candidate_signature
    ):
      return False
    return (
      state_id == 'review_hold_saved_selection_locked'
      and bool(saved_set_id)
      and _saved_selection_member_count() > 0
    )

  def _current_saved_set_consumed_by_submit_terminal() -> bool:
    saved_set_id = str(review_selection_state.get('saved_set_id') or '').strip()
    candidate_signature = str(review_selection_state.get('candidate_signature') or '').strip()
    consumed = review_selection_state.get('consumed_submit_terminal') if isinstance(review_selection_state.get('consumed_submit_terminal'), dict) else {}
    return bool(
      saved_set_id
      and candidate_signature
      and str(consumed.get('consumed_saved_set_id') or '').strip() == saved_set_id
      and str(consumed.get('consumed_candidate_signature') or '').strip() == candidate_signature
    )

  def _scheduler_public_timer_record(kind: str) -> JSONDict | None:
    with scheduler_lock:
      records = scheduler_state.get('timer_records') if isinstance(scheduler_state.get('timer_records'), dict) else {}
      record = records.get(kind) if isinstance(records, dict) else None
      return dict(record) if isinstance(record, dict) else None

  def _scheduler_clear_timer_record(kind: str) -> None:
    with scheduler_lock:
      records = scheduler_state.get('timer_records') if isinstance(scheduler_state.get('timer_records'), dict) else {}
      if not isinstance(records, dict):
        records = {}
        scheduler_state['timer_records'] = records
      records[kind] = None

  def _scheduler_set_timer_record(
    kind: str,
    *,
    source: str,
    lane_session_id: str,
    after_sec: float,
    source_terminal_ref: JSONDict | None = None,
  ) -> JSONDict:
    now_utc = datetime.now(timezone.utc)
    deadline_utc = now_utc + timedelta(seconds=max(0.0, float(after_sec)))
    terminal_ref = dict(source_terminal_ref) if isinstance(source_terminal_ref, dict) else {}
    record: JSONDict = {
      'active': True,
      'kind': str(kind or ''),
      'source': str(source or ''),
      'lane_session_id': str(lane_session_id or ''),
      'started_at_utc': now_utc.isoformat(timespec='milliseconds').replace('+00:00', 'Z'),
      'deadline_utc': deadline_utc.isoformat(timespec='milliseconds').replace('+00:00', 'Z'),
      'after_sec': float(max(0.0, float(after_sec))),
    }
    for key, value in terminal_ref.items():
      if str(key or '').startswith('source_'):
        record[str(key)] = value
    with scheduler_lock:
      records = scheduler_state.get('timer_records') if isinstance(scheduler_state.get('timer_records'), dict) else {}
      if not isinstance(records, dict):
        records = {}
        scheduler_state['timer_records'] = records
      records[kind] = dict(record)
    return record

  def _scheduler_timer_countdown_state(kind: str, *, base_state: JSONDict) -> JSONDict:
    record = _scheduler_public_timer_record(kind)
    if not isinstance(record, dict) or not bool(record.get('active')):
      return base_state
    deadline = _scheduler_parse_utc(record.get('deadline_utc'))
    now_utc = datetime.now(timezone.utc)
    remaining_ms = max(0.0, ((deadline - now_utc).total_seconds() * 1000.0) if deadline else 0.0)
    state = 'due' if remaining_ms <= 0.0 else 'waiting'
    payload = dict(base_state)
    payload.update(
      {
        'state': state,
        'active': True,
        'source': str(record.get('source') or ''),
        'lane_session_id': str(record.get('lane_session_id') or ''),
        'started_at_utc': record.get('started_at_utc'),
        'remaining_sec': int((remaining_ms + 999.0) // 1000.0),
      }
    )
    for key, value in record.items():
      if str(key or '').startswith('source_'):
        payload[str(key)] = value
    if kind == 'retry':
      payload['next_retry_at_utc'] = record.get('deadline_utc')
      payload['retry_after_sec'] = int(float(record.get('after_sec') or 0.0))
    else:
      payload['next_cadence_at_utc'] = record.get('deadline_utc')
      if record.get('source') == 'submit_completion' and scheduler_state.get('last_submit_completed_at_utc'):
        payload['last_submit_completed_at_utc'] = scheduler_state.get('last_submit_completed_at_utc')
    return payload

  def _scheduler_retry_state(scan_snapshot: JSONDict | None = None) -> JSONDict:
    return _scheduler_timer_countdown_state('retry', base_state={'state': 'none', 'active': False})

  def _scheduler_cadence_state(scan_snapshot: JSONDict | None = None) -> JSONDict:
    snapshot = scan_snapshot if isinstance(scan_snapshot, dict) else _scan_runtime_snapshot()
    enabled = bool(automation_overlay_state.get('enabled'))
    paused = bool(automation_overlay_state.get('paused'))
    state_id = str(automation_overlay_state.get('state_id') or '').strip().lower()
    cadence_ms = int(automation_overlay_state.get('cadence_ms') or 0)
    if not enabled:
      state = 'disabled'
    elif paused:
      state = 'paused'
    else:
      state = 'waiting'
    cadence_payload: JSONDict = {
      'state': state,
      'enabled': enabled,
      'paused': paused,
      'state_id': state_id,
      'cadence_ms': cadence_ms,
      'max_iterations': int(automation_overlay_state.get('max_iterations') or 0),
    }
    if not enabled or paused or cadence_ms <= 0:
      return cadence_payload
    pending_action = str(scheduler_state.get('pending_action') or '').strip().lower()
    # Submit-ready means submit owns the lane; cadence must not show a countdown.
    if _scheduler_submit_ready() or pending_action == 'submit':
      cadence_payload['state'] = 'waiting_owner'
      cadence_payload['wait_reason'] = 'submit_ready'
      return cadence_payload
    # SCHEDULER_ELIGIBILITY_THRESHOLD_REALIGNMENT_BMAP_2026-06-29 (C5 / D6): a countdown is active
    # only when a scheduler cadence timer record is armed. With automation enabled but no armed
    # record (e.g. startup, or while a retry threshold owns the wait) the resting state is 'idle'
    # so the UI shows '--' rather than a phantom 'waiting' countdown with no deadline behind it.
    cadence_payload['state'] = 'idle'
    cadence_projection = _scheduler_timer_countdown_state('cadence', base_state=cadence_payload)
    if bool(cadence_projection.get('active')):
      return cadence_projection
    last_submit_completed_at_utc = str(scheduler_state.get('last_submit_completed_at_utc') or '').strip()
    # AUTOMATION_CADENCE_RECOVERY_AND_INACTIVITY_GUARD_BMAP_2026-07-02 (C3 / Lane C): the
    # submit-completion integrity alarm must not resurrect after a later scan/retry transition
    # superseded the post-submit beat. An armed retry record owns the wait and an active halt
    # projection owns the explanation — in both cases the stale submit-completion timestamp stays
    # informational only instead of presenting a deadline-less cadence-missing state.
    retry_record = _scheduler_public_timer_record('retry')
    retry_armed = isinstance(retry_record, dict) and bool(retry_record.get('active'))
    with scheduler_lock:
      cadence_halt_projection = scheduler_state.get('halt_projection') if isinstance(scheduler_state.get('halt_projection'), dict) else None
    halt_projection_active = isinstance(cadence_halt_projection, dict) and bool(cadence_halt_projection.get('active'))
    if (
      last_submit_completed_at_utc
      and not pending_action
      and not retry_armed
      and not halt_projection_active
      and str(snapshot.get('status') or '').strip().lower() not in {'processing', 'canceling'}
    ):
      cadence_projection['state'] = 'cadence_timer_missing'
      cadence_projection['integrity_state'] = 'missing_submit_completion_cadence_timer'
      cadence_projection['last_submit_completed_at_utc'] = last_submit_completed_at_utc
      cadence_projection['wait_reason'] = 'submit_completion_cadence_timer_missing'
    return cadence_projection

  def _scheduler_public_lease(lease: JSONDict | None) -> JSONDict | None:
    if not isinstance(lease, dict):
      return None
    return {
      'lease_id': str(lease.get('lease_id') or ''),
      'owner': str(lease.get('owner') or ''),
      'source': str(lease.get('source') or ''),
      'reason': str(lease.get('reason') or ''),
      'operation_lane': str(lease.get('operation_lane') or ''),
      'lane_session_id': str(lease.get('lane_session_id') or ''),
      'priority': int(lease.get('priority') or 0),
      'lease_started_at_utc': lease.get('lease_started_at_utc'),
      'lease_expires_at_utc': lease.get('lease_expires_at_utc'),
      'lease_ttl_sec': lease.get('lease_ttl_sec'),
    }

  def _scheduler_active_lease_locked(now_monotonic: float) -> JSONDict | None:
    lease = scheduler_state.get('lease')
    if not isinstance(lease, dict):
      return None
    expires_monotonic = float(lease.get('expires_monotonic') or 0.0)
    if expires_monotonic and expires_monotonic <= now_monotonic:
      scheduler_state['lease'] = None
      return None
    return lease

  def _scheduler_build_snapshot(
    *,
    settings: Any | None = None,
    source: str = 'projection',
    decision: str = 'noop',
    owner: str | None = None,
    owner_reason: str = 'snapshot',
    allowed_actions: list[str] | None = None,
    blocked_actions: list[str] | None = None,
    lease: JSONDict | None = None,
  ) -> JSONDict:
    scan_snapshot = _scan_runtime_snapshot()
    scan_status = str(scan_snapshot.get('status') or 'idle').strip().lower()
    scan_stage = str(scan_snapshot.get('stage') or 'idle').strip().lower()
    socket_snapshot = _scheduler_socket_snapshot(settings)
    retry_state = _scheduler_retry_state(scan_snapshot)
    cadence_state = _scheduler_cadence_state(scan_snapshot)
    retry_timer_record = _scheduler_public_timer_record('retry')
    cadence_timer_record = _scheduler_public_timer_record('cadence')
    active_lease = lease
    if active_lease is None:
      with scheduler_lock:
        active_lease = _scheduler_active_lease_locked(time.monotonic())
    pending_action = str(scheduler_state.get('pending_action') or '').strip().lower() or None
    pending_reason = str(scheduler_state.get('pending_reason') or '').strip()
    state_owner = str(scheduler_state.get('owner') or '').strip().lower()
    halt_projection = scheduler_state.get('halt_projection') if isinstance(scheduler_state.get('halt_projection'), dict) else None
    stop_teardown = scheduler_state.get('stop_teardown') if isinstance(scheduler_state.get('stop_teardown'), dict) else None
    resolved_owner = str(owner or '').strip().lower()
    resolved_reason = str(owner_reason or '').strip().lower() or 'snapshot'
    if not resolved_owner:
      if isinstance(active_lease, dict):
        resolved_owner = str(active_lease.get('owner') or 'unknown')
        resolved_reason = str(active_lease.get('reason') or resolved_reason)
      elif pending_action:
        resolved_owner = pending_action
        resolved_reason = pending_reason or 'pending_action'
      elif scan_status == 'canceling':
        resolved_owner = 'cancel'
        resolved_reason = 'scan_canceling'
      elif scan_status == 'processing' and scan_stage != 'retry_wait':
        resolved_owner = 'scan'
        resolved_reason = 'scan_in_progress'
      elif (
        bool(socket_snapshot.get('mode_selected'))
        and socket_snapshot.get('operation_lane') in {'sandbox', 'live'}
        and str(socket_snapshot.get('socket_state') or '') in {'connecting', 'reconnecting', 'auth_failed'}
      ):
        resolved_owner = 'websocket_health'
        resolved_reason = 'socket_nonoperative'
      elif retry_state.get('state') in {'waiting', 'due'}:
        retry_owner = str(retry_state.get('source') or 'zero_found_retry').strip().lower() or 'zero_found_retry'
        resolved_owner = retry_owner if retry_owner in {'zero_found_retry', 'scan_failure_retry', 'scan_cancel_retry'} else 'zero_found_retry'
        resolved_reason = f"retry_{retry_state.get('state')}"
      elif cadence_state.get('state') in {'waiting', 'due', 'cadence_timer_missing'}:
        # BMAP 2026-06-29 (C5 / D7): surface the cadence eligibility owner symmetrically with retry
        # (both waiting and due). This is a yielding mid-priority label, not a focus lock.
        resolved_owner = 'automation_cadence'
        resolved_reason = f"cadence_{cadence_state.get('state')}"
      elif state_owner in {'scan', 'submit', 'retry_timer', 'cadence_timer', 'shelter', 'stop'}:
        resolved_owner = state_owner
        resolved_reason = pending_reason or state_owner
      else:
        resolved_owner = 'idle'
        resolved_reason = 'idle'
    submit_state = 'ready' if _scheduler_submit_ready() else 'idle'
    if isinstance(active_lease, dict) and str(active_lease.get('owner') or '') == 'submit_bridge':
      submit_state = 'submitting'
    elif pending_action == 'submit':
      submit_state = 'ready'
    if submit_state in {'ready', 'submitting'}:
      cadence_state = dict(cadence_state)
      cadence_state.pop('next_cadence_at_utc', None)
      cadence_state.pop('remaining_sec', None)
      if cadence_state.get('state') not in {'disabled', 'paused'}:
        cadence_state['state'] = 'waiting_owner'
        cadence_state['wait_reason'] = 'submit_ready'
    if submit_state == 'submitting':
      machine_state = 'SUBMIT_EXECUTING'
    elif submit_state == 'ready':
      machine_state = 'SUBMIT_READY'
    elif scan_status == 'processing' and scan_stage != 'retry_wait':
      machine_state = 'SCAN_EXECUTING'
    elif retry_state.get('state') in {'waiting', 'due'}:
      machine_state = 'RETRY_TIMER_RUNNING'
    elif cadence_state.get('state') in {'waiting', 'due', 'waiting_post_submit', 'cadence_timer_missing'}:
      machine_state = 'CADENCE_TIMER_RUNNING'
    elif pending_action:
      machine_state = f"{pending_action.upper()}_PENDING"
    else:
      machine_state = 'IDLE'
    public_lease = _scheduler_public_lease(active_lease)
    _blocked = list(blocked_actions or [])
    # AUTOMATION_CADENCE_RECOVERY_AND_INACTIVITY_GUARD_BMAP_2026-07-02 (C3 / Lane C): flat
    # projection of the single active scheduler timer. An owner is projected only together with a
    # backend deadline — a record without a deadline projects as no active timer rather than as an
    # owner the display cannot count down. Retry outranks cadence, matching scheduler priority.
    active_timer_record: JSONDict | None = None
    if isinstance(retry_timer_record, dict) and bool(retry_timer_record.get('active')):
      active_timer_record = retry_timer_record
    elif isinstance(cadence_timer_record, dict) and bool(cadence_timer_record.get('active')):
      active_timer_record = cadence_timer_record
    scheduler_timer_owner = ''
    scheduler_timer_started_at_utc = None
    scheduler_timer_deadline_utc = None
    scheduler_timer_state = ''
    scheduler_timer_source_ref: JSONDict = {}
    if isinstance(active_timer_record, dict) and str(active_timer_record.get('deadline_utc') or '').strip():
      timer_deadline = _scheduler_parse_utc(active_timer_record.get('deadline_utc'))
      scheduler_timer_owner = str(active_timer_record.get('source') or '')
      scheduler_timer_started_at_utc = active_timer_record.get('started_at_utc')
      scheduler_timer_deadline_utc = active_timer_record.get('deadline_utc')
      scheduler_timer_state = 'due' if (timer_deadline is not None and timer_deadline <= datetime.now(timezone.utc)) else 'waiting'
      scheduler_timer_source_ref = {
        str(key): value for key, value in active_timer_record.items() if str(key or '').startswith('source_')
      }
    # AUTOMATION_CADENCE_RECOVERY_AND_INACTIVITY_GUARD_BMAP_2026-07-02 (C4 / Lane C): submit
    # elapsed display state is backed by the backend submit lease — while the lease is active the
    # projection carries the lease id, the backend start time, and a derivable elapsed value.
    scheduler_submit_state = ''
    submit_scheduler_lease_id = ''
    submit_started_at_utc = None
    submit_elapsed_ms = None
    if isinstance(active_lease, dict) and str(active_lease.get('owner') or '') == 'submit_bridge':
      scheduler_submit_state = 'submitting'
      submit_scheduler_lease_id = str(active_lease.get('lease_id') or '')
      submit_started_at_utc = active_lease.get('lease_started_at_utc')
      submit_started = _scheduler_parse_utc(submit_started_at_utc)
      if submit_started is not None:
        submit_elapsed_ms = max(0, int((datetime.now(timezone.utc) - submit_started).total_seconds() * 1000.0))
    snapshot: JSONDict = {
      'schema_version': 2,
      'observed_at_utc': _scheduler_utc_now(),
      'source': str(source or 'projection'),
      'operation_lane': str(socket_snapshot.get('operation_lane') or _scheduler_operation_lane(settings)),
      'lane_session_id': str(
        (public_lease or {}).get('lane_session_id')
        or socket_snapshot.get('lane_session_id')
        or scan_snapshot.get('lane_session_id')
        or review_selection_state.get('persisted_lane_session_id')
        or ''
      ),
      'owner': resolved_owner,
      'state': machine_state,
      'owner_reason': resolved_reason,
      'priority': int(scheduler_priority.get(resolved_owner, 0)),
      'pending_action': pending_action,
      'pending_reason': pending_reason,
      'socket_state': str(socket_snapshot.get('socket_state') or 'unknown'),
      'socket_operative': bool(socket_snapshot.get('socket_operative')),
      'scan_state': {
        'status': scan_status,
        'stage': scan_stage,
        'active': bool(scan_snapshot.get('active')),
        'scan_session_id': str(scan_snapshot.get('scan_session_id') or ''),
      },
      'submit_state': submit_state,
      'scheduler_timer_owner': scheduler_timer_owner,
      'scheduler_timer_started_at_utc': scheduler_timer_started_at_utc,
      'scheduler_timer_deadline_utc': scheduler_timer_deadline_utc,
      'scheduler_timer_state': scheduler_timer_state,
      'scheduler_timer_source_ref': scheduler_timer_source_ref,
      'scheduler_submit_state': scheduler_submit_state,
      'submit_scheduler_lease_id': submit_scheduler_lease_id,
      'submit_started_at_utc': submit_started_at_utc,
      'submit_elapsed_ms': submit_elapsed_ms,
      'timer_records': {
        'retry': retry_timer_record,
        'cadence': cadence_timer_record,
        'guard': _scheduler_public_timer_record('guard'),
      },
      'inactivity_guard_state': str(scheduler_state.get('inactivity_guard_state') or 'disabled'),
      'halt_projection': dict(halt_projection) if isinstance(halt_projection, dict) else None,
      'cadence_state': cadence_state,
      'retry_state': retry_state,
      'last_submit_completed_at_utc': scheduler_state.get('last_submit_completed_at_utc'),
      'lease_id': (public_lease or {}).get('lease_id'),
      'lease_started_at_utc': (public_lease or {}).get('lease_started_at_utc'),
      'lease_expires_at_utc': (public_lease or {}).get('lease_expires_at_utc'),
      'lease_ttl_sec': (public_lease or {}).get('lease_ttl_sec'),
      'stop_teardown': dict(stop_teardown) if isinstance(stop_teardown, dict) else None,
      'decision': str(decision or 'noop'),
      'reason': resolved_reason,
      'allowed_actions': list(allowed_actions or []),
      'blocked_actions': _blocked,
    }
    with scheduler_lock:
      scheduler_state['last_snapshot'] = dict(snapshot)
    return snapshot

  def _persist_scheduler_event(
    settings: Any | None,
    event_type: str,
    snapshot: JSONDict,
    *,
    level: str = 'INFO',
    extra_detail: JSONDict | None = None,
  ) -> None:
    if settings is None:
      return
    try:
      db_path = str(getattr(settings, 'state_db_path', '') or '').strip()
      if not db_path:
        return
      connection = open_database(db_path)
      detail = {
        'schema_version': int(snapshot.get('schema_version') or 1),
        'owner': str(snapshot.get('owner') or ''),
        'decision': str(snapshot.get('decision') or ''),
        'reason': str(snapshot.get('reason') or snapshot.get('owner_reason') or ''),
        'source': str(snapshot.get('source') or ''),
        'priority': int(snapshot.get('priority') or 0),
        'socket_state': str(snapshot.get('socket_state') or ''),
        'scan_status': str(((snapshot.get('scan_state') or {}).get('status') if isinstance(snapshot.get('scan_state'), dict) else '') or ''),
        'scan_stage': str(((snapshot.get('scan_state') or {}).get('stage') if isinstance(snapshot.get('scan_state'), dict) else '') or ''),
        'submit_state': str(snapshot.get('submit_state') or ''),
        'lease_id': str(snapshot.get('lease_id') or ''),
      }
      if isinstance(extra_detail, dict):
        detail.update(extra_detail)
      persist_runtime_event(
        connection,
        level=level,
        event_type=event_type,
        recorded_at_utc=_scheduler_utc_now(),
        operation_lane=str(snapshot.get('operation_lane') or getattr(settings, 'operation_lane', 'sandbox') or 'sandbox'),
        lane_session_id=str(snapshot.get('lane_session_id') or ''),
        detail=detail,
      )
    except Exception:
      pass

  def _scheduler_effective_post_submit_processing_buffer_sec(settings: Any | None) -> int:
    raw_value = getattr(settings, 'post_submit_processing_buffer_sec', FLOOR_POST_SUBMIT_PROCESSING_BUFFER_SEC)
    try:
      configured = int(raw_value)
    except (TypeError, ValueError):
      configured = FLOOR_POST_SUBMIT_PROCESSING_BUFFER_SEC
    return max(FLOOR_POST_SUBMIT_PROCESSING_BUFFER_SEC, configured)

  def _scheduler_lease_ttl_sec(settings: Any | None, owner: str) -> float:
    if str(owner or '').strip() != 'submit_bridge':
      return float(scheduler_exclusive_lease_ttl_sec)
    try:
      entry_window_start_sec = int(getattr(settings, 'entry_window_start_sec', 0) or 0)
    except (TypeError, ValueError):
      entry_window_start_sec = 0
    return float(max(0, entry_window_start_sec) + _scheduler_effective_post_submit_processing_buffer_sec(settings))

  def _scheduler_stop_gate_snapshot(event_detail: JSONDict, lane_session_id: str) -> JSONDict:
    raw_snapshot = event_detail.get('gate_snapshot') if isinstance(event_detail.get('gate_snapshot'), dict) else {}
    return {
      'ready': bool(raw_snapshot.get('ready')) if isinstance(raw_snapshot, dict) else False,
      'reason': str((raw_snapshot or {}).get('reason') or event_detail.get('reason') or 'operator_stop'),
      'lane_session_id': str((raw_snapshot or {}).get('lane_session_id') or lane_session_id or ''),
    }

  def _scheduler_normalized_stop_teardown(
    *,
    settings: Any | None,
    lane_session_id: str,
    transition_reason: str,
    cancel_summary: JSONDict | None,
    halted_candidate_count: int,
  ) -> JSONDict:
    cancel_on_pause = bool(getattr(settings, 'cancel_on_pause', False)) if settings is not None else False
    canceled_pair_count = int((cancel_summary or {}).get('canceled_pair_count') or 0) if isinstance(cancel_summary, dict) else 0
    preserved_count = int((cancel_summary or {}).get('preserved_fill_bearing_pair_count') or 0) if isinstance(cancel_summary, dict) else 0
    halted_count = int(halted_candidate_count or 0)
    return {
      'schema_version': 1,
      'transition_reason': str(transition_reason or 'operator_stop'),
      'lane_session_id': str(lane_session_id or ''),
      'cancel_on_pause': cancel_on_pause,
      'canceled_pair_count': canceled_pair_count,
      'preserved_fill_bearing_pair_count': preserved_count,
      'halted_candidate_count': halted_count,
      'total_halted_count': canceled_pair_count + halted_count,
    }

  def _scheduler_acquire_lease(
    settings: Any | None,
    *,
    owner: str,
    source: str,
    reason: str,
  ) -> JSONDict:
    now_monotonic = time.monotonic()
    started_at = _scheduler_utc_now()
    lease_ttl_sec = _scheduler_lease_ttl_sec(settings, owner)
    expires_at_dt = datetime.now(timezone.utc) + timedelta(seconds=lease_ttl_sec)
    socket_snapshot = _scheduler_socket_snapshot(settings)
    lane_session_id = str(
      socket_snapshot.get('lane_session_id')
      or review_selection_state.get('persisted_lane_session_id')
      or _scan_runtime_snapshot().get('lane_session_id')
      or ''
    )
    lease: JSONDict = {
      'lease_id': '{owner}-{ts}-{suffix}'.format(
        owner=str(owner or 'scheduler').replace('_', '-'),
        ts=time.strftime('%Y%m%dT%H%M%SZ', time.gmtime()),
        suffix=os.urandom(3).hex(),
      ),
      'owner': owner,
      'source': source,
      'reason': reason,
      'operation_lane': str(socket_snapshot.get('operation_lane') or _scheduler_operation_lane(settings)),
      'lane_session_id': lane_session_id,
      'priority': int(scheduler_priority.get(owner, 0)),
      'lease_started_at_utc': started_at,
      'lease_expires_at_utc': expires_at_dt.isoformat(timespec='milliseconds').replace('+00:00', 'Z'),
      'lease_ttl_sec': lease_ttl_sec,
      'started_monotonic': now_monotonic,
      'expires_monotonic': now_monotonic + lease_ttl_sec,
    }
    with scheduler_lock:
      scheduler_state['lease'] = lease
      scheduler_state['owner'] = owner
      scheduler_state['pending_action'] = None
      scheduler_state['pending_reason'] = ''
    snapshot = _scheduler_build_snapshot(
      settings=settings,
      source=source,
      decision='allow',
      owner=owner,
      owner_reason=reason,
      allowed_actions=[owner],
      blocked_actions=[],
      lease=lease,
    )
    _persist_scheduler_event(settings, 'scheduler_lease_acquired', snapshot)
    return snapshot

  def _scheduler_release_lease(
    settings: Any | None,
    lease_id: str | None,
    *,
    reason: str,
    source: str = 'backend',
  ) -> JSONDict:
    if not lease_id:
      return _scheduler_build_snapshot(
        settings=settings,
        source=source,
        decision='noop',
        owner_reason=reason,
      )
    released_lease: JSONDict | None = None
    with scheduler_lock:
      current = scheduler_state.get('lease')
      if isinstance(current, dict) and (not lease_id or str(current.get('lease_id') or '') == str(lease_id or '')):
        released_lease = dict(current)
        scheduler_state['lease'] = None
        scheduler_state['owner'] = 'idle'
        # Contract 4 (Lane E): record submit completion timestamp so _scheduler_cadence_state
        # can use it as the post-submit cadence origin instead of scan completion time
        if str(released_lease.get('owner') or '') == 'submit_bridge':
          scheduler_state['last_submit_completed_at_utc'] = _scheduler_utc_now()
    snapshot = _scheduler_build_snapshot(
      settings=settings,
      source=source,
      decision='noop',
      owner='idle',
      owner_reason=reason,
      allowed_actions=[],
      blocked_actions=[],
      lease=None,
    )
    release_observed_at_utc = snapshot.get('observed_at_utc')
    if released_lease is not None:
      _persist_scheduler_event(
        settings,
        'scheduler_lease_released',
        snapshot,
        extra_detail={
          'released_lease_id': str(released_lease.get('lease_id') or ''),
          'released_owner': str(released_lease.get('owner') or ''),
        },
      )
    pending_retry: JSONDict | None = None
    if isinstance(released_lease, dict) and str(released_lease.get('owner') or '') == 'scan':
      with scheduler_lock:
        pending = scheduler_state.get('pending_retry_after_scan_release')
        if isinstance(pending, dict):
          pending_lease_id = str(pending.get('scan_scheduler_lease_id') or '').strip()
          released_lease_id = str(released_lease.get('lease_id') or '').strip()
          if pending_lease_id and pending_lease_id == released_lease_id:
            pending_retry = dict(pending)
            scheduler_state['pending_retry_after_scan_release'] = None
    if pending_retry is not None:
      terminal_ref = dict(pending_retry.get('source_terminal_ref') if isinstance(pending_retry.get('source_terminal_ref'), dict) else {})
      terminal_ref.update(
        {
          'source_lease_released_at_utc': release_observed_at_utc,
          'source_released_lease_id': str(released_lease.get('lease_id') or ''),
          'source_release_reason': str(reason or ''),
        }
      )
      retry_source = str(pending_retry.get('source') or 'zero_found_retry').strip().lower() or 'zero_found_retry'
      # AUTOMATION_CADENCE_RECOVERY_AND_INACTIVITY_GUARD_BMAP_2026-07-02 (C2 / Lane B): the source
      # reference is validated before the timer is armed so a doomed retry halts explicitly here
      # instead of at elapsed. The metadata-only gap self-corrects with warning evidence; every
      # other invalid state fails closed without arming a timer.
      start_probe: JSONDict = dict(terminal_ref)
      start_normalization_evidence = _normalize_metadata_only_retry_source_gap(start_probe)
      if start_normalization_evidence is not None:
        terminal_ref['source_retry'] = str(start_probe.get('source_retry') or '')
        normalization_snapshot = _scheduler_build_snapshot(
          settings=settings,
          source='scan_release_retry_timer',
          decision='retry_source_ref_normalized',
          owner_reason='metadata_only_retry_source_gap',
        )
        _persist_scheduler_event(settings, 'scheduler_retry_source_ref_normalized', normalization_snapshot, level='WARN', extra_detail={**terminal_ref, **start_normalization_evidence})
      if retry_source in {'zero_found_retry', 'scan_failure_retry'} and not _retry_elapsed_source_ref_valid(start_probe):
        with scheduler_lock:
          scheduler_state['owner'] = 'idle'
          scheduler_state['pending_action'] = None
          scheduler_state['pending_reason'] = ''
          scheduler_state['halt_projection'] = {
            'active': True,
            'kind': 'retry_timer_contract_invalid',
            'reason': 'missing_retry_source_terminal_ref_at_start',
            'operator_action': 'inspect_evidence',
            'retryable': False,
          }
        blocked_snapshot = _scheduler_build_snapshot(
          settings=settings,
          source='scan_release_retry_timer',
          decision='halted_retry_timer_contract_invalid',
          owner_reason='missing_retry_source_terminal_ref_at_start',
        )
        _persist_scheduler_event(settings, 'scheduler_retry_timer_start_blocked', blocked_snapshot, level='ERROR', extra_detail=dict(terminal_ref))
        return snapshot
      _scheduler_start_retry_timer(
        settings,
        pending_retry.get('env_override') if pending_retry.get('env_override') else None,
        int(pending_retry.get('subaccount_override')) if pending_retry.get('subaccount_override') is not None else None,
        lane_session_id=str(pending_retry.get('lane_session_id') or ''),
        after_sec=float(pending_retry.get('retry_after_sec') or 5),
        source=retry_source,
        source_terminal_ref=terminal_ref,
      )
      started_snapshot = _scheduler_build_snapshot(
        settings=settings,
        source='scan_release_retry_timer',
        decision='retry_timer_started_after_release',
        owner_reason=retry_source,
      )
      _persist_scheduler_event(
        settings,
        'scheduler_retry_timer_started_after_release',
        started_snapshot,
        extra_detail={
          'source': retry_source,
          'released_lease_id': str(released_lease.get('lease_id') or ''),
          'lease_released_at_utc': release_observed_at_utc,
          'retry_after_sec': float(pending_retry.get('retry_after_sec') or 5),
          **terminal_ref,
        },
      )
    return snapshot

  def _scheduler_block_snapshot(
    settings: Any | None,
    *,
    source: str,
    decision: str,
    owner: str,
    reason: str,
    blocked_actions: list[str],
    active_lease: JSONDict | None = None,
  ) -> JSONDict:
    snapshot = _scheduler_build_snapshot(
      settings=settings,
      source=source,
      decision=decision,
      owner=owner,
      owner_reason=reason,
      allowed_actions=[],
      blocked_actions=blocked_actions,
      lease=active_lease,
    )
    _persist_scheduler_event(
      settings,
      'scheduler_action_blocked',
      snapshot,
      level='WARN' if decision == 'reject' else 'INFO',
    )
    return snapshot

  def _scheduler_admit_action(
    action_kind: str,
    *,
    source: str,
    settings: Any | None,
    acquire: bool,
  ) -> JSONDict:
    normalized_action = str(action_kind or '').strip().lower()
    normalized_source = str(source or 'manual').strip().lower()
    now_monotonic = time.monotonic()
    expired_lease: JSONDict | None = None
    with scheduler_lock:
      current_lease = scheduler_state.get('lease')
      if isinstance(current_lease, dict):
        expires_monotonic = float(current_lease.get('expires_monotonic') or 0.0)
        if expires_monotonic and expires_monotonic <= now_monotonic:
          expired_lease = dict(current_lease)
          scheduler_state['lease'] = None
      active_lease = _scheduler_active_lease_locked(now_monotonic)
    if expired_lease is not None:
      expired_snapshot = _scheduler_build_snapshot(
        settings=settings,
        source=normalized_source,
        decision='noop',
        owner='idle',
        owner_reason='lease_expired',
      )
      _persist_scheduler_event(
        settings,
        'scheduler_lease_expired',
        expired_snapshot,
        level='WARN',
        extra_detail={
          'expired_lease_id': str(expired_lease.get('lease_id') or ''),
          'expired_owner': str(expired_lease.get('owner') or ''),
        },
      )
    if isinstance(active_lease, dict):
      lease_owner = str(active_lease.get('owner') or 'unknown')
      if lease_owner == 'submit_bridge' and normalized_action == 'scan':
        return _scheduler_block_snapshot(
          settings,
          source=normalized_source,
          decision='wait',
          owner=lease_owner,
          reason='submit_bridge_in_flight',
          blocked_actions=['scan', 'automation_cadence', 'zero_found_retry'],
          active_lease=active_lease,
        )
      if lease_owner == 'scan' and normalized_action == 'submit_bridge':
        return _scheduler_block_snapshot(
          settings,
          source=normalized_source,
          decision='wait',
          owner=lease_owner,
          reason='scan_in_progress',
          blocked_actions=['submit_bridge'],
          active_lease=active_lease,
        )
      if lease_owner == normalized_action or normalized_action in {'scan', 'submit_bridge'}:
        return _scheduler_block_snapshot(
          settings,
          source=normalized_source,
          decision='wait',
          owner=lease_owner,
          reason=f'{lease_owner}_lease_active',
          blocked_actions=[normalized_action],
          active_lease=active_lease,
        )
    scan_snapshot = _scan_runtime_snapshot()
    scan_status = str(scan_snapshot.get('status') or '').strip().lower()
    scan_stage = str(scan_snapshot.get('stage') or '').strip().lower()
    if normalized_action in {'scan', 'submit_bridge'} and scan_status in {'processing', 'canceling'} and scan_stage != 'retry_wait':
      return _scheduler_block_snapshot(
        settings,
        source=normalized_source,
        decision='wait',
        owner='scan' if scan_status == 'processing' else 'cancel',
        reason='scan_in_progress' if scan_status == 'processing' else 'scan_canceling',
        blocked_actions=[normalized_action],
      )
    automated_scan_sources = {'automation_cadence', 'zero_found_retry', 'client_scan_refire', 'monitor_probe'}
    socket_snapshot = _scheduler_socket_snapshot(settings)
    connected_lane_selected = bool(socket_snapshot.get('mode_selected')) and socket_snapshot.get('operation_lane') in {'sandbox', 'live'}
    context_mode_selected = bool(context_overlay_state.get('mode_selected'))
    socket_required = (
      normalized_action == 'submit_bridge'
      or normalized_source in automated_scan_sources
      or (normalized_action == 'scan' and context_mode_selected)
    )
    if normalized_action in {'scan', 'submit_bridge'} and socket_required and connected_lane_selected and not bool(socket_snapshot.get('socket_operative')):
      return _scheduler_block_snapshot(
        settings,
        source=normalized_source,
        decision='wait',
        owner='websocket_health',
        reason=f"socket_{socket_snapshot.get('socket_state') or 'unknown'}",
        blocked_actions=[normalized_action],
      )
    if normalized_action == 'scan' and normalized_source in automated_scan_sources and _scheduler_submit_ready():
      return _scheduler_block_snapshot(
        settings,
        source=normalized_source,
        decision='defer_to_submit',
        owner='submit_bridge',
        reason='submit_ready',
        blocked_actions=['scan'],
      )
    if not acquire:
      return _scheduler_build_snapshot(
        settings=settings,
        source=normalized_source,
        decision='allow',
        owner='idle',
        owner_reason='admission_available',
        allowed_actions=[normalized_action],
      )
    lease_owner = 'submit_bridge' if normalized_action == 'submit_bridge' else 'scan'
    return _scheduler_acquire_lease(
      settings,
      owner=lease_owner,
      source=normalized_source,
      reason=f'{normalized_action}_admitted',
    )

  def _attach_scheduler_snapshot(
    payload: JSONDict,
    *,
    action_name: str,
    source: str = 'projection',
    settings: Any | None = None,
    decision: str = 'noop',
    owner_reason: str = 'payload_projection',
  ) -> JSONDict:
    try:
      payload['scheduler_snapshot'] = _scheduler_build_snapshot(
        settings=settings,
        source=source,
        decision=decision,
        owner_reason=owner_reason,
      )
    except Exception:
      payload['scheduler_snapshot'] = {
        'schema_version': 1,
        'observed_at_utc': _scheduler_utc_now(),
        'source': source,
        'owner': 'unknown',
        'owner_reason': 'snapshot_failed',
        'decision': 'noop',
        'reason': 'snapshot_failed',
        'allowed_actions': [],
        'blocked_actions': [],
      }
    cadence_state = (
      payload.get('scheduler_snapshot', {}).get('cadence_state')
      if isinstance(payload.get('scheduler_snapshot'), dict)
      else None
    )
    if isinstance(cadence_state, dict):
      payload['cadence_state'] = dict(cadence_state)
      scan_runtime = payload.get('scan_runtime')
      if isinstance(scan_runtime, dict):
        scan_runtime['cadence_state'] = dict(cadence_state)
    return payload

  def _scheduler_wait_payload(
    action_name: str,
    admission: JSONDict,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict:
    payload = _refresh_state_payload(
      action_name,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    decision = str(admission.get('decision') or 'wait')
    reason = str(admission.get('reason') or admission.get('owner_reason') or 'scheduler_wait')
    payload['decision'] = 'planned' if decision in {'wait', 'defer_to_submit'} else 'no-go'
    payload['reason'] = reason
    payload['message'] = (
      'Submit order has priority over the scheduled scan.'
      if decision == 'defer_to_submit'
      else 'The backend scheduler is holding this action until the higher-priority runtime owner clears.'
    )
    payload['next_action'] = (
      'Submit order, then allow automation cadence to resume.'
      if decision == 'defer_to_submit'
      else 'Wait for the scheduler owner to clear, then retry the action.'
    )
    payload['scheduler_snapshot'] = dict(admission)
    if decision == 'defer_to_submit':
      payload['workflow'] = _workflow_state(
        'submit_order',
        auto_sequence=[],
        headline='Submit order has priority over the scheduled scan.',
        operator_message='The backend scheduler deferred the scan because a saved candidate set is ready to submit.',
        step_kind='execute',
        can_run_next_step=True,
        next_actionable_step='submit_order',
        focus_target='pairs-section',
        focus_tone='focus-ok',
        deck_view='operator',
        button_emphasis_tone='ok',
      )
    return payload

  def _scheduler_cancel_timers() -> None:
    with scheduler_lock:
      for key in ('retry_timer', 'cadence_timer', 'inactivity_guard_timer'):
        handle = scheduler_state.get(key)
        if handle is not None:
          handle.cancel()
          scheduler_state[key] = None
      records = scheduler_state.get('timer_records') if isinstance(scheduler_state.get('timer_records'), dict) else {}
      if isinstance(records, dict):
        records['retry'] = None
        records['cadence'] = None
        records['guard'] = None

  def _scan_terminal_kind(terminal_status: str, found_count: int) -> str:
    normalized_status = str(terminal_status or '').strip().lower()
    if normalized_status in {'canceled', 'cancelled'}:
      return 'canceled'
    if normalized_status == 'failed':
      return 'failed'
    if int(found_count or 0) > 0:
      return 'completed_found'
    return 'completed_zero'

  def _build_scan_terminal_completion_token(
    *,
    terminal_status: str,
    found_count: int,
    scan_scheduler_lease_id: str | None,
    result_payload: JSONDict | None,
    retry_source: str = '',
    retry_after_sec: int | None = None,
  ) -> JSONDict:
    runtime_snapshot = _scan_runtime_snapshot()
    payload = result_payload if isinstance(result_payload, dict) else {}
    token: JSONDict = {
      'schema_version': 1,
      'token_kind': 'scan_terminal_completion',
      'scan_session_id': str(runtime_snapshot.get('scan_session_id') or ''),
      'scan_runtime_lane_session_id': str(runtime_snapshot.get('scan_runtime_lane_session_id') or ''),
      'lane_session_id': str(runtime_snapshot.get('lane_session_id') or ''),
      'operation_lane': str(runtime_snapshot.get('operation_lane') or ''),
      'scan_scheduler_lease_id': str(scan_scheduler_lease_id or ''),
      'terminal_status': str(terminal_status or '').strip().lower(),
      'terminal_kind': _scan_terminal_kind(terminal_status, int(found_count or 0)),
      'found_count': int(found_count or 0),
      'raw_found_count': int(found_count or 0),
      'terminal_at_utc': runtime_snapshot.get('completed_at_utc'),
      'result_reason': str(payload.get('reason') or payload.get('decision') or ''),
      'retry_source': str(retry_source or ''),
      'retry_after_sec': int(retry_after_sec) if retry_after_sec is not None else None,
      'verified_runtime_written': True,
    }
    return token

  def _scan_terminal_source_ref_from_token(token: JSONDict | None) -> JSONDict:
    payload = token if isinstance(token, dict) else {}
    return {
      'source_scan_session_id': str(payload.get('scan_session_id') or ''),
      'source_lane_session_id': str(payload.get('lane_session_id') or ''),
      'source_scan_scheduler_lease_id': str(payload.get('scan_scheduler_lease_id') or ''),
      'source_terminal_status': str(payload.get('terminal_status') or ''),
      'source_found_count': int(payload.get('found_count') or 0),
      'source_raw_found_count': int(payload.get('raw_found_count') if payload.get('raw_found_count') is not None else payload.get('found_count') or 0),
      'source_terminal_at_utc': payload.get('terminal_at_utc'),
      'source_retry': str(payload.get('retry_source') or ''),
    }

  def _zero_actionable_retry_source_ref(
    token: JSONDict | None,
    actionability_resolution: JSONDict | None,
  ) -> JSONDict:
    # AUTOMATION_CADENCE_RECOVERY_AND_INACTIVITY_GUARD_BMAP_2026-07-02 (C1 / Lane A): a pending
    # retry that can later elapse must never carry a blank retry source. Completed-scan tokens do
    # not stamp retry_source, so the zero-actionable retry route stamps it here and carries the
    # actionability facts that prove the retry's provenance. A token-supplied source (the true
    # zero-found retry_wait token) is preserved unchanged.
    resolution = actionability_resolution if isinstance(actionability_resolution, dict) else {}
    ref = _scan_terminal_source_ref_from_token(token)
    ref['source_retry'] = str(ref.get('source_retry') or '').strip() or 'zero_found_retry'
    if resolution.get('raw_found_count') is not None:
      ref['source_raw_found_count'] = int(resolution.get('raw_found_count') or 0)
    ref['source_actionable_candidate_count'] = int(resolution.get('actionable_candidate_count') or 0)
    ref['source_actionability_status'] = str(resolution.get('actionability_status') or '')
    ref['source_actionability_reason'] = str(resolution.get('actionability_reason') or '')
    ref['source_scan_completed_at_utc'] = str((token or {}).get('terminal_at_utc') or '')
    return ref

  def _validate_scan_terminal_completion_token(
    event_detail: JSONDict,
    *,
    automation_active: bool,
    lane_session_id: str,
  ) -> tuple[bool, str, JSONDict]:
    token = event_detail.get('scan_terminal_completion_token')
    if not isinstance(token, dict):
      return (not automation_active, 'missing_scan_terminal_completion_token', {})
    normalized_token = dict(token)
    if str(normalized_token.get('token_kind') or '') != 'scan_terminal_completion':
      return False, 'invalid_scan_terminal_token_kind', normalized_token
    if int(normalized_token.get('schema_version') or 0) != 1:
      return False, 'invalid_scan_terminal_token_schema', normalized_token
    if not bool(normalized_token.get('verified_runtime_written')):
      return False, 'scan_terminal_runtime_not_verified', normalized_token
    terminal_status = str(event_detail.get('status') or '').strip().lower()
    token_status = str(normalized_token.get('terminal_status') or '').strip().lower()
    if token_status != terminal_status:
      return False, 'scan_terminal_status_mismatch', normalized_token
    found_count = int(event_detail.get('found_count') or 0)
    if int(normalized_token.get('found_count') or 0) != found_count:
      return False, 'scan_terminal_found_count_mismatch', normalized_token
    if 'raw_found_count' in normalized_token and int(normalized_token.get('raw_found_count') or 0) != found_count:
      return False, 'scan_terminal_raw_found_count_mismatch', normalized_token
    detail_session_id = str(event_detail.get('scan_session_id') or '').strip()
    token_session_id = str(normalized_token.get('scan_session_id') or '').strip()
    if not token_session_id or (detail_session_id and detail_session_id != token_session_id):
      return False, 'scan_terminal_session_mismatch', normalized_token
    token_lane_session_id = str(normalized_token.get('lane_session_id') or '').strip()
    if automation_active and (not token_lane_session_id or (lane_session_id and token_lane_session_id != lane_session_id)):
      return False, 'scan_terminal_lane_session_mismatch', normalized_token
    detail_lease_id = str(event_detail.get('scan_scheduler_lease_id') or '').strip()
    token_lease_id = str(normalized_token.get('scan_scheduler_lease_id') or '').strip()
    if automation_active and (not token_lease_id or (detail_lease_id and detail_lease_id != token_lease_id)):
      return False, 'scan_terminal_lease_mismatch', normalized_token
    if terminal_status in {'completed', 'retry_wait'} and not normalized_token.get('terminal_at_utc'):
      return False, 'scan_terminal_timestamp_missing', normalized_token
    return True, 'valid', normalized_token

  def _retry_elapsed_source_ref_valid(event_detail: JSONDict) -> bool:
    required = (
      'source_scan_session_id',
      'source_lane_session_id',
      'source_scan_scheduler_lease_id',
      'source_terminal_status',
      'source_terminal_at_utc',
      'source_retry',
      'source_lease_released_at_utc',
      'source_released_lease_id',
      'source_release_reason',
    )
    return all(str(event_detail.get(key) or '').strip() for key in required)

  def _normalize_metadata_only_retry_source_gap(event_detail: JSONDict) -> JSONDict | None:
    # AUTOMATION_CADENCE_RECOVERY_AND_INACTIVITY_GUARD_BMAP_2026-07-02 (C2 / Lane B): self-
    # correction is allowed only for the known metadata-only gap — a raw-found-zero-actionable
    # pending retry whose safety identity fields are all valid and whose ONLY missing field is the
    # retry source. Zero-actionable provenance (status zero_actionable, actionable count 0) proves
    # no order/pair/money path was created from the source scan; an active submit lease or an
    # active fail-closed halt still blocks normalization. Every other invalid state fails closed.
    if str(event_detail.get('source_retry') or '').strip():
      return None
    identity_fields = (
      'source_scan_session_id',
      'source_lane_session_id',
      'source_scan_scheduler_lease_id',
      'source_terminal_status',
      'source_terminal_at_utc',
      'source_lease_released_at_utc',
      'source_released_lease_id',
      'source_release_reason',
    )
    if not all(str(event_detail.get(key) or '').strip() for key in identity_fields):
      return None
    if str(event_detail.get('source_actionability_status') or '').strip().lower() != 'zero_actionable':
      return None
    if int(event_detail.get('source_actionable_candidate_count') or 0) != 0:
      return None
    with scheduler_lock:
      halt_projection = scheduler_state.get('halt_projection') if isinstance(scheduler_state.get('halt_projection'), dict) else None
      active_lease = _scheduler_active_lease_locked(time.monotonic())
    if isinstance(halt_projection, dict) and bool(halt_projection.get('active')):
      return None
    if isinstance(active_lease, dict) and str(active_lease.get('owner') or '') == 'submit_bridge':
      return None
    event_detail['source_retry'] = 'zero_found_retry'
    return {
      'normalized_field': 'source_retry',
      'normalized_value': 'zero_found_retry',
      'normalization_reason': 'metadata_only_gap_zero_actionable_provenance',
    }

  def _retry_elapsed_interrupted_by_stop_or_cancel() -> tuple[bool, str]:
    scan_snapshot = _scan_runtime_snapshot()
    scan_status = str(scan_snapshot.get('status') or '').strip().lower()
    scan_stage = str(scan_snapshot.get('stage') or '').strip().lower()
    with scheduler_lock:
      state_owner = str(scheduler_state.get('owner') or '').strip().lower()
      halt_projection = scheduler_state.get('halt_projection') if isinstance(scheduler_state.get('halt_projection'), dict) else {}
    halt_kind = str((halt_projection or {}).get('kind') or '').strip().lower()
    if str(automation_overlay_state.get('state_id') or '').strip().lower() == 'stopped':
      return True, 'automation_stopped'
    if state_owner in {'stop', 'manual_stop', 'cancel'}:
      return True, f'{state_owner}_owns_scheduler'
    if halt_kind in {'automation_stopped', 'scan_canceled_halted'}:
      return True, halt_kind
    if bool(scan_snapshot.get('cancel_requested')) or scan_status in {'canceling', 'canceled', 'cancelled'}:
      return True, f'scan_{scan_status or scan_stage or "cancel_requested"}'
    return False, ''

  def _scheduler_start_retry_timer(
    settings: Any,
    env_override: str | None,
    subaccount_override: int | None,
    lane_session_id: str,
    after_sec: float,
    *,
    source: str = 'zero_found_retry',
    source_terminal_ref: JSONDict | None = None,
  ) -> None:
    timer_ref: list[Any] = [None]
    timer_record = _scheduler_set_timer_record(
      'retry',
      source=source,
      lane_session_id=lane_session_id,
      after_sec=after_sec,
      source_terminal_ref=source_terminal_ref,
    )

    def _callback() -> None:
      elapsed_detail: JSONDict = {'lane_session_id': lane_session_id, 'source': source}
      with scheduler_lock:
        if scheduler_state.get('retry_timer') is not timer_ref[0]:
          return
        scheduler_state['retry_timer'] = None
        records = scheduler_state.get('timer_records') if isinstance(scheduler_state.get('timer_records'), dict) else {}
        if isinstance(records, dict):
          live_record = records.get('retry') if isinstance(records.get('retry'), dict) else timer_record
          if isinstance(live_record, dict):
            elapsed_detail.update(
              {
                key: value
                for key, value in live_record.items()
                if str(key or '').startswith('source_')
              }
            )
          records['retry'] = None
      _scheduler_handle_event(
        'retry_timer_elapsed',
        elapsed_detail,
        settings,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )

    with scheduler_lock:
      existing = scheduler_state.get('retry_timer')
      if existing is not None:
        existing.cancel()
      t = threading.Timer(after_sec, _callback)
      timer_ref[0] = t
      scheduler_state['retry_timer'] = t
      # SCHEDULER_ELIGIBILITY_THRESHOLD_REALIGNMENT_BMAP_2026-06-29 (C3 / INV-4): the threshold is
      # an eligibility gate, not a focus-holder. The timer must NOT claim scheduler ownership;
      # ownership during a wait is derived in the snapshot from the armed timer record. The pending
      # scan is cleared so it does not pollute the snapshot while the threshold counts down.
      scheduler_state['pending_action'] = None
      scheduler_state['pending_reason'] = ''
      scheduler_state['halt_projection'] = None
    t.start()

  def _scheduler_start_cadence_timer(
    settings: Any,
    env_override: str | None,
    subaccount_override: int | None,
    lane_session_id: str,
    after_sec: float,
    *,
    source: str = 'automation_cadence',
    source_terminal_ref: JSONDict | None = None,
  ) -> None:
    timer_ref: list[Any] = [None]
    timer_record = _scheduler_set_timer_record(
      'cadence',
      source=source,
      lane_session_id=lane_session_id,
      after_sec=after_sec,
      source_terminal_ref=source_terminal_ref,
    )

    def _callback() -> None:
      elapsed_detail: JSONDict = {'lane_session_id': lane_session_id, 'source': source}
      with scheduler_lock:
        if scheduler_state.get('cadence_timer') is not timer_ref[0]:
          return
        scheduler_state['cadence_timer'] = None
        records = scheduler_state.get('timer_records') if isinstance(scheduler_state.get('timer_records'), dict) else {}
        if isinstance(records, dict):
          live_record = records.get('cadence') if isinstance(records.get('cadence'), dict) else timer_record
          if isinstance(live_record, dict):
            elapsed_detail.update(
              {
                key: value
                for key, value in live_record.items()
                if str(key or '').startswith('source_')
              }
            )
          records['cadence'] = None
      _scheduler_handle_event(
        'cadence_timer_elapsed',
        elapsed_detail,
        settings,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )

    with scheduler_lock:
      existing = scheduler_state.get('cadence_timer')
      if existing is not None:
        existing.cancel()
      t = threading.Timer(after_sec, _callback)
      timer_ref[0] = t
      scheduler_state['cadence_timer'] = t
      # SCHEDULER_ELIGIBILITY_THRESHOLD_REALIGNMENT_BMAP_2026-06-29 (C3 / INV-4): the threshold is
      # an eligibility gate, not a focus-holder. The timer must NOT claim scheduler ownership;
      # ownership during a wait is derived in the snapshot from the armed timer record.
      scheduler_state['pending_action'] = None
      scheduler_state['pending_reason'] = ''
      scheduler_state['halt_projection'] = None
    t.start()

  # AUTOMATION_CADENCE_RECOVERY_AND_INACTIVITY_GUARD_BMAP_2026-07-02 (C5 / Lane E, D9/D10):
  # scheduler-owned inactivity guard. A single one-shot dead-man watchdog timer, re-armed by
  # every authoritative scheduler event, firing only after a genuinely silent gap. No polling
  # loop, no tick thread, no frontend or monitor participation. Recovery is scan-only through
  # existing scheduler admission, budget-limited, and never overrides stop/pause/cancel,
  # explicit halts, active leases, or active timer records.
  INACTIVITY_GUARD_PAD_SEC = 90.0
  INACTIVITY_GUARD_MAX_RECOVERIES = 2
  INACTIVITY_GUARD_BUDGET_WINDOW_SEC = 900.0

  def _inactivity_guard_trigger_threshold_sec() -> float | None:
    # D10: operator auto-find-candidates cadence plus a fixed pad, read at each re-arm. An absent
    # or invalid cadence value yields None — the guard rests in explicit 'disabled' state; the
    # guard trigger itself takes no substitute value.
    cadence_ms = int(automation_overlay_state.get('cadence_ms') or 0)
    if cadence_ms <= 0:
      return None
    return float(cadence_ms) / 1000.0 + INACTIVITY_GUARD_PAD_SEC

  def _inactivity_guard_set_state(state: str) -> str:
    with scheduler_lock:
      previous = str(scheduler_state.get('inactivity_guard_state') or '')
      scheduler_state['inactivity_guard_state'] = state
    return previous

  def _scheduler_cancel_inactivity_guard(reason: str) -> None:
    with scheduler_lock:
      existing = scheduler_state.get('inactivity_guard_timer')
      scheduler_state['inactivity_guard_timer'] = None
      records = scheduler_state.get('timer_records') if isinstance(scheduler_state.get('timer_records'), dict) else {}
      if isinstance(records, dict):
        records['guard'] = None
    if existing is not None:
      existing.cancel()

  def _persist_inactivity_guard_event(
    settings: Any | None,
    event_type: str,
    *,
    state: str,
    reason: str,
    threshold_sec: float | None,
    lane_session_id: str,
    extra: JSONDict | None = None,
  ) -> None:
    snapshot = _scheduler_build_snapshot(
      settings=settings,
      source='inactivity_guard',
      decision=event_type,
      owner_reason=reason,
    )
    detail: JSONDict = {
      'guard_state': state,
      'guard_reason': reason,
      'guard_threshold_sec': threshold_sec,
      'guard_lane_session_id': lane_session_id,
      'last_scheduler_event': str(scheduler_state.get('last_event') or ''),
      'last_scheduler_event_at_utc': str(scheduler_state.get('last_event_at_utc') or ''),
    }
    if isinstance(extra, dict):
      detail.update(extra)
    _persist_scheduler_event(
      settings,
      event_type,
      snapshot,
      level='WARN' if state in {'slow_work', 'blocked_fail_closed', 'budget_exhausted'} else 'INFO',
      extra_detail=detail,
    )

  def _inactivity_guard_classify(lane_session_id: str) -> tuple[str, str]:
    # C5: one classification pass against authoritative scheduler facts. Anything active or
    # ambiguous is a no-action state; only a verified silent idle gap is recoverable.
    if not bool(automation_overlay_state.get('enabled')) or bool(automation_overlay_state.get('paused')):
      return 'disabled', 'automation_disabled_or_paused'
    if _inactivity_guard_trigger_threshold_sec() is None:
      return 'disabled', 'cadence_value_absent'
    with scheduler_lock:
      halt_projection = scheduler_state.get('halt_projection') if isinstance(scheduler_state.get('halt_projection'), dict) else None
      active_lease = _scheduler_active_lease_locked(time.monotonic())
      records = scheduler_state.get('timer_records') if isinstance(scheduler_state.get('timer_records'), dict) else {}
      retry_record = records.get('retry') if isinstance(records.get('retry'), dict) else None
      cadence_record = records.get('cadence') if isinstance(records.get('cadence'), dict) else None
      state_owner = str(scheduler_state.get('owner') or '').strip().lower()
      pending_action = str(scheduler_state.get('pending_action') or '').strip().lower()
      pending_reason = str(scheduler_state.get('pending_reason') or '').strip().lower()
      recovery_history = list(scheduler_state.get('inactivity_guard_recovery_history') or [])
      review_state_id = str(review_selection_state.get('state_id') or '').strip().lower()
      failed_submit_attempt = review_selection_state.get('failed_submit_attempt') if isinstance(review_selection_state.get('failed_submit_attempt'), dict) else {}
    if str(automation_overlay_state.get('state_id') or '').strip().lower() == 'stopped' or state_owner in {'stop', 'manual_stop', 'cancel'}:
      return 'blocked_fail_closed', 'stop_or_cancel_ownership'
    if isinstance(halt_projection, dict) and bool(halt_projection.get('active')):
      return 'blocked_fail_closed', str(halt_projection.get('kind') or 'explicit_halt')
    if review_state_id == 'review_hold_saved_selection_locked' and _scheduler_submit_ready():
      return 'blocked_fail_closed', 'submit_ready_saved_set'
    if bool(failed_submit_attempt.get('failed_submit_money_path_crossed')):
      return 'blocked_fail_closed', 'failed_submit_money_path_crossed'
    if (isinstance(retry_record, dict) and bool(retry_record.get('active'))) or (
      isinstance(cadence_record, dict) and bool(cadence_record.get('active'))
    ):
      return 'healthy_wait', 'active_timer_record'
    if isinstance(active_lease, dict):
      return 'active_work', f"active_lease_{str(active_lease.get('owner') or 'unknown')}"
    scan_status = str(_scan_runtime_snapshot().get('status') or '').strip().lower()
    if scan_status in {'processing', 'canceling'}:
      return 'slow_work', f'scan_{scan_status}_without_lease'
    now_monotonic = time.monotonic()
    fresh_recoveries = [
      entry
      for entry in recovery_history
      if isinstance(entry, dict)
      and str(entry.get('lane_session_id') or '') == lane_session_id
      and now_monotonic - float(entry.get('monotonic') or 0.0) <= INACTIVITY_GUARD_BUDGET_WINDOW_SEC
    ]
    recovery_budget_available = len(fresh_recoveries) < INACTIVITY_GUARD_MAX_RECOVERIES
    if pending_action:
      # GUARD_RECOVERY_CORRECTION_AND_WATCH_STALE_ERROR_PROJECTION_BMAP_2026-07-02 (G2 / D13):
      # the socket-deferred pending scan is the one recoverable pending class, and every
      # recoverable classification is budget-gated; all other pending work stays protected.
      if pending_action == 'scan' and pending_reason.startswith('socket_'):
        if not recovery_budget_available:
          return 'budget_exhausted', 'recovery_budget_reached'
        return 'recoverable_idle_gap', f'deferred_scan_{pending_reason}'
      return 'active_work', f'pending_{pending_action}'
    if not recovery_budget_available:
      return 'budget_exhausted', 'recovery_budget_reached'
    return 'recoverable_idle_gap', 'no_lease_no_timer_no_halt'

  def _inactivity_guard_fire(
    settings: Any,
    env_override: str | None,
    subaccount_override: int | None,
    lane_session_id: str,
    threshold_sec: float,
  ) -> None:
    state, reason = _inactivity_guard_classify(lane_session_id)
    _inactivity_guard_set_state(state)
    _persist_inactivity_guard_event(
      settings,
      'inactivity_guard_decision',
      state=state,
      reason=reason,
      threshold_sec=threshold_sec,
      lane_session_id=lane_session_id,
    )
    if state == 'recoverable_idle_gap':
      _inactivity_guard_set_state('recovering')
      with scheduler_lock:
        history = scheduler_state.get('inactivity_guard_recovery_history')
        if not isinstance(history, list):
          history = []
          scheduler_state['inactivity_guard_recovery_history'] = history
        history.append({'lane_session_id': lane_session_id, 'monotonic': time.monotonic()})
      dispatch_result = _scheduler_dispatch_scan_internal(
        settings,
        env_override,
        subaccount_override,
        source='automation_cadence',
        captured_lane_session_id=lane_session_id,
      )
      dispatched = str(dispatch_result or '') == 'admitted'
      _persist_inactivity_guard_event(
        settings,
        'inactivity_guard_recovery_dispatched' if dispatched else 'inactivity_guard_recovery_deferred',
        state='recovering',
        reason=str(dispatch_result or 'no_op'),
        threshold_sec=threshold_sec,
        lane_session_id=lane_session_id,
      )
      if dispatched:
        _inactivity_guard_set_state('observing')
        return
      # GUARD_RECOVERY_CORRECTION_AND_WATCH_STALE_ERROR_PROJECTION_BMAP_2026-07-02 (G1 / D12):
      # a non-admitted recovery (deferred/no-op — e.g. the websocket is still down) must not end
      # the firing with the guard unarmed: socket reconnection emits no scheduler event, so an
      # unarmed guard here would turn a one-shot deferral into a permanent freeze.
      _scheduler_rearm_inactivity_guard(settings, env_override, subaccount_override, lane_session_id)
      return
    if state == 'disabled':
      _scheduler_cancel_inactivity_guard(reason)
      return
    # No-action states (healthy_wait / active_work / slow_work / blocked_fail_closed /
    # budget_exhausted) re-arm so the guard keeps observing without polling.
    _scheduler_rearm_inactivity_guard(settings, env_override, subaccount_override, lane_session_id)

  def _scheduler_rearm_inactivity_guard(
    settings: Any,
    env_override: str | None,
    subaccount_override: int | None,
    lane_session_id: str,
  ) -> None:
    # D9: dead-man's switch — every authoritative scheduler event pushes the deadline forward, so
    # the watchdog only ever fires after a genuinely silent gap. Stale firings are discarded by
    # the timer identity check, mirroring the retry/cadence timer pattern.
    if not bool(automation_overlay_state.get('enabled')) or bool(automation_overlay_state.get('paused')):
      _inactivity_guard_set_state('disabled')
      _scheduler_cancel_inactivity_guard('automation_inactive')
      return
    threshold_sec = _inactivity_guard_trigger_threshold_sec()
    if threshold_sec is None:
      previous = _inactivity_guard_set_state('disabled')
      _scheduler_cancel_inactivity_guard('cadence_value_absent')
      if previous not in {'', 'disabled'}:
        _persist_inactivity_guard_event(
          settings,
          'inactivity_guard_decision',
          state='disabled',
          reason='cadence_value_absent',
          threshold_sec=None,
          lane_session_id=lane_session_id,
        )
      return
    timer_ref: list[Any] = [None]
    _scheduler_set_timer_record(
      'guard',
      source='inactivity_guard',
      lane_session_id=lane_session_id,
      after_sec=threshold_sec,
    )

    def _callback() -> None:
      with scheduler_lock:
        if scheduler_state.get('inactivity_guard_timer') is not timer_ref[0]:
          return
        scheduler_state['inactivity_guard_timer'] = None
        records = scheduler_state.get('timer_records') if isinstance(scheduler_state.get('timer_records'), dict) else {}
        if isinstance(records, dict):
          records['guard'] = None
      _inactivity_guard_fire(settings, env_override, subaccount_override, lane_session_id, threshold_sec)

    with scheduler_lock:
      existing = scheduler_state.get('inactivity_guard_timer')
      if existing is not None:
        existing.cancel()
      t = threading.Timer(threshold_sec, _callback)
      timer_ref[0] = t
      scheduler_state['inactivity_guard_timer'] = t
    _inactivity_guard_set_state('observing')
    t.start()

  def _scheduler_finish_event(
    snapshot: JSONDict,
    settings: Any,
    env_override: str | None,
    subaccount_override: int | None,
    lane_session_id: str,
    normalized_event: str,
  ) -> JSONDict:
    if normalized_event in {'automation_stopped', 'automation_paused'}:
      _scheduler_cancel_inactivity_guard(normalized_event)
      return snapshot
    if not bool(automation_overlay_state.get('enabled')) or bool(automation_overlay_state.get('paused')):
      _scheduler_cancel_inactivity_guard('automation_inactive')
      _inactivity_guard_set_state('disabled')
      return snapshot
    _scheduler_rearm_inactivity_guard(settings, env_override, subaccount_override, lane_session_id)
    return snapshot

  def _scheduler_handle_event(
    event: str,
    detail: JSONDict,
    settings: Any,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict:
    normalized_event = str(event or '').strip().lower()
    event_detail = dict(detail or {})
    lane_session_id = str(
      event_detail.get('lane_session_id')
      or _scheduler_socket_snapshot(settings).get('lane_session_id')
      or ''
    )
    with scheduler_lock:
      scheduler_state['last_event'] = normalized_event
      scheduler_state['last_event_at_utc'] = _scheduler_utc_now()

    if normalized_event == 'automation_stopped':
      transition_reason = str(event_detail.get('reason') or 'operator_stop')
      transition_message = str(event_detail.get('message') or 'Automation policy stopped.')
      if not lane_session_id:
        lane_session_id = str(
          _scan_runtime_snapshot().get('lane_session_id')
          or review_selection_state.get('persisted_lane_session_id')
          or ''
        )
      gate_snapshot = _scheduler_stop_gate_snapshot(event_detail, lane_session_id)
      automation_overlay_state['enabled'] = False
      automation_overlay_state['paused'] = False
      automation_overlay_state['state_id'] = 'stopped'
      automation_overlay_state['last_transition_action'] = 'stop'
      automation_overlay_state['last_transition_reason'] = transition_reason
      automation_overlay_state['last_transition_at_utc'] = _utc_now_iso()
      _sync_runtime_overlay_auto_find_candidates_cadence(
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      _scheduler_cancel_timers()
      _scheduler_stage_stop_scan_cancel(settings)
      cancel_summary, halted_candidate_count = _run_operator_teardown(
        active_settings=settings,
        lane_session_id=lane_session_id,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      stop_teardown = _scheduler_normalized_stop_teardown(
        settings=settings,
        lane_session_id=lane_session_id,
        transition_reason=transition_reason,
        cancel_summary=cancel_summary,
        halted_candidate_count=halted_candidate_count,
      )
      if settings is not None:
        _persist_automation_transition(
          settings=settings,
          action_name='stop',
          transition_reason=transition_reason,
          transition_message=transition_message,
          gate_snapshot=gate_snapshot,
        )
      with scheduler_lock:
        scheduler_state['owner'] = 'stop'
        scheduler_state['pending_action'] = None
        scheduler_state['pending_reason'] = ''
        scheduler_state['stop_teardown'] = stop_teardown
        scheduler_state['halt_projection'] = {
          'active': True,
          'kind': 'automation_stopped',
          'reason': transition_reason,
          'operator_action': 'start_automation',
          'retryable': False,
        }
      snapshot = _scheduler_build_snapshot(
        settings=settings,
        source=normalized_event,
        decision='interrupt',
        owner='stop',
        owner_reason=transition_reason,
      )
      snapshot['stop_teardown'] = dict(stop_teardown)
      _persist_scheduler_event(
        settings,
        f'scheduler_event_{normalized_event}',
        snapshot,
        extra_detail={**event_detail, 'stop_teardown': stop_teardown},
      )
      return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)

    if normalized_event == 'automation_paused':
      _scheduler_cancel_timers()
      with scheduler_lock:
        scheduler_state['owner'] = 'idle'
        scheduler_state['pending_action'] = None
        scheduler_state['pending_reason'] = ''
        scheduler_state['stop_teardown'] = None
        scheduler_state['halt_projection'] = {
          'active': True,
          'kind': 'automation_paused',
          'reason': str(event_detail.get('reason') or normalized_event),
          'operator_action': 'resume_automation',
          'retryable': False,
        }
      snapshot = _scheduler_build_snapshot(
        settings=settings,
        source=normalized_event,
        decision='interrupt',
        owner='idle',
        owner_reason=str(event_detail.get('reason') or normalized_event),
      )
      _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail=event_detail)
      return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)

    if normalized_event == 'automation_enabled':
      if not bool(automation_overlay_state.get('enabled')) or bool(automation_overlay_state.get('paused')):
        snapshot = _scheduler_build_snapshot(settings=settings, source=normalized_event, decision='noop', owner_reason='automation_inactive')
        _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail=event_detail)
        return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      if _scheduler_submit_ready():
        _scheduler_cancel_timers()
        with scheduler_lock:
          scheduler_state['owner'] = 'submit'
          scheduler_state['pending_action'] = 'submit'
          scheduler_state['pending_reason'] = 'saved_set_ready'
          scheduler_state['stop_teardown'] = None
          scheduler_state['halt_projection'] = None
        result = _scheduler_dispatch_submit_internal(
          settings,
          env_override,
          subaccount_override,
          source='backend_auto_dispatch',
          captured_lane_session_id=lane_session_id,
        )
        snapshot = _scheduler_build_snapshot(
          settings=settings,
          source=normalized_event,
          decision=result,
          owner_reason='saved_set_ready',
        )
        _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail=event_detail)
        return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      with scheduler_lock:
        scheduler_state['owner'] = 'scan'
        scheduler_state['pending_action'] = 'scan'
        scheduler_state['pending_reason'] = 'automation_enabled'
        scheduler_state['stop_teardown'] = None
        scheduler_state['halt_projection'] = None
      result = _scheduler_dispatch_scan_internal(
        settings,
        env_override,
        subaccount_override,
        source='automation_cadence',
        captured_lane_session_id=lane_session_id,
      )
      snapshot = _scheduler_build_snapshot(
        settings=settings,
        source=normalized_event,
        decision=result,
        owner_reason='automation_enabled',
      )
      _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail=event_detail)
      return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)

    if normalized_event == 'scan_terminal':
      terminal_status = str(event_detail.get('status') or '').strip().lower()
      automation_active = bool(automation_overlay_state.get('enabled')) and not bool(automation_overlay_state.get('paused'))
      token_valid, token_reason, scan_terminal_token = _validate_scan_terminal_completion_token(
        event_detail,
        automation_active=automation_active,
        lane_session_id=lane_session_id,
      )
      if not token_valid:
        halt_projection = {
          'active': True,
          'kind': 'scan_terminal_contract_invalid',
          'reason': token_reason,
          'operator_action': 'inspect_evidence',
          'retryable': False,
        }
        with scheduler_lock:
          scheduler_state['owner'] = 'idle'
          scheduler_state['pending_action'] = None
          scheduler_state['pending_reason'] = ''
          scheduler_state['halt_projection'] = halt_projection
        snapshot = _scheduler_build_snapshot(
          settings=settings,
          source=normalized_event,
          decision='halted_scan_terminal_contract_invalid',
          owner_reason=token_reason,
        )
        _persist_scheduler_event(
          settings,
          f'scheduler_event_{normalized_event}',
          snapshot,
          level='ERROR',
          extra_detail={**event_detail, 'token_validation_reason': token_reason},
        )
        return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      if terminal_status in {'failed', 'canceled', 'cancelled'}:
        terminal_reason = str(event_detail.get('reason') or '').strip().lower()
        scan_payload = event_detail.get('scan_payload') if isinstance(event_detail.get('scan_payload'), dict) else {}
        if not terminal_reason and isinstance(scan_payload, dict):
          terminal_reason = str(scan_payload.get('reason') or '').strip().lower()
        explicit_retryable = event_detail.get('retryable')
        retryable_failed = terminal_status == 'failed' and automation_active and explicit_retryable is not False
        if retryable_failed:
          retry_payload = event_detail.get('retry_payload') if isinstance(event_detail.get('retry_payload'), dict) else {}
          scan_retry = retry_payload.get('scan_retry') if isinstance(retry_payload.get('scan_retry'), dict) else {}
          retry_after_sec = float(int(scan_retry.get('retry_after_sec') or retry_payload.get('retry_after_sec') or 5))
          with scheduler_lock:
            scheduler_state['pending_retry_after_scan_release'] = {
              'source': 'scan_failure_retry',
              'lane_session_id': lane_session_id,
              'retry_after_sec': retry_after_sec,
              'scan_scheduler_lease_id': str(event_detail.get('scan_scheduler_lease_id') or ''),
              'source_terminal_ref': _scan_terminal_source_ref_from_token(scan_terminal_token),
              'env_override': env_override,
              'subaccount_override': subaccount_override,
            }
          snapshot = _scheduler_build_snapshot(
            settings=settings,
            source=normalized_event,
            decision='retry_timer_pending_scan_release',
            owner_reason='scan_failed_retry',
          )
          _persist_scheduler_event(
            settings,
            f'scheduler_event_{normalized_event}',
            snapshot,
            extra_detail={**event_detail, 'retry_source': 'scan_failure_retry'},
          )
          return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
        halt_projection: JSONDict | None = None
        decision = 'terminal_no_continuation'
        owner_reason = terminal_status or 'scan_terminal'
        if automation_active:
          halted_kind = 'scan_canceled_halted' if terminal_status in {'canceled', 'cancelled'} else 'scan_failed_halted'
          halt_projection = {
            'active': True,
            'kind': halted_kind,
            'reason': terminal_reason or terminal_status or 'scan_terminal',
            'operator_action': 'find_candidates',
            'retryable': False,
          }
          decision = 'halted_scan_canceled' if terminal_status in {'canceled', 'cancelled'} else 'halted_scan_failed'
          owner_reason = halted_kind
        with scheduler_lock:
          scheduler_state['owner'] = 'idle'
          scheduler_state['pending_action'] = None
          scheduler_state['pending_reason'] = ''
          scheduler_state['halt_projection'] = halt_projection
        snapshot = _scheduler_build_snapshot(
          settings=settings,
          source=normalized_event,
          decision=decision,
          owner_reason=owner_reason,
        )
        _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail=event_detail)
        return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      found_count = int(event_detail.get('found_count') or 0)
      raw_found_count = int(
        scan_terminal_token.get('raw_found_count')
        if isinstance(scan_terminal_token, dict) and scan_terminal_token.get('raw_found_count') is not None
        else scan_terminal_token.get('found_count')
        if isinstance(scan_terminal_token, dict)
        else found_count
      )
      if terminal_status == 'completed' and not automation_active:
        actionability_resolution = {
          'schema_version': 1,
          'resolution_kind': 'scan_actionability_resolution',
          'source_scan_session_id': str(scan_terminal_token.get('scan_session_id') or ''),
          'source_lane_session_id': str(scan_terminal_token.get('lane_session_id') or ''),
          'source_scan_scheduler_lease_id': str(scan_terminal_token.get('scan_scheduler_lease_id') or ''),
          'source_terminal_status': str(scan_terminal_token.get('terminal_status') or ''),
          'raw_found_count': raw_found_count,
          'actionability_status': 'automation_inactive',
          'actionability_reason': 'automation_disabled_or_paused',
          'actionable_candidate_count': 0,
          'saved_set_id': '',
          'saved_set_recorded_at_utc': '',
          'candidate_signature': '',
          'candidate_keys': [],
          'submit_handoff_id': '',
          'retry_after_sec': None,
          'created_at_utc': _scheduler_utc_now(),
        }
        with scheduler_lock:
          scheduler_state['owner'] = 'idle'
          scheduler_state['pending_action'] = None
          scheduler_state['pending_reason'] = ''
          scheduler_state['halt_projection'] = None
        snapshot = _scheduler_build_snapshot(
          settings=settings,
          source=normalized_event,
          decision='scan_actionability_automation_inactive',
          owner_reason='automation_disabled_or_paused',
        )
        snapshot['scan_actionability_resolution'] = dict(actionability_resolution)
        _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail={**event_detail, 'found_count': found_count, 'scan_actionability_resolution': actionability_resolution})
        return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      if found_count > 0 and bool(automation_overlay_state.get('enabled')) and not bool(automation_overlay_state.get('paused')):
        _scheduler_cancel_timers()
        with scheduler_lock:
          scheduler_state['halt_projection'] = None
        scan_actionability_result = _scheduler_auto_select_and_submit_after_scan(
          settings,
          env_override,
          subaccount_override,
          scan_payload=event_detail.get('scan_payload') if isinstance(event_detail.get('scan_payload'), dict) else {},
          scan_scheduler_lease_id=str(event_detail.get('scan_scheduler_lease_id') or '') or None,
          scan_terminal_token=scan_terminal_token,
          captured_lane_session_id=lane_session_id,
        )
        actionability_resolution = dict(scan_actionability_result.get('scan_actionability_resolution') if isinstance(scan_actionability_result.get('scan_actionability_resolution'), dict) else {})
        actionability_status = str(actionability_resolution.get('actionability_status') or '').strip()
        invalid_reason = ''
        submit_handoff = scan_actionability_result.get('submit_handoff') if isinstance(scan_actionability_result.get('submit_handoff'), dict) else {}
        if not actionability_resolution:
          invalid_reason = 'missing_scan_actionability_resolution'
        elif actionability_status == 'actionable_ready':
          candidate_keys = list(actionability_resolution.get('candidate_keys') or [])
          if int(actionability_resolution.get('actionable_candidate_count') or 0) <= 0:
            invalid_reason = 'actionability_candidate_count_missing'
          elif not str(actionability_resolution.get('saved_set_id') or '').strip():
            invalid_reason = 'actionability_saved_set_missing'
          elif not str(actionability_resolution.get('candidate_signature') or '').strip():
            invalid_reason = 'actionability_candidate_signature_missing'
          elif not candidate_keys:
            invalid_reason = 'actionability_candidate_keys_missing'
          elif not str(actionability_resolution.get('submit_handoff_id') or '').strip():
            invalid_reason = 'actionability_submit_handoff_missing'
          elif not submit_handoff:
            invalid_reason = 'actionability_submit_handoff_payload_missing'
        elif actionability_status == 'zero_actionable':
          if int(actionability_resolution.get('actionable_candidate_count') or 0) != 0:
            invalid_reason = 'zero_actionability_candidate_count_nonzero'
          elif not actionability_resolution.get('retry_after_sec'):
            invalid_reason = 'zero_actionability_retry_after_missing'
        elif actionability_status == 'automation_inactive':
          snapshot = _scheduler_build_snapshot(
            settings=settings,
            source=normalized_event,
            decision='scan_actionability_automation_inactive',
            owner_reason='automation_disabled_or_paused',
          )
          snapshot['scan_actionability_resolution'] = dict(actionability_resolution)
          _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail={**event_detail, 'found_count': found_count, 'scan_actionability_resolution': actionability_resolution})
          return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
        elif actionability_status == 'contract_invalid':
          invalid_reason = str(actionability_resolution.get('actionability_reason') or 'contract_invalid')
        else:
          invalid_reason = 'unknown_scan_actionability_status'
        if invalid_reason:
          actionability_resolution.setdefault('schema_version', 1)
          actionability_resolution.setdefault('resolution_kind', 'scan_actionability_resolution')
          actionability_resolution['actionability_status'] = 'contract_invalid'
          actionability_resolution['actionability_reason'] = invalid_reason
          with scheduler_lock:
            scheduler_state['owner'] = 'idle'
            scheduler_state['pending_action'] = None
            scheduler_state['pending_reason'] = ''
            scheduler_state['halt_projection'] = {
              'active': True,
              'kind': 'scan_actionability_contract_invalid',
              'reason': invalid_reason,
              'operator_action': 'inspect_evidence',
              'retryable': False,
            }
          snapshot = _scheduler_build_snapshot(
            settings=settings,
            source=normalized_event,
            decision='halted_scan_actionability_contract_invalid',
            owner_reason=invalid_reason,
          )
          snapshot['scan_actionability_resolution'] = dict(actionability_resolution)
          _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, level='ERROR', extra_detail={**event_detail, 'found_count': found_count, 'scan_actionability_resolution': actionability_resolution})
          return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
        if actionability_status == 'actionable_ready':
          pre_dispatch_snapshot = _scheduler_build_snapshot(
            settings=settings,
            source=normalized_event,
            decision='actionable_submit_handoff',
            owner_reason='scan_found_candidates',
          )
          pre_dispatch_snapshot['scan_actionability_resolution'] = dict(actionability_resolution)
          _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', pre_dispatch_snapshot, extra_detail={**event_detail, 'found_count': found_count, 'scan_actionability_resolution': actionability_resolution})
          _scheduler_release_lease(
            settings,
            str(event_detail.get('scan_scheduler_lease_id') or '') or None,
            reason='scan_runtime_released_for_submit_dispatch',
            source='scan_runtime',
          )
          with scheduler_lock:
            scheduler_state['pending_action'] = 'submit'
            scheduler_state['pending_reason'] = 'scan_found_candidates'
          submit_dispatch_result = _scheduler_dispatch_submit_internal(
            settings,
            env_override,
            subaccount_override,
            source='backend_auto_dispatch',
            captured_lane_session_id=lane_session_id,
            submit_handoff=submit_handoff,
          )
          snapshot = _scheduler_build_snapshot(
            settings=settings,
            source=normalized_event,
            decision=submit_dispatch_result,
            owner_reason='scan_found_candidates',
          )
          snapshot['scan_lease_released'] = True
          snapshot['scan_actionability_resolution'] = dict(actionability_resolution)
          return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
        retry_after_sec = float(int(actionability_resolution.get('retry_after_sec') or 5))
        with scheduler_lock:
          scheduler_state['pending_retry_after_scan_release'] = {
            'source': 'zero_found_retry',
            'lane_session_id': lane_session_id,
            'retry_after_sec': retry_after_sec,
            'scan_scheduler_lease_id': str(event_detail.get('scan_scheduler_lease_id') or ''),
            'source_terminal_ref': _zero_actionable_retry_source_ref(scan_terminal_token, actionability_resolution),
            'env_override': env_override,
            'subaccount_override': subaccount_override,
          }
        snapshot = _scheduler_build_snapshot(settings=settings, source=normalized_event, decision='retry_timer_pending_scan_release', owner_reason='zero_found_retry')
        snapshot['scan_actionability_resolution'] = dict(actionability_resolution)
        _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail={**event_detail, 'found_count': found_count, 'scan_actionability_resolution': actionability_resolution})
        return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      # SCHEDULER_ELIGIBILITY_THRESHOLD_REALIGNMENT_BMAP_2026-06-29 (C2 / INV-1): a zero-candidate
      # terminal routes to the retry eligibility threshold regardless of WHY it was empty
      # (empty entry-window and loaded-but-zero-qualifying are treated identically). Cadence is
      # reserved for the post-submit/shelter beat (submit_terminal) and never starts on a found==0
      # path. The scheduler authors the deadline; retry_after_sec is taken from the engine retry
      # metadata when present, else the default.
      if found_count == 0 and bool(automation_overlay_state.get('enabled')) and not bool(automation_overlay_state.get('paused')):
        retry_payload = event_detail.get('retry_payload') if isinstance(event_detail.get('retry_payload'), dict) else {}
        scan_retry = retry_payload.get('scan_retry') if isinstance(retry_payload.get('scan_retry'), dict) else {}
        retry_after_sec = float(int(scan_retry.get('retry_after_sec') or retry_payload.get('retry_after_sec') or 5))
        actionability_resolution = {
          'schema_version': 1,
          'resolution_kind': 'scan_actionability_resolution',
          'source_scan_session_id': str(scan_terminal_token.get('scan_session_id') or ''),
          'source_lane_session_id': str(scan_terminal_token.get('lane_session_id') or ''),
          'source_scan_scheduler_lease_id': str(scan_terminal_token.get('scan_scheduler_lease_id') or ''),
          'source_terminal_status': str(scan_terminal_token.get('terminal_status') or ''),
          'raw_found_count': raw_found_count,
          'actionability_status': 'zero_actionable',
          'actionability_reason': 'raw_zero',
          'actionable_candidate_count': 0,
          'saved_set_id': '',
          'saved_set_recorded_at_utc': '',
          'candidate_signature': '',
          'candidate_keys': [],
          'submit_handoff_id': '',
          'retry_after_sec': retry_after_sec,
          'created_at_utc': _scheduler_utc_now(),
        }
        with scheduler_lock:
          scheduler_state['pending_retry_after_scan_release'] = {
            'source': 'zero_found_retry',
            'lane_session_id': lane_session_id,
            'retry_after_sec': retry_after_sec,
            'scan_scheduler_lease_id': str(event_detail.get('scan_scheduler_lease_id') or ''),
            'source_terminal_ref': _zero_actionable_retry_source_ref(scan_terminal_token, actionability_resolution),
            'env_override': env_override,
            'subaccount_override': subaccount_override,
          }
        snapshot = _scheduler_build_snapshot(settings=settings, source=normalized_event, decision='retry_timer_pending_scan_release', owner_reason='zero_found_retry')
        snapshot['scan_actionability_resolution'] = dict(actionability_resolution)
        _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail={**event_detail, 'found_count': found_count, 'scan_actionability_resolution': actionability_resolution})
        return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)

    if normalized_event == 'retry_timer_elapsed':
      retry_source = str(event_detail.get('source') or 'zero_found_retry').strip().lower() or 'zero_found_retry'
      # AUTOMATION_CADENCE_RECOVERY_AND_INACTIVITY_GUARD_BMAP_2026-07-02 (C2 / Lane B): metadata-
      # only self-correction runs before validation and persists warning evidence; every other
      # invalid state falls through to the fail-closed halt below.
      normalization_evidence = _normalize_metadata_only_retry_source_gap(event_detail)
      if normalization_evidence is not None:
        normalization_snapshot = _scheduler_build_snapshot(
          settings=settings,
          source=normalized_event,
          decision='retry_source_ref_normalized',
          owner_reason='metadata_only_retry_source_gap',
        )
        _persist_scheduler_event(settings, 'scheduler_retry_source_ref_normalized', normalization_snapshot, level='WARN', extra_detail={**event_detail, **normalization_evidence})
      if retry_source in {'zero_found_retry', 'scan_failure_retry'} and not _retry_elapsed_source_ref_valid(event_detail):
        with scheduler_lock:
          scheduler_state['owner'] = 'idle'
          scheduler_state['pending_action'] = None
          scheduler_state['pending_reason'] = ''
          scheduler_state['halt_projection'] = {
            'active': True,
            'kind': 'retry_timer_contract_invalid',
            'reason': 'missing_retry_source_terminal_ref',
            'operator_action': 'inspect_evidence',
            'retryable': False,
          }
        snapshot = _scheduler_build_snapshot(
          settings=settings,
          source=normalized_event,
          decision='halted_retry_timer_contract_invalid',
          owner_reason='missing_retry_source_terminal_ref',
        )
        _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, level='ERROR', extra_detail=event_detail)
        return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      interrupted, interrupt_reason = _retry_elapsed_interrupted_by_stop_or_cancel()
      if interrupted:
        with scheduler_lock:
          scheduler_state['owner'] = 'stop' if 'stop' in interrupt_reason else 'cancel'
          scheduler_state['pending_action'] = None
          scheduler_state['pending_reason'] = ''
        snapshot = _scheduler_build_snapshot(
          settings=settings,
          source=normalized_event,
          decision='interrupted',
          owner_reason=interrupt_reason,
        )
        _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail={**event_detail, 'interrupt_reason': interrupt_reason})
        return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      with scheduler_lock:
        scheduler_state['owner'] = 'scan'
        scheduler_state['pending_action'] = 'scan'
        scheduler_state['pending_reason'] = f'{retry_source}_elapsed'
        scheduler_state['halt_projection'] = None
      pre_dispatch_snapshot = _scheduler_build_snapshot(
        settings=settings,
        source=normalized_event,
        decision='dispatch_requested',
        owner_reason=f'{retry_source}_elapsed',
      )
      _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', pre_dispatch_snapshot, extra_detail=event_detail)
      result = _scheduler_dispatch_scan_internal(
        settings,
        env_override,
        subaccount_override,
        source=retry_source,
        captured_lane_session_id=lane_session_id,
      )
      snapshot = _scheduler_build_snapshot(settings=settings, source=normalized_event, decision=result, owner_reason=f'{retry_source}_elapsed')
      return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)

    if normalized_event == 'cadence_timer_elapsed':
      cadence_source = str(event_detail.get('source') or '').strip().lower()
      if cadence_source == 'submit_completion':
        required_submit_source_fields = (
          'source_submit_token_kind',
          'source_submit_terminal_status',
          'source_submit_scheduler_lease_id',
          'source_saved_set_id',
          'source_candidate_signature',
          'source_submit_terminal_at_utc',
          'source_last_submit_completed_at_utc',
        )
        if not all(str(event_detail.get(key) or '').strip() for key in required_submit_source_fields):
          with scheduler_lock:
            scheduler_state['owner'] = 'idle'
            scheduler_state['pending_action'] = None
            scheduler_state['pending_reason'] = ''
            scheduler_state['halt_projection'] = {
              'active': True,
              'kind': 'cadence_timer_contract_invalid',
              'reason': 'missing_submit_source_token_ref',
              'operator_action': 'inspect_evidence',
              'retryable': False,
            }
          snapshot = _scheduler_build_snapshot(
            settings=settings,
            source=normalized_event,
            decision='halted_cadence_timer_contract_invalid',
            owner_reason='missing_submit_source_token_ref',
          )
          _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, level='ERROR', extra_detail=event_detail)
          return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      if _scheduler_submit_ready():
        with scheduler_lock:
          scheduler_state['owner'] = 'submit'
          scheduler_state['pending_action'] = 'submit'
          scheduler_state['pending_reason'] = 'cadence_elapsed_submit_ready'
          scheduler_state['halt_projection'] = None
        result = _scheduler_dispatch_submit_internal(
          settings,
          env_override,
          subaccount_override,
          source='backend_auto_dispatch',
          captured_lane_session_id=lane_session_id,
        )
      else:
        with scheduler_lock:
          scheduler_state['owner'] = 'scan'
          scheduler_state['pending_action'] = 'scan'
          scheduler_state['pending_reason'] = 'cadence_elapsed'
          scheduler_state['halt_projection'] = None
        result = _scheduler_dispatch_scan_internal(
          settings,
          env_override,
          subaccount_override,
          source='automation_cadence',
          captured_lane_session_id=lane_session_id,
        )
      snapshot = _scheduler_build_snapshot(settings=settings, source=normalized_event, decision=result, owner_reason='cadence_elapsed')
      _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail=event_detail)
      return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)

    if normalized_event == 'submit_terminal':
      terminal_status = str(event_detail.get('terminal_status') or event_detail.get('status') or '').strip().lower()
      with scheduler_lock:
        current_halt_projection = dict(scheduler_state.get('halt_projection')) if isinstance(scheduler_state.get('halt_projection'), dict) else None
      stopped_terminal = (
        str(automation_overlay_state.get('state_id') or '').strip().lower() == 'stopped'
        or str((current_halt_projection or {}).get('kind') or '').strip().lower() == 'automation_stopped'
      )
      automation_active = bool(automation_overlay_state.get('enabled')) and not bool(automation_overlay_state.get('paused'))
      submit_terminal_token = event_detail.get('submit_terminal_completion_token') if isinstance(event_detail.get('submit_terminal_completion_token'), dict) else {}
      token_required = automation_active and not stopped_terminal
      token_invalid_reason = ''
      if token_required and not submit_terminal_token:
        token_invalid_reason = 'missing_submit_terminal_completion_token'
      elif submit_terminal_token:
        if str(submit_terminal_token.get('token_kind') or '') != 'submit_terminal_completion':
          token_invalid_reason = 'invalid_submit_terminal_token_kind'
        elif int(submit_terminal_token.get('schema_version') or 0) != 1:
          token_invalid_reason = 'invalid_submit_terminal_token_schema'
        elif str(submit_terminal_token.get('terminal_status') or '').strip().lower() != terminal_status:
          token_invalid_reason = 'submit_terminal_status_mismatch'
        elif not bool(submit_terminal_token.get('verified_lease_released')):
          token_invalid_reason = 'submit_terminal_lease_not_verified'
        elif token_required and not str(submit_terminal_token.get('submit_scheduler_lease_id') or '').strip():
          token_invalid_reason = 'submit_terminal_lease_missing'
        elif terminal_status == 'completed' and not bool(submit_terminal_token.get('verified_submit_projection_recorded')):
          token_invalid_reason = 'submit_terminal_projection_not_verified'
        elif terminal_status == 'completed' and not str(submit_terminal_token.get('last_submit_completed_at_utc') or '').strip():
          token_invalid_reason = 'submit_terminal_completed_at_missing'
        else:
          current_saved_set_id = str(review_selection_state.get('saved_set_id') or '').strip()
          current_candidate_signature = str(review_selection_state.get('candidate_signature') or '').strip()
          token_saved_set_id = str(submit_terminal_token.get('saved_set_id') or '').strip()
          token_candidate_signature = str(submit_terminal_token.get('candidate_signature') or '').strip()
          if (
            str(review_selection_state.get('state_id') or '').strip().lower() == 'review_hold_saved_selection_locked'
            and current_saved_set_id
            and current_candidate_signature
            and (current_saved_set_id != token_saved_set_id or current_candidate_signature != token_candidate_signature)
          ):
            token_invalid_reason = 'submit_terminal_saved_set_mismatch'
      if token_invalid_reason:
        with scheduler_lock:
          scheduler_state['owner'] = 'idle'
          scheduler_state['pending_action'] = None
          scheduler_state['pending_reason'] = ''
          scheduler_state['halt_projection'] = {
            'active': True,
            'kind': 'submit_terminal_contract_invalid',
            'reason': token_invalid_reason,
            'operator_action': 'inspect_evidence',
            'retryable': False,
          }
        snapshot = _scheduler_build_snapshot(
          settings=settings,
          source=normalized_event,
          decision='halted_submit_terminal_contract_invalid',
          owner_reason=token_invalid_reason,
        )
        _persist_scheduler_event(
          settings,
          f'scheduler_event_{normalized_event}',
          snapshot,
          level='ERROR',
          extra_detail={**event_detail, 'token_validation_reason': token_invalid_reason},
        )
        return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      if terminal_status == 'failed':
        _submit_handoff = event_detail.get('submit_handoff') if isinstance(event_detail.get('submit_handoff'), dict) else {}
        _failed_failure_phase = str(submit_terminal_token.get('failure_phase') or event_detail.get('failure_phase') or '').strip()
        _failed_reason_code = str(submit_terminal_token.get('reason_code') or '').strip().lower()
        _failed_kalshi_method = str(submit_terminal_token.get('kalshi_method') or '').strip().upper()
        _failed_kalshi_endpoint = str(submit_terminal_token.get('kalshi_endpoint') or '').strip()
        _failed_error_family = str(submit_terminal_token.get('error_family') or '').strip()
        _failed_token_saved_set_id = str(submit_terminal_token.get('saved_set_id') or _submit_handoff.get('saved_set_id') or '').strip()
        _failed_token_candidate_signature = str(
          submit_terminal_token.get('candidate_signature') or _submit_handoff.get('candidate_signature') or ''
        ).strip()
        _failed_current_saved_set_id = str(review_selection_state.get('saved_set_id') or '').strip()
        _failed_current_candidate_signature = str(review_selection_state.get('candidate_signature') or '').strip()
        _failed_token_handoff_id = str(submit_terminal_token.get('submit_handoff_id') or _submit_handoff.get('handoff_id') or '').strip()
        _failed_current_halt = current_halt_projection if isinstance(current_halt_projection, dict) else {}
        _failed_current_halt_active = bool(_failed_current_halt.get('active'))
        _failed_current_halt_kind = str(_failed_current_halt.get('kind') or '').strip().lower()
        _failed_current_halt_saved_set_id = str(_failed_current_halt.get('saved_set_id') or '').strip()
        _failed_current_halt_handoff_id = str(_failed_current_halt.get('handoff_id') or '').strip()
        _failed_current_halt_clearable = (
          not _failed_current_halt_active
          or (
            _failed_current_halt_kind == 'submit_failed_halted'
            and (
              not _failed_current_halt_saved_set_id
              or _failed_current_halt_saved_set_id == _failed_token_saved_set_id
            )
            and (
              not _failed_current_halt_handoff_id
              or _failed_current_halt_handoff_id == _failed_token_handoff_id
            )
          )
        )
        _failed_required_fields_present = all(
          key in submit_terminal_token
          for key in (
            'failure_phase',
            'error_family',
            'reason_code',
            'kalshi_method',
            'kalshi_endpoint',
            'money_path_crossed',
            'pair_plan_created',
            'orders_created',
          )
        )
        _failed_order_id_absent = not any(
          str(submit_terminal_token.get(key) or '').strip()
          for key in (
            'accepted_order_id',
            'accepted_order_ids',
            'accepted_yes_order_id',
            'accepted_no_order_id',
            'yes_order_id',
            'no_order_id',
            'order_id',
            'order_ids',
            'client_order_id',
            'client_order_ids',
          )
        )
        _failed_exposure_absent = not any(
          str(submit_terminal_token.get(key) or '').strip()
          for key in (
            'pair_id',
            'pair_ids',
            'accepted_pair_id',
            'yes_filled_contracts',
            'no_filled_contracts',
            'filled_contracts',
          )
        )
        _recoverable_pre_order_submit_failure = (
          not stopped_terminal
          and bool(automation_overlay_state.get('enabled'))
          and not bool(automation_overlay_state.get('paused'))
          and bool(submit_terminal_token)
          and str(submit_terminal_token.get('token_kind') or '').strip() == 'submit_terminal_completion'
          and _failed_required_fields_present
          and _failed_current_saved_set_id
          and _failed_current_candidate_signature
          and _failed_token_saved_set_id == _failed_current_saved_set_id
          and _failed_token_candidate_signature == _failed_current_candidate_signature
          and _failed_failure_phase == 'submit_dispatch'
          and _failed_error_family == 'KalshiHttpError'
          and _failed_reason_code == 'network_timeout'
          and _failed_kalshi_method == 'GET'
          and _failed_kalshi_endpoint == '/portfolio/balance'
          and not bool(submit_terminal_token.get('money_path_crossed'))
          and not bool(submit_terminal_token.get('pair_plan_created'))
          and not bool(submit_terminal_token.get('orders_created'))
          and _failed_order_id_absent
          and _failed_exposure_absent
          and _failed_current_halt_clearable
        )
        if submit_terminal_token:
          review_selection_state['failed_submit_attempt'] = {
            'failed_submit_saved_set_id': str(submit_terminal_token.get('saved_set_id') or _submit_handoff.get('saved_set_id') or ''),
            'failed_submit_candidate_signature': str(submit_terminal_token.get('candidate_signature') or _submit_handoff.get('candidate_signature') or ''),
            'failed_submit_handoff_id': str(submit_terminal_token.get('submit_handoff_id') or _submit_handoff.get('handoff_id') or ''),
            'failed_submit_terminal_at_utc': str(submit_terminal_token.get('submit_terminal_at_utc') or _scheduler_utc_now()),
            'failed_submit_failure_phase': str(submit_terminal_token.get('failure_phase') or event_detail.get('failure_phase') or ''),
            'failed_submit_money_path_crossed': bool(submit_terminal_token.get('money_path_crossed')),
          }
          review_selection_state['saved_set_status_reason'] = 'Submit was attempted and failed before order placement.'
        event_detail['submit_failure_classification'] = (
          'pre_order_connectivity_failed' if _recoverable_pre_order_submit_failure else 'dangerous_submit_failure'
        )
        if _recoverable_pre_order_submit_failure:
          submit_terminal_token['blocked_reason'] = str(submit_terminal_token.get('blocked_reason') or 'pre_order_connectivity_failed')
        if not _recoverable_pre_order_submit_failure:
          halt_projection = current_halt_projection if stopped_terminal else {
            'active': True,
            'kind': 'submit_failed_halted',
            'reason': str(event_detail.get('reason') or 'submit_bridge_service_failed'),
            'failure_phase': str(event_detail.get('failure_phase') or ''),
            'error_family': str(submit_terminal_token.get('error_family') or ''),
            'error_message': str(submit_terminal_token.get('error_message') or ''),
            'money_path_crossed': bool(submit_terminal_token.get('money_path_crossed')),
            'pair_plan_created': bool(submit_terminal_token.get('pair_plan_created')),
            'orders_created': bool(submit_terminal_token.get('orders_created')),
            'handoff_id': str(_submit_handoff.get('handoff_id') or ''),
            'saved_set_id': str(_submit_handoff.get('saved_set_id') or ''),
            'scan_session_id': str(_submit_handoff.get('scan_session_id') or ''),
            'scan_shape_operator_summary': str(_submit_handoff.get('scan_shape_operator_summary') or ''),
            'operator_action': 'inspect_evidence',
            'retryable': False,
          }
          with scheduler_lock:
            scheduler_state['owner'] = 'idle'
            scheduler_state['pending_action'] = None
            scheduler_state['pending_reason'] = ''
            scheduler_state['halt_projection'] = halt_projection
          snapshot = _scheduler_build_snapshot(
            settings=settings,
            source=normalized_event,
            decision='noop' if stopped_terminal else 'halted_submit_failed',
            owner_reason='automation_stopped' if stopped_terminal else 'submit_failed_halted',
          )
          _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail=event_detail)
          return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)
      cadence_source_terminal_ref: JSONDict = {}
      if submit_terminal_token:
        current_saved_set_id = str(review_selection_state.get('saved_set_id') or '').strip()
        current_candidate_signature = str(review_selection_state.get('candidate_signature') or '').strip()
        token_saved_set_id = str(submit_terminal_token.get('saved_set_id') or '').strip()
        token_candidate_signature = str(submit_terminal_token.get('candidate_signature') or '').strip()
        if current_saved_set_id and current_candidate_signature and current_saved_set_id == token_saved_set_id and current_candidate_signature == token_candidate_signature:
          consumed_record = {
            'consumed_saved_set_id': token_saved_set_id,
            'consumed_candidate_signature': token_candidate_signature,
            'consumed_at_utc': str(submit_terminal_token.get('submit_terminal_at_utc') or _scheduler_utc_now()),
            'consumed_submit_token_kind': str(submit_terminal_token.get('token_kind') or ''),
            'consumed_submit_terminal_status': str(submit_terminal_token.get('terminal_status') or ''),
            'consumed_submit_handoff_id': str(submit_terminal_token.get('submit_handoff_id') or ''),
            'consumed_submit_scheduler_lease_id': str(submit_terminal_token.get('submit_scheduler_lease_id') or ''),
            'source_blocked_reason': str(submit_terminal_token.get('blocked_reason') or ''),
            'source_submit_response_id': str(submit_terminal_token.get('submit_response_id') or ''),
            'source_planned_pair_count': int(submit_terminal_token.get('planned_pair_count') or 0),
            'source_orders_created': bool(submit_terminal_token.get('orders_created')),
            'source_money_path_crossed': bool(submit_terminal_token.get('money_path_crossed')),
          }
          review_selection_state['consumed_submit_terminal'] = consumed_record
          review_selection_state['saved_set_status'] = 'submitted_terminal'
          review_selection_state['saved_set_status_reason'] = (
            'Submit failed before order placement; saved set retired from current automation routing.'
            if str(submit_terminal_token.get('terminal_status') or '').strip().lower() == 'failed'
            else 'Saved set was submitted and retired from current automation routing.'
          )
          db_path = str(getattr(settings, 'state_db_path', '') or '').strip() if settings is not None else ''
          if db_path and token_saved_set_id:
            try:
              connection = open_database(db_path)
              persist_candidate_saved_set_evaluation(
                connection,
                saved_set_id=token_saved_set_id,
                recorded_at_utc=str(consumed_record.get('consumed_at_utc') or _scheduler_utc_now()),
                operation_lane=str(submit_terminal_token.get('operation_lane') or getattr(settings, 'operation_lane', 'sandbox') or 'sandbox'),
                evaluation_status='submitted_terminal',
                actionability_status='submitted_terminal',
                visibility_status='history_only',
                offline_verifiable=True,
                online_revalidation_required=False,
                detail={
                  'reason': (
                    'Submit failed before order placement; saved set retired from current automation routing.'
                    if str(submit_terminal_token.get('terminal_status') or '').strip().lower() == 'failed'
                    else 'Saved set submitted and retired from current automation routing.'
                  ),
                  'submit_handoff_id': str(submit_terminal_token.get('submit_handoff_id') or ''),
                  'submit_scheduler_lease_id': str(submit_terminal_token.get('submit_scheduler_lease_id') or ''),
                  'candidate_signature': token_candidate_signature,
                  'candidate_count': int(submit_terminal_token.get('candidate_count') or 0),
                },
              )
            except Exception:
              pass
        cadence_source_terminal_ref = {
          'source_submit_token_kind': str(submit_terminal_token.get('token_kind') or ''),
          'source_submit_terminal_status': str(submit_terminal_token.get('terminal_status') or ''),
          'source_submit_scheduler_lease_id': str(submit_terminal_token.get('submit_scheduler_lease_id') or ''),
          'source_submit_handoff_id': str(submit_terminal_token.get('submit_handoff_id') or ''),
          'source_saved_set_id': str(submit_terminal_token.get('saved_set_id') or ''),
          'source_candidate_signature': str(submit_terminal_token.get('candidate_signature') or ''),
          'source_candidate_count': int(submit_terminal_token.get('candidate_count') or 0),
          'source_submit_terminal_at_utc': str(submit_terminal_token.get('submit_terminal_at_utc') or ''),
          'source_last_submit_completed_at_utc': str(submit_terminal_token.get('last_submit_completed_at_utc') or ''),
        }
      with scheduler_lock:
        scheduler_state['owner'] = 'idle'
        scheduler_state['pending_action'] = None
        scheduler_state['pending_reason'] = ''
        scheduler_state['halt_projection'] = current_halt_projection if stopped_terminal else None
      if (
        not stopped_terminal
        and bool(automation_overlay_state.get('enabled'))
        and not bool(automation_overlay_state.get('paused'))
      ):
        cadence_sec = int(automation_overlay_state.get('cadence_ms') or 0) // 1000 or 600
        _scheduler_start_cadence_timer(
          settings=settings,
          env_override=env_override,
          subaccount_override=subaccount_override,
          lane_session_id=lane_session_id,
          after_sec=float(cadence_sec),
          source='submit_completion',
          source_terminal_ref=cadence_source_terminal_ref,
        )
        decision = 'cadence_timer_started'
      else:
        decision = 'noop'
      snapshot = _scheduler_build_snapshot(settings=settings, source=normalized_event, decision=decision, owner_reason='submit_terminal')
      _persist_scheduler_event(settings, f'scheduler_event_{normalized_event}', snapshot, extra_detail=event_detail)
      return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)

    snapshot = _scheduler_build_snapshot(settings=settings, source=normalized_event or 'scheduler_event', decision='noop', owner_reason='event_ignored')
    _persist_scheduler_event(settings, f'scheduler_event_{normalized_event or "ignored"}', snapshot, extra_detail=event_detail)
    return _scheduler_finish_event(snapshot, settings, env_override, subaccount_override, lane_session_id, normalized_event)

  def _scheduler_dispatch_scan_internal(
    settings: Any,
    env_override: str | None,
    subaccount_override: int | None,
    source: str,
    captured_lane_session_id: str,
  ) -> str:
    try:
      if not bool(automation_overlay_state.get('enabled')):
        return 'no_op'
      if bool(automation_overlay_state.get('paused')):
        return 'no_op'
      admission = _scheduler_admit_action(
        'scan',
        source=source,
        settings=settings,
        acquire=True,
      )
      if str(admission.get('decision') or '').strip().lower() != 'allow':
        with scheduler_lock:
          if str(admission.get('decision') or '').strip().lower() == 'defer_to_submit':
            scheduler_state['owner'] = 'submit'
            scheduler_state['pending_action'] = 'submit'
            scheduler_state['pending_reason'] = 'submit_ready'
          else:
            scheduler_state['owner'] = 'scan'
            scheduler_state['pending_action'] = 'scan'
            scheduler_state['pending_reason'] = str(admission.get('reason') or admission.get('owner_reason') or 'scan_deferred')
        _persist_scheduler_event(
          settings,
          'timer_dispatch_deferred',
          admission,
          extra_detail={
            'source': source,
            'captured_lane_session_id': captured_lane_session_id,
          },
        )
        if str(admission.get('decision') or '').strip().lower() == 'defer_to_submit':
          _scheduler_dispatch_submit_internal(
            settings,
            env_override,
            subaccount_override,
            source='backend_auto_dispatch',
            captured_lane_session_id=captured_lane_session_id,
          )
        return 'deferred'
      lease_id = str(admission.get('lease_id') or '').strip() or None
      try:
        _start_scan_runtime(
          settings,
          env_override=env_override,
          subaccount_override=subaccount_override,
          scheduler_lease_id=lease_id,
        )
      except Exception:
        _scheduler_release_lease(
          settings,
          lease_id,
          reason='timer_dispatch_launch_failed',
          source='timer_dispatch',
        )
        raise
      return 'admitted'
    except Exception:
      return 'no_op'

  def _promote_saved_selection_members_to_in_flight(settings: Any) -> None:
    saved_set_id = str(review_selection_state.get('saved_set_id') or '').strip()
    state_db_path = str(getattr(settings, 'state_db_path', None) or '').strip()
    if not saved_set_id or not state_db_path:
      return
    try:
      conn = open_database(state_db_path)
      now_utc = _utc_now_iso()
      saved_set_row = conn.execute(
        'SELECT run_id, operation_lane, lane_session_id FROM candidate_saved_sets WHERE saved_set_id = ?',
        (saved_set_id,),
      ).fetchone()
      if not saved_set_row or not saved_set_row[0]:
        return
      run_id = str(saved_set_row[0])
      operation_lane = str(saved_set_row[1] or 'sandbox')
      lane_session_id = str(saved_set_row[2] or review_selection_state.get('persisted_lane_session_id') or '').strip()
      with conn:
        conn.execute(
          "INSERT OR IGNORE INTO candidate_review_runs"
          " (run_id, operation_lane, lane_session_id, candidate_signature, candidate_count, source_action, detail_json, recorded_at_utc)"
          " VALUES (?, ?, ?, '', 0, 'submit', '{}', ?)",
          (run_id, operation_lane, lane_session_id, now_utc),
        )
        conn.execute(
          "INSERT OR IGNORE INTO candidate_review_candidates"
          " (run_id, candidate_uid, candidate_key, detail_json, recorded_at_utc, lifecycle_stage)"
          " SELECT ?, candidate_uid, candidate_key, detail_json, ?, 'in_flight'"
          " FROM candidate_saved_set_members"
          " WHERE saved_set_id = ?"
          " AND NOT EXISTS ("
          "   SELECT 1 FROM candidate_review_candidates c"
          "   WHERE c.run_id = ? AND c.candidate_uid = candidate_saved_set_members.candidate_uid"
          " )",
          (run_id, now_utc, saved_set_id, run_id),
        )
        conn.execute(
          "UPDATE candidate_review_candidates"
          " SET lifecycle_stage = 'in_flight'"
          " WHERE run_id = ? AND lifecycle_stage NOT IN ('in_flight', 'terminal')",
          (run_id,),
        )
      review_selection_state['persisted_run_id'] = run_id
    except Exception:
      return

  def _scan_shape_operator_summary(scan_shape_summary: Mapping[str, Any] | None, candidate_count: int | None = None) -> str:
    return _scan_shape_operator_summary_line(scan_shape_summary, candidate_count)

  def _build_backend_submit_handoff(
    submit_payload: JSONDict,
    *,
    source_scan_payload: JSONDict,
    candidate_keys: list[str],
    captured_lane_session_id: str,
  ) -> JSONDict:
    scan_runtime = submit_payload.get('scan_runtime') if isinstance(submit_payload.get('scan_runtime'), dict) else {}
    source_scan_runtime = source_scan_payload.get('scan_runtime') if isinstance(source_scan_payload.get('scan_runtime'), dict) else {}
    operation_lane = _review_selection_operation_lane(submit_payload)
    operator_lane_session_id = str(
      review_selection_state.get('persisted_lane_session_id')
      or captured_lane_session_id
      or scan_runtime.get('lane_session_id')
      or source_scan_runtime.get('lane_session_id')
      or ''
    ).strip()
    scan_session_id = str(
      scan_runtime.get('scan_session_id')
      or source_scan_runtime.get('scan_session_id')
      or review_selection_state.get('persisted_run_id')
      or ''
    ).strip()
    normalized_keys = [str(key or '').strip() for key in candidate_keys if str(key or '').strip()]
    scan_shape_summary = (
      source_scan_payload.get('scan_shape_summary')
      if isinstance(source_scan_payload.get('scan_shape_summary'), dict)
      else submit_payload.get('scan_shape_summary')
      if isinstance(submit_payload.get('scan_shape_summary'), dict)
      else {}
    )
    return {
      'schema_version': 1,
      'handoff_id': 'handoff-{timestamp}-{suffix}'.format(
        timestamp=time.strftime('%Y%m%dT%H%M%SZ', time.gmtime()),
        suffix=os.urandom(4).hex(),
      ),
      'source': 'backend_auto_dispatch',
      'operation_lane': operation_lane,
      'operator_lane_session_id': operator_lane_session_id,
      'scan_session_id': scan_session_id,
      'scan_completed_at_utc': str(scan_runtime.get('completed_at_utc') or source_scan_runtime.get('completed_at_utc') or ''),
      'saved_set_id': str(review_selection_state.get('saved_set_id') or '').strip(),
      'saved_set_recorded_at_utc': str(review_selection_state.get('saved_set_recorded_at_utc') or '').strip(),
      'candidate_signature': '|'.join(normalized_keys),
      'candidate_count': len(normalized_keys),
      'candidate_keys': normalized_keys,
      'created_at_utc': _utc_now_iso(),
      'scan_shape_summary': dict(scan_shape_summary or {}),
      'scan_shape_operator_summary': _scan_shape_operator_summary(scan_shape_summary, len(normalized_keys)),
    }

  def _scheduler_dispatch_submit_internal(
    settings: Any,
    env_override: str | None,
    subaccount_override: int | None,
    *,
    source: str,
    captured_lane_session_id: str,
    submit_handoff: JSONDict | None = None,
  ) -> str:
    try:
      if not bool(automation_overlay_state.get('enabled')):
        return 'no_op'
      if bool(automation_overlay_state.get('paused')):
        return 'no_op'
      guard_failure = _run_bridge_guard_failure(
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      if guard_failure is not None:
        snapshot = _scheduler_build_snapshot(
          settings=settings,
          source=source,
          decision='reject',
          owner='submit_bridge',
          owner_reason=str(guard_failure[0] or 'submit_guard_failed'),
          blocked_actions=['submit_bridge'],
        )
        _persist_scheduler_event(
          settings,
          'scheduler_submit_dispatch_blocked',
          snapshot,
          level='WARN',
          extra_detail={'captured_lane_session_id': captured_lane_session_id},
        )
        return 'blocked'
      admission = _scheduler_admit_action(
        'submit_bridge',
        source=source,
        settings=settings,
        acquire=True,
      )
      if str(admission.get('decision') or '').strip().lower() != 'allow':
        with scheduler_lock:
          scheduler_state['owner'] = 'submit'
          scheduler_state['pending_action'] = 'submit'
          scheduler_state['pending_reason'] = str(admission.get('reason') or admission.get('owner_reason') or 'submit_deferred')
        _persist_scheduler_event(
          settings,
          'scheduler_submit_dispatch_deferred',
          admission,
          extra_detail={'captured_lane_session_id': captured_lane_session_id},
        )
        return 'deferred'
      lease_id = str(admission.get('lease_id') or '').strip() or None
      try:
        call_kwargs: dict[str, Any] = {
          'settings': settings,
          'env_override': env_override,
          'subaccount_override': subaccount_override,
          'execution_profile': 'submit_order_bridge',
        }
        operator_lane_session_id = str(
          review_selection_state.get('persisted_lane_session_id')
          or _websocket_runtime_snapshot().get('lane_session_id')
          or ''
        ).strip()
        if operator_lane_session_id:
          call_kwargs['operator_lane_session_id'] = operator_lane_session_id
        if str(source or '').strip().lower() == 'backend_auto_dispatch':
          call_kwargs['submit_handoff'] = dict(submit_handoff or {})
        raw_payload = _call_with_key_overlay(resolved_services.run, **call_kwargs)
        _promote_saved_selection_members_to_in_flight(settings)
        _persist_run_response_projection_event(
          settings,
          raw_payload if isinstance(raw_payload, dict) else {'decision': 'planned'},
          lane_session_id='run-{suffix}'.format(suffix=os.urandom(6).hex()),
        )
      except Exception as exc:
        failure_phase = str(getattr(exc, 'polyventure_submit_bridge_phase', '') or 'submit_dispatch')
        exception_detail = kalshi_error_safe_detail(exc)
        pre_order_failure = failure_phase in {
          'submit_handoff_validation',
          'candidate_math_projection',
          'risk_gate',
          'binary_proof',
          'live_orderbook_readback',
          'pair_plan_validation',
          'submit_dispatch',
        }
        release_snapshot = _scheduler_release_lease(
          settings,
          lease_id,
          reason='submit_bridge_service_failed',
          source=source,
        )
        submit_terminal_token: JSONDict = {
          'schema_version': 1,
          'token_kind': 'submit_terminal_completion',
          'terminal_status': 'failed',
          'terminal_kind': 'failed_submit',
          'failure_phase': failure_phase,
          'failure_reason': failure_phase,
          'error_family': type(exc).__name__,
          'error_message': str(exc),
          **exception_detail,
          'source': str(source or ''),
          'operation_lane': str(release_snapshot.get('operation_lane') or getattr(settings, 'operation_lane', '') or ''),
          'lane_session_id': str(admission.get('lane_session_id') or captured_lane_session_id or ''),
          'submit_scheduler_lease_id': str(lease_id or ''),
          'lease_released_at_utc': release_snapshot.get('observed_at_utc'),
          'submit_terminal_at_utc': _scheduler_utc_now(),
          'last_submit_completed_at_utc': '',
          'submit_handoff_id': str((submit_handoff or {}).get('handoff_id') or ''),
          'saved_set_id': str((submit_handoff or {}).get('saved_set_id') or review_selection_state.get('saved_set_id') or ''),
          'saved_set_recorded_at_utc': str((submit_handoff or {}).get('saved_set_recorded_at_utc') or review_selection_state.get('saved_set_recorded_at_utc') or ''),
          'candidate_signature': str((submit_handoff or {}).get('candidate_signature') or review_selection_state.get('candidate_signature') or ''),
          'candidate_count': int((submit_handoff or {}).get('candidate_count') or len(list(review_selection_state.get('saved_keys') or []))),
          'candidate_keys': list((submit_handoff or {}).get('candidate_keys') or review_selection_state.get('saved_keys') or []),
          'scan_session_id': str((submit_handoff or {}).get('scan_session_id') or review_selection_state.get('persisted_run_id') or ''),
          'scan_completed_at_utc': str((submit_handoff or {}).get('scan_completed_at_utc') or ''),
          'release_reason': 'submit_bridge_service_failed',
          'verified_submit_projection_recorded': False,
          'verified_lease_released': True,
          'money_path_crossed': not pre_order_failure,
          'pair_plan_created': not pre_order_failure,
          'orders_created': failure_phase in {'live_order_dispatch'},
        }
        _persist_scheduler_event(
          settings,
          'scheduler_submit_dispatch_failed',
          release_snapshot,
          level='ERROR',
          extra_detail={
            'source': source,
            'captured_lane_session_id': captured_lane_session_id,
            'submit_handoff': dict(submit_handoff or {}),
            'handoff_id': str((submit_handoff or {}).get('handoff_id') or ''),
            'lease_id': lease_id,
            'failure_phase': failure_phase,
            'error_family': type(exc).__name__,
            'error_message': str(exc),
            **exception_detail,
            'money_path_crossed': not pre_order_failure,
            'pair_plan_created': not pre_order_failure,
            'orders_created': failure_phase in {'live_order_dispatch'},
            'terminal_status': 'failed',
            'submit_terminal_completion_token': submit_terminal_token,
          },
        )
        _scheduler_handle_event(
          'submit_terminal',
          {
            'lane_session_id': str(admission.get('lane_session_id') or captured_lane_session_id or ''),
            'source': source,
            'terminal_status': 'failed',
            'reason': 'submit_bridge_service_failed',
            'failure_phase': failure_phase,
            'submit_handoff': dict(submit_handoff or {}),
            'submit_terminal_completion_token': submit_terminal_token,
          },
          settings,
          env_override=env_override,
          subaccount_override=subaccount_override,
        )
        return 'failed'
      release_snapshot = _scheduler_release_lease(
        settings,
        lease_id,
        reason='submit_bridge_projection_recorded',
        source=source,
      )
      submit_terminal_token = {
        'schema_version': 1,
        'token_kind': 'submit_terminal_completion',
        'terminal_status': 'completed',
        'terminal_kind': 'completed_submitted',
        'source': str(source or ''),
        'operation_lane': str(release_snapshot.get('operation_lane') or getattr(settings, 'operation_lane', '') or ''),
        'lane_session_id': str(admission.get('lane_session_id') or captured_lane_session_id or ''),
        'submit_scheduler_lease_id': str(lease_id or ''),
        'lease_released_at_utc': release_snapshot.get('observed_at_utc'),
        'submit_terminal_at_utc': _scheduler_utc_now(),
        'last_submit_completed_at_utc': str(scheduler_state.get('last_submit_completed_at_utc') or ''),
        'submit_handoff_id': str((submit_handoff or {}).get('handoff_id') or ''),
        'saved_set_id': str((submit_handoff or {}).get('saved_set_id') or review_selection_state.get('saved_set_id') or ''),
        'saved_set_recorded_at_utc': str((submit_handoff or {}).get('saved_set_recorded_at_utc') or review_selection_state.get('saved_set_recorded_at_utc') or ''),
        'candidate_signature': str((submit_handoff or {}).get('candidate_signature') or review_selection_state.get('candidate_signature') or ''),
        'candidate_count': int((submit_handoff or {}).get('candidate_count') or len(list(review_selection_state.get('saved_keys') or []))),
        'candidate_keys': list((submit_handoff or {}).get('candidate_keys') or review_selection_state.get('saved_keys') or []),
        'scan_session_id': str((submit_handoff or {}).get('scan_session_id') or review_selection_state.get('persisted_run_id') or ''),
        'scan_completed_at_utc': str((submit_handoff or {}).get('scan_completed_at_utc') or ''),
        'release_reason': 'submit_bridge_projection_recorded',
        'verified_submit_projection_recorded': True,
        'verified_lease_released': True,
      }
      if isinstance(raw_payload, dict):
        submit_terminal_token.update(
          {
            'blocked_reason': str(raw_payload.get('blocked_reason') or ''),
            'submit_response_id': str(raw_payload.get('submit_response_id') or ''),
            'submit_rest_state_id': str(raw_payload.get('submit_rest_state_id') or ''),
            'planned_pair_count': int(raw_payload.get('planned_pair_count') or 0),
            'orders_created': bool(int(raw_payload.get('planned_pair_count') or 0)),
            'pair_plan_created': bool(int(raw_payload.get('planned_pair_count') or 0)),
            'money_path_crossed': bool(int(raw_payload.get('planned_pair_count') or 0)),
          }
        )
        if str(raw_payload.get('blocked_reason') or '') == 'pair_plan_validation':
          submit_terminal_token.update(
            {
              'candidate_rejected_count': int(raw_payload.get('candidate_count') or 0),
              'saved_set_exhausted': True,
              'failure_phase': 'pair_plan_validation',
            }
          )
      _persist_scheduler_event(
        settings,
        'scheduler_submit_dispatch_completed',
        release_snapshot,
        extra_detail={
          'captured_lane_session_id': captured_lane_session_id,
          'submit_handoff': dict(submit_handoff or {}),
          'handoff_id': str((submit_handoff or {}).get('handoff_id') or ''),
          'submit_terminal_completion_token': submit_terminal_token,
        },
      )
      _scheduler_handle_event(
        'submit_terminal',
        {
          'lane_session_id': str(admission.get('lane_session_id') or captured_lane_session_id or ''),
          'source': source,
          'terminal_status': 'completed',
          'submit_handoff': dict(submit_handoff or {}),
          'submit_terminal_completion_token': submit_terminal_token,
        },
        settings,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      return 'submitted'
    except Exception:
      return 'no_op'

  def _scheduler_auto_select_and_submit_after_scan(
    settings: Any,
    env_override: str | None,
    subaccount_override: int | None,
    *,
    scan_payload: JSONDict,
    scan_scheduler_lease_id: str | None,
    scan_terminal_token: JSONDict,
    captured_lane_session_id: str,
  ) -> JSONDict:
    raw_found_count = int(
      scan_terminal_token.get('raw_found_count')
      if isinstance(scan_terminal_token, dict) and scan_terminal_token.get('raw_found_count') is not None
      else scan_terminal_token.get('found_count')
      if isinstance(scan_terminal_token, dict)
      else 0
    )
    source_scan_session_id = str((scan_terminal_token.get('scan_session_id') if isinstance(scan_terminal_token, dict) else '') or '')
    source_lane_session_id = str((scan_terminal_token.get('lane_session_id') if isinstance(scan_terminal_token, dict) else '') or '')
    source_scan_scheduler_lease_id = str((scan_terminal_token.get('scan_scheduler_lease_id') if isinstance(scan_terminal_token, dict) else scan_scheduler_lease_id) or '')
    source_terminal_status = str((scan_terminal_token.get('terminal_status') if isinstance(scan_terminal_token, dict) else 'completed') or '')
    if not bool(automation_overlay_state.get('enabled')) or bool(automation_overlay_state.get('paused')):
      return {'scan_actionability_resolution': {
        'schema_version': 1,
        'resolution_kind': 'scan_actionability_resolution',
        'source_scan_session_id': source_scan_session_id,
        'source_lane_session_id': source_lane_session_id,
        'source_scan_scheduler_lease_id': source_scan_scheduler_lease_id,
        'source_terminal_status': source_terminal_status,
        'raw_found_count': raw_found_count,
        'actionability_status': 'automation_inactive',
        'actionability_reason': 'automation_disabled_or_paused',
        'actionable_candidate_count': 0,
        'saved_set_id': '',
        'saved_set_recorded_at_utc': '',
        'candidate_signature': '',
        'candidate_keys': [],
        'submit_handoff_id': '',
        'retry_after_sec': None,
        'created_at_utc': _scheduler_utc_now(),
      }, 'submit_handoff': None}
    raw_rows = []
    if isinstance(scan_payload.get('sandbox_candidates_extended'), list):
      raw_rows = [dict(row) for row in scan_payload.get('sandbox_candidates_extended', []) if isinstance(row, dict)]
    elif isinstance(scan_payload.get('candidates'), list):
      raw_rows = [dict(row) for row in scan_payload.get('candidates', []) if isinstance(row, dict)]
    if not raw_rows:
      return {'scan_actionability_resolution': {
        'schema_version': 1,
        'resolution_kind': 'scan_actionability_resolution',
        'source_scan_session_id': source_scan_session_id,
        'source_lane_session_id': source_lane_session_id,
        'source_scan_scheduler_lease_id': source_scan_scheduler_lease_id,
        'source_terminal_status': source_terminal_status,
        'raw_found_count': raw_found_count,
        'actionability_status': 'zero_actionable',
        'actionability_reason': 'raw_rows_missing' if raw_found_count > 0 else 'raw_zero',
        'actionable_candidate_count': 0,
        'saved_set_id': '',
        'saved_set_recorded_at_utc': '',
        'candidate_signature': '',
        'candidate_keys': [],
        'submit_handoff_id': '',
        'retry_after_sec': 5,
        'created_at_utc': _scheduler_utc_now(),
      }, 'submit_handoff': None}
    payload = _refresh_shell_payload(
      'scan',
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    if not _payload_has_review_candidates(payload):
      payload['candidates'] = list(raw_rows)
      payload['sandbox_candidates_extended'] = list(raw_rows)
      payload['candidate_count'] = len(raw_rows)
      payload['sandbox_extended_count'] = len(raw_rows)
      payload['pair_monitor'] = {
        **(payload.get('pair_monitor') if isinstance(payload.get('pair_monitor'), dict) else {}),
        'candidate_rows': list(raw_rows),
        'candidate_count': len(raw_rows),
      }
    payload['workflow'] = _candidate_review_workflow('review_hold_candidates_available', working_count=0)
    auto_rows = [candidate for candidate in _candidate_review_rows(payload) if not _candidate_is_previous(candidate)]
    auto_keys = [str(candidate.get('candidate_key') or '') for candidate in auto_rows if candidate.get('candidate_key')]
    if not auto_keys:
      return {'scan_actionability_resolution': {
        'schema_version': 1,
        'resolution_kind': 'scan_actionability_resolution',
        'source_scan_session_id': source_scan_session_id,
        'source_lane_session_id': source_lane_session_id,
        'source_scan_scheduler_lease_id': source_scan_scheduler_lease_id,
        'source_terminal_status': source_terminal_status,
        'raw_found_count': raw_found_count,
        'actionability_status': 'zero_actionable',
        'actionability_reason': 'candidate_keys_missing',
        'actionable_candidate_count': 0,
        'saved_set_id': '',
        'saved_set_recorded_at_utc': '',
        'candidate_signature': '',
        'candidate_keys': [],
        'submit_handoff_id': '',
        'retry_after_sec': 5,
        'created_at_utc': _scheduler_utc_now(),
      }, 'submit_handoff': None}
    _clear_review_selection_state()
    _clear_review_selection_hydration_state()
    _refresh_review_selection_projection(payload, selected_keys=auto_keys, save_selection=True)
    _persist_saved_review_selection(payload)
    submit_payload = _refresh_shell_payload(
      'scan',
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    _refresh_review_selection_projection(submit_payload, selected_keys=auto_keys, save_selection=True)
    review_state = submit_payload.get('review_selection') if isinstance(submit_payload.get('review_selection'), dict) else {}
    if str(review_state.get('state_id') or '') != 'review_hold_saved_selection_locked' or not bool(review_state.get('submit_ready')):
      return {'scan_actionability_resolution': {
        'schema_version': 1,
        'resolution_kind': 'scan_actionability_resolution',
        'source_scan_session_id': source_scan_session_id,
        'source_lane_session_id': source_lane_session_id,
        'source_scan_scheduler_lease_id': source_scan_scheduler_lease_id,
        'source_terminal_status': source_terminal_status,
        'raw_found_count': raw_found_count,
        'actionability_status': 'zero_actionable',
        'actionability_reason': 'saved_set_not_submit_ready',
        'actionable_candidate_count': 0,
        'saved_set_id': '',
        'saved_set_recorded_at_utc': '',
        'candidate_signature': '',
        'candidate_keys': [],
        'submit_handoff_id': '',
        'retry_after_sec': 5,
        'created_at_utc': _scheduler_utc_now(),
      }, 'submit_handoff': None}
    submit_handoff = _build_backend_submit_handoff(
      submit_payload,
      source_scan_payload=scan_payload,
      candidate_keys=[str(key or '').strip() for key in review_state.get('saved_keys', []) if str(key or '').strip()] or auto_keys,
      captured_lane_session_id=captured_lane_session_id,
    )
    actionability_resolution = {
      'schema_version': 1,
      'resolution_kind': 'scan_actionability_resolution',
      'source_scan_session_id': source_scan_session_id,
      'source_lane_session_id': source_lane_session_id,
      'source_scan_scheduler_lease_id': source_scan_scheduler_lease_id,
      'source_terminal_status': source_terminal_status,
      'raw_found_count': raw_found_count,
      'actionability_status': 'actionable_ready',
      'actionability_reason': 'saved_set_package_verified',
      'actionable_candidate_count': int(submit_handoff.get('candidate_count') or 0),
      'saved_set_id': str(submit_handoff.get('saved_set_id') or ''),
      'saved_set_recorded_at_utc': str(submit_handoff.get('saved_set_recorded_at_utc') or ''),
      'candidate_signature': str(submit_handoff.get('candidate_signature') or ''),
      'candidate_keys': list(submit_handoff.get('candidate_keys') or []),
      'submit_handoff_id': str(submit_handoff.get('handoff_id') or ''),
      'retry_after_sec': None,
      'created_at_utc': _scheduler_utc_now(),
    }
    return {'scan_actionability_resolution': actionability_resolution, 'submit_handoff': submit_handoff}

  def _start_scan_runtime(
    settings: Any,
    *,
    env_override: str | None,
    subaccount_override: int | None,
    scheduler_lease_id: str | None = None,
  ) -> JSONDict:
    nonlocal scan_runtime_thread, scan_runtime_cancel_event

    existing_snapshot = _scan_runtime_snapshot()
    if (
      scan_runtime_thread is not None
      and scan_runtime_thread.is_alive()
      and str(existing_snapshot.get('status') or '').lower() in {'processing', 'canceling'}
    ):
      return existing_snapshot

    scan_session_id = 'scan-{timestamp}-{suffix}'.format(
      timestamp=time.strftime('%Y%m%dT%H%M%SZ', time.gmtime()),
      suffix=os.urandom(4).hex(),
    )
    scan_runtime_lane_session_id = 'scan-{suffix}'.format(suffix=os.urandom(6).hex())
    started_at_utc = _scan_runtime_utc_now()
    started_event = threading.Event()
    cancel_event = threading.Event()
    scan_runtime_cancel_event = cancel_event
    operation_lane = str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox')
    scan_mode_selected = bool(context_overlay_state.get('mode_selected'))
    runtime_state_db_path = str(getattr(settings, 'state_db_path', '') or '').strip()
    websocket_lane_session_id = str(_websocket_runtime_snapshot().get('lane_session_id') or '').strip()
    operator_lane_session_id = str(
      review_selection_state.get('persisted_lane_session_id')
      or websocket_lane_session_id
      or ''
    ).strip()
    if operation_lane in {'sandbox', 'live'} and scan_mode_selected and not operator_lane_session_id:
      now_utc = _scan_runtime_utc_now()
      no_go_payload: JSONDict = {
        'decision': 'no_go',
        'reason': 'operator_lane_session_unavailable',
        'message': 'Find candidates requires an operator lane session before scan results can be persisted.',
        'next_action': 'Reconnect the active lane, then find candidates again.',
        'candidate_write_attempted': False,
      }
      _set_scan_runtime_state(
        status='failed',
        active=False,
        scan_session_id=scan_session_id,
        lane_session_id='',
        operator_lane_session_id='',
        scan_runtime_lane_session_id=scan_runtime_lane_session_id,
        operation_lane=operation_lane,
        mode_selected=scan_mode_selected,
        stage='operator_session_unavailable',
        message=str(no_go_payload['message']),
        progress_percent=0.0,
        started_at_utc=started_at_utc,
        completed_at_utc=now_utc,
        last_progress_at_utc=now_utc,
        cancel_requested=False,
        result_payload=no_go_payload,
        error_payload=no_go_payload,
        hydrated_from_persistence=False,
        replay_candidate_source_available=False,
        hydration_state_db_path=runtime_state_db_path,
      )
      _persist_scan_runtime_event(
        settings,
        lane_session_id='',
        level='WARN',
        event_type='operator_lane_session_unavailable',
        detail={
          'scan_session_id': scan_session_id,
          'scan_runtime_lane_session_id': scan_runtime_lane_session_id,
          'candidate_write_attempted': False,
        },
      )
      _scheduler_release_lease(
        settings,
        scheduler_lease_id,
        reason='scan_operator_session_unavailable',
        source='scan_runtime',
      )
      return _scan_runtime_snapshot()
    if operator_lane_session_id and not review_selection_state.get('persisted_lane_session_id'):
      review_selection_state['persisted_lane_session_id'] = operator_lane_session_id

    if not data_management_state.get(f'{operation_lane}_datapack_id') and runtime_state_db_path:
      try:
        _scan_mint_id = '{ts}-{lane}-{tok}'.format(
          ts=time.strftime('%Y%m%dT%H%M%SZ', time.gmtime()),
          lane=operation_lane,
          tok=os.urandom(3).hex(),
        )
        _scan_db_path = Path(runtime_state_db_path).expanduser()
        _scan_conn = open_database(_scan_db_path)
        _scan_key_path = str(getattr(settings, 'private_key_file', None) or '').strip() or None
        with _scan_conn:
          resolve_active_profile_token(_scan_conn, operation_lane, key_path=_scan_key_path)
          _scan_conn.execute(
            'UPDATE lane_active_datapack SET detail_json = ? WHERE operation_lane = ? AND closed_at_utc IS NULL',
            (json.dumps({'datapack_id': _scan_mint_id}), operation_lane),
          )
        data_management_state[f'{operation_lane}_datapack_id'] = _scan_mint_id
      except Exception:
        pass

    _set_scan_runtime_state(
      status='processing',
      active=True,
      scan_session_id=scan_session_id,
      lane_session_id=operator_lane_session_id or scan_runtime_lane_session_id,
      operator_lane_session_id=operator_lane_session_id,
      scan_runtime_lane_session_id=scan_runtime_lane_session_id,
      operation_lane=operation_lane,
      mode_selected=scan_mode_selected,
      stage='request_accepted',
      message='Find candidates request accepted; the background scan is starting now.',
      progress_percent=0.04,
      started_at_utc=started_at_utc,
      completed_at_utc=None,
      last_progress_at_utc=started_at_utc,
      cancel_requested=False,
      result_payload=None,
      error_payload=None,
      hydrated_from_persistence=False,
      replay_candidate_source_available=False,
      hydration_state_db_path=runtime_state_db_path,
    )
    _persist_scan_runtime_event(
      settings,
      lane_session_id=operator_lane_session_id or scan_runtime_lane_session_id,
      level='INFO',
      event_type='scan_request_accepted',
      detail={
        'scan_session_id': scan_session_id,
        'operator_lane_session_id': operator_lane_session_id,
        'scan_runtime_lane_session_id': scan_runtime_lane_session_id,
        'stage': 'request_accepted',
        'message': 'Find candidates request accepted.',
      },
    )

    def _progress_callback(
      stage: str,
      message: str,
      detail: JSONDict | None = None,
      progress_percent: float | None = None,
    ) -> None:
      detail_payload = dict(detail or {})
      now_utc = _scan_runtime_utc_now()
      _set_scan_runtime_state(
        status='processing',
        active=True,
        stage=str(stage or 'processing'),
        message=str(message or 'Find candidates is processing in the background.'),
        progress_percent=float(progress_percent if progress_percent is not None else scan_runtime_state.get('progress_percent') or 0.0),
        last_progress_at_utc=now_utc,
        hydrated_from_persistence=False,
      )
      _persist_scan_runtime_event(
        settings,
        lane_session_id=operator_lane_session_id or scan_runtime_lane_session_id,
        level='INFO',
        event_type='scan_progress',
        detail={
          'scan_session_id': scan_session_id,
          'operator_lane_session_id': operator_lane_session_id,
          'scan_runtime_lane_session_id': scan_runtime_lane_session_id,
          'stage': str(stage or 'processing'),
          'message': str(message or ''),
          **({'progress_percent': float(progress_percent)} if progress_percent is not None else {}),
          **detail_payload,
        },
      )
      started_event.set()

    def _run_scan() -> None:
      nonlocal scan_runtime_cancel_event, scheduler_lease_id
      try:
        call_kwargs: JSONDict = {
          'settings': settings,
          'env_override': env_override,
          'subaccount_override': subaccount_override,
        }
        if _scan_call_accepts_keyword(resolved_services.scan, 'progress_callback'):
          call_kwargs['progress_callback'] = _progress_callback
        if _scan_call_accepts_keyword(resolved_services.scan, 'cancel_check'):
          call_kwargs['cancel_check'] = cancel_event.is_set
        if _scan_call_accepts_keyword(resolved_services.scan, 'cancel_event'):
          call_kwargs['cancel_event'] = cancel_event
        if _scan_call_accepts_keyword(resolved_services.scan, 'operator_lane_session_id'):
          if operator_lane_session_id:
            call_kwargs['operator_lane_session_id'] = operator_lane_session_id
        # The scan worker already receives fully resolved settings, including an
        # explicit private_key_file path when one is active. Holding overlay_lock
        # for the full background scan can block the immediate /api/scan refresh
        # response and stall the single-threaded local console host while the
        # scan is still in flight.
        payload = resolved_services.scan(**call_kwargs)
        current_snapshot = _scan_runtime_snapshot()
        if str(current_snapshot.get('status') or '').lower() == 'failed' and str((current_snapshot.get('result_payload') or {}).get('reason') or '') == 'stage_timeout':
          return
        # Lane A (projection coherence, FIND_CANDIDATES_RETRY_PROJECTION_COHERENCE_BMAP_2026-06-19):
        # fail closed to a cancel that arrived while this scan cycle was in flight. Without
        # this, a zero-found result would set status 'processing'/'retry_wait' with
        # cancel_requested=False below, clobbering the cancel -- the client then re-fires and
        # the retry loop "kicks in" after the operator stopped the cycle, leaving the bootstrap
        # route showing 'processing' while the report route shows 'cancelled' for the same
        # session. The terminal/cancel state is authoritative; honor it via the existing
        # ScanCanceledError handler so both routes agree on 'cancelled'.
        if cancel_event.is_set() or bool(current_snapshot.get('cancel_requested')):
          raise ScanCanceledError()
        now_utc = _scan_runtime_utc_now()
        retry_payload = payload if isinstance(payload, dict) else {}
        synthesized_retry_payload = _synthesize_zero_found_retry_payload(
          retry_payload,
          lane_session_id=operator_lane_session_id or scan_runtime_lane_session_id,
        )
        if synthesized_retry_payload is not None:
          retry_payload = synthesized_retry_payload
          payload = synthesized_retry_payload
        is_zero_found_retry = bool(retry_payload.get('scan_retry')) and int(retry_payload.get('candidate_count', 0) or 0) == 0
        if is_zero_found_retry:
          _set_scan_runtime_state(
            status='completed',
            active=False,
            stage='retry_wait',
            message=str(retry_payload.get('message') or '0 candidates found; retrying in 5 seconds.'),
            progress_percent=0.99,
            completed_at_utc=now_utc,
            last_progress_at_utc=now_utc,
            cancel_requested=False,
            result_payload=retry_payload,
            error_payload=None,
            hydrated_from_persistence=False,
            replay_candidate_source_available=False,
            hydration_state_db_path=runtime_state_db_path,
          )
          scan_retry = retry_payload.get('scan_retry') if isinstance(retry_payload.get('scan_retry'), dict) else {}
          retry_after_sec = int(scan_retry.get('retry_after_sec') or retry_payload.get('retry_after_sec') or 5)
          scan_terminal_token = _build_scan_terminal_completion_token(
            terminal_status='retry_wait',
            found_count=0,
            scan_scheduler_lease_id=scheduler_lease_id,
            result_payload=retry_payload,
            retry_source='zero_found_retry',
            retry_after_sec=retry_after_sec,
          )
          _scheduler_handle_event(
            'scan_terminal',
            {
              'status': 'retry_wait',
              'found_count': 0,
              'retry_payload': retry_payload,
              'lane_session_id': str(operator_lane_session_id or scan_runtime_lane_session_id or ''),
              'scan_session_id': scan_session_id,
              'scan_scheduler_lease_id': scheduler_lease_id,
              'terminal_at_utc': now_utc,
              'scan_terminal_completion_token': scan_terminal_token,
            },
            settings,
            env_override=env_override,
            subaccount_override=subaccount_override,
          )
        else:
          payload_settings = payload.get('settings') if isinstance(payload, dict) and isinstance(payload.get('settings'), dict) else {}
          payload_mode_selected = _settings_mode_selected(cast(JSONDict, payload_settings))
          _set_scan_runtime_state(
            status='completed',
            active=False,
            stage='complete',
            message='Find candidates finished and returned a shell payload.',
            progress_percent=1.0,
            completed_at_utc=now_utc,
            last_progress_at_utc=now_utc,
            cancel_requested=False,
            mode_selected=bool(scan_mode_selected or payload_mode_selected),
            result_payload=payload,
            error_payload=None,
            hydrated_from_persistence=False,
            replay_candidate_source_available=_payload_has_review_candidates(payload if isinstance(payload, dict) else {}),
            hydration_state_db_path=runtime_state_db_path,
          )
          _found_count = max(
            int((payload or {}).get('candidate_count', 0) or 0),
            int((payload or {}).get('sandbox_extended_count', 0) or 0),
            len((payload or {}).get('candidates') or []) if isinstance((payload or {}).get('candidates'), list) else 0,
            len((payload or {}).get('sandbox_candidates_extended') or []) if isinstance((payload or {}).get('sandbox_candidates_extended'), list) else 0,
          )
          scan_terminal_token = _build_scan_terminal_completion_token(
            terminal_status='completed',
            found_count=_found_count,
            scan_scheduler_lease_id=scheduler_lease_id,
            result_payload=payload if isinstance(payload, dict) else {},
          )
          terminal_snapshot = _scheduler_handle_event(
            'scan_terminal',
            {
              'status': 'completed',
              'found_count': _found_count,
              'scan_payload': payload if isinstance(payload, dict) else {},
              'lane_session_id': str(operator_lane_session_id or scan_runtime_lane_session_id or ''),
              'scan_session_id': scan_session_id,
              'scan_scheduler_lease_id': scheduler_lease_id,
              'terminal_at_utc': now_utc,
              'scan_terminal_completion_token': scan_terminal_token,
            },
            settings,
            env_override=env_override,
            subaccount_override=subaccount_override,
          )
          if bool(terminal_snapshot.get('scan_lease_released')):
            scheduler_lease_id = None
        started_event.set()
        _persist_scan_runtime_event(
          settings,
          lane_session_id=operator_lane_session_id or scan_runtime_lane_session_id,
          level='INFO',
          event_type='scan_zero_found_retry' if is_zero_found_retry else 'scan_background_completed',
          detail={
            'scan_session_id': scan_session_id,
            'operator_lane_session_id': operator_lane_session_id,
            'scan_runtime_lane_session_id': scan_runtime_lane_session_id,
            'candidate_count': int((payload or {}).get('candidate_count', 0) or 0),
            'sandbox_extended_count': int((payload or {}).get('sandbox_extended_count', 0) or 0),
            'result_decision': str((payload or {}).get('decision') or 'planned'),
            'result_reason': str((payload or {}).get('reason') or 'planned'),
            'result_message': str((payload or {}).get('message') or ''),
            'result_next_action': str((payload or {}).get('next_action') or ''),
            'result_payload': _persistable_scan_terminal_payload(payload),
          },
        )
      except ScanCanceledError:
        current_snapshot = _scan_runtime_snapshot()
        current_result = current_snapshot.get('result_payload') if isinstance(current_snapshot.get('result_payload'), dict) else {}
        if (
          str(current_snapshot.get('status') or '').lower() == 'failed'
          and str(current_result.get('reason') or '').lower() == 'stage_timeout'
        ):
          return
        canceled_payload = _scan_canceled_result_payload(
          settings,
          env_override=env_override,
          subaccount_override=subaccount_override,
        )
        now_utc = _scan_runtime_utc_now()
        _set_scan_runtime_state(
          status='canceled',
          active=False,
          stage='canceled',
          message='Scan canceled by user.',
          progress_percent=float(scan_runtime_state.get('progress_percent') or 0.0),
          completed_at_utc=now_utc,
          last_progress_at_utc=now_utc,
          cancel_requested=True,
          result_payload=canceled_payload,
          error_payload=None,
          hydrated_from_persistence=False,
          hydration_state_db_path=runtime_state_db_path,
        )
        started_event.set()
        _persist_scan_runtime_event(
          settings,
          lane_session_id=operator_lane_session_id or scan_runtime_lane_session_id,
          level='INFO',
          event_type='scan_canceled',
          detail={
            'scan_session_id': scan_session_id,
            'operator_lane_session_id': operator_lane_session_id,
            'scan_runtime_lane_session_id': scan_runtime_lane_session_id,
            'message': 'Scan canceled by user.',
            'reason': str(canceled_payload.get('reason') or 'scan_canceled'),
            'result_payload': _persistable_scan_terminal_payload(canceled_payload),
          },
        )
        _scheduler_handle_event(
          'scan_terminal',
          {
            'status': 'canceled',
            'found_count': 0,
            'scan_payload': canceled_payload,
            'lane_session_id': str(operator_lane_session_id or scan_runtime_lane_session_id or ''),
            'scan_session_id': scan_session_id,
            'scan_scheduler_lease_id': scheduler_lease_id,
            'terminal_at_utc': now_utc,
            'scan_terminal_completion_token': _build_scan_terminal_completion_token(
              terminal_status='canceled',
              found_count=0,
              scan_scheduler_lease_id=scheduler_lease_id,
              result_payload=canceled_payload,
            ),
          },
          settings,
          env_override=env_override,
          subaccount_override=subaccount_override,
        )
      except Exception as exc:
        failure_payload = _action_failure_payload('scan', exc)
        now_utc = _scan_runtime_utc_now()
        _set_scan_runtime_state(
          status='failed',
          active=False,
          stage='failed',
          message=str(failure_payload.get('message') or 'Find candidates failed.'),
          progress_percent=float(scan_runtime_state.get('progress_percent') or 0.0),
          completed_at_utc=now_utc,
          last_progress_at_utc=now_utc,
          cancel_requested=bool(scan_runtime_state.get('cancel_requested')),
          result_payload=failure_payload,
          error_payload=failure_payload,
          hydrated_from_persistence=False,
          hydration_state_db_path=runtime_state_db_path,
        )
        started_event.set()
        _persist_scan_runtime_event(
          settings,
          lane_session_id=operator_lane_session_id or scan_runtime_lane_session_id,
          level='WARN',
          event_type='scan_background_failed',
          detail={
            'scan_session_id': scan_session_id,
            'operator_lane_session_id': operator_lane_session_id,
            'scan_runtime_lane_session_id': scan_runtime_lane_session_id,
            'message': str(failure_payload.get('message') or str(exc)),
            'reason': str(failure_payload.get('reason') or 'scan_failed'),
            'result_payload': _persistable_scan_terminal_payload(failure_payload),
          },
        )
        _scheduler_handle_event(
          'scan_terminal',
          {
            'status': 'failed',
            'found_count': 0,
            'scan_payload': failure_payload,
            'lane_session_id': str(operator_lane_session_id or scan_runtime_lane_session_id or ''),
            'scan_session_id': scan_session_id,
            'scan_scheduler_lease_id': scheduler_lease_id,
            'terminal_at_utc': now_utc,
            'scan_terminal_completion_token': _build_scan_terminal_completion_token(
              terminal_status='failed',
              found_count=0,
              scan_scheduler_lease_id=scheduler_lease_id,
              result_payload=failure_payload,
              retry_source='scan_failure_retry',
              retry_after_sec=5,
            ),
          },
          settings,
          env_override=env_override,
          subaccount_override=subaccount_override,
        )
      finally:
        _scheduler_release_lease(
          settings,
          scheduler_lease_id,
          reason='scan_runtime_released',
          source='scan_runtime',
        )
        scan_runtime_cancel_event = None

    scan_runtime_thread = threading.Thread(target=_run_scan, daemon=True)
    scan_runtime_thread.start()
    started_event.wait(0.25)
    return _scan_runtime_snapshot()

  def _request_scan_runtime_cancel(settings: Any) -> JSONDict:
    nonlocal scan_runtime_cancel_event

    snapshot = _scan_runtime_snapshot()
    if not _scan_runtime_allows_cancel(snapshot):
      return snapshot
    if str(snapshot.get('status') or '').lower() == 'canceling':
      return snapshot

    now_utc = _scan_runtime_utc_now()
    lane_session_id = str(snapshot.get('lane_session_id') or '')
    scan_session_id = str(snapshot.get('scan_session_id') or '')
    hydration_state_db_path = str(snapshot.get('hydration_state_db_path') or getattr(settings, 'state_db_path', '') or '').strip()
    worker_alive = bool(scan_runtime_thread is not None and scan_runtime_thread.is_alive())

    if scan_runtime_cancel_event is not None:
      scan_runtime_cancel_event.set()

    if not worker_alive:
      if str(snapshot.get('stage') or '').lower() == 'retry_wait':
        _scheduler_cancel_timers()
      canceled_payload = _scan_canceled_result_payload(
        settings,
        env_override=None,
        subaccount_override=None,
      )
      _set_scan_runtime_state(
        status='canceled',
        active=False,
        stage='canceled',
        message='Scan canceled by user.',
        progress_percent=float(snapshot.get('progress_percent') or 0.0),
        completed_at_utc=now_utc,
        last_progress_at_utc=now_utc,
        cancel_requested=True,
        result_payload=canceled_payload,
        error_payload=None,
        hydrated_from_persistence=False,
        replay_candidate_source_available=False,
        hydration_state_db_path=hydration_state_db_path,
      )
      _persist_scan_runtime_event(
        settings,
        lane_session_id=lane_session_id,
        level='INFO',
        event_type='scan_canceled',
        detail={
          'scan_session_id': scan_session_id,
          'message': 'Scan canceled by user.',
          'reason': str(canceled_payload.get('reason') or 'scan_canceled'),
          'result_payload': _persistable_scan_terminal_payload(canceled_payload),
        },
      )
      try:
        connection = open_database(getattr(settings, 'state_db_path'))
        persist_operator_action(
          connection,
          action='scan-cancel',
          recorded_at_utc=now_utc,
          operation_lane=str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox'),
          lane_session_id=lane_session_id,
          detail={
            'scan_session_id': scan_session_id,
            'message': 'Cancel completed without an active worker; retry-wait ownership closed immediately.',
          },
        )
      except Exception:
        pass
      return _scan_runtime_snapshot()

    _set_scan_runtime_state(
      status='canceling',
      active=True,
      stage='cancel_requested',
      message='Cancel requested; waiting for the current scan checkpoint.',
      last_progress_at_utc=now_utc,
      cancel_requested=True,
      hydrated_from_persistence=False,
    )
    _persist_scan_runtime_event(
      settings,
      lane_session_id=lane_session_id,
      level='INFO',
      event_type='scan_cancel_requested',
      detail={
        'scan_session_id': scan_session_id,
        'message': 'Cancel requested by operator.',
      },
    )
    try:
      connection = open_database(getattr(settings, 'state_db_path'))
      persist_operator_action(
        connection,
        action='scan-cancel',
        recorded_at_utc=now_utc,
        operation_lane=str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox'),
        lane_session_id=lane_session_id,
        detail={
          'scan_session_id': scan_session_id,
          'message': 'Cancel requested by operator.',
        },
      )
    except Exception:
      pass
    return _scan_runtime_snapshot()

  def _scheduler_stage_stop_scan_cancel(settings: Any | None) -> JSONDict:
    if settings is None:
      return _scan_runtime_snapshot()
    before_snapshot = _scan_runtime_snapshot()
    try:
      cancel_snapshot = _request_scan_runtime_cancel(settings)
    except Exception:
      return before_snapshot
    if bool(cancel_snapshot.get('cancel_requested')):
      with scheduler_lock:
        scheduler_state['owner'] = 'stop'
        scheduler_state['pending_action'] = None
        scheduler_state['pending_reason'] = ''
        scheduler_state['halt_projection'] = {
          'active': True,
          'kind': 'automation_stopped',
          'reason': 'operator_stop',
          'operator_action': 'start_automation',
          'retryable': False,
        }
    return cancel_snapshot

  def _start_websocket_runtime(
    settings: Any,
    *,
    wait_for_ready_sec: float = 3.0,
    wait_for_extended_sec: float = 6.0,
  ) -> JSONDict:
    nonlocal websocket_runtime_thread, websocket_runtime_stop_event, websocket_runtime_ready_event

    lane = str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox').strip().lower() or 'sandbox'
    active_websocket_url = str(getattr(settings, 'active_websocket_url', None) or '').strip()
    private_key_path = str(getattr(settings, 'private_key_file', None) or '').strip()
    api_key_id = str(getattr(settings, 'api_key_id', None) or '').strip()
    config_fingerprint = (lane, active_websocket_url, private_key_path, api_key_id, str(getattr(settings, 'state_db_path', '') or ''))
    current_snapshot = _websocket_runtime_snapshot()
    if (
      current_snapshot.get('config_fingerprint') == config_fingerprint
      and bool(current_snapshot.get('websocket_connected'))
      and str(current_snapshot.get('status') or '') == 'connected'
    ):
      return current_snapshot

    _stop_websocket_runtime(reason='restart_required')

    stop_event = threading.Event()
    ready_event = threading.Event()
    websocket_runtime_stop_event = stop_event
    websocket_runtime_ready_event = ready_event
    lane_session_id = '{lane}-{timestamp}-{suffix}'.format(
      lane=lane,
      timestamp=time.strftime('%Y%m%dT%H%M%SZ', time.gmtime()),
      suffix=os.urandom(4).hex(),
    )

    _set_websocket_runtime_state(
      status='connecting',
      websocket_connected=False,
      operation_lane=lane,
      lane_session_id=lane_session_id,
      active_websocket_url_tail=_websocket_label(active_websocket_url),
      reason_code=None,
      message='Establishing authenticated websocket session.',
      last_heartbeat=None,
      config_fingerprint=config_fingerprint,
      connecting_since=_websocket_runtime_utc_now(),  # W1: start the connect grace clock
    )

    def _run_runtime() -> None:
      message_count = 0

      async def _runtime_loop() -> None:
        nonlocal message_count
        _reconnect_backoff_seconds = [2, 5, 10, 30, 60]

        async def _stop_aware_sleep(seconds: float) -> bool:
          loop = asyncio.get_running_loop()
          deadline = loop.time() + seconds
          while not stop_event.is_set():
            remaining = deadline - loop.time()
            if remaining <= 0:
              return False
            await asyncio.sleep(min(0.25, remaining))
          return True

        private_key = load_private_key(private_key_path)
        # Funds-on-heartbeat: a live-lane HTTP client fetches the balance on each
        # beat so funds are bound to websocket liveness, not to scan activity.
        # Live lane only; sandbox/offline make no balance call. Best-effort
        # construction — a failure here just means beats carry no funds.
        _funds_http_client = None
        if lane == 'live':
          try:
            _funds_http_client = KalshiHttpClient(settings, private_key, request_timeout=3, max_attempts=1)
          except Exception:
            _funds_http_client = None

        def _heartbeat_funds_detail() -> JSONDict | None:
          # Fetch the live balance for this beat. Fail-closed and non-fatal: any
          # error returns None so the heartbeat still fires and the banner falls
          # back through its own staleness grace. get_balance() is a blocking HTTP
          # call, so callers run this via a worker thread to keep the websocket
          # event loop (and its keepalive) responsive.
          if _funds_http_client is None:
            return None
          try:
            _bal = _funds_http_client.get_balance()
            _now = datetime.now(timezone.utc)
            _posture = _project_funds_posture(balance=_bal, as_of=_now, now=_now)
            if _posture.get('available_funds_snapshot') is None:
              return None
            return {
              'available_funds_snapshot': _posture['available_funds_snapshot'],
              'available_funds_as_of': _posture['available_funds_as_of'],
              'funds_refresh_status': _posture['funds_refresh_status'],
              'funds_refresh_reason': _posture['funds_refresh_reason'],
            }
          except Exception:
            return None

        async def _heartbeat_funds_detail_async() -> JSONDict | None:
          # Run the blocking balance fetch off the event loop so the websocket
          # keepalive and recv stay responsive while the beat carries funds.
          if _funds_http_client is None:
            return None
          try:
            return await asyncio.to_thread(_heartbeat_funds_detail)
          except Exception:
            return None

        # T1: throttle the expiry sweep well below the ~2s beat. open_database runs the
        # full schema init on every call and the engine UPDATE scans the (unindexed,
        # churn-bloated) candidate table, so running it every beat adds avoidable DB
        # load under the deck-rebuild contention regime. ~6s is still far more prompt
        # than the >=60s scan cycle while cutting the sweep load ~3x.
        _expiry_throttle = {'last_monotonic': 0.0}
        _EXPIRY_SWEEP_MIN_INTERVAL_SEC = 6.0

        def _heartbeat_expiry_sweep() -> None:
          # T1: run the candidate-expiry transition engine so cards flip to terminal at
          # their view/close deadline instead of waiting for the next scan cycle.
          # Bounded + idempotent (only non-terminal past-deadline rows touched), scoped
          # to this session's lane + lane_session_id (persisted_lane_session_id is sourced
          # from this WS runtime id). Fail-closed/non-fatal; run_service_once is the backstop.
          _db = str(getattr(settings, 'state_db_path', None) or '').strip()
          if not _db or not lane_session_id:
            return
          _conn = None
          try:
            _conn = open_database(_db)
            _mark_expired_candidates_terminal(
              _conn,
              operation_lane=lane,
              operator_lane_session_id=lane_session_id,
              recorded_at=datetime.now(timezone.utc),
            )
          except Exception:
            return
          finally:
            if _conn is not None:
              try:
                _conn.close()
              except Exception:
                pass

        async def _heartbeat_expiry_sweep_async() -> None:
          # Throttled, and run off the event loop (like the balance fetch) so the
          # websocket keepalive/recv stay responsive.
          _now_mono = time.monotonic()
          if _now_mono - _expiry_throttle['last_monotonic'] < _EXPIRY_SWEEP_MIN_INTERVAL_SEC:
            return
          _expiry_throttle['last_monotonic'] = _now_mono
          try:
            await asyncio.to_thread(_heartbeat_expiry_sweep)
          except Exception:
            return

        def _persist_websocket_connected_reconcile_event(
          *,
          level: str,
          event_type: str,
          detail: JSONDict,
        ) -> None:
          _db = str(getattr(settings, 'state_db_path', '') or '').strip()
          if not _db:
            return
          _conn = None
          try:
            _conn = open_database(_db)
            persist_runtime_event(
              _conn,
              level=level,
              event_type=event_type,
              recorded_at_utc=_websocket_runtime_utc_now(),
              operation_lane=lane,
              lane_session_id=lane_session_id,
              detail=detail,
            )
          finally:
            if _conn is not None:
              try:
                _conn.close()
              except Exception:
                pass

        def _websocket_connected_reconcile(reason: str) -> None:
          if lane != 'live':
            return
          if stop_event.is_set():
            return
          try:
            payload = reconcile_pairs(
              settings=settings,
              client_factory=_bounded_interactive_client_factory,
              suppress_live_funds_refresh=True,
              current_operating_session_id=lane_session_id,
            )
            _persist_websocket_connected_reconcile_event(
              level='INFO',
              event_type='websocket_connected_reconcile',
              detail={
                'reason': reason,
                'pair_count': int(payload.get('pair_count', 0) or 0),
                'repair_close_reconciled_count': int(payload.get('repair_close_reconciled_count', 0) or 0),
              },
            )
          except Exception as exc:
            try:
              _persist_websocket_connected_reconcile_event(
                level='WARN',
                event_type='websocket_connected_reconcile_failed',
                detail={'reason': reason, 'error_family': exc.__class__.__name__},
              )
            except Exception:
              return

        async def _websocket_connected_reconcile_async(reason: str) -> None:
          try:
            await asyncio.to_thread(_websocket_connected_reconcile, reason)
          except Exception:
            return

        client = KalshiWebSocketClient(
          ws_url=active_websocket_url,
          api_key_id=api_key_id,
          private_key=private_key,
        )
        await client.connect()
        _set_websocket_runtime_state(
          status='connected',
          websocket_connected=True,
          operation_lane=lane,
          lane_session_id=lane_session_id,
          active_websocket_url_tail=_websocket_label(active_websocket_url),
          reason_code=None,
          message='Authenticated websocket session active.',
          connecting_since=None,  # W1: connected -> clear the grace clock
        )
        _persist_websocket_runtime_event(
          settings,
          lane_session_id=lane_session_id,
          level='INFO',
          event_type='websocket_session_connected',
          detail={
            'active_websocket_url_tail': _websocket_label(active_websocket_url),
            'websocket_connected': True,
          },
        )
        # No funds on the initial connect beat: ready_event must fire promptly so
        # the lane change does not block on a balance fetch. Funds attach to the
        # steady-state beats below (first one ~2s later).
        _persist_websocket_runtime_heartbeat(
          settings,
          lane_session_id=lane_session_id,
          status='connected',
          websocket_connected=True,
          message_count=message_count,
        )
        asyncio.create_task(_websocket_connected_reconcile_async('connected'))
        ready_event.set()
        retry_count = 0
        ws_connected = True
        while not stop_event.is_set():
          if not ws_connected:
            try:
              await client.connect()
              ws_connected = True
              _set_websocket_runtime_state(
                status='connected',
                websocket_connected=True,
                operation_lane=lane,
                lane_session_id=lane_session_id,
                active_websocket_url_tail=_websocket_label(active_websocket_url),
                reason_code=None,
                message='WebSocket session reconnected.',
                connecting_since=None,  # W1: connected -> clear the grace clock
              )
              _persist_websocket_runtime_event(
                settings,
                lane_session_id=lane_session_id,
                level='INFO',
                event_type='websocket_session_reconnected',
                detail={
                  'active_websocket_url_tail': _websocket_label(active_websocket_url),
                  'websocket_connected': True,
                  'attempt': retry_count,
                },
              )
              _persist_websocket_runtime_heartbeat(
                settings,
                lane_session_id=lane_session_id,
                status='reconnected',
                websocket_connected=True,
                message_count=message_count,
                funds_detail=await _heartbeat_funds_detail_async(),
              )
              asyncio.create_task(_websocket_connected_reconcile_async('reconnected'))
              retry_count = 0
            except WebSocketAuthError:
              raise
            except Exception:
              if stop_event.is_set():
                raise
              backoff = _reconnect_backoff_seconds[min(retry_count, len(_reconnect_backoff_seconds) - 1)]
              retry_count += 1
              _set_websocket_runtime_state(
                status='reconnecting',
                websocket_connected=False,
                operation_lane=lane,
                lane_session_id=lane_session_id,
                active_websocket_url_tail=_websocket_label(active_websocket_url),
                reason_code=None,
                message=f'WebSocket reconnect attempt {retry_count} failed; retrying in {backoff}s.',
              )
              stopped = await _stop_aware_sleep(backoff)
              if stopped:
                return
              continue
          try:
            await client._recv_with_timeout(2.0)
            message_count += 1
          except Exception as exc:
            if exc.__class__.__name__ != 'WebSocketTimeout':
              ws_connected = False
              await client.disconnect()
              if stop_event.is_set():
                raise
              backoff = _reconnect_backoff_seconds[min(retry_count, len(_reconnect_backoff_seconds) - 1)]
              retry_count += 1
              _set_websocket_runtime_state(
                status='reconnecting',
                websocket_connected=False,
                operation_lane=lane,
                lane_session_id=lane_session_id,
                active_websocket_url_tail=_websocket_label(active_websocket_url),
                reason_code=None,
                message=f'WebSocket disconnected; reconnecting in {backoff}s (attempt {retry_count}).',
              )
              _persist_websocket_runtime_event(
                settings,
                lane_session_id=lane_session_id,
                level='INFO',
                event_type='websocket_session_reconnect_attempt',
                detail={
                  'active_websocket_url_tail': _websocket_label(active_websocket_url),
                  'websocket_connected': False,
                  'attempt': retry_count,
                  'backoff_sec': backoff,
                },
              )
              stopped = await _stop_aware_sleep(backoff)
              if stopped:
                return
              continue
          # T1: prompt candidate-expiry transition on each steady-state beat (~2s),
          # so cards flip at their deadline instead of one scan cycle later.
          await _heartbeat_expiry_sweep_async()
          _persist_websocket_runtime_heartbeat(
            settings,
            lane_session_id=lane_session_id,
            status='heartbeat-live',
            websocket_connected=True,
            message_count=message_count,
            funds_detail=await _heartbeat_funds_detail_async(),
          )
        await client.disconnect()

      try:
        asyncio.run(_runtime_loop())
      except WebSocketAuthError:
        _set_websocket_runtime_state(
          status='auth_failed',
          websocket_connected=False,
          operation_lane=lane,
          lane_session_id=lane_session_id,
          active_websocket_url_tail=_websocket_label(active_websocket_url),
          reason_code='credential_acceptance_failed',
          message='Authenticated websocket session was rejected by the platform.',
        )
        _persist_websocket_runtime_event(
          settings,
          lane_session_id=lane_session_id,
          level='WARN',
          event_type='websocket_session_auth_failed',
          detail={
            'active_websocket_url_tail': _websocket_label(active_websocket_url),
            'websocket_connected': False,
          },
        )
        _persist_websocket_runtime_heartbeat(
          settings,
          lane_session_id=lane_session_id,
          status='auth-failed',
          websocket_connected=False,
          message_count=message_count,
        )
        ready_event.set()
      except Exception as exc:
        _set_websocket_runtime_state(
          status='connection_failed',
          websocket_connected=False,
          operation_lane=lane,
          lane_session_id=lane_session_id,
          active_websocket_url_tail=_websocket_label(active_websocket_url),
          reason_code='websocket_connection_failed',
          message=str(exc) or 'Authenticated websocket session could not be established.',
        )
        _persist_websocket_runtime_event(
          settings,
          lane_session_id=lane_session_id,
          level='WARN',
          event_type='websocket_session_connection_failed',
          detail={
            'active_websocket_url_tail': _websocket_label(active_websocket_url),
            'websocket_connected': False,
            'message': str(exc),
          },
        )
        _persist_websocket_runtime_heartbeat(
          settings,
          lane_session_id=lane_session_id,
          status='connection-failed',
          websocket_connected=False,
          message_count=message_count,
        )
        ready_event.set()

    websocket_runtime_thread = threading.Thread(target=_run_runtime, daemon=True)
    websocket_runtime_thread.start()
    ready_event.wait(wait_for_ready_sec)
    if not ready_event.is_set() and websocket_runtime_thread.is_alive():
      ready_event.wait(wait_for_extended_sec)
    snapshot = _websocket_runtime_snapshot()
    if not bool(snapshot.get('websocket_connected')):
      _ws_status = str(snapshot.get('status') or '')
      # W1: a transient slow connect must NOT hard-fail the mode change and kill the
      # in-flight connect. Three-way decision at the wait timeout:
      #   - auth rejection (terminal, credential) -> fail closed immediately (unchanged);
      #   - a terminal connection failure or an exited runtime thread -> fail closed;
      #   - otherwise the connect is still in progress (status 'connecting', thread alive)
      #     -> leave it running and report connecting. The next deck poll surfaces
      #     'connected' when the cold connect lands; connecting_slow flags it past the grace.
      # 'connecting' is non-operative: money/submit/automation stay closed until connected.
      _ws_terminal = (
        _ws_status in {'auth_failed', 'connection_failed'}
        or not websocket_runtime_thread.is_alive()
      )
      if _ws_terminal:
        _stop_websocket_runtime(reason=str(snapshot.get('reason_code') or 'websocket_connection_failed'))
        snapshot = _websocket_runtime_snapshot()
    return snapshot

  def _sanitize_tone(value: Any) -> str | None:
    tone = str(value or '').strip().lower()
    return tone if tone in HIGHLIGHT_TONES else None

  def _resolve_deck_action_key(action_name: str) -> str | None:
    normalized_action = str(action_name or '').strip().lower()
    for deck_key, action_names in DECK_ACTION_GROUPS.items():
      if normalized_action in action_names:
        return deck_key
    return None

  def _resolve_detail_control_key(action_name: str) -> str | None:
    normalized_action = str(action_name or '').strip().lower()
    return DETAIL_CONTROL_ACTION_KEY_MAP.get(normalized_action)

  def _extract_action_tone(action_name: str, payload: JSONDict) -> str | None:
    normalized_action = str(action_name or '').strip().lower()
    deck_key = _resolve_deck_action_key(normalized_action)
    if deck_key == 'key_management':
      return _sanitize_tone(((payload.get('key_management') or {}).get('last_result') or {}).get('tone'))
    if deck_key == 'websocket_management':
      return _sanitize_tone(((payload.get('websocket_management') or {}).get('last_result') or {}).get('tone'))
    if deck_key == 'data_management':
      return _sanitize_tone(((payload.get('data_management') or {}).get('last_result') or {}).get('tone'))
    if deck_key == 'runtime_configuration':
      runtime_overlay = ((payload.get('session_overlay') or {}).get('runtime') or {})
      return _sanitize_tone(((runtime_overlay.get('last_result') or {}).get('tone')))
    if deck_key == 'context_overlay':
      context_overlay = ((payload.get('session_overlay') or {}).get('context') or {})
      return _sanitize_tone(((context_overlay.get('last_result') or {}).get('tone')))
    if str(payload.get('decision') or '').strip().lower() == 'no-go':
      return 'no-go'
    return None

  def _compute_highlight_updates(action_name: str, payload: JSONDict) -> JSONDict:
    tone = _extract_action_tone(action_name, payload)
    deck_key = _resolve_deck_action_key(action_name)
    detail_key = _resolve_detail_control_key(action_name)
    return {
      'tone': tone,
      'deck_key': deck_key,
      'detail_key': detail_key,
      'explicit_clear_deck': bool(payload.get('clear_deck_highlights')),
      'explicit_clear_detail': bool(payload.get('clear_detail_highlights')),
    }

  def _derive_deck_readiness_highlights(payload: JSONDict) -> dict[str, str]:
    def _pair_tone(left_present: bool, right_present: bool, *, empty_tone: str) -> str:
      if left_present and right_present:
        return 'ok'
      if not left_present and not right_present:
        return empty_tone
      return 'warn'

    settings_candidate = payload.get('settings')
    settings = cast(dict[str, Any], settings_candidate) if isinstance(settings_candidate, dict) else {}
    connection_posture_candidate = payload.get('connection_posture')
    connection_posture = cast(dict[str, Any], connection_posture_candidate) if isinstance(connection_posture_candidate, dict) else {}
    key_management_candidate = payload.get('key_management')
    key_management = cast(dict[str, Any], key_management_candidate) if isinstance(key_management_candidate, dict) else {}
    posture_urls_candidate = connection_posture.get('available_websocket_urls')
    posture_urls = cast(dict[str, Any], posture_urls_candidate) if isinstance(posture_urls_candidate, dict) else {}
    highlights: dict[str, str] = {}

    if connection_posture:
      sandbox_url = str(posture_urls.get('sandbox') or '').strip().lower()
      live_url = str(posture_urls.get('live') or '').strip().lower()
      sandbox_configured = bool(sandbox_url and sandbox_url != 'unconfigured')
      live_configured = bool(live_url and live_url != 'unconfigured')
      highlights['websocket_management'] = _pair_tone(sandbox_configured, live_configured, empty_tone='warn')
      if bool(connection_posture.get('mode_selected')):
        highlights['context_overlay'] = 'ok'

    if key_management:
      sandbox_key_present = bool(key_management.get('sandbox_key_loaded'))
      live_key_present = bool(key_management.get('live_key_loaded'))
      highlights['key_management'] = _pair_tone(sandbox_key_present, live_key_present, empty_tone='no-go')

    data_management_candidate = payload.get('data_management')
    data_management = cast(dict[str, Any], data_management_candidate) if isinstance(data_management_candidate, dict) else {}
    if data_management:
      sandbox_data_present = bool(data_management.get('sandbox_datapack_loaded'))
      live_data_present = bool(data_management.get('live_datapack_loaded'))
      if sandbox_data_present or live_data_present:
        highlights['data_management'] = _pair_tone(sandbox_data_present, live_data_present, empty_tone='warn')

    if bool(settings.get('settings_ready')):
      highlights['runtime_configuration'] = 'ok'
    return highlights

  def _prune_mutation_nonce_cache(now_ts: float) -> None:
    stale_nonces = [nonce for nonce, seen_at in mutation_nonce_seen_at.items() if now_ts - seen_at > MUTATION_NONCE_TTL_SEC]
    for nonce in stale_nonces:
      mutation_nonce_seen_at.pop(nonce, None)

  def _validate_signed_mutation_request(environ: dict[str, Any], path: str) -> JSONDict | None:
    if session_controller is None:
      return None
    session_token_value = str(parse_qs(str(environ.get('QUERY_STRING', ''))).get('session', [None])[0] or '')
    launch_token_value = str(parse_qs(str(environ.get('QUERY_STRING', ''))).get('launch', [None])[0] or '')
    if session_controller.requires_launch_identity():
      if not session_controller.accepts_identity(session_token_value, launch_token_value):
        return _no_go_payload(
          'session_identity_mismatch',
          'The browser session or launch identity is invalid for this local console host.',
          'Reopen the console from the current command line session.',
        )
    elif not session_controller.accepts(session_token_value):
      return _no_go_payload(
        'session_token_mismatch',
        'The browser session token is invalid for this local console host.',
        'Reopen the console from the current command line session.',
      )

    key_id = _request_header(environ, UI_MUTATION_KEY_ID_HEADER)
    timestamp_raw = _request_header(environ, UI_MUTATION_TIMESTAMP_HEADER)
    nonce = _request_header(environ, UI_MUTATION_NONCE_HEADER)
    supplied_hash = _request_header(environ, UI_MUTATION_HASH_HEADER).lower()
    supplied_signature = _request_header(environ, UI_MUTATION_SIGNATURE_HEADER)

    if not all((key_id, timestamp_raw, nonce, supplied_hash, supplied_signature)):
      return _no_go_payload(
        'mutation_signature_required',
        'Mutation request is missing required signed-call headers.',
        'Refresh the shell and retry the operation from the control deck.',
      )
    if key_id != mutation_signing_key_id:
      return _no_go_payload(
        'mutation_signature_invalid',
        'Mutation signing key mismatch detected for this local shell session.',
        'Reload the shell so the browser can re-bind to the active local session.',
      )

    try:
      timestamp_sec = int(timestamp_raw)
    except ValueError:
      return _no_go_payload(
        'mutation_signature_invalid',
        'Mutation timestamp is invalid.',
        'Reload the shell and retry the action.',
      )
    now_ts = int(time.time())
    if abs(now_ts - timestamp_sec) > MUTATION_SIGNATURE_WINDOW_SEC:
      return _no_go_payload(
        'mutation_signature_expired',
        'Mutation signature expired before validation completed.',
        'Retry the action from the current shell session.',
      )

    _prune_mutation_nonce_cache(float(now_ts))
    if nonce in mutation_nonce_seen_at:
      return _no_go_payload(
        'mutation_replay_detected',
        'Mutation request nonce was already used in this shell session.',
        'Retry the action from the control deck to generate a fresh signed call.',
      )

    body_bytes = _request_body_bytes(environ)
    computed_hash = hashlib.sha256(body_bytes).hexdigest().lower()
    if supplied_hash != computed_hash:
      return _no_go_payload(
        'mutation_hash_mismatch',
        'Mutation body hash did not match the signed payload.',
        'Retry from the shell UI and avoid replaying stale requests.',
      )

    canonical = f"POST\n{path}\n{timestamp_sec}\n{nonce}\n{computed_hash}".encode('utf-8')
    expected_signature = base64.b64encode(hmac.new(mutation_signing_secret, canonical, hashlib.sha256).digest()).decode('ascii')
    if not hmac.compare_digest(expected_signature, supplied_signature):
      return _no_go_payload(
        'mutation_signature_invalid',
        'Mutation signature verification failed for this request.',
        'Reload the shell and retry the operation.',
      )

    mutation_nonce_seen_at[nonce] = float(now_ts)
    return None

  def _apply_highlight_merge(current: dict[str, str], *, key: str | None, tone: str | None, clear: bool) -> dict[str, str]:
    if clear:
      return {}
    merged = dict(current)
    if not key or key not in {*DECK_ACTION_KEYS, *DETAIL_CONTROL_KEYS}:
      return merged
    if tone == 'ok':
      merged.pop(key, None)
      return merged
    if tone in HIGHLIGHT_TONES:
      merged[key] = tone
    return merged

  def _apply_orchestrator_highlight_envelope(action_name: str, payload: JSONDict) -> None:
    workflow_payload = payload.get('workflow')
    if not isinstance(workflow_payload, dict):
      workflow_payload = {}
      payload['workflow'] = workflow_payload

    current_deck = _derive_deck_readiness_highlights(payload)
    current_detail = dict(highlight_state.get('detail_control_highlights') or {})
    updates = _compute_highlight_updates(action_name, payload)

    next_detail = _apply_highlight_merge(
      current_detail,
      key=updates.get('detail_key'),
      tone=updates.get('tone'),
      clear=bool(updates.get('explicit_clear_detail')),
    )

    highlight_state['deck_action_highlights'] = {
      key: value
      for key, value in current_deck.items()
      if key in DECK_ACTION_KEYS and value in HIGHLIGHT_TONES
    }
    highlight_state['detail_control_highlights'] = {
      key: value
      for key, value in next_detail.items()
      if key in DETAIL_CONTROL_KEYS and value in HIGHLIGHT_TONES
    }

    workflow_payload['deck_action_highlights'] = dict(highlight_state['deck_action_highlights'])
    workflow_payload['detail_control_highlights'] = dict(highlight_state['detail_control_highlights'])
    workflow_payload['highlight_policy_version'] = HIGHLIGHT_POLICY_VERSION

  # --- Persistent clear tombstone -----------------------------------------------
  # A tombstone is a durable marker that survives process restart.  When an
  # operator explicitly clears the key reference or websocket URLs the tombstone
  # is written to disk.  On startup the tombstone is read first, before any
  # .env/config fallback is applied, so cleared state can NEVER repopulate
  # without an explicit operator Load action.
  #
  # Fields:
  #   key_reference_cleared   - set by /api/key-clear; removed only by /api/key-apply after an explicit Load
  #   websocket_urls_cleared  - set by websocket-overlay clear_all; retained until an explicit lane load updates tombstones
  #   websocket_sandbox_cleared / websocket_live_cleared - per-lane clear holds removed only by explicit lane load
  #
  # Storage: JSON file adjacent to state_db_path (same directory), or
  #          ~/.polyventure/operator_clear_tombstones.json if state_db_path is absent.

  def _hydrate_lane_validation_from_tombstone(lane: str) -> None:
    normalized_lane = str(lane or '').strip().lower()
    if normalized_lane not in {'sandbox', 'live'}:
      return
    validated = _startup_tombstone.get(f'{normalized_lane}_key_validated')
    if validated not in {True, False}:
      return
    key_management_state[f'{normalized_lane}_key_validated'] = bool(validated)
    key_management_state[f'{normalized_lane}_key_validation_reason'] = str(
      _startup_tombstone.get(f'{normalized_lane}_key_validation_reason') or ('pass' if validated else 'error')
    ).strip().lower() or ('pass' if validated else 'error')
    key_management_state[f'{normalized_lane}_key_validation_timestamp'] = str(
      _startup_tombstone.get(f'{normalized_lane}_key_validation_timestamp') or ''
    ).strip() or None
    key_management_state[f'{normalized_lane}_key_validation_path'] = str(
      _startup_tombstone.get(f'{normalized_lane}_key_validation_path') or ''
    ).strip() or None

  def _sync_lane_validation_tombstone(lane: str) -> None:
    normalized_lane = str(lane or '').strip().lower()
    if normalized_lane not in {'sandbox', 'live'}:
      return
    validated = key_management_state.get(f'{normalized_lane}_key_validated')
    tombstone_fields = (
      f'{normalized_lane}_key_validated',
      f'{normalized_lane}_key_validation_reason',
      f'{normalized_lane}_key_validation_timestamp',
      f'{normalized_lane}_key_validation_path',
    )
    if validated not in {True, False}:
      for field in tombstone_fields:
        _remove_tombstone(field)
      return
    _set_tombstone_value(f'{normalized_lane}_key_validated', bool(validated))
    _set_tombstone_value(
      f'{normalized_lane}_key_validation_reason',
      str(key_management_state.get(f'{normalized_lane}_key_validation_reason') or ('pass' if validated else 'error')).strip().lower() or ('pass' if validated else 'error'),
    )
    _set_tombstone_value(
      f'{normalized_lane}_key_validation_timestamp',
      str(key_management_state.get(f'{normalized_lane}_key_validation_timestamp') or '').strip(),
    )
    _set_tombstone_value(
      f'{normalized_lane}_key_validation_path',
      str(key_management_state.get(f'{normalized_lane}_key_validation_path') or '').strip(),
    )

  def _default_tombstone_path() -> Path:
    configured_state_db = os.getenv('KALSHI_STATE_DB_PATH', '').strip()
    if not configured_state_db:
      try:
        configured_settings = _resolve_settings(None)
      except Exception:
        configured_settings = None
      configured_state_db = str(getattr(configured_settings, 'state_db_path', '') or '').strip()
    if configured_state_db:
      resolved_state_db = Path(configured_state_db).expanduser()
      if not resolved_state_db.is_absolute():
        resolved_state_db = (PROJECT_ROOT / resolved_state_db).resolve()
      return resolved_state_db.parent / '_operator_clear_tombstones.json'
    return Path.home() / '.polyventure' / 'operator_clear_tombstones.json'

  def _websocket_tombstone_config_truth(*, env_override: str | None = None, subaccount_override: int | None = None) -> JSONDict:
    try:
      configured_settings = _resolve_settings(
        None,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
    except Exception:
      return {
        'sandbox': '',
        'live': '',
      }
    return {
      'sandbox': _websocket_label(getattr(configured_settings, 'sandbox_websocket_url', None)),
      'live': _websocket_label(getattr(configured_settings, 'live_websocket_url', None)),
    }

  _tombstone_file: Path = (
    tombstone_path
    if tombstone_path is not None
    else _default_tombstone_path()
  )
  _uploaded_key_dir: Path = _tombstone_file.parent / 'uploaded_keys'
  _tombstone_lock = threading.Lock()

  def _persistence_hydration_allowed(active_settings: Any) -> bool:
    state_db_path = str(getattr(active_settings, 'state_db_path', '') or '').strip()
    if not state_db_path:
      return False
    if not os.getenv('PYTEST_CURRENT_TEST'):
      return True
    resolved_state_db = Path(state_db_path).expanduser()
    if not resolved_state_db.is_absolute():
      resolved_state_db = (PROJECT_ROOT / resolved_state_db).resolve()
    resolved_project_root = PROJECT_ROOT.resolve()
    resolved_pytest_tmp = (resolved_project_root / '.pytest-tmp').resolve()
    if resolved_state_db == resolved_pytest_tmp or resolved_pytest_tmp in resolved_state_db.parents:
      return True
    return resolved_state_db != resolved_project_root and resolved_project_root not in resolved_state_db.parents

  def _read_tombstone() -> dict[str, Any]:
    try:
      with open(_tombstone_file, 'r', encoding='utf-8') as _fh:
        _data = json.load(_fh)
      return _data if isinstance(_data, dict) else {}
    except (FileNotFoundError, json.JSONDecodeError, OSError):
      return {}

  def _write_tombstone(data: dict[str, Any]) -> None:
    try:
      _tombstone_file.parent.mkdir(parents=True, exist_ok=True)
      _tmp = _tombstone_file.with_suffix('.tmp')
      _tmp.write_text(json.dumps(data, indent=2), encoding='utf-8')
      _tmp.replace(_tombstone_file)
    except OSError:
      pass  # non-fatal; in-memory state still holds for this session

  def _set_tombstone(field: str) -> None:
    with _tombstone_lock:
      _d = _read_tombstone()
      _d[field] = True
      _write_tombstone(_d)

  def _set_tombstone_value(field: str, value: Any) -> None:
    with _tombstone_lock:
      _d = _read_tombstone()
      _d[field] = value
      _write_tombstone(_d)

  def _remove_tombstone(field: str) -> None:
    with _tombstone_lock:
      _d = _read_tombstone()
      _d.pop(field, None)
      _write_tombstone(_d)

  # Hydrate in-memory state from tombstone on startup so cleared state
  # is enforced immediately -- before any first request arrives.
  _startup_tombstone = _read_tombstone()
  _startup_tombstone_keys = sorted([str(key) for key in _startup_tombstone.keys()]) if isinstance(_startup_tombstone, dict) else []
  print(
    '[INFO] Key/session tombstone hydration startup :: '
    f'path={_tombstone_file} :: '
    f'keys={",".join(_startup_tombstone_keys) if _startup_tombstone_keys else "none"}'
  )
  if _startup_tombstone.get('key_reference_cleared'):
    key_management_state['sandbox_key_path'] = None
    key_management_state['sandbox_key_source_label'] = None
    key_management_state['sandbox_api_key_id'] = None
    key_management_state['live_key_path'] = None
    key_management_state['live_key_source_label'] = None
    key_management_state['live_api_key_id'] = None
    key_management_state['overlay_key_path'] = None
    key_management_state['overlay_key_source_label'] = None
    key_management_state['clear_requested'] = True
  else:
    _startup_sandbox_key_path = str(_startup_tombstone.get('sandbox_key_reference_path') or '').strip()
    _startup_live_key_path = str(_startup_tombstone.get('live_key_reference_path') or '').strip()
    if _startup_sandbox_key_path:
      key_management_state['sandbox_key_path'] = _startup_sandbox_key_path
      key_management_state['sandbox_key_source_label'] = str(_startup_tombstone.get('sandbox_key_reference_source_label') or 'Session key')
    if _startup_live_key_path:
      key_management_state['live_key_path'] = _startup_live_key_path
      key_management_state['live_key_source_label'] = str(_startup_tombstone.get('live_key_reference_source_label') or 'Session key')
    _startup_key_path = str(_startup_tombstone.get('key_reference_path') or '').strip()
    if _startup_key_path:
      key_management_state['overlay_key_path'] = _startup_key_path
      key_management_state['overlay_key_source_label'] = str(_startup_tombstone.get('key_reference_source_label') or 'Session key')
    if not _startup_sandbox_key_path and not _startup_live_key_path and _startup_key_path:
      key_management_state['sandbox_key_path'] = _startup_key_path
      key_management_state['sandbox_key_source_label'] = str(_startup_tombstone.get('key_reference_source_label') or 'Session key')
    _hydrate_lane_validation_from_tombstone('sandbox')
    _hydrate_lane_validation_from_tombstone('live')
  _startup_sandbox_datapack_root = str(_startup_tombstone.get('sandbox_datapack_root') or '').strip()
  _startup_live_datapack_root = str(_startup_tombstone.get('live_datapack_root') or '').strip()
  if _startup_sandbox_datapack_root:
    data_management_state['sandbox_datapack_root'] = _startup_sandbox_datapack_root
  if _startup_live_datapack_root:
    data_management_state['live_datapack_root'] = _startup_live_datapack_root
  try:
    _startup_base_settings = _resolve_settings(None, env_override=None, subaccount_override=None)
    for _startup_lane in ('sandbox', 'live'):
      _startup_db_path_value = str(getattr(_startup_base_settings, 'state_db_path', None) or '').strip()
      if not _startup_db_path_value:
        continue
      _startup_db_path = Path(_startup_db_path_value).expanduser()
      if not _startup_db_path.is_absolute():
        _startup_db_path = (Path.cwd() / _startup_db_path).resolve()
      if not _startup_db_path.exists():
        continue
      _startup_conn = open_database(_startup_db_path)
      _startup_row = _startup_conn.execute(
        'SELECT detail_json FROM lane_active_datapack WHERE operation_lane = ? AND closed_at_utc IS NULL LIMIT 1',
        (_startup_lane,),
      ).fetchone()
      if _startup_row is not None:
        try:
          _startup_detail = json.loads(str(_startup_row['detail_json'] or '{}'))
          _startup_datapack_id = str(_startup_detail.get('datapack_id') or '').strip()
          if _startup_datapack_id:
            data_management_state[f'{_startup_lane}_datapack_id'] = _startup_datapack_id
        except Exception:
          pass
  except Exception:
    pass
  if _startup_tombstone.get('websocket_urls_cleared'):
    websocket_overlay_state.update({
      'websocket_url': '',
      'sandbox_websocket_url': '',
      'live_websocket_url': '',
      'active_websocket_url': '',
    })
  if _startup_tombstone.get('websocket_sandbox_cleared'):
    websocket_overlay_state['sandbox_websocket_url'] = ''
  if _startup_tombstone.get('websocket_live_cleared'):
    websocket_overlay_state['live_websocket_url'] = ''
  startup_websocket_truth = _websocket_tombstone_config_truth()
  startup_websocket_contract = str(_startup_tombstone.get('websocket_overlay_contract_version') or '').strip()
  startup_sandbox_truth = str(_startup_tombstone.get('websocket_sandbox_config_url') or '').strip()
  startup_live_truth = str(_startup_tombstone.get('websocket_live_config_url') or '').strip()
  startup_persisted_websocket_labels = {
    'sandbox': _websocket_label(_startup_tombstone.get('websocket_sandbox_url')),
    'live': _websocket_label(_startup_tombstone.get('websocket_live_url')),
  }
  startup_truth_markers_match_current_config = bool(startup_sandbox_truth or startup_live_truth) and {
    'sandbox': startup_sandbox_truth,
    'live': startup_live_truth,
  } == startup_websocket_truth
  startup_legacy_persisted_urls_match_current_config = startup_persisted_websocket_labels == startup_websocket_truth
  can_hydrate_persisted_websocket_urls = (
    startup_truth_markers_match_current_config
    and (
      startup_websocket_contract == WEBSOCKET_TOMBSTONE_CONTRACT_VERSION
      or startup_legacy_persisted_urls_match_current_config
    )
  )
  if 'websocket_sandbox_url' in _startup_tombstone and can_hydrate_persisted_websocket_urls:
    websocket_overlay_state['sandbox_websocket_url'] = str(_startup_tombstone.get('websocket_sandbox_url') or '')
  if 'websocket_live_url' in _startup_tombstone and can_hydrate_persisted_websocket_urls:
    websocket_overlay_state['live_websocket_url'] = str(_startup_tombstone.get('websocket_live_url') or '')
  _startup_registry = _startup_tombstone.get('key_registry')
  if isinstance(_startup_registry, list):
    key_management_state['key_registry'] = [entry for entry in _startup_registry if isinstance(entry, dict)]
    key_management_state['discovery_ran'] = False
  print(
    '[INFO] Key/session tombstone hydration applied :: '
    f'clear_hold={bool(key_management_state.get("clear_requested"))} :: '
    f'sandbox_ref_present={bool(key_management_state.get("sandbox_key_path"))} :: '
    f'live_ref_present={bool(key_management_state.get("live_key_path"))} :: '
    f'sandbox_datapack_ref_present={bool(data_management_state.get("sandbox_datapack_id"))} :: '
    f'live_datapack_ref_present={bool(data_management_state.get("live_datapack_id"))}'
  )
  
  # ============ DISCOVERY CACHE LIFECYCLE ============
  # KDISC-001 Contract: Discovery cache (discovered_candidates) is volatile and must be flushed on
  # app teardown; it does not persist across restarts. Loaded state (keys/URLs) persists separately.
  
  def _validate_discovery_cache_boot_state() -> None:
    """Boot validation: Assert discovery cache is empty; if stale data exists, log and clear it."""
    discovered_count = len(key_management_state.get('discovered_candidates', []))
    if discovered_count > 0:
      print(
        f'[WARN] Discovery cache not empty at boot startup: {discovered_count} stale candidates detected. '
        f'Clearing cache for fresh session. (This should not occur unless prior session teardown was incomplete.)'
      )
      key_management_state['discovered_candidates'] = []
      key_management_state['candidate_lookup'] = {}
  
  def _flush_discovery_cache_on_teardown() -> None:
    """Teardown hook: Flush discovery cache to zero; called on app shutdown/restart."""
    # KDISC-001: Explicitly zero out the discovery cache; do NOT persist across sessions.
    key_management_state['discovered_candidates'] = []
    key_management_state['candidate_lookup'] = {}
    # Note: discovery_ran flag is kept as-is; it will be set to False on next boot hydration.
  
  # Boot validation: Call immediately after tombstone hydration
  _validate_discovery_cache_boot_state()
  
  # Shutdown hook registration note:
  # This function should be called in the app lifecycle shutdown handler:
  # - For WSGI: call _flush_discovery_cache_on_teardown() in a finally block or context manager
  # - For Flask: register via app.teardown_appcontext(_flush_discovery_cache_on_teardown)
  # - For other frameworks: wire to the appropriate lifecycle hook before process exit
  # Currently set up for manual invocation; no automatic lifecycle hook exists in base WSGI.
  # ===================================================
  # ------------------------------------------------------------------------------

  def _parse_boolish(value: Any) -> bool:
    if isinstance(value, bool):
      return value
    return str(value).strip().lower() in {'1', 'true', 'yes', 'on'}

  def _coerce_overlay_values(raw_values: dict[str, Any], specs: dict[str, Callable[[Any], Any]]) -> JSONDict:
    normalized: JSONDict = {}
    for key, parser in specs.items():
      raw_value = raw_values.get(key)
      if raw_value in {None, ''}:
        continue
      normalized[key] = parser(raw_value)
    return normalized

  def _runtime_overlay_invalid_keys(raw_values: Any) -> list[str]:
    if not isinstance(raw_values, dict):
      raise TypeError('runtime overlay values must be a mapping')
    invalid_keys: list[str] = []
    for key, raw_value in raw_values.items():
      normalized_key = str(key or '').strip()
      if not normalized_key or normalized_key in runtime_overlay_specs:
        continue
      if raw_value in {None, ''}:
        continue
      invalid_keys.append(normalized_key)
    return sorted(set(invalid_keys))

  def _runtime_overlay_success_message(overlay_values: Mapping[str, Any], *, reset_requested: bool) -> str:
    if reset_requested or not overlay_values:
      return 'Runtime session overlay reset to config values.'
    parameter_count = len(overlay_values)
    return 'Runtime session overlay applied for {count} parameter{suffix}.'.format(
      count=parameter_count,
      suffix='' if parameter_count == 1 else 's',
    )

  def _runtime_baseline_default_values(*, env_override: str | None, subaccount_override: int | None) -> JSONDict:
    baseline_settings = _resolve_settings(
      None,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    return {
      field_id: getattr(baseline_settings, field_id, None)
      for field_id in runtime_overlay_specs
    }

  def _runtime_working_default_values(*, env_override: str | None, subaccount_override: int | None) -> JSONDict:
    baseline_values = _runtime_baseline_default_values(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    return {
      field_id: runtime_working_default_state.get(field_id, baseline_values.get(field_id))
      for field_id in runtime_overlay_specs
    }

  def _sync_runtime_overlay_auto_find_candidates_cadence(
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> int:
    baseline_values = _runtime_baseline_default_values(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    baseline_cadence = int(baseline_values.get('auto_find_candidates_cadence_ms') or 600000)
    current_cadence = int(automation_overlay_state.get('cadence_ms') or baseline_cadence or 600000)
    if current_cadence <= 0:
      current_cadence = baseline_cadence or 600000
    if current_cadence == baseline_cadence:
      runtime_overlay_state.pop('auto_find_candidates_cadence_ms', None)
    else:
      runtime_overlay_state['auto_find_candidates_cadence_ms'] = current_cadence
    return current_cadence

  def _sync_automation_cadence_from_settings(
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> int:
    active_settings = _effective_shell_settings(env_override, subaccount_override)
    resolved_cadence = int(
      getattr(active_settings, 'auto_find_candidates_cadence_ms', None)
      or automation_overlay_state.get('cadence_ms')
      or 600000
    )
    if resolved_cadence <= 0:
      resolved_cadence = int(automation_overlay_state.get('cadence_ms') or 600000)
    automation_overlay_state['cadence_ms'] = resolved_cadence
    return _sync_runtime_overlay_auto_find_candidates_cadence(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )

  def _runtime_group_field_ids(group_id: Any) -> tuple[str, ...]:
    return runtime_set_group_field_ids.get(str(group_id or '').strip(), ())

  def _normalized_runtime_full_values(
    raw_values: Any,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict:
    invalid_keys = _runtime_overlay_invalid_keys(raw_values)
    if invalid_keys:
      raise KeyError(','.join(invalid_keys))
    normalized_values = _coerce_overlay_values(raw_values, runtime_overlay_specs)
    baseline_values = _runtime_baseline_default_values(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    return {
      field_id: normalized_values.get(field_id, baseline_values.get(field_id))
      for field_id in runtime_overlay_specs
    }

  def _store_runtime_working_defaults(
    full_values: Mapping[str, Any],
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict:
    baseline_values = _runtime_baseline_default_values(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    runtime_working_default_state.clear()
    for field_id in runtime_overlay_specs:
      value = full_values.get(field_id, baseline_values.get(field_id))
      if baseline_values.get(field_id) != value:
        runtime_working_default_state[field_id] = value
    return _runtime_working_default_values(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )

  def _persist_runtime_working_defaults_to_db(*, env_override: str | None, subaccount_override: int | None) -> None:
    resolved = _server_base_settings(env_override, subaccount_override)
    db_path = str(getattr(resolved, 'state_db_path', '') or '').strip()
    if not db_path:
      return
    lane = str(getattr(resolved, 'operation_lane', 'sandbox') or 'sandbox').lower()
    try:
      with open_database(db_path) as connection:
        persist_lane_defaults(
          connection,
          lane,
          dict(runtime_working_default_state),
          sources={
            field_id: source
            for field_id, source in runtime_working_default_sources.items()
            if field_id in runtime_working_default_state
          },
        )
    except Exception as _wd_exc:
      print(f'[WARN] WD defaults persist failed: {_wd_exc}')

  def _load_runtime_working_defaults_from_db(*, env_override: str | None, subaccount_override: int | None) -> None:
    resolved = _server_base_settings(env_override, subaccount_override)
    db_path = str(getattr(resolved, 'state_db_path', '') or '').strip()
    if not db_path:
      return
    lane = str(getattr(resolved, 'operation_lane', 'sandbox') or 'sandbox').lower()
    try:
      with open_database(db_path) as connection:
        stored = load_lane_defaults(connection, lane)
        stored_sources = load_lane_default_sources(connection, lane)
      baseline = _runtime_baseline_default_values(
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      for field_id, raw_value in stored.items():
        if field_id in runtime_overlay_specs:
          coerced = runtime_overlay_specs[field_id](raw_value)
          if baseline.get(field_id) != coerced:
            runtime_working_default_state[field_id] = coerced
            # carry provenance forward so the OPTIMIZED pill survives restart
            runtime_working_default_sources[field_id] = stored_sources.get(field_id, 'operator')
    except Exception as _wd_exc:
      print(f'[WARN] WD defaults load failed: {_wd_exc}')

  def _apply_runtime_working_defaults_to_overlay(*, env_override: str | None, subaccount_override: int | None) -> JSONDict:
    baseline_values = _runtime_baseline_default_values(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    working_values = _runtime_working_default_values(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    runtime_overlay_state.clear()
    runtime_overlay_state.update(
      {
        field_id: working_values[field_id]
        for field_id in runtime_overlay_specs
        if working_values.get(field_id) != baseline_values.get(field_id)
      }
    )
    return dict(runtime_overlay_state)

  _base_settings_cache: dict[str, Any] = {}
  # FB-7: per-server cache of the last fresh header funds value, used to bridge the
  # banner across funds-less (scan-driven) rebuilds during automation.
  _header_funds_cache: dict[str, Any] = {}

  def _server_base_settings(env_override: str | None, subaccount_override: int | None) -> Any:
    # S6: the .env file base is immutable for the life of the server process, so
    # load and parse it once and reuse it across every rebuild instead of
    # re-reading the file on each call. env/subaccount overrides still derive
    # from the cached base via replace(), preserving prior _resolve_settings
    # semantics exactly. A genuine .env edit is a restart-required config change.
    base = _base_settings_cache.get('base')
    if base is None:
      base = _resolve_settings(None, env_override=None, subaccount_override=None)
      _base_settings_cache['base'] = base
    resolved = base
    if env_override is not None:
      resolved = replace(resolved, kalshi_env=env_override)
    if subaccount_override is not None:
      resolved = replace(resolved, subaccount=subaccount_override)
    return resolved

  def _active_settings(env_override: str | None, subaccount_override: int | None) -> Any:
    combined_values = {
      **runtime_overlay_state,
      **context_overlay_state,
      **websocket_overlay_state,
    }
    overlay_key_path = None
    if not key_management_state.get('clear_requested'):
      overlay_key_path = (
        key_management_state.get('overlay_key_path')
        or key_management_state.get('sandbox_key_path')
        or key_management_state.get('live_key_path')
      )
    if env_override is None and subaccount_override is None and not combined_values and not overlay_key_path:
      return None
    base_settings = _server_base_settings(env_override, subaccount_override)
    if not combined_values and not overlay_key_path:
      return base_settings
    operation_lane = str(combined_values.get('operation_lane', base_settings.operation_lane or 'sandbox')).strip().lower() or 'sandbox'
    sandbox_websocket_url = str(combined_values.get('sandbox_websocket_url', base_settings.sandbox_websocket_url or '') or '').strip()
    live_websocket_url = str(combined_values.get('live_websocket_url', base_settings.live_websocket_url or '') or '').strip()
    compatibility_websocket_url = str(combined_values.get('websocket_url', base_settings.websocket_url or '') or '').strip()
    active_websocket_url = sandbox_websocket_url if operation_lane == 'sandbox' else live_websocket_url
    if not active_websocket_url:
      active_websocket_url = compatibility_websocket_url
    if any(key in combined_values for key in {'operation_lane', 'sandbox_websocket_url', 'live_websocket_url', 'websocket_url', 'active_websocket_url'}):
      compatibility_websocket_url = active_websocket_url
    elif not compatibility_websocket_url:
      compatibility_websocket_url = active_websocket_url
    replace_values = {
      key: value
      for key, value in combined_values.items()
      if key not in {
        'operation_lane',
        'websocket_url',
        'sandbox_websocket_url',
        'live_websocket_url',
        'active_websocket_url',
        'mode_selected',
        'detected_api_base_url',
      }
    }
    lane_key_path = None
    if operation_lane == 'live':
      lane_key_path = key_management_state.get('live_key_path')
    else:
      lane_key_path = key_management_state.get('sandbox_key_path')
    lane_api_key_id = _lane_api_key_id(
      operation_lane,
      base_api_key_id=getattr(base_settings, 'api_key_id', None),
      lane_settings_api_key_id=getattr(base_settings, f'{operation_lane}_api_key_id', None),
    )
    if key_management_state.get('clear_requested'):
      effective_key_path = None
    elif operation_lane == 'live':
      effective_key_path = lane_key_path or getattr(base_settings, 'live_private_key_file', '') or None
    else:
      effective_key_path = lane_key_path or base_settings.private_key_file
    effective_api_base_url, effective_kalshi_env = _lane_api_environment_profile(
      operation_lane,
      lane_websocket_url=active_websocket_url,
    )
    return replace(
      base_settings,
      **replace_values,
      operation_lane=operation_lane,
      kalshi_env=effective_kalshi_env,
      api_base_url=effective_api_base_url,
      websocket_url=compatibility_websocket_url,
      sandbox_websocket_url=sandbox_websocket_url,
      live_websocket_url=live_websocket_url,
      active_websocket_url=active_websocket_url,
      private_key_file=effective_key_path,
      api_key_id=str(lane_api_key_id or ('' if operation_lane == 'live' else getattr(base_settings, 'api_key_id', '')) or '').strip(),
    )

  def _effective_shell_settings(env_override: str | None, subaccount_override: int | None) -> Any:
    active_settings = _active_settings(env_override, subaccount_override)
    if not key_management_state.get('clear_requested'):
      return active_settings
    base_settings = active_settings if active_settings is not None else _server_base_settings(
      env_override, subaccount_override
    )
    return replace(base_settings, private_key_file=None, private_key_path_legacy=None, private_key_inline=None)

  def _automation_state_id(enabled: bool, paused: bool, *, previous_state: str | None = None) -> str:
    if enabled and paused:
      return 'paused'
    if enabled:
      return 'enabled_idle'
    if str(previous_state or '').strip().lower() == 'stopped':
      return 'stopped'
    return 'disabled'

  def _automation_manual_truth_gate(*, env_override: str | None, subaccount_override: int | None) -> JSONDict:
    active_settings = _effective_shell_settings(env_override, subaccount_override)
    if active_settings is None:
      try:
        active_settings = _resolve_settings(
          None,
          env_override=env_override,
          subaccount_override=subaccount_override,
        )
      except Exception:
        return {
          'ready': False,
          'reason': 'settings_unavailable',
          'message': 'Automation requires a resolved shell configuration before it can resume.',
          'lane_session_id': '',
        }
    state_db_path = str(getattr(active_settings, 'state_db_path', '') or '').strip()
    if not state_db_path:
      return {
        'ready': False,
        'reason': 'state_db_unavailable',
        'message': 'Automation requires local runtime state history before activation.',
        'lane_session_id': '',
      }
    operation_lane = str(getattr(active_settings, 'operation_lane', 'sandbox') or 'sandbox')
    required_events = {'submit_order_intent', 'fill', 'reconcile_snapshot', 'cancel_applied'}
    try:
      connection = open_database(state_db_path)
      rows = connection.execute(
        '''
        SELECT lane_session_id, event_type, detail_json
        FROM runtime_events
        WHERE operation_lane = ?
          AND event_type IN ('submit_order_intent', 'fill', 'reconcile_snapshot', 'cancel_applied')
        ORDER BY id DESC
        LIMIT 500
        ''',
        (operation_lane,),
      ).fetchall()
    except Exception:
      return {
        'ready': False,
        'reason': 'history_unavailable',
        'message': 'Automation could not read local execution chronology evidence.',
        'lane_session_id': '',
      }

    events_by_session: dict[str, set[str]] = {}
    for row in rows:
      lane_session_id = str(row['lane_session_id'] or '').strip()
      if not lane_session_id:
        continue
      detail_json = row['detail_json']
      if detail_json:
        try:
          detail = json.loads(detail_json)
        except (TypeError, ValueError):
          detail = {}
      else:
        detail = {}
      profile = str(detail.get('profile') or '').strip().lower()
      if profile and profile != 'submit_order_bridge':
        continue
      events_by_session.setdefault(lane_session_id, set()).add(str(row['event_type'] or ''))

    for lane_session_id, event_names in events_by_session.items():
      if required_events.issubset(event_names):
        return {
          'ready': True,
          'reason': 'manual_execution_verified',
          'message': 'Manual execution chronology verified for this lane.',
          'lane_session_id': lane_session_id,
        }

    if events_by_session:
      return {
        'ready': False,
        'reason': 'manual_execution_not_verified',
        'message': 'Run Submit order once and retain complete chronology evidence before resuming automation.',
        'lane_session_id': '',
      }

    scan_snapshot = _scan_runtime_snapshot()
    if str(scan_snapshot.get('status') or '').lower() in {'processing', 'canceling'}:
      return {
        'ready': False,
        'reason': 'scan_processing_active',
        'message': 'Automation cannot resume while Find candidates is still processing.',
        'lane_session_id': str(scan_snapshot.get('lane_session_id') or ''),
      }

    mode_selected = bool(context_overlay_state.get('mode_selected', False))
    if not mode_selected or operation_lane not in {'sandbox', 'live'}:
      return {
        'ready': False,
        'reason': 'connected_lane_not_selected',
        'message': 'Automation requires a connected sandbox or live lane before it can be enabled.',
        'lane_session_id': '',
      }

    settings_payload, settings_error = _load_shell_settings_context(settings_override=active_settings)
    if settings_error is not None or not _is_mode_change_ready(settings_payload):
      return {
        'ready': False,
        'reason': 'connected_lane_not_ready',
        'message': 'Automation requires credential and websocket readiness before it can be enabled.',
        'lane_session_id': '',
      }

    runtime_snapshot = _websocket_runtime_projection(operation_lane, mode_selected=mode_selected)
    if not bool((runtime_snapshot or {}).get('websocket_connected')):
      return {
        'ready': False,
        'reason': 'websocket_connection_unavailable',
        'message': 'Automation requires a healthy authenticated websocket session in the active connected lane.',
        'lane_session_id': str((runtime_snapshot or {}).get('lane_session_id') or ''),
      }

    return {
      'ready': True,
      'reason': 'connected_lane_ready_no_manual_history',
      'message': 'Connected lane readiness verified; automation may be enabled before the first scan.',
      'lane_session_id': str((runtime_snapshot or {}).get('lane_session_id') or ''),
    }

  def _persist_automation_transition(
    *,
    settings: Any,
    action_name: str,
    transition_reason: str,
    transition_message: str,
    gate_snapshot: JSONDict,
  ) -> None:
    try:
      connection = open_database(getattr(settings, 'state_db_path'))
      recorded_at_utc = _utc_now_iso()
      operation_lane = str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox')
      persist_operator_action(
        connection,
        action=f'automation-{action_name}',
        recorded_at_utc=recorded_at_utc,
        operation_lane=operation_lane,
        lane_session_id=str(gate_snapshot.get('lane_session_id') or ''),
        detail={
          'automation_state_id': str(automation_overlay_state.get('state_id') or ''),
          'enabled': bool(automation_overlay_state.get('enabled')),
          'paused': bool(automation_overlay_state.get('paused')),
          'cadence_ms': int(automation_overlay_state.get('cadence_ms') or 0),
          'max_iterations': int(automation_overlay_state.get('max_iterations') or 0),
          'transition_reason': transition_reason,
          'transition_message': transition_message,
          'manual_truth_ready': bool(gate_snapshot.get('ready')),
          'manual_truth_reason': str(gate_snapshot.get('reason') or ''),
        },
      )
      persist_runtime_event(
        connection,
        level='INFO',
        event_type='automation_policy_transition',
        recorded_at_utc=recorded_at_utc,
        operation_lane=operation_lane,
        lane_session_id=str(gate_snapshot.get('lane_session_id') or ''),
        detail={
          'action': action_name,
          'automation_state_id': str(automation_overlay_state.get('state_id') or ''),
          'enabled': bool(automation_overlay_state.get('enabled')),
          'paused': bool(automation_overlay_state.get('paused')),
          'transition_reason': transition_reason,
          'manual_truth_ready': bool(gate_snapshot.get('ready')),
          'manual_truth_reason': str(gate_snapshot.get('reason') or ''),
        },
      )
    except Exception:
      pass

  def _active_transition_lane_session_id() -> str:
    scan_snapshot = _scan_runtime_snapshot()
    scan_lane_session_id = str(scan_snapshot.get('lane_session_id') or '').strip()
    if scan_lane_session_id:
      return scan_lane_session_id
    websocket_snapshot = _websocket_runtime_snapshot()
    return str(websocket_snapshot.get('lane_session_id') or '').strip()

  def _stop_automation_for_offline_transition(
    *,
    settings: Any | None,
    transition_reason: str,
    transition_message: str,
    client_auto_forward_active: bool,
  ) -> bool:
    automation_enabled = bool(automation_overlay_state.get('enabled'))
    automation_paused = bool(automation_overlay_state.get('paused'))
    automation_state_id = str(automation_overlay_state.get('state_id') or '').strip().lower()
    automation_active = automation_enabled or automation_paused or automation_state_id in {'enabled_idle', 'paused'}
    if not automation_active and not client_auto_forward_active:
      return False

    automation_overlay_state['enabled'] = False
    automation_overlay_state['paused'] = False
    automation_overlay_state['state_id'] = 'stopped'
    automation_overlay_state['last_transition_action'] = 'stop'
    automation_overlay_state['last_transition_reason'] = transition_reason
    automation_overlay_state['last_transition_at_utc'] = _utc_now_iso()
    _scheduler_cancel_timers()

    lane_session_id = _active_transition_lane_session_id()
    gate_snapshot = {
      'ready': False,
      'reason': 'offline_transition_stop',
      'lane_session_id': lane_session_id,
    }
    if settings is not None:
      _persist_automation_transition(
        settings=settings,
        action_name='stop',
        transition_reason=transition_reason,
        transition_message=transition_message,
        gate_snapshot=gate_snapshot,
      )
      if client_auto_forward_active:
        try:
          connection = open_database(getattr(settings, 'state_db_path'))
          persist_runtime_event(
            connection,
            level='INFO',
            event_type='client_auto_forward_stopped',
            recorded_at_utc=_utc_now_iso(),
            operation_lane=str(getattr(settings, 'operation_lane', 'sandbox') or 'sandbox'),
            lane_session_id=lane_session_id,
            detail={
              'transition_reason': transition_reason,
              'message': transition_message,
            },
          )
        except Exception:
          pass
    return True

  def _session_overlay_payload(payload: JSONDict, *, env_override: str | None, subaccount_override: int | None) -> JSONDict:
    _sync_automation_cadence_from_settings(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    settings = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    context_active = bool(context_overlay_state or websocket_overlay_state)
    working_default_values = _runtime_working_default_values(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    automation_enabled = bool(automation_overlay_state.get('enabled'))
    automation_paused = bool(automation_overlay_state.get('paused'))
    automation_state_id = str(automation_overlay_state.get('state_id') or '').strip().lower() or 'disabled'
    client_executor_allowed = automation_enabled and not automation_paused and automation_state_id == 'enabled_idle'
    policy_state_label = (
      'paused'
      if automation_enabled and automation_paused
      else 'enabled'
      if automation_enabled
      else 'stopped'
      if automation_state_id == 'stopped'
      else 'disabled'
    )
    gate_snapshot = _automation_manual_truth_gate(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    gate_ready = bool(gate_snapshot.get('ready'))
    client_executor_summary = (
      'Client auto-forward may run when armed in this browser session.'
      if client_executor_allowed
      else 'Client auto-forward can resume bounded automation from this chip when the paused lane is ready.'
      if gate_ready and automation_enabled and automation_paused and automation_state_id == 'paused'
      else 'Client auto-forward can enable bounded automation from this chip for a ready connected lane before the first scan.'
      if gate_ready and not automation_enabled and automation_state_id in {'disabled', 'stopped'}
      else 'Client auto-forward is waiting because bounded automation is paused.'
      if automation_enabled and automation_paused and automation_state_id == 'paused'
      else 'Client auto-forward is off because bounded automation was stopped.'
      if automation_state_id == 'stopped'
      else 'Client auto-forward is held off until bounded automation readiness is restored for the active lane.'
    )
    return {
      'runtime': {
        'active': bool(runtime_overlay_state),
        'values': dict(runtime_overlay_state),
        'summary': 'Session overlay active' if runtime_overlay_state else 'Using config-discovered runtime values',
        'working_default_active': bool(runtime_working_default_state),
        'working_default_values': working_default_values,
        'durable_default_available': bool(runtime_working_default_state),
        'durable_default_reason': None if runtime_working_default_state else RUNTIME_DURABLE_DEFAULT_BLOCK_REASON,
        'prior_saved_set_available': _prior_saved_set_available(
          env_override=env_override,
          subaccount_override=subaccount_override,
        ),
      },
      'context': {
        'active': context_active,
        'values': dict(context_overlay_state),
        'operation_lane': str(context_overlay_state.get('operation_lane') or ''),
        'subaccount': (
          int(context_overlay_state.get('subaccount'))
          if context_overlay_state.get('subaccount') not in {None, ''}
          else None
        ),
        'websocket_values': {
          'sandbox': _websocket_label(websocket_overlay_state.get('sandbox_websocket_url')) if 'sandbox_websocket_url' in websocket_overlay_state else '',
          'live': _websocket_label(websocket_overlay_state.get('live_websocket_url')) if 'live_websocket_url' in websocket_overlay_state else '',
        },
        'base_operation_lane': str(settings.get('operation_lane') or ''),
        'requires_rebootstrap': context_active,
        'mode_selected': bool(context_overlay_state.get('mode_selected', False)),
      },
      'automation': {
        **dict(automation_overlay_state),
        'authority': 'Backend session overlay',
        'policy_state_label': policy_state_label,
        'client_executor_allowed': client_executor_allowed,
        'client_executor_summary': client_executor_summary,
        'retry_policy': {
          'write_retry': 'bounded',
          'read_freshness_retry': 'bounded',
          'websocket_reconnect': 'bounded',
        },
        'summary': (
          'Paused bounded automation policy'
          if automation_overlay_state.get('enabled') and automation_overlay_state.get('paused')
          else 'Bounded automation policy enabled'
          if automation_overlay_state.get('enabled')
          else 'Auto-forward only'
        ),
      },
    }

  def _resolved_connection_posture_mode_selected(payload: JSONDict) -> bool:
    report_candidate = payload.get('report')
    report_payload = cast(JSONDict, report_candidate) if isinstance(report_candidate, dict) else {}
    latest_terminal = report_payload.get('latest_scan_terminal') if isinstance(report_payload.get('latest_scan_terminal'), dict) else {}
    report_connection_state = report_payload.get('connection_state') if isinstance(report_payload.get('connection_state'), dict) else {}
    settings_candidate = payload.get('settings')
    settings = cast(JSONDict, settings_candidate) if isinstance(settings_candidate, dict) else {}
    workflow_source = str(payload.get('workflow_source') or '').strip().lower()
    if 'mode_selected' in context_overlay_state:
      return bool(context_overlay_state.get('mode_selected'))
    settings_mode = _settings_mode_selected(settings)
    if settings_mode is not None:
      return settings_mode
    if workflow_source == 'terminal_scan_replay' or bool(latest_terminal):
      return True
    if bool(report_connection_state.get('websocket_connected')) and bool(settings.get('settings_ready')):
      return True

    connection_posture_candidate = payload.get('connection_posture')
    connection_posture = cast(JSONDict, connection_posture_candidate) if isinstance(connection_posture_candidate, dict) else {}
    if 'mode_selected' in connection_posture:
      return bool(connection_posture.get('mode_selected'))

    connection_lane = str(connection_posture.get('operation_lane') or '').strip().lower()
    if connection_lane in {'sandbox', 'live'}:
      return True

    if str(payload.get('resting_connection_posture') or '').strip().lower() in {'candidate_review_hold', 'empty_scan_result_hold'}:
      return True
    return False

  def _build_connection_posture_payload(
    payload: JSONDict,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict:
    settings_candidate = payload.get('settings')
    settings = cast(JSONDict, settings_candidate) if isinstance(settings_candidate, dict) else {}
    report_payload_candidate = payload.get('report')
    report_payload = cast(JSONDict, report_payload_candidate) if isinstance(report_payload_candidate, dict) else {}
    effective_settings = _active_settings(env_override, subaccount_override)
    mode_selected = _resolved_connection_posture_mode_selected(payload)
    report_urls = report_payload.get('available_websocket_urls') if isinstance(report_payload.get('available_websocket_urls'), dict) else {}
    settings_urls = settings.get('available_websocket_urls') if isinstance(settings.get('available_websocket_urls'), dict) else {}
    effective_sandbox_websocket = _websocket_label(getattr(effective_settings, 'sandbox_websocket_url', None) if effective_settings is not None else None)
    effective_live_websocket = _websocket_label(getattr(effective_settings, 'live_websocket_url', None) if effective_settings is not None else None)
    available_websocket_urls = {
      'sandbox': str(
        '' if websocket_overlay_state.get('sandbox_websocket_url', None) == '' and 'sandbox_websocket_url' in websocket_overlay_state
        else _websocket_label(websocket_overlay_state.get('sandbox_websocket_url')) if 'sandbox_websocket_url' in websocket_overlay_state
        else settings_urls.get('sandbox')
        or effective_sandbox_websocket
        or _websocket_label(settings.get('sandbox_websocket_url'))
        or report_urls.get('sandbox')
        or ''
      ),
      'live': str(
        '' if websocket_overlay_state.get('live_websocket_url', None) == '' and 'live_websocket_url' in websocket_overlay_state
        else _websocket_label(websocket_overlay_state.get('live_websocket_url')) if 'live_websocket_url' in websocket_overlay_state
        else settings_urls.get('live')
        or effective_live_websocket
        or _websocket_label(settings.get('live_websocket_url'))
        or report_urls.get('live')
        or ''
      ),
    }
    authoritative_lane = str(
      getattr(effective_settings, 'operation_lane', None)
      or report_payload.get('operation_lane')
      or settings.get('operation_lane')
      or 'sandbox'
    ).strip().lower() or 'sandbox'
    projected_lane = 'offline' if not mode_selected else authoritative_lane
    if not mode_selected:
      configured_active_tail = str(
        _websocket_label(settings.get('active_websocket_url'))
        or available_websocket_urls.get(authoritative_lane)
        or available_websocket_urls.get('sandbox')
        or available_websocket_urls.get('live')
        or 'unconfigured'
      )
      return {
        'operation_lane': 'offline',
        'mode_selected': False,
        'lane_session_id': '',
        'available_websocket_urls': available_websocket_urls,
        'active_websocket_url_tail': configured_active_tail,
        'connection_state': {
          'status': 'waiting',
          'websocket_connected': False,
        },
        'is_offline': True,
      }
    runtime_snapshot = _websocket_runtime_projection(authoritative_lane, mode_selected=mode_selected)
    connection_state = dict(report_payload.get('connection_state') or {'status': 'waiting', 'websocket_connected': False})
    lane_session_id = str(report_payload.get('lane_session_id') or '')
    lane_websocket_override_key = f'{authoritative_lane}_websocket_url'
    explicit_lane_websocket = lane_websocket_override_key in websocket_overlay_state
    effective_active_websocket = _websocket_label(getattr(effective_settings, 'active_websocket_url', None) if effective_settings is not None else settings.get('active_websocket_url'))
    active_websocket_url_tail = str(
      (available_websocket_urls.get(authoritative_lane) if explicit_lane_websocket else '')
      or effective_active_websocket
      or available_websocket_urls.get(authoritative_lane)
      or (report_payload.get('active_websocket_url_tail') if mode_selected else '')
      or ''
    )
    if runtime_snapshot is not None:
      connection_state = {
        'status': str(runtime_snapshot.get('status') or 'waiting'),
        'websocket_connected': bool(runtime_snapshot.get('websocket_connected')),
      }
      lane_session_id = str(runtime_snapshot.get('lane_session_id') or lane_session_id)
      active_websocket_url_tail = str(runtime_snapshot.get('active_websocket_url_tail') or active_websocket_url_tail)
    if explicit_lane_websocket and not str(available_websocket_urls.get(authoritative_lane) or '').strip():
      active_websocket_url_tail = 'unconfigured'
    credential_ready = bool(settings.get('credential_ready'))
    has_any_websocket_url = any(_websocket_url_is_configured(value) for value in available_websocket_urls.values())
    websocket_connected = bool(connection_state.get('websocket_connected'))
    is_offline = (
      projected_lane == 'offline'
      or ((not credential_ready or not has_any_websocket_url) and not websocket_connected)
    )
    return {
      'operation_lane': projected_lane,
      'mode_selected': mode_selected,
      'lane_session_id': lane_session_id,
      'available_websocket_urls': available_websocket_urls,
      'active_websocket_url_tail': active_websocket_url_tail or 'unconfigured',
      'connection_state': connection_state,
      'is_offline': is_offline,
    }

  def _attach_connection_posture(
    payload: JSONDict,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict:
    payload['connection_posture'] = _build_connection_posture_payload(
      payload,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    return payload

  def _build_credential_posture_payload(settings_payload: JSONDict | None) -> JSONDict:
    settings_payload = settings_payload or {}
    active_lane = _normalize_key_lane(settings_payload.get('operation_lane')) or _default_key_lane()
    validated, reason, validated_at, _ = _lane_key_validation_snapshot(active_lane)
    if validated is None:
      validated = key_management_state.get('credential_platform_validated')
      if validated is None:
        return {
          'acceptance_ready': None,
          'platform_validated': None,
          'validation_reason': None,
          'validation_timestamp': '',
          'acceptance_detail': 'Runtime account-auth acceptance is not yet verified for this shell state.',
        }
      reason = str(key_management_state.get('credential_validation_reason') or ('pass' if validated else 'error')).lower()
      validated_at = str(key_management_state.get('credential_validation_timestamp') or '').strip()
    else:
      reason = str(reason or ('pass' if validated else 'error')).lower()
      validated_at = str(validated_at or '').strip()
    detail = (
      f'Runtime account-auth acceptance validated{f" at {validated_at}" if validated_at else ""}.'
      if validated
      else {
        'auth_fail': 'Platform rejected credentials on authenticated account checks.',
        'credential_environment_mismatch': 'Credential validated, but it belongs to a different Kalshi environment than the selected lane.',
        'format_error': 'Selected key format is invalid or unreadable.',
        'timeout': 'Credential acceptance checks timed out before completion.',
        'error': 'Credential acceptance checks failed unexpectedly.',
      }.get(reason, 'Credential acceptance checks did not pass.') + (f' Last validation: {validated_at}.' if validated_at else '')
    )
    return {
      'acceptance_ready': bool(validated),
      'platform_validated': bool(validated),
      'validation_reason': reason,
      'validation_timestamp': validated_at,
      'acceptance_detail': detail,
    }

  def _set_key_result(
    message: str,
    tone: str = 'info',
    *,
    reason: str | None = None,
    origin: str | None = None,
  ) -> None:
    inferred_origin = str(origin or '').strip().lower() or _infer_message_origin(reason=reason, message=message)
    key_management_state['last_result'] = {
      'message': message,
      'tone': tone,
      'reason': reason,
      'origin': inferred_origin,
    }

  def _utc_now_iso() -> str:
    return time.strftime('%Y-%m-%dT%H:%M:%SZ', time.gmtime())

  def _normalized_key_path(path_value: str | None) -> str:
    return str(Path(str(path_value or '')).expanduser().resolve())

  def _normalize_key_lane(lane_value: Any) -> str | None:
    lane = str(lane_value or '').strip().lower()
    return lane if lane in {'sandbox', 'live'} else None

  def _payload_operation_lane(payload: JSONDict) -> str | None:
    connection_posture = payload.get('connection_posture') if isinstance(payload.get('connection_posture'), dict) else {}
    payload_lane = _normalize_key_lane(connection_posture.get('operation_lane'))
    if payload_lane is not None:
      return payload_lane
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    return _normalize_key_lane(settings_payload.get('operation_lane'))

  def _lane_boundary_mode_selected(
    *,
    env_override: str | None,
    subaccount_override: int | None,
    settings_override: Any | None = None,
  ) -> bool:
    settings_payload, _ = _load_shell_settings_context(
      env_override=env_override,
      subaccount_override=subaccount_override,
      settings_override=settings_override,
    )
    settings_lane = str(settings_payload.get('operation_lane') or '').strip().lower()
    if 'mode_selected' in context_overlay_state:
      return bool(context_overlay_state.get('mode_selected'))
    if settings_lane == 'offline':
      return False
    settings_mode = _settings_mode_selected(settings_payload)
    if settings_mode is not None:
      return settings_mode
    return False

  def _payload_is_inactive_lane_boundary(payload: JSONDict) -> bool:
    if 'mode_selected' in context_overlay_state:
      return not bool(context_overlay_state.get('mode_selected'))
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    settings_lane = str(settings_payload.get('operation_lane') or '').strip().lower()
    if settings_lane == 'offline':
      return True
    settings_mode = _settings_mode_selected(settings_payload)
    if settings_mode is not None:
      return not settings_mode
    connection_posture = payload.get('connection_posture') if isinstance(payload.get('connection_posture'), dict) else {}
    if 'mode_selected' in connection_posture:
      return not bool(connection_posture.get('mode_selected'))
    connection_lane = str(connection_posture.get('operation_lane') or '').strip().lower()
    if connection_lane in {'sandbox', 'live'}:
      return False
    return True

  def _scrub_inactive_lane_boundary_runtime_payload(payload: JSONDict) -> JSONDict:
    if not _payload_is_inactive_lane_boundary(payload):
      return payload

    scrubbed = dict(payload)
    scrubbed['report'] = None
    scrubbed['reconcile'] = None
    scrubbed['latest_heartbeat'] = None
    scrubbed['candidates'] = []
    scrubbed['candidate_count'] = 0
    scrubbed['sandbox_candidates_extended'] = []
    scrubbed['sandbox_extended_count'] = 0
    scrubbed['planned_pairs'] = []
    scrubbed['reconciled_pairs'] = []
    scrubbed['pair_runtime_summary'] = []
    scrubbed['pair_state_history'] = []
    scrubbed['pair_lane_session_history'] = []
    return scrubbed

  def _scrub_inactive_lane_boundary_visuals_payload(payload: JSONDict) -> JSONDict:
    scrubbed = dict(payload)
    scrubbed['status'] = 'empty'
    scrubbed['empty_reason'] = 'Operational visuals stay hidden until sandbox or live mode is selected.'
    scrubbed['series'] = []
    scrubbed['stats'] = []
    scrubbed['annotations'] = []
    scrubbed['summary_rows'] = []
    scrubbed['headline'] = 'Operational visuals parked'
    scrubbed['subheadline'] = 'Select sandbox or live mode to resume lane-owned visuals.'
    scrubbed['narrative'] = []
    table_payload = scrubbed.get('table') if isinstance(scrubbed.get('table'), dict) else {}
    report_payload = scrubbed.get('report') if isinstance(scrubbed.get('report'), dict) else {}
    threshold_state = scrubbed.get('threshold_state') if isinstance(scrubbed.get('threshold_state'), dict) else {}
    scrubbed['table'] = {
      **table_payload,
      'rows': [],
    }
    scrubbed['report'] = {
      **report_payload,
      'sections': [],
    }
    if threshold_state:
      scrubbed['threshold_state'] = {
        **threshold_state,
        'status': 'threshold_undetermined',
        'message': 'Operational visuals stay hidden until sandbox or live mode is selected.',
        'action_label': 'Select sandbox or live mode.',
      }
    return scrubbed

  def _inactive_lane_boundary_system_log_payload() -> JSONDict:
    return {
      'entries': [],
      'latest_recorded_at_utc': None,
      'message': 'System log entries stay hidden until sandbox or live mode is selected.',
    }

  def _review_selection_lane_matches(lane: str | None) -> bool:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      return True
    saved_lane = _normalize_key_lane(review_selection_state.get('saved_set_operation_lane'))
    hydrated_lane = _normalize_key_lane(review_selection_hydration_state.get('operation_lane'))
    review_lane = saved_lane or hydrated_lane
    if review_lane is None:
      return True
    return review_lane == normalized_lane

  def _payload_accepts_review_selection(payload: JSONDict) -> bool:
    if _payload_is_inactive_lane_boundary(payload):
      return False
    return _review_selection_lane_matches(_payload_operation_lane(payload))

  def _payload_preserves_action_workflow(payload: JSONDict) -> bool:
    command_family = str(payload.get('command_family') or '').strip().lower()
    if int(payload.get('planned_pair_count', 0) or 0) > 0:
      return True
    return command_family in {
      'polyventure run',
      'polyventure reconcile',
      'polyventure report',
      'polyventure cancel-all',
    }

  def _clear_review_selection_hydration_state() -> None:
    review_selection_hydration_state.update(
      {
        'db_path': '',
        'operation_lane': '',
        'saved_set_id': '',
      }
    )

  def _clear_lane_mismatched_review_selection(lane: str | None) -> None:
    if _review_selection_lane_matches(lane):
      return
    _clear_review_selection_state()
    _clear_persisted_run_state()
    _clear_review_selection_hydration_state()

  def _scan_runtime_lane(snapshot: JSONDict) -> str | None:
    runtime_lane = _normalize_key_lane(snapshot.get('operation_lane'))
    if runtime_lane is not None:
      return runtime_lane
    result_payload = snapshot.get('result_payload') if isinstance(snapshot.get('result_payload'), dict) else {}
    connection_posture = result_payload.get('connection_posture') if isinstance(result_payload.get('connection_posture'), dict) else {}
    payload_lane = _normalize_key_lane(connection_posture.get('operation_lane'))
    if payload_lane is not None:
      return payload_lane
    settings_payload = result_payload.get('settings') if isinstance(result_payload.get('settings'), dict) else {}
    return _normalize_key_lane(settings_payload.get('operation_lane'))

  def _scan_runtime_matches_lane(snapshot: JSONDict, lane: str | None) -> bool:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      return True
    snapshot_lane = _scan_runtime_lane(snapshot)
    if snapshot_lane is None:
      return True
    return snapshot_lane == normalized_lane

  def _clear_scan_runtime_terminal_replay_state() -> None:
    _set_scan_runtime_state(
      status='idle',
      active=False,
      scan_session_id='',
      lane_session_id='',
      operation_lane='sandbox',
      stage='idle',
      message='',
      progress_percent=0.0,
      started_at_utc=None,
      completed_at_utc=None,
      last_progress_at_utc=None,
      cancel_requested=False,
      result_payload=None,
      error_payload=None,
      hydrated_from_persistence=False,
      replay_candidate_source_available=False,
      hydration_state_db_path='',
    )

  def _clear_lane_mismatched_scan_runtime(lane: str | None) -> None:
    snapshot = _scan_runtime_snapshot()
    if bool(snapshot.get('active')):
      return
    if snapshot.get('result_payload') is None:
      return
    if _scan_runtime_matches_lane(snapshot, lane):
      return
    _clear_scan_runtime_terminal_replay_state()

  def _default_key_lane(*, env_override: str | None = None, subaccount_override: int | None = None) -> str:
    explicit_lane = _normalize_key_lane(context_overlay_state.get('operation_lane'))
    if explicit_lane is not None:
      return explicit_lane
    try:
      base_settings = _resolve_settings(
        None,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
    except Exception:
      base_settings = None
    return _normalize_key_lane(getattr(base_settings, 'operation_lane', None)) or 'sandbox'

  def _lane_key_path(lane: str) -> str | None:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      return None
    return str(key_management_state.get(f'{normalized_lane}_key_path') or '').strip() or None

  def _lane_key_source_label(lane: str) -> str | None:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      return None
    return str(key_management_state.get(f'{normalized_lane}_key_source_label') or '').strip() or None

  def _lane_api_key_id(
    lane: str,
    *,
    base_api_key_id: str | None = None,
    lane_settings_api_key_id: str | None = None,
  ) -> str | None:
    resolved_value, _ = _lane_api_key_resolution(
      lane,
      base_api_key_id=base_api_key_id,
      lane_settings_api_key_id=lane_settings_api_key_id,
    )
    return resolved_value

  def _lane_api_key_resolution(
    lane: str,
    *,
    base_api_key_id: str | None = None,
    lane_settings_api_key_id: str | None = None,
  ) -> tuple[str | None, str | None]:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      resolved_generic = str(base_api_key_id or '').strip() or None
      return resolved_generic, ('generic_settings' if resolved_generic else None)

    stored_value = str(key_management_state.get(f'{normalized_lane}_api_key_id') or '').strip()
    if stored_value:
      return stored_value, 'lane_state'

    env_var = SANDBOX_API_KEY_ID_ENV_VAR if normalized_lane == 'sandbox' else LIVE_API_KEY_ID_ENV_VAR
    env_value = str(os.getenv(env_var, '') or '').strip()
    if env_value:
      return env_value, 'lane_env'

    settings_value = str(lane_settings_api_key_id or '').strip()
    if settings_value:
      return settings_value, 'lane_settings'

    if normalized_lane == 'live':
      return None, None
    resolved_generic = str(base_api_key_id or '').strip() or None
    return resolved_generic, ('generic_settings' if resolved_generic else None)

  def _lane_key_validation_snapshot(lane: str, *, fallback_to_generic: bool = False) -> tuple[bool | None, str | None, str | None, str | None]:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      return None, None, None, None
    validated = key_management_state.get(f'{normalized_lane}_key_validated')
    reason = key_management_state.get(f'{normalized_lane}_key_validation_reason')
    validated_at = key_management_state.get(f'{normalized_lane}_key_validation_timestamp')
    path_value = key_management_state.get(f'{normalized_lane}_key_validation_path')
    if validated is None and fallback_to_generic:
      fallback_lane = _default_key_lane()
      if normalized_lane == fallback_lane:
        validated = key_management_state.get('credential_platform_validated')
        reason = key_management_state.get('credential_validation_reason')
        validated_at = key_management_state.get('credential_validation_timestamp')
        path_value = key_management_state.get('credential_validation_path')
    return validated, (str(reason).strip().lower() or None) if reason is not None else None, str(validated_at or '').strip() or None, str(path_value or '').strip() or None

  def _set_lane_key_reference(
    lane: str,
    path_value: str | None,
    source_label: str | None,
    *,
    api_key_id: str | None = None,
    api_key_source_class: str | None = None,
  ) -> None:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      return
    key_management_state[f'{normalized_lane}_key_path'] = str(path_value or '').strip() or None
    key_management_state[f'{normalized_lane}_key_source_label'] = str(source_label or '').strip() or None
    key_management_state[f'{normalized_lane}_api_key_id'] = str(api_key_id or '').strip() or None
    key_management_state[f'{normalized_lane}_api_key_source_class'] = str(api_key_source_class or '').strip() or None

  def _clear_lane_key_reference(lane: str) -> None:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      return
    key_management_state[f'{normalized_lane}_key_path'] = None
    key_management_state[f'{normalized_lane}_key_source_label'] = None
    key_management_state[f'{normalized_lane}_api_key_id'] = None
    key_management_state[f'{normalized_lane}_api_key_source_class'] = None
    key_management_state[f'{normalized_lane}_key_validated'] = None
    key_management_state[f'{normalized_lane}_key_validation_reason'] = None
    key_management_state[f'{normalized_lane}_key_validation_timestamp'] = None
    key_management_state[f'{normalized_lane}_key_validation_path'] = None

  def _loaded_key_lane_count() -> int:
    return sum(1 for lane in ('sandbox', 'live') if _lane_key_path(lane))

  def _key_glow_state() -> str:
    loaded_count = _loaded_key_lane_count()
    if loaded_count >= 2:
      return 'ready'
    if loaded_count == 1:
      return 'warning'
    return 'neutral'

  def _key_glow_tone() -> str:
    glow_state = _key_glow_state()
    if glow_state == 'ready':
      return 'ok'
    if glow_state == 'warning':
      return 'warn'
    return ''

  def _sync_overlay_from_current_lane(*, env_override: str | None = None, subaccount_override: int | None = None) -> None:
    if key_management_state.get('clear_requested'):
      key_management_state['overlay_key_path'] = None
      key_management_state['overlay_key_source_label'] = None
      return
    current_lane = _default_key_lane(env_override=env_override, subaccount_override=subaccount_override)
    lane_key_path = _lane_key_path(current_lane)
    if lane_key_path:
      key_management_state['overlay_key_path'] = lane_key_path
      key_management_state['overlay_key_source_label'] = _lane_key_source_label(current_lane)

  def _sync_legacy_key_tombstones_from_overlay() -> None:
    overlay_key_path = str(key_management_state.get('overlay_key_path') or '').strip()
    overlay_key_label = str(key_management_state.get('overlay_key_source_label') or '').strip()
    if overlay_key_path:
      _set_tombstone_value('key_reference_path', overlay_key_path)
      _set_tombstone_value('key_reference_source_label', overlay_key_label or 'Session key')
      return
    _remove_tombstone('key_reference_path')
    _remove_tombstone('key_reference_source_label')

  def _profile_token_for_path(path_value: str | None) -> str:
    digest = hashlib.sha256(_normalized_key_path(path_value).encode('utf-8')).hexdigest()
    return f'kalshi-{digest[-6:]}'

  def _candidate_id_for_path(path_value: str | None, ordinal: int) -> str:
    _ = ordinal
    return _profile_token_for_path(path_value)

  def _persist_key_registry() -> None:
    _set_tombstone_value('key_registry', list(key_management_state.get('key_registry', [])))

  def _sync_key_registry_state(*, persist: bool = True, populate_candidates_from_registry: bool = False) -> None:
    registry_entries: list[JSONDict] = []
    now_utc = _utc_now_iso()

    for entry in key_management_state.get('key_registry', []):
      resolved_path = str(entry.get('resolved_path') or '').strip()
      if not resolved_path:
        continue
      if str(entry.get('status') or '').lower() == 'cleared':
        continue
      source_label = str(entry.get('source_label') or 'Discovered source')
      profile_token = str(entry.get('profile_token') or _profile_token_for_path(resolved_path))
      discovered_at_utc = str(entry.get('discovered_at_utc') or now_utc)
      last_seen_at_utc = str(entry.get('last_seen_at_utc') or discovered_at_utc)
      path_exists = Path(resolved_path).exists() and Path(resolved_path).is_file()
      if not path_exists:
        continue
      registry_entries.append(
        {
          'resolved_path': resolved_path,
          'path_tail': _path_tail(resolved_path),
          'source_label': source_label,
          'profile_token': profile_token,
          'lane_tag': entry.get('lane_tag') or _lane_tag_for_path(resolved_path),
          'discovered_at_utc': discovered_at_utc,
          'last_seen_at_utc': last_seen_at_utc,
          'status': 'available',
        }
      )

    registry_entries.sort(key=lambda item: str(item.get('resolved_path', '')))
    
    # Update candidate_lookup to maintain valid paths for selected_candidate_id validation
    candidate_lookup: dict[str, str] = {}
    discovered_candidates: list[JSONDict] = []
    
    if populate_candidates_from_registry:
      # When called from discovery reconciliation, populate discovered_candidates from the reconciled registry.
      # This is used only after a fresh discovery run to set discovered_candidates.
      for index, entry in enumerate(registry_entries, start=1):
        candidate_id = _candidate_id_for_path(str(entry.get('resolved_path') or ''), index)
        discovered_candidates.append(
          {
            'candidate_id': candidate_id,
            'resolved_path': str(entry.get('resolved_path') or ''),
            'path_tail': entry.get('path_tail') or _path_tail(entry.get('resolved_path')),
            'source_label': entry.get('source_label') or 'Discovered source',
            'profile_token': entry.get('profile_token') or _profile_token_for_path(entry.get('resolved_path')),
            'lane_tag': entry.get('lane_tag') or _lane_tag_for_path(entry.get('resolved_path')),
            'status': entry.get('status') or 'available',
          }
        )
        candidate_lookup[candidate_id] = str(entry.get('resolved_path') or '')
      key_management_state['discovered_candidates'] = discovered_candidates
    else:
      # When called from staging or registry syncing (not discovery), preserve discovered_candidates.
      # Only update candidate_lookup so selected_candidate_id validation works.
      # Build candidate_lookup from current discovered_candidates for validation purposes.
      for candidate in key_management_state.get('discovered_candidates', []):
        candidate_id = candidate.get('candidate_id')
        if candidate_id:
          candidate_lookup[candidate_id] = str(candidate.get('resolved_path') or '')
      # Also add entries from registry for selected_candidate_id validation
      for index, entry in enumerate(registry_entries, start=1):
        candidate_id = _candidate_id_for_path(str(entry.get('resolved_path') or ''), index)
        if candidate_id not in candidate_lookup:
          candidate_lookup[candidate_id] = str(entry.get('resolved_path') or '')

    key_management_state['key_registry'] = registry_entries
    key_management_state['candidate_lookup'] = candidate_lookup
    selected_candidate_id = key_management_state.get('selected_candidate_id')
    if selected_candidate_id and selected_candidate_id not in {item.get('candidate_id') for item in key_management_state.get('discovered_candidates', [])}:
      key_management_state['selected_candidate_id'] = None
    if persist:
      _persist_key_registry()

  def _upsert_key_registry_entry(path_value: str | None, source_label: str, *, status: str | None = None) -> None:
    resolved_path = _normalized_key_path(path_value)
    if not resolved_path:
      return
    now_utc = _utc_now_iso()
    normalized_source = str(source_label or 'Discovered source')
    target_status = str(status or '').lower()
    if target_status not in {'available', 'missing', 'cleared'}:
      target_status = 'available' if Path(resolved_path).exists() and Path(resolved_path).is_file() else 'missing'

    if target_status == 'cleared':
      key_management_state['key_registry'] = [
        entry for entry in key_management_state.get('key_registry', [])
        if str(entry.get('resolved_path') or '') != resolved_path
      ]
      return

    updated = False
    for entry in key_management_state.get('key_registry', []):
      if str(entry.get('resolved_path') or '') != resolved_path:
        continue
      entry['source_label'] = normalized_source
      entry['path_tail'] = _path_tail(resolved_path)
      entry['profile_token'] = entry.get('profile_token') or _profile_token_for_path(resolved_path)
      entry['lane_tag'] = entry.get('lane_tag') or _lane_tag_for_path(resolved_path)
      entry['status'] = target_status
      entry['last_seen_at_utc'] = now_utc
      entry['discovered_at_utc'] = str(entry.get('discovered_at_utc') or now_utc)
      updated = True
      break

    if not updated:
      key_management_state.setdefault('key_registry', []).append(
        {
          'resolved_path': resolved_path,
          'path_tail': _path_tail(resolved_path),
          'source_label': normalized_source,
          'profile_token': _profile_token_for_path(resolved_path),
          'lane_tag': _lane_tag_for_path(resolved_path),
          'discovered_at_utc': now_utc,
          'last_seen_at_utc': now_utc,
          'status': target_status,
        }
      )

  def _reconcile_key_registry_with_discovery(discovered_candidates: list[JSONDict]) -> None:
    previous_by_path: dict[str, JSONDict] = {}
    for entry in key_management_state.get('key_registry', []):
      normalized_path = _normalized_key_path(str(entry.get('resolved_path') or ''))
      if not normalized_path or normalized_path in previous_by_path:
        continue
      previous_by_path[normalized_path] = entry

    reconciled_registry: list[JSONDict] = []
    seen_paths: set[str] = set()
    now_utc = _utc_now_iso()

    for candidate in discovered_candidates:
      normalized_path = _normalized_key_path(str(candidate.get('resolved_path') or ''))
      if not normalized_path or normalized_path in seen_paths:
        continue
      seen_paths.add(normalized_path)
      prior_entry = previous_by_path.get(normalized_path, {})
      reconciled_registry.append(
        {
          'resolved_path': normalized_path,
          'path_tail': _path_tail(normalized_path),
          'source_label': str(candidate.get('source_label') or prior_entry.get('source_label') or 'Discovered source'),
          'profile_token': str(prior_entry.get('profile_token') or _profile_token_for_path(normalized_path)),
          'lane_tag': prior_entry.get('lane_tag') or _lane_tag_for_path(normalized_path),
          'discovered_at_utc': str(prior_entry.get('discovered_at_utc') or now_utc),
          'last_seen_at_utc': now_utc,
          'status': 'available',
        }
      )

    key_management_state['key_registry'] = reconciled_registry
    _sync_key_registry_state(populate_candidates_from_registry=True)

  if key_management_state.get('key_registry'):
    _sync_key_registry_state(persist=False)

  _sync_overlay_from_current_lane()

  def _stage_key_reference(
    path_value: str | None,
    source_label: str,
    *,
    candidate_id: str | None = None,
    api_key_id: str | None = None,
    api_key_source_class: str | None = None,
  ) -> None:
    key_management_state['selected_key_path'] = path_value
    key_management_state['selected_key_source_label'] = source_label
    key_management_state['selected_api_key_id'] = str(api_key_id or '').strip() or None
    key_management_state['selected_api_key_source_class'] = str(api_key_source_class or '').strip() or None
    key_management_state['selected_candidate_id'] = candidate_id
    key_management_state['credential_platform_validated'] = None
    key_management_state['credential_validation_reason'] = None
    key_management_state['credential_validation_timestamp'] = None
    key_management_state['credential_validation_path'] = None

  def _clear_key_reference_state() -> None:
    _stop_websocket_runtime(reason='key_reference_cleared')
    _clear_lane_key_reference('sandbox')
    _clear_lane_key_reference('live')
    key_management_state['selected_key_path'] = None
    key_management_state['selected_key_source_label'] = None
    key_management_state['selected_candidate_id'] = None
    key_management_state['overlay_key_path'] = None
    key_management_state['overlay_key_source_label'] = None
    key_management_state['clear_requested'] = True
    key_management_state['credential_platform_validated'] = None
    key_management_state['credential_validation_reason'] = None
    key_management_state['credential_validation_timestamp'] = None
    key_management_state['credential_validation_path'] = None
    _set_tombstone('key_reference_cleared')
    _remove_tombstone('sandbox_key_reference_path')
    _remove_tombstone('sandbox_key_reference_source_label')
    _remove_tombstone('live_key_reference_path')
    _remove_tombstone('live_key_reference_source_label')
    _sync_lane_validation_tombstone('sandbox')
    _sync_lane_validation_tombstone('live')
    _remove_tombstone('key_reference_path')
    _remove_tombstone('key_reference_source_label')
    _sync_key_registry_state()

  def _clear_staged_key_reference_state() -> None:
    key_management_state['selected_key_path'] = None
    key_management_state['selected_key_source_label'] = None
    key_management_state['selected_api_key_id'] = None
    key_management_state['selected_api_key_source_class'] = None
    key_management_state['selected_candidate_id'] = None

  def _clear_mode_change_discovery_hold() -> None:
    mode_change_guidance_state.clear()

  def _set_mode_change_discovery_hold(lane: str) -> None:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      _clear_mode_change_discovery_hold()
      return
    mode_change_guidance_state.clear()
    mode_change_guidance_state.update(
      {
        'lane': normalized_lane,
        'established_at_utc': _utc_now_iso(),
      }
    )

  def _commit_mode_selection(
    lane: str,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> None:
    context_overlay_state['operation_lane'] = lane
    context_overlay_state['mode_selected'] = (lane in {'sandbox', 'live'})
    if lane in {'sandbox', 'live'}:
      _clear_lane_mismatched_review_selection(lane)
      _clear_lane_mismatched_scan_runtime(lane)
    else:
      _clear_review_selection_state()
      _clear_persisted_run_state()
      _clear_review_selection_hydration_state()
      _clear_scan_runtime_terminal_replay_state()
    if lane in {'sandbox', 'live'}:
      _set_mode_change_discovery_hold(lane)
    else:
      _clear_mode_change_discovery_hold()
    _sync_overlay_from_current_lane(env_override=env_override, subaccount_override=subaccount_override)
    _sync_legacy_key_tombstones_from_overlay()

  def _settings_for_lane(
    lane: str,
    *,
    env_override: str | None,
    subaccount_override: int | None,
    key_path_override: str | None = None,
    api_key_id_override: str | None = None,
  ) -> Any:
    normalized_lane = _normalize_key_lane(lane) or 'sandbox'
    active_settings = _active_settings(env_override, subaccount_override)
    base_settings = active_settings if active_settings is not None else _resolve_settings(
      None,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    sandbox_websocket_url = str(getattr(base_settings, 'sandbox_websocket_url', None) or '').strip()
    live_websocket_url = str(getattr(base_settings, 'live_websocket_url', None) or '').strip()
    lane_websocket_url = live_websocket_url if normalized_lane == 'live' else sandbox_websocket_url
    compatibility_websocket_url = str(getattr(base_settings, 'websocket_url', None) or '').strip()
    active_websocket_url = lane_websocket_url or compatibility_websocket_url
    if key_path_override is not None:
      effective_key_path = key_path_override
    elif normalized_lane == 'live':
      effective_key_path = _lane_key_path(normalized_lane) or getattr(base_settings, 'live_private_key_file', '') or None
    else:
      effective_key_path = _lane_key_path(normalized_lane) or getattr(base_settings, 'private_key_file', None)
    effective_api_key_id = (
      str(api_key_id_override or '').strip()
      or _lane_api_key_id(
        normalized_lane,
        base_api_key_id=getattr(base_settings, 'api_key_id', None),
        lane_settings_api_key_id=getattr(base_settings, f'{normalized_lane}_api_key_id', None),
      )
      or ('' if normalized_lane == 'live' else str(getattr(base_settings, 'api_key_id', '') or '').strip())
    )
    effective_api_base_url, effective_kalshi_env = _lane_api_environment_profile(
      normalized_lane,
      lane_websocket_url=active_websocket_url,
    )
    return replace(
      base_settings,
      operation_lane=normalized_lane,
      kalshi_env=effective_kalshi_env,
      api_base_url=effective_api_base_url,
      websocket_url=active_websocket_url,
      active_websocket_url=active_websocket_url,
      sandbox_websocket_url=sandbox_websocket_url,
      live_websocket_url=live_websocket_url,
      private_key_file=effective_key_path,
      api_key_id=effective_api_key_id,
    )

  def _promote_current_validation_to_lane(lane: str, *, path_value: str | None) -> None:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      return
    key_management_state[f'{normalized_lane}_key_validated'] = key_management_state.get('credential_platform_validated')
    key_management_state[f'{normalized_lane}_key_validation_reason'] = key_management_state.get('credential_validation_reason')
    key_management_state[f'{normalized_lane}_key_validation_timestamp'] = key_management_state.get('credential_validation_timestamp')
    key_management_state[f'{normalized_lane}_key_validation_path'] = str(path_value or key_management_state.get('credential_validation_path') or '').strip() or None

  def _load_selected_key_into_lane(
    lane: str,
    *,
    env_override: str | None,
    subaccount_override: int | None,
    validate_before_load: bool,
    action_name: str,
  ) -> JSONDict:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      _set_key_result('Choose Load sandbox or Load live for the staged key reference.', 'no-go')
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)

    selected_path = key_management_state.get('selected_key_path')
    selected_api_key_id = str(key_management_state.get('selected_api_key_id') or '').strip() or None
    selected_api_key_source_class = str(key_management_state.get('selected_api_key_source_class') or '').strip() or None
    if not selected_path:
      _set_key_result('Stage a key reference before loading it into a lane slot.', 'no-go')
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)

    if not Path(str(selected_path)).exists():
      _record_platform_validation(validated=False, reason='format_error', path_value=str(selected_path), lane=normalized_lane)
      _set_key_result(f"{_path_tail(selected_path) or 'Selected key'} is not currently available, so it cannot be loaded.", 'no-go')
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)

    if validate_before_load:
      lane_settings = _settings_for_lane(
        normalized_lane,
        env_override=env_override,
        subaccount_override=subaccount_override,
        key_path_override=str(selected_path),
        api_key_id_override=selected_api_key_id,
      )
      probe_result = _probe_key_reference_acceptance(lane_settings, key_path=str(selected_path))
      detected_environment = str(probe_result.get('detected_environment') or '').strip().lower() or None
      if not bool(probe_result.get('ok')):
        failure_reason = str(probe_result.get('reason') or 'error').lower()
        _record_platform_validation(
          validated=False,
          reason=failure_reason,
          path_value=str(selected_path),
          lane=normalized_lane,
          detected_environment=detected_environment,
        )
        _set_key_result(str(probe_result.get('message') or 'Credential acceptance checks failed.'), 'no-go')
        return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)
      _record_platform_validation(
        validated=True,
        reason='pass',
        path_value=str(selected_path),
        lane=normalized_lane,
        detected_environment=detected_environment,
      )
    else:
      _promote_current_validation_to_lane(normalized_lane, path_value=str(selected_path))

    resolved_key_path = str(Path(str(selected_path)).resolve())
    resolved_key_label = key_management_state.get('selected_key_source_label') or 'Session key'
    base_settings = _active_settings(env_override, subaccount_override) or _resolve_settings(
      None,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    resolved_api_key_id, resolved_api_key_source_class = _lane_api_key_resolution(
      normalized_lane,
      base_api_key_id=getattr(base_settings, 'api_key_id', None),
      lane_settings_api_key_id=getattr(base_settings, f'{normalized_lane}_api_key_id', None),
    )
    if selected_api_key_id:
      resolved_api_key_id = selected_api_key_id
      resolved_api_key_source_class = selected_api_key_source_class or 'staged_override'
    _set_lane_key_reference(
      normalized_lane,
      resolved_key_path,
      str(resolved_key_label),
      api_key_id=resolved_api_key_id,
      api_key_source_class=resolved_api_key_source_class,
    )
    key_management_state['clear_requested'] = False
    _remove_tombstone('key_reference_cleared')
    _set_tombstone_value(f'{normalized_lane}_key_reference_path', resolved_key_path)
    _set_tombstone_value(f'{normalized_lane}_key_reference_source_label', str(resolved_key_label))
    _sync_lane_validation_tombstone(normalized_lane)
    _upsert_key_registry_entry(resolved_key_path, str(resolved_key_label), status='available')
    _sync_key_registry_state()
    _clear_staged_key_reference_state()
    _sync_overlay_from_current_lane(env_override=env_override, subaccount_override=subaccount_override)
    key_management_state['overlay_key_path'] = resolved_key_path
    key_management_state['overlay_key_source_label'] = str(resolved_key_label)
    _sync_legacy_key_tombstones_from_overlay()
    _set_key_result(
      f"Loaded {_path_tail(selected_path) or 'selected key'} into the {normalized_lane} key slot for this shell session.",
      'ok',
    )
    return _refresh_state_payload(
      action_name,
      env_override=env_override,
      subaccount_override=subaccount_override,
      successful_transition=True,
    )

  def _stage_uploaded_key_reference(file_name: str, file_bytes_b64: str) -> str:
    decoded_bytes = base64.b64decode(str(file_bytes_b64 or '').encode('ascii'), validate=True)
    safe_name = Path(str(file_name or 'selected-key.pem')).name or 'selected-key.pem'
    suffix = Path(safe_name).suffix or '.pem'
    stem = Path(safe_name).stem or 'selected-key'
    digest = hashlib.sha256(decoded_bytes).hexdigest()[:12]
    stored_path = _uploaded_key_dir / f'{stem}-{digest}{suffix}'
    _uploaded_key_dir.mkdir(parents=True, exist_ok=True)
    stored_path.write_bytes(decoded_bytes)
    return str(stored_path.resolve())

  def _call_with_key_overlay(call: Callable[..., JSONDict], **kwargs: Any) -> JSONDict:
    settings_override = kwargs.get('settings')
    overlay_key_path = str(getattr(settings_override, 'private_key_file', None) or key_management_state.get('overlay_key_path') or '')
    with _private_key_file_env_overlay(overlay_key_path, lock=overlay_lock):
      return call(**kwargs)

  def _record_platform_validation(
    *,
    validated: bool,
    reason: str,
    path_value: str | None,
    lane: str | None = None,
    detected_environment: str | None = None,
  ) -> None:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is not None:
      key_management_state[f'{normalized_lane}_key_validated'] = bool(validated)
      key_management_state[f'{normalized_lane}_key_validation_reason'] = str(reason or '').strip().lower() or ('pass' if validated else 'error')
      key_management_state[f'{normalized_lane}_key_validation_timestamp'] = _utc_now_iso()
      key_management_state[f'{normalized_lane}_key_validation_path'] = str(path_value or '').strip() or None
    key_management_state['credential_platform_validated'] = bool(validated)
    key_management_state['credential_validation_reason'] = str(reason or '').strip().lower() or ('pass' if validated else 'error')
    key_management_state['credential_validation_timestamp'] = _utc_now_iso()
    key_management_state['credential_validation_path'] = str(path_value or '').strip() or None
    key_management_state['credential_validation_environment_detected'] = str(detected_environment or '').strip().lower() or None
    key_management_state['last_validation_timestamp'] = key_management_state['credential_validation_timestamp']
    key_management_state['last_validation_reason'] = key_management_state['credential_validation_reason']
    key_management_state['last_validation_environment_detected'] = key_management_state['credential_validation_environment_detected']
    if normalized_lane is not None and _lane_key_path(normalized_lane):
      _sync_lane_validation_tombstone(normalized_lane)

  def _log_key_discovery(lane: str, candidates: list[JSONDict], settings: Any | None = None) -> None:
    """Log key discovery results to audit trail."""
    if settings is None or not hasattr(settings, 'state_db_path'):
      return
    try:
      connection = open_database(settings.state_db_path)
      discovery_timestamp = _utc_now_iso()
      persist_operator_action(
        connection,
        action='discover_private_keys',
        recorded_at_utc=discovery_timestamp,
        operation_lane=lane or 'sandbox',
        detail={
          'candidate_count': len(candidates),
          'candidates': [
            {
              'resolved_path': c.get('resolved_path', ''),
              'path_tail': c.get('path_tail', ''),
              'source_label': c.get('source_label', ''),
              'pem_valid': True,
            }
            for c in candidates
          ],
          'discovery_ran_fresh': True,
        },
      )
      key_management_state['last_discovery_timestamp'] = discovery_timestamp
      key_management_state['last_discovery_candidate_count'] = len(candidates)
    except Exception:
      pass

  def _log_key_validation(lane: str, path: str, validated: bool, reason: str, detected_environment: str | None, settings: Any | None = None) -> None:
    """Log key validation result to audit trail."""
    if settings is None or not hasattr(settings, 'state_db_path'):
      return
    try:
      connection = open_database(settings.state_db_path)
      persist_operator_action(
        connection,
        action='validate_key_credentials',
        recorded_at_utc=_utc_now_iso(),
        operation_lane=lane or 'sandbox',
        detail={
          'key_path_used': _path_tail(path) or path,
          'environment_selected': lane or 'sandbox',
          'environment_detected': detected_environment,
          'validated': validated,
          'reason': reason,
          'status_by_environment': {
            'demo': 'ok' if validated and detected_environment == 'demo' else 'auth_fail',
            'live': 'ok' if validated and detected_environment == 'live' else 'auth_fail',
          },
        },
      )
    except Exception:
      pass

  def _log_key_applied(lane: str, path: str, reason: str, settings: Any | None = None) -> None:
    """Log key applied to lane."""
    if settings is None or not hasattr(settings, 'state_db_path'):
      return
    try:
      connection = open_database(settings.state_db_path)
      applied_timestamp = _utc_now_iso()
      persist_operator_action(
        connection,
        action='apply_validated_key',
        recorded_at_utc=applied_timestamp,
        operation_lane=lane or 'sandbox',
        detail={
          'key_path': _path_tail(path) or path,
          'lane': lane or 'sandbox',
          'validation_reason': reason,
        },
      )
      key_management_state['last_applied_timestamp'] = applied_timestamp
      key_management_state['last_applied_path'] = _path_tail(path) or path
      key_management_state['last_applied_lane'] = lane or 'sandbox'
    except Exception:
      pass

  def _inject_platform_validation_settings(settings_payload: JSONDict | None) -> None:
    return

  def _key_management_payload(payload: JSONDict) -> JSONDict:
    selected_path_raw = key_management_state.get('selected_key_path')
    selected_path = Path(str(selected_path_raw)).resolve() if selected_path_raw else None
    selected_ready = bool(selected_path and selected_path.exists() and selected_path.is_file())
    current_lane = _default_key_lane()
    _sync_overlay_from_current_lane()
    overlay_path_raw = key_management_state.get('overlay_key_path')
    overlay_path = Path(str(overlay_path_raw)).resolve() if overlay_path_raw else None
    cleared_in_session = bool(key_management_state.get('clear_requested'))
    settings = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    sandbox_path_raw = _lane_key_path('sandbox')
    live_path_raw = _lane_key_path('live')
    sandbox_validated, sandbox_reason, sandbox_validated_at, _ = _lane_key_validation_snapshot('sandbox')
    live_validated, live_reason, live_validated_at, _ = _lane_key_validation_snapshot('live')
    detected_environment = str(key_management_state.get('credential_validation_environment_detected') or '').strip().lower() or None
    selected_environment = 'demo' if current_lane == 'sandbox' else 'live'
    environment_warning = None
    if detected_environment and detected_environment in {'demo', 'live'} and detected_environment != selected_environment:
      environment_warning = {
        'selected_lane': current_lane,
        'selected_environment': selected_environment,
        'detected_environment': detected_environment,
      }

    discovered_candidates: list[JSONDict] = []
    for candidate in key_management_state.get('discovered_candidates', []):
      candidate_id = str(candidate.get('candidate_id', ''))
      candidate_path_raw = str(candidate.get('resolved_path', ''))
      candidate_path = Path(candidate_path_raw).resolve() if candidate_path_raw else None
      discovered_candidates.append(
        {
          'candidate_id': candidate_id,
          'profile_token': str(candidate.get('profile_token') or _profile_token_for_path(str(candidate_path) if candidate_path is not None else candidate_path_raw)),
          'path_tail': candidate.get('path_tail') or _path_tail(candidate_path),
          'path_hint': _path_hint(candidate_path),
          'source_label': candidate.get('source_label') or 'Discovered source',
          'lane_tag': str(candidate.get('lane_tag') or '').strip().lower() or None,
          'status': str(candidate.get('status') or 'available'),
          'selected': candidate_id == key_management_state.get('selected_candidate_id'),
          'active': bool(overlay_path and candidate_path is not None and candidate_path == overlay_path),
        }
      )

    active_key_tail = _path_tail(overlay_path)
    if not active_key_tail:
      active_key_tail = '--' if cleared_in_session else (settings.get('private_key_path_tail') or '--')
    active_key_source_label = (
      key_management_state.get('overlay_key_source_label')
      if key_management_state.get('overlay_key_path')
      else ('Cleared in session' if cleared_in_session else 'Config discovery')
    )
    result = {
      'candidate_count': len(discovered_candidates),
      'discovery_ran': bool(key_management_state.get('discovery_ran')),
      'discovered_candidates': discovered_candidates,
      'loaded_count': _loaded_key_lane_count(),
      'key_glow': _key_glow_state(),
      'key_glow_tone': _key_glow_tone(),
      'current_lane': current_lane,
      'selected_key_tail': _path_tail(selected_path),
      'selected_key_path_display': str(selected_path_raw or ''),
      'selected_key_source_label': _human_key_source_label(key_management_state.get('selected_key_source_label')),
      'selected_api_key_id_tail': _api_key_id_tail(key_management_state.get('selected_api_key_id')),
      'selected_api_key_source_class': str(key_management_state.get('selected_api_key_source_class') or '').strip() or None,
      'selected_key_ready': selected_ready,
      'active_key_tail': active_key_tail,
      'active_key_source_label': _human_key_source_label(active_key_source_label),
      'overlay_active': bool(key_management_state.get('overlay_key_path')),
      'clear_hold_active': cleared_in_session,
      'sandbox_key_tail': _path_hint(sandbox_path_raw),
      'sandbox_key_source_label': _human_key_source_label(_lane_key_source_label('sandbox')),
      'sandbox_api_key_id_tail': _api_key_id_tail(key_management_state.get('sandbox_api_key_id')),
      'sandbox_api_key_source_class': str(key_management_state.get('sandbox_api_key_source_class') or '').strip() or None,
      'sandbox_key_loaded': bool(sandbox_path_raw),
      'sandbox_key_validated': sandbox_validated,
      'sandbox_key_validation_reason': sandbox_reason,
      'sandbox_key_validation_timestamp': sandbox_validated_at,
      'live_key_tail': _path_hint(live_path_raw),
      'live_key_source_label': _human_key_source_label(_lane_key_source_label('live')),
      'live_api_key_id_tail': _api_key_id_tail(key_management_state.get('live_api_key_id')),
      'live_api_key_source_class': str(key_management_state.get('live_api_key_source_class') or '').strip() or None,
      'live_key_loaded': bool(live_path_raw),
      'live_key_validated': live_validated,
      'live_key_validation_reason': live_reason,
      'live_key_validation_timestamp': live_validated_at,
      'credential_platform_validated': key_management_state.get('credential_platform_validated'),
      'credential_validation_reason': key_management_state.get('credential_validation_reason'),
      'credential_validation_timestamp': key_management_state.get('credential_validation_timestamp'),
      'credential_validation_environment_detected': detected_environment,
      'key_environment_warning': environment_warning,
      'last_discovery': {
        'recorded_at_utc': key_management_state.get('last_discovery_timestamp'),
        'candidate_count': key_management_state.get('last_discovery_candidate_count'),
      },
      'last_validation': {
        'recorded_at_utc': key_management_state.get('last_validation_timestamp'),
        'reason': key_management_state.get('last_validation_reason'),
        'environment_detected': key_management_state.get('last_validation_environment_detected'),
      },
      'last_applied': {
        'recorded_at_utc': key_management_state.get('last_applied_timestamp'),
        'key_path_tail': key_management_state.get('last_applied_path'),
        'lane': key_management_state.get('last_applied_lane'),
      },
      'last_result': key_management_state.get('last_result'),
    }
    if _payload_is_inactive_lane_boundary(payload):
      result.update(
        {
          'current_lane': 'offline',
          'key_environment_warning': None,
        }
      )
    return result

  def _set_data_result(
    message: str,
    tone: str = 'info',
    *,
    reason: str | None = None,
    origin: str | None = None,
  ) -> None:
    inferred_origin = str(origin or '').strip().lower() or _infer_message_origin(reason=reason, message=message)
    data_management_state['last_result'] = {
      'message': message,
      'tone': tone,
      'reason': reason,
      'origin': inferred_origin,
    }

  def _datapack_candidate_id(root_path: str | None) -> str:
    normalized_root = str(Path(str(root_path or '')).expanduser()).strip().lower()
    digest = hashlib.sha256(normalized_root.encode('utf-8')).hexdigest()
    return f'datapack-{digest[:12]}'

  def _resolve_datapack_root(path_value: str | None) -> Path | None:
    raw_value = str(path_value or '').strip()
    if not raw_value:
      return None
    candidate = Path(raw_value).expanduser()
    if not candidate.is_absolute():
      candidate = (Path.cwd() / candidate).resolve()
    else:
      candidate = candidate.resolve()
    if candidate.is_dir():
      root = candidate
    elif candidate.name.lower() in {'manifest.json', 'restore_policy.json'}:
      root = candidate.parent
    elif candidate.parent.name.lower() == 'payloads':
      root = candidate.parent.parent
    else:
      return None
    if not root.exists() or not root.is_dir():
      return None
    if not (root / 'manifest.json').is_file() or not (root / 'restore_policy.json').is_file():
      return None
    return root.resolve()

  def _read_datapack_control_pair(root: Path) -> tuple[JSONDict, JSONDict]:
    manifest = json.loads((root / 'manifest.json').read_text(encoding='utf-8'))
    restore_policy = json.loads((root / 'restore_policy.json').read_text(encoding='utf-8'))
    if not isinstance(manifest, dict) or not isinstance(restore_policy, dict):
      raise ValueError('Datapack control files must both decode to JSON objects.')
    return cast(JSONDict, manifest), cast(JSONDict, restore_policy)

  def _active_datapack_identity(
    lane: str,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict:
    normalized_lane = _normalize_key_lane(lane) or _default_key_lane(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    settings = _settings_for_lane(
      normalized_lane,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    _api_key_id_for_hash = str(getattr(settings, 'api_key_id', '') or '').strip()
    return {
      'operation_lane': normalized_lane,
      'api_key_hash': api_key_hash_for_id(_api_key_id_for_hash) if _api_key_id_for_hash else '',
      'profile_token': profile_token_for_key_path(getattr(settings, 'private_key_file', None)),
      'state_db_path': str(getattr(settings, 'state_db_path', '') or '').strip(),
    }

  def _canonical_datapack_discovery_root() -> Path:
    return _data_extracts_root()

  def _datapack_discovery_fingerprint(search_root: Path) -> str:
    fingerprint_lines: list[str] = []
    if search_root.exists() and search_root.is_dir():
      for current_root, _dir_names, file_names in os.walk(search_root):
        current_path = Path(current_root)
        if 'manifest.json' not in file_names or 'restore_policy.json' not in file_names:
          continue
        payload_root = current_path / 'payloads'
        if not payload_root.exists() or not payload_root.is_dir():
          continue
        try:
          manifest_path = (current_path / 'manifest.json').resolve()
          restore_policy_path = (current_path / 'restore_policy.json').resolve()
          manifest_stat = manifest_path.stat()
          restore_policy_stat = restore_policy_path.stat()
        except OSError:
          continue
        fingerprint_lines.append(
          '|'.join(
            [
              str(current_path.resolve()).lower(),
              str(manifest_path).lower(),
              str(int(manifest_stat.st_mtime_ns)),
              str(int(manifest_stat.st_size)),
              str(restore_policy_path).lower(),
              str(int(restore_policy_stat.st_mtime_ns)),
              str(int(restore_policy_stat.st_size)),
            ]
          )
        )
    digest_input = '\n'.join(sorted(fingerprint_lines)).encode('utf-8')
    return hashlib.sha256(digest_input).hexdigest()

  def _discover_available_datapacks(
    *,
    env_override: str | None = None,
    subaccount_override: int | None = None,
  ) -> list[JSONDict]:
    search_root = _canonical_datapack_discovery_root().resolve()
    active_lane = _default_key_lane(env_override=env_override, subaccount_override=subaccount_override)
    active_identity = _active_datapack_identity(
      active_lane,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    active_api_key_hash = str(active_identity.get('api_key_hash') or '').strip()
    discovered: list[JSONDict] = []
    seen_roots: set[Path] = set()
    if search_root.exists() and search_root.is_dir():
      for current_root, _dir_names, file_names in os.walk(search_root):
        current_path = Path(current_root)
        if current_path in seen_roots:
          continue
        if 'manifest.json' not in file_names or 'restore_policy.json' not in file_names:
          continue
        payload_root = current_path / 'payloads'
        if not payload_root.exists() or not payload_root.is_dir():
          continue
        try:
          manifest, restore_policy = _read_datapack_control_pair(current_path)
        except Exception:
          continue
        attestation_issues = validate_datapack_controls(manifest, restore_policy)
        attestation_issues.extend(validate_datapack_artifacts(current_path, manifest, restore_policy))
        identity_result = evaluate_datapack_identity(
          manifest,
          active_operation_lane=str(active_identity.get('operation_lane') or active_lane),
          active_api_key_hash=active_api_key_hash,
        )
        identity_reasons = [
          str(reason).strip().lower()
          for reason in (identity_result.get('reasons') if isinstance(identity_result, dict) else []) or []
          if str(reason).strip()
        ]
        attested_now = len(attestation_issues) == 0
        key_match_now = (
          bool(active_api_key_hash)
          and str(manifest.get('api_key_hash') or '').strip().lower() == active_api_key_hash.lower()
        )
        eligible_now = bool(attested_now and bool(identity_result.get('allowed')))
        reason_codes = list(dict.fromkeys([
          *(['attestation_failed'] if not attested_now else []),
          *identity_reasons,
        ]))
        seen_roots.add(current_path)
        resolved_root = current_path.resolve()
        discovered.append(
          {
            'candidate_id': _datapack_candidate_id(str(resolved_root)),
            'resolved_root': str(resolved_root),
            'path_tail': _path_tail(resolved_root),
            'path_hint': _path_hint(resolved_root),
            'source_label': 'Saved datapack',
            'operation_lane': str(manifest.get('operation_lane') or '').strip().lower() or None,
            'datapack_type': str(manifest.get('datapack_type') or 'session_snapshot').strip() or 'session_snapshot',
            'schema_version': str(manifest.get('schema_version') or '').strip() or None,
            'created_at_utc': str(manifest.get('created_at_utc') or '').strip() or None,
            'api_key_hash': str(manifest.get('api_key_hash') or '').strip() or None,
            'key_match_now': key_match_now,
            'attested_now': attested_now,
            'eligible_now': eligible_now,
            'eligibility_reason_codes': reason_codes,
          }
        )
    discovered.sort(
      key=lambda item: (
        str(item.get('operation_lane') or ''),
        str(item.get('datapack_type') or ''),
        str(item.get('resolved_root') or ''),
      )
    )
    data_management_state['candidate_lookup'] = {
      str(item.get('candidate_id') or ''): str(item.get('resolved_root') or '')
      for item in discovered
      if str(item.get('candidate_id') or '').strip() and str(item.get('resolved_root') or '').strip()
    }
    return discovered

  def _stage_selected_datapack(root_path: str, source_label: str, *, candidate_id: str | None = None) -> None:
    root = _resolve_datapack_root(root_path)
    if root is None:
      raise ValueError('Select a datapack directory or control file that contains manifest.json and restore_policy.json.')
    manifest, restore_policy = _read_datapack_control_pair(root)
    data_management_state['selected_datapack_root'] = str(root)
    data_management_state['selected_datapack_source_label'] = str(source_label or 'Manual path').strip() or 'Manual path'
    data_management_state['selected_candidate_id'] = candidate_id
    data_management_state['selected_manifest'] = dict(manifest)
    data_management_state['selected_restore_policy'] = dict(restore_policy)
    data_management_state['selected_identity'] = {
      'operation_lane': str(manifest.get('operation_lane') or '').strip().lower() or None,
      'schema_version': str(manifest.get('schema_version') or '').strip() or None,
      'datapack_type': str(manifest.get('datapack_type') or 'session_snapshot').strip() or 'session_snapshot',
      'api_key_hash': str(manifest.get('api_key_hash') or '').strip() or None,
      'profile_token': str(manifest.get('profile_token') or '').strip() or None,
    }

  def _clear_selected_datapack() -> None:
    data_management_state['selected_datapack_root'] = None
    data_management_state['selected_datapack_source_label'] = None
    data_management_state['selected_candidate_id'] = None
    data_management_state['selected_manifest'] = None
    data_management_state['selected_restore_policy'] = None
    data_management_state['selected_identity'] = None

  def _loaded_datapack_lane_count() -> int:
    return sum(
      1
      for lane in ('sandbox', 'live')
      if str(data_management_state.get(f'{lane}_datapack_root') or '').strip()
    )

  def _datapack_bundle_size_bytes(root: Path | None) -> int:
    if root is None or not root.exists() or not root.is_dir():
      return 0
    total = 0
    try:
      for current_root, _dir_names, file_names in os.walk(root):
        current_path = Path(current_root)
        for file_name in file_names:
          try:
            total += int((current_path / file_name).stat().st_size)
          except OSError:
            continue
    except OSError:
      return 0
    return total

  def _approximate_size_label(size_bytes: int) -> str | None:
    size_value = int(size_bytes or 0)
    if size_value <= 0:
      return None
    units = ('B', 'KB', 'MB', 'GB')
    amount = float(size_value)
    unit_index = 0
    while amount >= 1024 and unit_index < len(units) - 1:
      amount /= 1024.0
      unit_index += 1
    if unit_index == 0:
      return f'{int(amount)} {units[unit_index]}'
    return f'{amount:.1f} {units[unit_index]}'

  def _datapack_slot_payload(lane: str) -> JSONDict:
    normalized_lane = _normalize_key_lane(lane) or 'sandbox'
    root_value = str(data_management_state.get(f'{normalized_lane}_datapack_root') or '').strip()
    root = Path(root_value) if root_value else None
    manifest = data_management_state.get(f'{normalized_lane}_manifest') if isinstance(data_management_state.get(f'{normalized_lane}_manifest'), dict) else {}
    size_bytes = _datapack_bundle_size_bytes(root)
    datapack_start = str(manifest.get('created_at_utc') or '').strip() or None
    return {
      'lane': normalized_lane,
      'lane_label': 'Live lane' if normalized_lane == 'live' else 'Sandbox lane',
      'occupied': bool(root_value),
      'identifier': _path_tail(root_value),
      'path_tail': _path_tail(root_value),
      'datapack_start': datapack_start,
      'approx_size_bytes': size_bytes or None,
      'approx_size_label': _approximate_size_label(size_bytes),
      'datapack_type': str(manifest.get('datapack_type') or 'session_snapshot').strip() or 'session_snapshot',
      'schema_version': str(manifest.get('schema_version') or '').strip() or None,
    }

  def _data_management_payload(_payload: JSONDict) -> JSONDict:
    selected_root = str(data_management_state.get('selected_datapack_root') or '').strip()
    selected_manifest = data_management_state.get('selected_manifest') if isinstance(data_management_state.get('selected_manifest'), dict) else {}
    datapack_slots = [_datapack_slot_payload('sandbox'), _datapack_slot_payload('live')]
    discovered_candidates = []
    for candidate in data_management_state.get('discovered_candidates', []):
      if not isinstance(candidate, dict):
        continue
      candidate_root = str(candidate.get('resolved_root') or '').strip()
      discovered_candidates.append(
        {
          'candidate_id': str(candidate.get('candidate_id') or ''),
          'path_tail': str(candidate.get('path_tail') or _path_tail(candidate_root) or '--'),
          'path_hint': str(candidate.get('path_hint') or _path_hint(candidate_root) or ''),
          'source_label': str(candidate.get('source_label') or 'Project datapack'),
          'operation_lane': str(candidate.get('operation_lane') or '').strip().lower() or None,
          'datapack_type': str(candidate.get('datapack_type') or 'session_snapshot'),
          'schema_version': str(candidate.get('schema_version') or '').strip() or None,
          'created_at_utc': str(candidate.get('created_at_utc') or '').strip() or None,
          'api_key_hash': str(candidate.get('api_key_hash') or '').strip() or None,
          'key_match_now': bool(candidate.get('key_match_now')),
          'attested_now': bool(candidate.get('attested_now')),
          'eligible_now': bool(candidate.get('eligible_now')),
          'eligibility_reason_codes': [
            str(reason).strip().lower()
            for reason in (candidate.get('eligibility_reason_codes') if isinstance(candidate.get('eligibility_reason_codes'), list) else [])
            if str(reason).strip()
          ],
          'selected': str(candidate.get('candidate_id') or '') == str(data_management_state.get('selected_candidate_id') or ''),
          'active': candidate_root in {
            str(data_management_state.get('sandbox_datapack_root') or '').strip(),
            str(data_management_state.get('live_datapack_root') or '').strip(),
          },
        }
      )
    last_extraction_candidate = data_management_state.get('last_extraction')
    last_extraction = cast(JSONDict, last_extraction_candidate) if isinstance(last_extraction_candidate, dict) else None
    if isinstance(last_extraction, dict):
      extraction_items_candidate = last_extraction.get('items')
      extraction_items = extraction_items_candidate if isinstance(extraction_items_candidate, list) else []
      normalized_items: list[JSONDict] = []
      for item in extraction_items:
        if not isinstance(item, dict):
          continue
        normalized_items.append(
          {
            'lane': str(item.get('lane') or '').strip().lower() or None,
            'source_datapack_tail': str(item.get('source_datapack_tail') or '').strip() or None,
            'extracted_root': str(item.get('extracted_root') or '').strip() or None,
            'extracted_root_tail': str(item.get('extracted_root_tail') or '').strip() or None,
            'manifest_path': str(item.get('manifest_path') or '').strip() or None,
            'restore_policy_path': str(item.get('restore_policy_path') or '').strip() or None,
            'operation_lane': str(item.get('operation_lane') or '').strip().lower() or None,
            'schema_version': str(item.get('schema_version') or '').strip() or None,
            'datapack_type': str(item.get('datapack_type') or '').strip() or None,
            'api_key_hash': str(item.get('api_key_hash') or '').strip() or None,
            'profile_token': str(item.get('profile_token') or '').strip() or None,
            'created_at_utc': str(item.get('created_at_utc') or '').strip() or None,
            'checksum_count': int(item.get('checksum_count') or 0) or None,
            'datapack_id': str(item.get('datapack_id') or '').strip() or None,
            'parent_datapack_id': str(item.get('parent_datapack_id') or '').strip() or None,
            'source_loaded_datapack_id': str(item.get('source_loaded_datapack_id') or '').strip() or None,
            'storage_class': str(item.get('storage_class') or '').strip().lower() or None,
            'write_origin': str(item.get('write_origin') or '').strip().lower() or None,
          }
        )
      last_extraction = {
        'mode': str(last_extraction.get('mode') or '').strip().lower() or 'clear_extract',
        'recorded_at_utc': str(last_extraction.get('recorded_at_utc') or '').strip() or None,
        'lane_count': int(last_extraction.get('lane_count') or len(normalized_items) or 0),
        'items': normalized_items,
      }
    last_load_attestation_candidate = data_management_state.get('last_load_attestation')
    last_load_attestation = cast(JSONDict, last_load_attestation_candidate) if isinstance(last_load_attestation_candidate, dict) else None
    if isinstance(last_load_attestation, dict):
      hydrated_family_ids = [
        str(family_id).strip().lower()
        for family_id in (
          last_load_attestation.get('hydrated_family_ids')
          if isinstance(last_load_attestation.get('hydrated_family_ids'), list)
          else []
        )
        if str(family_id).strip()
      ]
      provenance_candidate = last_load_attestation.get('provenance')
      provenance = cast(JSONDict, provenance_candidate) if isinstance(provenance_candidate, dict) else {}
      last_load_attestation = {
        'recorded_at_utc': str(last_load_attestation.get('recorded_at_utc') or '').strip() or None,
        'lane': str(last_load_attestation.get('lane') or '').strip().lower() or None,
        'datapack_id': str(last_load_attestation.get('datapack_id') or '').strip() or None,
        'loaded_from_tail': str(last_load_attestation.get('loaded_from_tail') or '').strip() or None,
        'parity_verdict': str(last_load_attestation.get('parity_verdict') or '').strip().lower() or None,
        'hydrated_family_ids': hydrated_family_ids,
        'hydrated_family_count': int(last_load_attestation.get('hydrated_family_count') or len(hydrated_family_ids) or 0),
        'hydrated_table_count': int(last_load_attestation.get('hydrated_table_count') or 0),
        'hydrated_row_count': int(last_load_attestation.get('hydrated_row_count') or 0),
        'completion_status': str(last_load_attestation.get('completion_status') or '').strip().lower() or None,
        'completion_message': str(last_load_attestation.get('completion_message') or '').strip() or None,
        'provenance': {
          'source_datapack_id': str(provenance.get('source_datapack_id') or '').strip() or None,
          'source_loaded_datapack_id': str(provenance.get('source_loaded_datapack_id') or '').strip() or None,
          'operation_lane': str(provenance.get('operation_lane') or '').strip().lower() or None,
          'api_key_hash': str(provenance.get('api_key_hash') or '').strip() or None,
          'profile_token': str(provenance.get('profile_token') or '').strip() or None,
        },
      }
    result = {
      'candidate_count': len(discovered_candidates),
      'discovery_ran': bool(data_management_state.get('discovery_ran')),
      'discovered_candidates': discovered_candidates,
      'loaded_count': _loaded_datapack_lane_count(),
      'discovery_fingerprint': str(data_management_state.get('discovery_fingerprint') or '').strip() or None,
      'discovery_cache_reused': bool(data_management_state.get('discovery_cache_reused')),
      'selected_datapack_tail': _path_tail(selected_root),
      'selected_datapack_path_display': selected_root,
      'selected_datapack_source_label': str(data_management_state.get('selected_datapack_source_label') or '').strip() or None,
      'selected_datapack_ready': bool(selected_root and selected_manifest),
      'selected_datapack_operation_lane': str(selected_manifest.get('operation_lane') or '').strip().lower() or None,
      'selected_datapack_schema_version': str(selected_manifest.get('schema_version') or '').strip() or None,
      'selected_datapack_type': str(selected_manifest.get('datapack_type') or 'session_snapshot').strip() or 'session_snapshot',
      'datapack_slots': datapack_slots,
      'sandbox_datapack_tail': _path_tail(data_management_state.get('sandbox_datapack_root')),
      'sandbox_datapack_loaded': bool(data_management_state.get('sandbox_datapack_id')),
      'sandbox_datapack_schema_version': str((((data_management_state.get('sandbox_manifest') or {}) if isinstance(data_management_state.get('sandbox_manifest'), dict) else {}).get('schema_version')) or '').strip() or None,
      'sandbox_datapack_type': str((((data_management_state.get('sandbox_manifest') or {}) if isinstance(data_management_state.get('sandbox_manifest'), dict) else {}).get('datapack_type')) or 'session_snapshot').strip() or 'session_snapshot',
      'sandbox_datapack_id': str(data_management_state.get('sandbox_datapack_id') or '').strip() or None,
      'sandbox_loaded_at': datapack_slots[0].get('datapack_start'),
      'live_datapack_tail': _path_tail(data_management_state.get('live_datapack_root')),
      'live_datapack_loaded': bool(data_management_state.get('live_datapack_id')),
      'live_datapack_schema_version': str((((data_management_state.get('live_manifest') or {}) if isinstance(data_management_state.get('live_manifest'), dict) else {}).get('schema_version')) or '').strip() or None,
      'live_datapack_type': str((((data_management_state.get('live_manifest') or {}) if isinstance(data_management_state.get('live_manifest'), dict) else {}).get('datapack_type')) or 'session_snapshot').strip() or 'session_snapshot',
      'live_datapack_id': str(data_management_state.get('live_datapack_id') or '').strip() or None,
      'live_loaded_at': datapack_slots[1].get('datapack_start'),
      'loaded_source_datapack_id': str(data_management_state.get('loaded_source_datapack_id') or '').strip() or None,
      'runtime_state_dirty_since_load': bool(data_management_state.get('runtime_state_dirty_since_load')),
      'runtime_state_dirty_at_utc': str(data_management_state.get('runtime_state_dirty_at_utc') or '').strip() or None,
      'runtime_state_dirty_reason': str(data_management_state.get('runtime_state_dirty_reason') or '').strip() or None,
      'pending_load_overwrite': data_management_state.get('pending_load_overwrite') if isinstance(data_management_state.get('pending_load_overwrite'), dict) else None,
      'pending_mint_confirmation': data_management_state.get('pending_mint_confirmation') if isinstance(data_management_state.get('pending_mint_confirmation'), dict) else None,
      'last_load_attestation': last_load_attestation,
      'last_extraction': last_extraction,
      'last_result': data_management_state.get('last_result'),
    }
    if _payload_is_inactive_lane_boundary(_payload):
      if str(_payload.get('shell_action') or '').strip().lower() in {
        'detect_available_datapacks',
        'select_datapack',
        'load_datapack',
        'load_sandbox_datapack',
        'load_live_datapack',
      }:
        return result
      result.update(
        {
          'candidate_count': 0,
          'discovered_candidates': [],
          'loaded_count': 0,
          'discovery_cache_reused': False,
          'selected_datapack_tail': '--',
          'selected_datapack_path_display': '',
          'selected_datapack_source_label': None,
          'selected_datapack_ready': False,
          'selected_datapack_operation_lane': None,
          'selected_datapack_schema_version': None,
          'selected_datapack_type': None,
          'datapack_slots': [
            {
              **slot,
              'occupied': False,
              'identifier': None,
              'path_tail': '--',
              'datapack_tail': '--',
              'loaded': False,
              'datapack_id': None,
              'schema_version': None,
              'datapack_type': None,
              'operation_lane': None,
              'datapack_start': None,
            }
            for slot in result.get('datapack_slots', [])
            if isinstance(slot, dict)
          ],
          'sandbox_datapack_schema_version': None,
          'sandbox_datapack_type': None,
          'live_datapack_schema_version': None,
          'live_datapack_type': None,
          'loaded_source_datapack_id': None,
          'runtime_state_dirty_since_load': False,
          'runtime_state_dirty_at_utc': None,
          'runtime_state_dirty_reason': None,
          'pending_load_overwrite': None,
          'last_load_attestation': None,
        }
      )
    return result

  def _identity_failure_message(identity_result: JSONDict, lane: str) -> str:
    reasons = {str(reason).strip().lower() for reason in identity_result.get('reasons', []) if str(reason).strip()}
    if 'operation_lane_mismatch' in reasons and 'api_key_hash_mismatch' in reasons:
      return (
        f'The selected datapack is locked to a different lane and API key identity than the {lane} session. '
        'GUI load stays fail-closed; use the explicit CLI-only rebind path only if joediggidyyy authorizes it.'
      )
    if 'operation_lane_mismatch' in reasons:
      return f'The selected datapack targets a different operation lane, so it cannot be loaded into the {lane} slot.'
    if 'api_key_hash_mismatch' in reasons:
      return (
        'The selected datapack is locked to a different API key hash. GUI load stays fail-closed; '
        'cross-key rebind remains CLI-only.'
      )
    return 'The selected datapack did not pass the current lane-plus-key identity check.'

  def _resolve_trust_lane_for_datapack_load(
    manifest: JSONDict,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> tuple[str | None, str | None]:
    eligible_lanes: list[str] = []
    for candidate_lane in ('sandbox', 'live'):
      active_identity = _active_datapack_identity(
        candidate_lane,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      identity_result = evaluate_datapack_identity(
        manifest,
        active_operation_lane=str(active_identity.get('operation_lane') or candidate_lane),
        active_api_key_hash=str(active_identity.get('api_key_hash') or ''),
      )
      if bool(identity_result.get('allowed')):
        eligible_lanes.append(candidate_lane)

    if len(eligible_lanes) == 1:
      return eligible_lanes[0], None
    if len(eligible_lanes) == 0:
      return None, 'no_eligible_lane'
    return None, 'ambiguous_eligible_lanes'

  def _operator_notifications_payload(
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict:
    if not _lane_boundary_mode_selected(
      env_override=env_override,
      subaccount_override=subaccount_override,
    ):
      return {
        'operation_lane': 'offline',
        'profile_token': None,
        'rows': [],
        'visible_rows': [],
        'unread_count': 0,
        'latest_created_at_utc': None,
      }
    lane = _default_key_lane(env_override=env_override, subaccount_override=subaccount_override)
    settings = _settings_for_lane(
      lane,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    profile_token = profile_token_for_key_path(getattr(settings, 'private_key_file', None))
    if not profile_token:
      return {
        'operation_lane': lane,
        'profile_token': None,
        'rows': [],
        'visible_rows': [],
        'unread_count': 0,
        'latest_created_at_utc': None,
      }
    connection = open_database(getattr(settings, 'state_db_path'))
    rows = fetch_operator_notifications(
      connection,
      operation_lane=lane,
      profile_token=profile_token,
      include_dismissed=False,
      include_expired=False,
    )
    return {
      'operation_lane': lane,
      'profile_token': profile_token,
      'rows': rows,
      'visible_rows': list(rows),
      'unread_count': sum(1 for row in rows if not bool(row.get('is_dismissed')) and not bool(row.get('is_expired'))),
      'latest_created_at_utc': rows[0].get('created_at_utc') if rows else None,
    }

  def _load_selected_datapack_into_lane(
    lane: str | None,
    *,
    env_override: str | None,
    subaccount_override: int | None,
    action_name: str,
    overwrite_confirmed: bool = False,
  ) -> JSONDict:
    normalized_lane = _normalize_key_lane(lane)
    selected_root = str(data_management_state.get('selected_datapack_root') or '').strip()
    if not selected_root:
      _set_data_result('Select a datapack reference before loading it into a lane slot.', 'no-go')
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)
    resolved_root = _resolve_datapack_root(selected_root)
    if resolved_root is None:
      _set_data_result('Select a datapack directory or control file that contains manifest.json and restore_policy.json.', 'no-go')
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)
    try:
      manifest, restore_policy = _read_datapack_control_pair(resolved_root)
    except Exception as exc:
      _set_data_result(str(exc) or 'Datapack control files could not be read.', 'no-go', reason='datapack_controls_invalid')
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)
    issues = validate_datapack_controls(manifest, restore_policy)
    issues.extend(validate_datapack_artifacts(resolved_root, manifest, restore_policy))
    if issues:
      _set_data_result(
        'Selected datapack failed attestation: {issues}.'.format(issues=', '.join(issues[:3])),
        'no-go',
        reason='datapack_attestation_failed',
      )
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)
    if normalized_lane is None:
      resolved_lane, resolution_reason = _resolve_trust_lane_for_datapack_load(
        manifest,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      if resolved_lane is None:
        if resolution_reason == 'ambiguous_eligible_lanes':
          _set_data_result(
            'The selected datapack is eligible for more than one lane in this shell context. Load stays fail-closed until lane identity is unambiguous.',
            'no-go',
            reason='datapack_lane_resolution_ambiguous',
          )
        else:
          _set_data_result(
            'The selected datapack did not match an eligible lane in this shell context, so trust-resolved load stayed fail-closed.',
            'no-go',
            reason='datapack_lane_resolution_failed',
          )
        return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)
      normalized_lane = resolved_lane
    active_identity = _active_datapack_identity(
      normalized_lane,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    identity_result = evaluate_datapack_identity(
      manifest,
      active_operation_lane=str(active_identity.get('operation_lane') or normalized_lane),
      active_api_key_hash=str(active_identity.get('api_key_hash') or ''),
    )
    if not bool(identity_result.get('allowed')):
      _set_data_result(
        _identity_failure_message(cast(JSONDict, identity_result), normalized_lane),
        'no-go',
        reason='datapack_identity_mismatch',
      )
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)
    state_db_path_value = str(active_identity.get('state_db_path') or '').strip()
    if not state_db_path_value:
      _set_data_result('State database path is required before datapack load can run.', 'no-go', reason='state_db_path_missing')
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)
    state_db_path = Path(state_db_path_value).expanduser()
    if not state_db_path.is_absolute():
      state_db_path = (Path.cwd() / state_db_path).resolve()
    connection = open_database(state_db_path)
    lane_row_count, lane_table_counts = _lane_runtime_partition_row_count(connection, normalized_lane)
    if lane_row_count > 0 and not overwrite_confirmed:
      profile_token = str(active_identity.get('profile_token') or '').strip()
      if profile_token:
        emit_notification(
          connection,
          event_key='datapack_overwrite_prompted',
          operation_lane=normalized_lane,
          profile_token=profile_token,
          source='datapack',
          detail={'lane_label': normalized_lane.title()},
        )
      data_management_state['pending_load_overwrite'] = {
        'lane': normalized_lane,
        'row_count': lane_row_count,
        'table_counts': lane_table_counts,
        'required_confirmation': 'continue_overwrite',
        'extract_first_recommended': True,
      }
      _set_data_result(
        'Loading this datapack will overwrite existing {lane} lane data. Extract first if you need preservation, then confirm overwrite to continue.'.format(
          lane=normalized_lane,
        ),
          'warn',
        reason='datapack_overwrite_confirmation_required',
      )
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)

    table_payloads = _read_datapack_payload_tables(resolved_root, manifest)
    hydrated_row_count = 0
    for table_payload in table_payloads.values():
      if not isinstance(table_payload, dict):
        continue
      rows = table_payload.get('rows') if isinstance(table_payload.get('rows'), list) else []
      hydrated_row_count += len(rows)
    if hydrated_row_count <= 0:
      data_management_state['last_load_attestation'] = None
      data_management_state['pending_load_overwrite'] = None
      _set_data_result(
        'Selected datapack has no loadable runtime rows, so destructive load is blocked before clear. Proof-only or zero-hydration datapacks stay fail-closed.',
        'no-go',
        reason='datapack_proof_only_non_loadable',
      )
      return _refresh_state_payload(action_name, env_override=env_override, subaccount_override=subaccount_override)
    _clear_lane_runtime_partition(connection, normalized_lane)
    _hydrate_lane_runtime_partition_from_datapack(
      connection,
      normalized_lane,
      table_payloads,
    )
    profile_token = str(active_identity.get('profile_token') or '').strip()
    if profile_token:
      emit_notification(
        connection,
        event_key='datapack_load_overwrite_completed',
        operation_lane=normalized_lane,
        profile_token=profile_token,
        source='datapack',
        detail={'lane_label': normalized_lane.title()},
      )

    active_datapack_id = str(manifest.get('datapack_id') or '').strip()
    if not active_datapack_id:
      active_datapack_id = '{ts}-{lane}-{tok}'.format(
        ts=time.strftime('%Y%m%dT%H%M%SZ', time.gmtime()),
        lane=normalized_lane,
        tok=os.urandom(3).hex(),
      )
    _load_settings = _settings_for_lane(normalized_lane, env_override=env_override, subaccount_override=subaccount_override)
    _key_path = str(getattr(_load_settings, 'private_key_file', None) or '').strip() or None
    with connection:
      resolve_active_profile_token(connection, normalized_lane, key_path=_key_path)
      connection.execute(
        'UPDATE lane_active_datapack SET detail_json = ? WHERE operation_lane = ? AND closed_at_utc IS NULL',
        (json.dumps({'datapack_id': active_datapack_id}), normalized_lane),
      )
    data_management_state[f'{normalized_lane}_datapack_root'] = str(resolved_root)
    _set_tombstone_value(f'{normalized_lane}_datapack_root', str(resolved_root))
    data_management_state[f'{normalized_lane}_datapack_source_label'] = str(
      data_management_state.get('selected_datapack_source_label') or 'Manual path'
    )
    data_management_state[f'{normalized_lane}_manifest'] = dict(manifest)
    data_management_state[f'{normalized_lane}_restore_policy'] = dict(restore_policy)
    data_management_state[f'{normalized_lane}_identity'] = dict(active_identity)
    data_management_state[f'{normalized_lane}_datapack_id'] = active_datapack_id
    data_management_state['loaded_source_datapack_id'] = active_datapack_id
    data_management_state['runtime_state_dirty_since_load'] = False
    data_management_state['runtime_state_dirty_at_utc'] = None
    data_management_state['runtime_state_dirty_reason'] = None
    data_management_state['pending_load_overwrite'] = None
    included_families = sorted(
      {
        str(inventory_entry.get('family_id') or '').strip().lower()
        for inventory_entry in (manifest.get('inventory') if isinstance(manifest.get('inventory'), list) else [])
        if isinstance(inventory_entry, dict) and bool(inventory_entry.get('included')) and str(inventory_entry.get('family_id') or '').strip()
      }
    )
    hydrated_table_count = 0
    for table_payload in table_payloads.values():
      if not isinstance(table_payload, dict):
        continue
      rows = table_payload.get('rows') if isinstance(table_payload.get('rows'), list) else []
      if rows:
        hydrated_table_count += 1
    parity_verdict = 'hydrated_with_expected_delta' if lane_row_count > 0 and overwrite_confirmed else 'hydrated_equal'
    completion_message = (
      'Hydration complete for {lane}: {families} families, {tables} tables, {rows} rows ({parity}).'.format(
        lane=normalized_lane,
        families=len(included_families),
        tables=hydrated_table_count,
        rows=hydrated_row_count,
        parity=parity_verdict,
      )
    )
    data_management_state['last_load_attestation'] = {
      'recorded_at_utc': _utc_now_iso(),
      'lane': normalized_lane,
      'datapack_id': active_datapack_id,
      'loaded_from_tail': _path_tail(resolved_root),
      'parity_verdict': parity_verdict,
      'hydrated_family_ids': included_families,
      'hydrated_family_count': len(included_families),
      'hydrated_table_count': hydrated_table_count,
      'hydrated_row_count': hydrated_row_count,
      'completion_status': 'complete',
      'completion_message': completion_message,
      'provenance': {
        'source_datapack_id': active_datapack_id,
        'source_loaded_datapack_id': active_datapack_id,
        'operation_lane': str(manifest.get('operation_lane') or normalized_lane),
        'api_key_hash': str(manifest.get('api_key_hash') or ''),
        'profile_token': str(manifest.get('profile_token') or ''),
      },
    }
    _clear_selected_datapack()
    _set_data_result(
      (
        f'Loaded {_path_tail(resolved_root) or "selected datapack"} into the {normalized_lane} data slot for this shell session. '
        f'{completion_message}'
      ),
      'ok',
      reason=f'datapack_load_{parity_verdict}',
    )
    return _refresh_state_payload(
      action_name,
      env_override=env_override,
      subaccount_override=subaccount_override,
      successful_transition=True,
    )

  def _clear_loaded_datapack_lane(lane: str) -> None:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      return
    current_datapack_id = str(data_management_state.get(f'{normalized_lane}_datapack_id') or '').strip()
    data_management_state[f'{normalized_lane}_datapack_root'] = None
    _remove_tombstone(f'{normalized_lane}_datapack_root')
    data_management_state[f'{normalized_lane}_datapack_source_label'] = None
    data_management_state[f'{normalized_lane}_manifest'] = None
    data_management_state[f'{normalized_lane}_restore_policy'] = None
    data_management_state[f'{normalized_lane}_identity'] = None
    data_management_state[f'{normalized_lane}_datapack_id'] = None
    data_management_state[f'{normalized_lane}_loaded_at'] = None
    if current_datapack_id and str(data_management_state.get('loaded_source_datapack_id') or '').strip() == current_datapack_id:
      data_management_state['loaded_source_datapack_id'] = None
      data_management_state['runtime_state_dirty_since_load'] = False
      data_management_state['runtime_state_dirty_at_utc'] = None
      data_management_state['runtime_state_dirty_reason'] = None

  def _table_exists(connection: Any, table_name: str) -> bool:
    row = connection.execute(
      "SELECT name FROM sqlite_master WHERE type='table' AND name=?",
      (table_name,),
    ).fetchone()
    return row is not None

  def _table_column_names(connection: Any, table_name: str) -> list[str]:
    rows = connection.execute(f'PRAGMA table_info({table_name})').fetchall()
    names: list[str] = []
    for row in rows:
      if isinstance(row, dict):
        names.append(str(row.get('name') or ''))
      else:
        try:
          names.append(str(row['name']))
        except Exception:
          continue
    return [name for name in names if name]

  def _lane_runtime_partition_row_count(connection: Any, lane: str) -> tuple[int, dict[str, int]]:
    normalized_lane = _normalize_key_lane(lane) or 'sandbox'
    table_counts: dict[str, int] = {}
    total = 0
    for table_name in sorted(LANE_BEARING_TABLES):
      if not _table_exists(connection, table_name):
        continue
      row = connection.execute(
        f'SELECT COUNT(*) AS count_value FROM {table_name} WHERE operation_lane = ?',
        (normalized_lane,),
      ).fetchone()
      count_value = int((row['count_value'] if row is not None else 0) or 0)
      table_counts[table_name] = count_value
      total += count_value
    return total, table_counts

  def _clear_lane_runtime_partition(connection: Any, lane: str) -> None:
    normalized_lane = _normalize_key_lane(lane) or 'sandbox'
    explicitly_cleared_lane_tables = {
      'candidate_review_runs',
      'candidate_saved_sets',
    }
    with connection:
      if _table_exists(connection, 'candidate_review_candidates') and _table_exists(connection, 'candidate_review_runs'):
        connection.execute(
          '''
          DELETE FROM candidate_review_candidates
          WHERE run_id IN (
            SELECT run_id FROM candidate_review_runs WHERE operation_lane = ?
          )
          ''',
          (normalized_lane,),
        )
      if _table_exists(connection, 'candidate_saved_set_evaluations') and _table_exists(connection, 'candidate_saved_sets'):
        connection.execute(
          '''
          DELETE FROM candidate_saved_set_evaluations
          WHERE saved_set_id IN (
            SELECT saved_set_id FROM candidate_saved_sets WHERE operation_lane = ?
          )
          ''',
          (normalized_lane,),
        )
      if _table_exists(connection, 'candidate_saved_set_members') and _table_exists(connection, 'candidate_saved_sets'):
        connection.execute(
          '''
          DELETE FROM candidate_saved_set_members
          WHERE saved_set_id IN (
            SELECT saved_set_id FROM candidate_saved_sets WHERE operation_lane = ?
          )
          ''',
          (normalized_lane,),
        )
      if _table_exists(connection, 'candidate_saved_sets'):
        connection.execute(
          'DELETE FROM candidate_saved_sets WHERE operation_lane = ?',
          (normalized_lane,),
        )
      if _table_exists(connection, 'candidate_review_runs'):
        connection.execute(
          'DELETE FROM candidate_review_runs WHERE operation_lane = ?',
          (normalized_lane,),
        )
      for table_name in sorted(LANE_BEARING_TABLES):
        if table_name in explicitly_cleared_lane_tables:
          continue
        if not _table_exists(connection, table_name):
          continue
        connection.execute(
          f'DELETE FROM {table_name} WHERE operation_lane = ?',
          (normalized_lane,),
        )

  def _read_datapack_payload_tables(root: Path, manifest: JSONDict) -> dict[str, JSONDict]:
    table_payloads: dict[str, JSONDict] = {}
    inventory = manifest.get('inventory') if isinstance(manifest.get('inventory'), list) else []
    for inventory_entry in inventory:
      if not isinstance(inventory_entry, dict) or not bool(inventory_entry.get('included')):
        continue
      payload_path_value = str(inventory_entry.get('payload_path') or '').strip()
      if not payload_path_value:
        continue
      payload_path = root / Path(payload_path_value)
      if not payload_path.exists() or not payload_path.is_file():
        continue
      try:
        payload = json.loads(payload_path.read_text(encoding='utf-8'))
      except (OSError, json.JSONDecodeError):
        continue
      if not isinstance(payload, dict):
        continue
      tables = payload.get('tables') if isinstance(payload.get('tables'), dict) else {}
      for table_name, table_payload in tables.items():
        if isinstance(table_payload, dict):
          table_payloads[str(table_name)] = cast(JSONDict, table_payload)
    return table_payloads

  def _hydrate_lane_runtime_partition_from_datapack(connection: Any, lane: str, table_payloads: dict[str, JSONDict]) -> None:
    normalized_lane = _normalize_key_lane(lane) or 'sandbox'
    with connection:
      for table_name, table_payload in table_payloads.items():
        if not _table_exists(connection, table_name):
          continue
        actual_columns = _table_column_names(connection, table_name)
        configured_columns = [str(column) for column in (table_payload.get('columns') or []) if str(column) in actual_columns]
        if not configured_columns:
          continue
        rows = table_payload.get('rows') if isinstance(table_payload.get('rows'), list) else []
        if not rows:
          continue
        placeholders = ', '.join(['?'] * len(configured_columns))
        column_sql = ', '.join(configured_columns)
        insert_sql = f'INSERT OR REPLACE INTO {table_name} ({column_sql}) VALUES ({placeholders})'
        value_rows: list[tuple[Any, ...]] = []
        for row in rows:
          if not isinstance(row, dict):
            continue
          materialized = dict(row)
          if 'operation_lane' in configured_columns:
            materialized['operation_lane'] = normalized_lane
          value_rows.append(tuple(materialized.get(column) for column in configured_columns))
        if value_rows:
          connection.executemany(insert_sql, value_rows)

  def _mark_loaded_datapack_runtime_dirty(action_name: str, lane: str) -> None:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      return
    loaded_root = str(data_management_state.get(f'{normalized_lane}_datapack_root') or '').strip()
    if not loaded_root:
      return
    data_management_state['runtime_state_dirty_since_load'] = True
    data_management_state['runtime_state_dirty_at_utc'] = _utc_now_iso()
    data_management_state['runtime_state_dirty_reason'] = str(action_name or 'runtime_mutation').strip().lower() or 'runtime_mutation'

  class _DatapackExtractPolicyError(ValueError):
    pass

  def _data_extracts_root() -> Path:
    root = (PROJECT_ROOT / 'var' / 'datapack_extracts').resolve()
    root.mkdir(parents=True, exist_ok=True)
    return root

  def _datapack_ephemeral_extracts_root() -> Path:
    root = (PROJECT_ROOT / 'var' / 'datapack_store' / 'ephemeral' / 'extracts').resolve()
    root.mkdir(parents=True, exist_ok=True)
    return root

  def _resolve_datapack_extract_write_policy(requested_origin: str | None) -> JSONDict:
    profile = str(os.environ.get('POLYVENTURE_DATAPACK_WRITE_PROFILE') or '').strip().lower()
    if not profile:
      profile = 'test' if os.environ.get('PYTEST_CURRENT_TEST') else 'operator'
    if profile not in {'operator', 'test', 'diagnostic'}:
      raise _DatapackExtractPolicyError('Datapack write profile is invalid for datastore policy context.')

    normalized_origin = str(requested_origin or '').strip().lower()
    allowed_origins = {'operator_extract'} if profile == 'operator' else {'operator_extract', 'automation_test', 'diagnostic'}
    if normalized_origin and normalized_origin not in allowed_origins:
      raise _DatapackExtractPolicyError('Datapack extract origin is invalid for this datastore policy context.')

    session_managed = session_controller is not None
    default_origin = 'operator_extract' if profile == 'operator' else ('operator_extract' if session_managed else 'automation_test')
    resolved_origin = normalized_origin or default_origin
    if resolved_origin == 'operator_extract' and not session_managed:
      raise _DatapackExtractPolicyError(
        'Canonical datapack writes require a managed signed shell session context.'
      )

    if resolved_origin == 'operator_extract':
      return {
        'write_origin': 'operator_extract',
        'storage_class': 'canonical',
        'output_parent_root': str(_data_extracts_root()),
      }
    return {
      'write_origin': resolved_origin,
      'storage_class': 'ephemeral',
      'output_parent_root': str(_datapack_ephemeral_extracts_root()),
    }

  def _write_datapack_json_file(path: Path, payload: Any, *, checksum: str | None = None) -> str:
    serialized = serialize_datapack_json(payload)
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(serialized + '\n', encoding='utf-8')
    return str(checksum or datapack_payload_checksum(payload))

  def _write_datapack_bundle_files(
    *,
    output_root: Path,
    manifest: JSONDict,
    restore_policy: JSONDict,
    payloads: dict[str, Any],
  ) -> JSONDict:
    checksums: dict[str, str] = {}
    payload_root = output_root / 'payloads'
    for family_id, payload in payloads.items():
      relative_path = f'payloads/{family_id}.json'
      checksum = datapack_payload_checksum(payload)
      checksums[relative_path] = _write_datapack_json_file(payload_root / f'{family_id}.json', payload, checksum=checksum)

    restore_policy_checksum = datapack_payload_checksum(restore_policy)
    checksums['restore_policy.json'] = restore_policy_checksum
    manifest['checksums'] = dict(checksums)
    manifest_checksum = datapack_manifest_checksum(manifest)
    manifest['checksums']['manifest.json'] = manifest_checksum
    # Lane L5c (Class-2): sign the manifest (integrity root) alongside the checksums; bundle stays
    # checksum-only. Fail-closed unsigned when no key.
    sign_datapack_manifest(manifest)

    _write_datapack_json_file(output_root / 'restore_policy.json', restore_policy, checksum=restore_policy_checksum)
    _write_datapack_json_file(output_root / 'manifest.json', manifest, checksum=manifest_checksum)
    return cast(JSONDict, dict(manifest['checksums']))

  def _extract_loaded_datapack_lane(
    lane: str,
    *,
    env_override: str | None,
    subaccount_override: int | None,
    requested_origin: str | None,
  ) -> JSONDict:
    normalized_lane = _normalize_key_lane(lane)
    if normalized_lane is None:
      raise ValueError('Choose sandbox or live when requesting datapack extraction on clear.')

    loaded_root = str(data_management_state.get(f'{normalized_lane}_datapack_root') or '').strip()
    active_datapack_id_for_extract = str(data_management_state.get(f'{normalized_lane}_datapack_id') or '').strip()
    if not active_datapack_id_for_extract:
      raise ValueError(
        'Clear-as-extract requires an active datapack identity in the lane. {lane} has no datapack loaded or initialised.'.format(
          lane=normalized_lane,
        )
      )

    active_identity = _active_datapack_identity(
      normalized_lane,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    state_db_path_value = str(active_identity.get('state_db_path') or '').strip()
    if not state_db_path_value:
      raise ValueError('State database path is required before clear-as-extract can run.')
    state_db_path = Path(state_db_path_value).expanduser()
    if not state_db_path.is_absolute():
      state_db_path = (Path.cwd() / state_db_path).resolve()

    connection = open_database(state_db_path)
    bundle = build_datapack_bundle(
      connection,
      operation_lane=normalized_lane,
      datapack_type='session_snapshot',
      api_key_hash=str(active_identity.get('api_key_hash') or ''),
      profile_token=str(active_identity.get('profile_token') or '').strip() or None,
      state_db_path_tail=state_db_path.name,
      include_synthetic_refinement=False,
    )
    manifest = cast(JSONDict, bundle['manifest'])
    restore_policy = cast(JSONDict, bundle['restore_policy'])
    payloads = cast(dict[str, Any], bundle['payloads'])
    source_datapack_id = active_datapack_id_for_extract
    manifest['datapack_id'] = source_datapack_id
    manifest['parent_datapack_id'] = source_datapack_id
    manifest['source_loaded_datapack_id'] = source_datapack_id
    write_policy = _resolve_datapack_extract_write_policy(requested_origin)

    extract_id = '{timestamp}-{lane}-{token}'.format(
      timestamp=time.strftime('%Y%m%dT%H%M%SZ', time.gmtime()),
      lane=normalized_lane,
      token=os.urandom(3).hex(),
    )
    output_root = Path(str(write_policy.get('output_parent_root') or _data_extracts_root())) / extract_id
    checksums = _write_datapack_bundle_files(
      output_root=output_root,
      manifest=manifest,
      restore_policy=restore_policy,
      payloads=payloads,
    )

    issues = validate_datapack_artifacts(output_root, manifest, restore_policy)
    if issues:
      raise ValueError(
        'Extracted datapack validation failed: {issues}.'.format(
          issues=', '.join(issues[:3]),
        )
      )

    return {
      'lane': normalized_lane,
      'source_datapack_tail': _path_tail(loaded_root),
      'extracted_root': str(output_root),
      'extracted_root_tail': _path_tail(output_root),
      'manifest_path': str(output_root / 'manifest.json'),
      'restore_policy_path': str(output_root / 'restore_policy.json'),
      'operation_lane': str(manifest.get('operation_lane') or normalized_lane),
      'schema_version': str(manifest.get('schema_version') or ''),
      'datapack_type': str(manifest.get('datapack_type') or 'session_snapshot'),
      'api_key_hash': str(manifest.get('api_key_hash') or ''),
      'profile_token': str(manifest.get('profile_token') or ''),
      'created_at_utc': str(manifest.get('created_at_utc') or _utc_now_iso()),
      'checksum_count': len(checksums),
      'datapack_id': source_datapack_id or None,
      'parent_datapack_id': source_datapack_id or None,
      'source_loaded_datapack_id': source_datapack_id or None,
      'storage_class': str(write_policy.get('storage_class') or ''),
      'write_origin': str(write_policy.get('write_origin') or ''),
    }

  def _candidate_identity_component(value: Any) -> str:
    return re.sub(r'\s+', ' ', str(value or '').strip())

  def _candidate_review_uid(candidate: JSONDict, index: int) -> str:
    # Lane 0: delegate to the single canonical candidate identity (see module-level twin).
    has_identity = any(
      _candidate_identity_component(candidate.get(_field))
      for _field in (
        'candidate_uid', 'ticker', 'event_ticker', 'contract_label', 'selection_label',
        'yes_sub_title', 'no_sub_title', 'market_title', 'title', 'event_title',
      )
    )
    return _canonical_candidate_uid(candidate) if has_identity else f'candidate-{index + 1}'

  def _candidate_review_legacy_key(candidate: JSONDict, index: int) -> str:
    ticker = _candidate_identity_component(candidate.get('ticker')) or f'candidate-{index + 1}'
    rank = _candidate_identity_component(candidate.get('rank') if candidate.get('rank') not in {None, ''} else index + 1)
    qualifier = _candidate_identity_component(candidate.get('qualifier_tier')) or 'candidate'
    return f'{ticker}::{rank}::{qualifier}'

  def _candidate_review_key(candidate: JSONDict, index: int) -> str:
    return _candidate_review_uid(candidate, index)

  def _candidate_review_key_aliases(candidate: JSONDict, index: int) -> set[str]:
    aliases = {
      _candidate_review_key(candidate, index),
      _candidate_review_legacy_key(candidate, index),
    }
    return {alias for alias in aliases if str(alias).strip()}

  def _candidate_review_row_origin(candidate: JSONDict) -> str:
    return str(candidate.get('review_row_origin') or 'current').strip().lower() or 'current'

  def _candidate_is_previous(candidate: JSONDict) -> bool:
    return _candidate_review_row_origin(candidate) in {'saved_prior', 'saved_prior_hidden_expired'}

  def _saved_prior_review_row_origin(candidate: JSONDict) -> str:
    return 'saved_prior_hidden_expired' if _candidate_close_time_expired(candidate) else 'saved_prior'

  def _candidate_review_row_with_identity(candidate: JSONDict, index: int) -> JSONDict:
    candidate_uid = _candidate_review_uid(candidate, index)
    candidate_key = _candidate_review_key(candidate, index)
    return {
      **candidate,
      'candidate_uid': candidate_uid,
      'candidate_key': candidate_key,
    }

  def _candidate_review_rows(payload: JSONDict) -> list[JSONDict]:
    pair_monitor = payload.get('pair_monitor') if isinstance(payload.get('pair_monitor'), dict) else {}
    candidate_rows = pair_monitor.get('candidate_rows') if isinstance(pair_monitor.get('candidate_rows'), list) else []
    return [
      _candidate_review_row_with_identity(candidate, index)
      for index, candidate in enumerate(candidate_rows)
      if isinstance(candidate, dict)
    ]

  def _payload_has_review_candidates(payload: JSONDict) -> bool:
    sandbox_extended = payload.get('sandbox_candidates_extended') if isinstance(payload.get('sandbox_candidates_extended'), list) else []
    candidates = payload.get('candidates') if isinstance(payload.get('candidates'), list) else []
    return bool(
      int(payload.get('candidate_count', 0) or 0) > 0
      or int(payload.get('sandbox_extended_count', 0) or 0) > 0
      or len(sandbox_extended) > 0
      or len(candidates) > 0
    )

  def _review_hold_snapshot_payload() -> JSONDict | None:
    snapshot = _scan_runtime_snapshot()
    if str(snapshot.get('status') or '').strip().lower() != 'completed':
      return None
    result_payload_candidate = snapshot.get('result_payload')
    result_payload = cast(JSONDict, result_payload_candidate) if isinstance(result_payload_candidate, dict) else None
    if result_payload is None or not _payload_has_review_candidates(result_payload):
      return None
    return dict(result_payload)

  def _review_selection_explicit_empty_saved_set() -> bool:
    if bool(review_selection_state.get('explicit_empty_save')):
      return True
    saved_set_id = str(review_selection_state.get('saved_set_id') or '').strip()
    if not saved_set_id:
      return False
    saved_keys = [
      str(key).strip()
      for key in review_selection_state.get('saved_keys', [])
      if str(key).strip()
    ]
    saved_candidates = [
      candidate
      for candidate in review_selection_state.get('saved_candidates', [])
      if isinstance(candidate, dict)
    ]
    return not saved_keys and not saved_candidates

  def _set_projection_contract(
    payload: JSONDict,
    *,
    projection_source: str,
    projection_reason: str,
    recovery_mode: bool,
    projection_authority: str = 'backend_authored',
  ) -> JSONDict:
    payload['projection_source'] = str(projection_source or '').strip() or 'runtime_payload'
    payload['projection_authority'] = str(projection_authority or '').strip() or 'backend_authored'
    payload['projection_reason'] = str(projection_reason or '').strip() or 'Backend projector emitted the current payload contract.'
    payload['recovery_mode'] = bool(recovery_mode)
    return payload

  def _apply_projection_contract_defaults(payload: JSONDict, *, action_name: str) -> JSONDict:
    if all(key in payload for key in ('projection_source', 'projection_authority', 'projection_reason', 'recovery_mode')):
      return payload
    normalized_action = str(action_name or '').strip().lower()
    has_candidates = _payload_has_review_candidates(payload)
    if normalized_action == 'scan' and has_candidates:
      return _set_projection_contract(
        payload,
        projection_source='authoritative_scan_result',
        projection_reason='Find candidates produced the active candidate projection.',
        recovery_mode=False,
      )
    if has_candidates:
      return _set_projection_contract(
        payload,
        projection_source='authoritative_payload',
        projection_reason='Backend payload includes candidate rows without recovery reconstruction.',
        recovery_mode=False,
      )
    return _set_projection_contract(
      payload,
      projection_source='authoritative_payload_empty',
      projection_reason='Backend payload contains no candidate rows for this response.',
      recovery_mode=False,
    )

  def _emit_projection_recovery_event(payload: JSONDict, *, projection_source: str) -> None:
    normalized_source = str(projection_source or '').strip().lower()
    if not normalized_source:
      return
    workflow_source = str(payload.get('workflow_source') or '').strip().lower()
    if (
      projection_recovery_state.get('last_source') == normalized_source
      and projection_recovery_state.get('last_workflow_source') == workflow_source
    ):
      return
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    state_db_path = str(settings_payload.get('state_db_path') or '').strip()
    if not state_db_path:
      return
    operation_lane = _review_selection_operation_lane(payload)
    if not operation_lane:
      return  # fail closed: do not write a runtime event under an unresolved lane
    lane_session_id = str(((payload.get('scan_runtime') or {}).get('lane_session_id') or ''))
    try:
      connection = open_database(state_db_path)
      persist_runtime_event(
        connection,
        level='INFO',
        event_type='projection_recovery_entered',
        recorded_at_utc=_utc_now_iso(),
        operation_lane=operation_lane,
        lane_session_id=lane_session_id,
        detail={
          'projection_source': normalized_source,
          'projection_authority': str(payload.get('projection_authority') or 'backend_authored'),
          'recovery_mode': bool(payload.get('recovery_mode')),
          'workflow_source': workflow_source,
          'review_state_id': str(review_selection_state.get('state_id') or ''),
        },
      )
      projection_recovery_state['last_source'] = normalized_source
      projection_recovery_state['last_workflow_source'] = workflow_source
      projection_recovery_state['last_recorded_at_utc'] = _utc_now_iso()
    except Exception:
      return

  def _emit_rebuild_timing_event(payload: JSONDict, timing: JSONDict) -> None:
    # S1 diagnostic (PLAN-POLYVENTURE-LIVE-AUTO-STABILITY-20260615): record how long a
    # dashboard rebuild took and where the time went, out-of-band in the runtime event
    # log so slow rebuilds are captured even when the client probe has already timed out.
    # Durations and lane/scan status only -- no credential values.
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    state_db_path = str(settings_payload.get('state_db_path') or '').strip()
    if not state_db_path:
      return
    operation_lane = _review_selection_operation_lane(payload)
    if not operation_lane:
      return  # fail closed: do not write a runtime event under an unresolved lane
    lane_session_id = str(((payload.get('scan_runtime') or {}).get('lane_session_id') or ''))
    try:
      connection = open_database(state_db_path)
      persist_runtime_event(
        connection,
        level='INFO',
        event_type='rebuild_timing',
        recorded_at_utc=_utc_now_iso(),
        operation_lane=operation_lane,
        lane_session_id=lane_session_id,
        detail={
          'action': str(timing.get('action') or ''),
          'path': str(timing.get('path') or ''),
          'scan_active': bool(timing.get('scan_active')),
          'scan_status': timing.get('scan_status'),
          'scan_stage': timing.get('scan_stage'),
          'total_ms': timing.get('total_ms'),
          'bootstrap_service_ms': timing.get('bootstrap_service_ms'),
          'replay_build_ms': timing.get('replay_build_ms'),
          'post_service_ms': timing.get('post_service_ms'),
          'report_ms': timing.get('report_ms'),
          'reconcile_ms': timing.get('reconcile_ms'),
          'funds_refresh_ms': timing.get('funds_refresh_ms'),
          'db_read_wait_ms': timing.get('db_read_wait_ms'),
          'db_write_wait_ms': timing.get('db_write_wait_ms'),
          'unattributed_ms': timing.get('unattributed_ms'),
        },
      )
    except Exception:
      return

  def _emit_rebuild_db_read_busy_event(payload: JSONDict, timing: JSONDict) -> None:
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    state_db_path = str(settings_payload.get('state_db_path') or '').strip()
    if not state_db_path:
      return
    operation_lane = _review_selection_operation_lane(payload)
    if not operation_lane:
      return
    lane_session_id = str(((payload.get('scan_runtime') or {}).get('lane_session_id') or ''))
    try:
      connection = open_database(state_db_path)
      persist_runtime_event(
        connection,
        level='WARN',
        event_type='rebuild_db_read_busy',
        recorded_at_utc=_utc_now_iso(),
        operation_lane=operation_lane,
        lane_session_id=lane_session_id,
        detail={
          'action': str(timing.get('action') or ''),
          'path': str(timing.get('path') or ''),
          'db_read_wait_ms': timing.get('db_read_wait_ms'),
          'scan_active': bool(timing.get('scan_active')),
          'scan_status': timing.get('scan_status'),
          'scan_stage': timing.get('scan_stage'),
        },
      )
    except Exception:
      return

  def _merge_preserved_review_hold_payload(action_name: str, payload: JSONDict) -> JSONDict:
    return _apply_projection_contract_defaults(payload, action_name=action_name)

  def _candidate_close_time_expired(candidate: JSONDict) -> bool:
    for field_name in ('close_time', 'close_time_utc', 'market_close_time_utc'):
      raw_value = str(candidate.get(field_name) or '').strip()
      if not raw_value:
        continue
      try:
        parsed = datetime.fromisoformat(raw_value.replace('Z', '+00:00'))
      except ValueError:
        continue
      if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
      if parsed <= datetime.now(timezone.utc):
        return True
    return False

  def _review_selection_operation_lane(payload: JSONDict) -> str:
    # Fail closed: no 'sandbox' fallback. Returns '' when the lane cannot be
    # resolved from any explicit source; every caller MUST treat '' as "do not
    # write" and skip the persistence call rather than mislabel the row.
    connection_posture = payload.get('connection_posture') if isinstance(payload.get('connection_posture'), dict) else {}
    lane = str(connection_posture.get('operation_lane') or '').strip().lower()
    if lane in {'sandbox', 'live'}:
      return lane
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    settings_lane = str(settings_payload.get('operation_lane') or '').strip().lower()
    if settings_lane in {'sandbox', 'live'}:
      return settings_lane
    state_lane = str(review_selection_state.get('saved_set_operation_lane') or '').strip().lower()
    if state_lane in {'sandbox', 'live'}:
      return state_lane
    return ''

  def _persist_candidate_review_snapshot(payload: JSONDict, *, action_name: str) -> str:
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    state_db_path = str(settings_payload.get('state_db_path') or '').strip()
    if not state_db_path:
      state_db_path = str(os.environ.get('KALSHI_STATE_DB_PATH') or '').strip()
    if not state_db_path:
      try:
        state_db_path = str(getattr(_effective_shell_settings(None, None), 'state_db_path', '') or '').strip()
      except Exception:
        state_db_path = ''
    if not state_db_path:
      return ''
    _ws_only_lsid = str(_websocket_runtime_snapshot().get('lane_session_id') or '').strip()
    if _ws_only_lsid and not review_selection_state.get('persisted_lane_session_id'):
      review_selection_state['persisted_lane_session_id'] = _ws_only_lsid
    source_candidates = payload.get('sandbox_candidates_extended') if isinstance(payload.get('sandbox_candidates_extended'), list) else []
    if not source_candidates and isinstance(payload.get('candidates'), list):
      source_candidates = list(payload.get('candidates', []))
    # P2-B2: do not re-admit a candidate that is already past its view-selection
    # deadline (close - view_buffer) — it is no longer selectable. It still shows
    # terminal/cancelled via the prior-cycle row + the expiry engine. Fail OPEN
    # (include) when the close time is absent/unparseable, so we only drop candidates
    # we can prove are past-deadline.
    _now_z = datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace('+00:00', 'Z')

    def _candidate_past_view_deadline(candidate: JSONDict) -> bool:
      _deadlines = _compute_candidate_deadlines(
        candidate.get('close_time_utc')
        or candidate.get('market_close_time_utc')
        or candidate.get('close_time')
      )
      return bool(_deadlines and str(_deadlines.get('view_expires_at_utc') or '') <= _now_z)

    current_candidates = [
      _candidate_review_row_with_identity(candidate, index)
      for index, candidate in enumerate(source_candidates)
      if isinstance(candidate, dict)
      and not _candidate_is_previous(candidate)
      and not _candidate_past_view_deadline(candidate)
    ]
    if not current_candidates:
      return ''
    scan_runtime = payload.get('scan_runtime') if isinstance(payload.get('scan_runtime'), dict) else {}
    execution_state = payload.get('execution_state') if isinstance(payload.get('execution_state'), dict) else {}
    run_id = str(
      scan_runtime.get('scan_session_id')
      or execution_state.get('scan_session_id')
      or review_selection_state.get('persisted_run_id')
      or ''
    ).strip()
    if not run_id:
      return ''
    operation_lane = _review_selection_operation_lane(payload)
    if not operation_lane:
      return ''  # fail closed: do not persist run or candidates under an unresolved lane
    candidate_signature = '|'.join(candidate.get('candidate_key') or _candidate_review_key(candidate, index) for index, candidate in enumerate(current_candidates))
    recorded_at_utc = str(scan_runtime.get('completed_at_utc') or _utc_now_iso())
    try:
      connection = open_database(state_db_path)
      # STOP-2: if an operator stop landed after this cycle started, this snapshot is a
      # straggler persisting after the halt -- skip it so a fresh 'discovered' row cannot
      # mask the halt's auto_cancel. Manual saves after a stop start later and are kept.
      _stop_fence_sess = str(review_selection_state.get('persisted_lane_session_id') or '').strip()
      if _stop_fence_sess:
        try:
          _cycle_at = datetime.fromisoformat(recorded_at_utc.replace('Z', '+00:00'))
          if _lane_session_stopped_after(
            connection,
            lane_session_id=_stop_fence_sess,
            operation_lane=operation_lane,
            cycle_recorded_at=_cycle_at,
          ):
            return ''
        except Exception:
          pass
      persist_candidate_review_run(
        connection,
        run_id=run_id,
        recorded_at_utc=recorded_at_utc,
        operation_lane=operation_lane,
        lane_session_id=str(review_selection_state.get('persisted_lane_session_id') or _websocket_runtime_snapshot().get('lane_session_id') or scan_runtime.get('lane_session_id') or execution_state.get('lane_session_id') or ''),
        candidate_signature=candidate_signature,
        candidate_count=len(current_candidates),
        source_action=action_name,
        detail={
          'reason': str(payload.get('reason') or ''),
          'resting_connection_posture': str(payload.get('resting_connection_posture') or ''),
        },
      )
      persist_candidate_review_candidates(
        connection,
        run_id=run_id,
        recorded_at_utc=recorded_at_utc,
        operation_lane=operation_lane,
        candidates=current_candidates,
      )
      _lsid = str(_websocket_runtime_snapshot().get('lane_session_id') or scan_runtime.get('lane_session_id') or execution_state.get('lane_session_id') or '').strip()
      if _lsid and not review_selection_state.get('persisted_lane_session_id'):
        review_selection_state['persisted_lane_session_id'] = _lsid
      return run_id
    except Exception:
      return ''

  def _persist_saved_set_evaluation(
    payload: JSONDict,
    *,
    saved_set_id: str,
    actionability_status: str,
    status_reason: str,
    visibility_status: str,
    offline_verifiable: bool,
    online_revalidation_required: bool,
  ) -> None:
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    state_db_path = str(settings_payload.get('state_db_path') or '').strip()
    if not state_db_path or not saved_set_id:
      return
    operation_lane = _review_selection_operation_lane(payload)
    if not operation_lane:
      return  # fail closed: do not write an evaluation under an unresolved lane
    try:
      connection = open_database(state_db_path)
      persist_candidate_saved_set_evaluation(
        connection,
        saved_set_id=saved_set_id,
        recorded_at_utc=_utc_now_iso(),
        operation_lane=operation_lane,
        evaluation_status='projected',
        actionability_status=actionability_status,
        visibility_status=visibility_status,
        offline_verifiable=offline_verifiable,
        online_revalidation_required=online_revalidation_required,
        detail={
          'reason': status_reason,
          'restored': bool(review_selection_state.get('saved_set_restored')),
        },
      )
    except Exception:
      return

  def _persist_saved_review_selection(payload: JSONDict) -> None:
    saved_candidates = [
      _candidate_review_row_with_identity(candidate, index)
      for index, candidate in enumerate(review_selection_state.get('saved_candidates', []))
      if isinstance(candidate, dict)
    ]
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    state_db_path = str(settings_payload.get('state_db_path') or '').strip()
    if not state_db_path:
      return
    run_id = _persist_candidate_review_snapshot(payload, action_name='save_selection') or str(review_selection_state.get('persisted_run_id') or '').strip() or None
    saved_set_id = 'saved-set-{timestamp}-{suffix}'.format(
      timestamp=time.strftime('%Y%m%dT%H%M%SZ', time.gmtime()),
      suffix=os.urandom(4).hex(),
    )
    # Submit-handoff signature integrity (BMAP 2026-07-03): the stored signature must
    # describe THIS saved set's members, so derive it from the same list that produces
    # the member rows. Copying review_selection_state['candidate_signature'] here let a
    # stale phantom from the broader candidate-row cache into the signature while the
    # members stayed clean, and the submit gate halted every live submit on the mismatch.
    member_signature = '|'.join(
      key
      for key in (str(candidate.get('candidate_key') or '').strip() for candidate in saved_candidates)
      if key
    )
    recorded_at_utc = _utc_now_iso()
    operation_lane = _review_selection_operation_lane(payload)
    if not operation_lane:
      return  # fail closed: do not persist saved set or evaluation under an unresolved lane
    try:
      connection = open_database(state_db_path)
      persist_candidate_saved_set(
        connection,
        saved_set_id=saved_set_id,
        run_id=run_id,
        recorded_at_utc=recorded_at_utc,
        operation_lane=operation_lane,
        lane_session_id=str(((payload.get('scan_runtime') or {}).get('lane_session_id') or '')),
        saved_key_count=len(saved_candidates),
        state_id=str(review_selection_state.get('state_id') or ('review_hold_saved_selection_locked' if saved_candidates else 'review_hold_empty_selection')),
        source_action='save_selection',
        members=saved_candidates,
        detail={
          'candidate_signature': member_signature,
          'saved_signature': member_signature,
        },
      )
      persist_candidate_saved_set_evaluation(
        connection,
        saved_set_id=saved_set_id,
        recorded_at_utc=recorded_at_utc,
        operation_lane=operation_lane,
        evaluation_status='saved',
        actionability_status='active_valid' if saved_candidates else 'historical_only',
        visibility_status='default_actionable' if saved_candidates else 'history_only',
        offline_verifiable=True,
        online_revalidation_required=False,
        detail={
          'reason': 'Saved from the current candidate review selection.' if saved_candidates else 'Saved candidate selection cleared by operator.',
        },
      )
    except Exception:
      return
    review_selection_state.update(
      {
        'saved_set_id': saved_set_id,
        'saved_set_recorded_at_utc': recorded_at_utc,
        'saved_set_operation_lane': operation_lane,
        'saved_set_status': 'active_valid' if saved_candidates else 'historical_only',
        'saved_set_status_reason': 'Saved from the current candidate review selection.' if saved_candidates else 'Saved candidate selection cleared by operator.',
        'saved_set_restored': False,
        'explicit_empty_save': not bool(saved_candidates),
        'consumed_submit_terminal': None,
        'failed_submit_attempt': None,
      }
    )
    review_selection_hydration_state.update(
      {
        'db_path': state_db_path,
        'operation_lane': operation_lane,
        'saved_set_id': saved_set_id,
      }
    )

  def _hydrate_review_selection_from_persistence(*, env_override: str | None, subaccount_override: int | None) -> None:
    active_settings = _effective_shell_settings(env_override, subaccount_override)
    if active_settings is None:
      active_settings = _resolve_settings(
        None,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
    if not _lane_boundary_mode_selected(
      env_override=env_override,
      subaccount_override=subaccount_override,
      settings_override=active_settings,
    ):
      _clear_review_selection_state()
      _clear_persisted_run_state()
      _clear_review_selection_hydration_state()
      return
    if not _persistence_hydration_allowed(active_settings):
      return
    state_db_path = str(getattr(active_settings, 'state_db_path', '') or '').strip()
    if not state_db_path:
      return
    requested_lane = str(getattr(active_settings, 'operation_lane', '') or '').strip().lower()
    persisted_lane = requested_lane if requested_lane in {'sandbox', 'live'} else None
    _clear_lane_mismatched_review_selection(persisted_lane)
    if (
      review_selection_state.get('saved_candidates')
      and not review_selection_state.get('saved_set_restored')
      and review_selection_hydration_state.get('db_path') == state_db_path
      and _review_selection_lane_matches(persisted_lane)
    ):
      return
    try:
      connection = open_database(state_db_path)
      saved_set = fetch_latest_candidate_saved_set(connection, operation_lane=persisted_lane)
      if saved_set is None and persisted_lane is None:
        saved_set = fetch_latest_candidate_saved_set(connection, operation_lane=None)
    except Exception:
      return
    if saved_set is None:
      return
    if (
      review_selection_hydration_state.get('db_path') == state_db_path
      and review_selection_hydration_state.get('saved_set_id') == str(saved_set.get('saved_set_id') or '')
      and review_selection_state.get('saved_candidates')
    ):
      return
    members = []
    for member in saved_set.get('members', []):
      member_detail = dict(member.get('detail') or {})
      candidate = _candidate_review_row_with_identity(member_detail, int(member.get('member_order', 0) or 0))
      candidate['review_row_origin'] = _saved_prior_review_row_origin(candidate)
      members.append(candidate)
    latest_evaluation = saved_set.get('latest_evaluation') if isinstance(saved_set.get('latest_evaluation'), dict) else {}
    restored_state_id = 'review_hold_saved_selection_restored' if members else 'review_hold_empty_selection'
    review_selection_state.update(
      {
        'candidate_signature': '',
        'working_keys': [str(member.get('candidate_key') or '') for member in members if str(member.get('candidate_key') or '').strip()],
        'saved_keys': [str(member.get('candidate_key') or '') for member in members if str(member.get('candidate_key') or '').strip()],
        'saved_candidates': members,
        'saved_signature': str(((saved_set.get('detail') or {}).get('saved_signature') or '')),
        'expired_missing_keys': [],
        'edit_mode_open': False,
        'saved_set_id': str(saved_set.get('saved_set_id') or ''),
        'saved_set_recorded_at_utc': str(saved_set.get('recorded_at_utc') or ''),
        'saved_set_operation_lane': str(saved_set.get('operation_lane') or persisted_lane or ''),
        'saved_set_status': str(latest_evaluation.get('actionability_status') or ''),
        'saved_set_status_reason': str(((latest_evaluation.get('detail') or {}).get('reason') or '')),
        'saved_set_restored': True,
        'persisted_run_id': str(saved_set.get('run_id') or ''),
        'state_id': restored_state_id,
      }
    )
    review_selection_hydration_state.update(
      {
        'db_path': state_db_path,
        'operation_lane': str(saved_set.get('operation_lane') or persisted_lane or ''),
        'saved_set_id': str(saved_set.get('saved_set_id') or ''),
      }
    )

  def _prior_saved_set_available(*, env_override: str | None, subaccount_override: int | None) -> bool:
    active_settings = _effective_shell_settings(env_override, subaccount_override)
    if active_settings is None:
      active_settings = _resolve_settings(
        None,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
    if not _persistence_hydration_allowed(active_settings):
      return False
    state_db_path = str(getattr(active_settings, 'state_db_path', '') or '').strip()
    if not state_db_path:
      return False
    requested_lane = str(getattr(active_settings, 'operation_lane', '') or '').strip().lower()
    persisted_lane = requested_lane if requested_lane in {'sandbox', 'live'} else None
    try:
      connection = open_database(state_db_path)
      saved_set = fetch_latest_candidate_saved_set(connection, operation_lane=persisted_lane)
      return saved_set is not None
    except Exception:
      return False

  def _merge_saved_candidate_rows_for_restored_history(payload: JSONDict) -> JSONDict:
    if _payload_has_review_candidates(payload):
      return payload
    if not _payload_accepts_review_selection(payload):
      return payload
    saved_candidates = [
      dict(candidate)
      for candidate in review_selection_state.get('saved_candidates', [])
      if isinstance(candidate, dict)
    ]
    if not saved_candidates:
      return payload
    payload['sandbox_candidates_extended'] = [
      {
        **candidate,
        'review_row_origin': _saved_prior_review_row_origin(candidate),
      }
      for candidate in saved_candidates
    ]
    payload['sandbox_extended_count'] = len(saved_candidates)
    payload['candidates'] = list(payload['sandbox_candidates_extended'])
    payload['candidate_count'] = len(saved_candidates)
    if not str(payload.get('resting_connection_posture') or '').strip():
      payload['resting_connection_posture'] = 'candidate_review_hold'
    _set_projection_contract(
      payload,
      projection_source='saved_set_restored_history',
      projection_reason='Saved candidate history restored from persistence for continuity mode review.',
      recovery_mode=True,
    )
    _emit_projection_recovery_event(payload, projection_source='saved_set_restored_history')
    return payload

  def _restored_saved_selection_status(payload: JSONDict) -> tuple[str, str, str, bool, bool]:
    saved_candidates = [
      candidate for candidate in review_selection_state.get('saved_candidates', [])
      if isinstance(candidate, dict)
    ]
    if any(_candidate_close_time_expired(candidate) for candidate in saved_candidates):
      return (
        'expired_actionability',
        'One or more restored saved candidates are past their locally verifiable close time.',
        'history_only',
        True,
        False,
      )
    connection_posture = payload.get('connection_posture') if isinstance(payload.get('connection_posture'), dict) else {}
    connection_state = connection_posture.get('connection_state') if isinstance(connection_posture.get('connection_state'), dict) else {}
    mode_selected = bool(connection_posture.get('mode_selected'))
    operation_lane = str(connection_posture.get('operation_lane') or '').strip().lower()
    websocket_connected = bool(connection_state.get('websocket_connected'))
    if not mode_selected or operation_lane == 'offline':
      return (
        'offline_limited',
        'Saved candidate history was restored from persistence while the shell is offline.',
        'saved_only',
        True,
        True,
      )
    if operation_lane in {'sandbox', 'live'} and not websocket_connected:
      return (
        'revalidation_required',
        'Saved candidate history was restored, but the connected lane is not currently healthy.',
        'saved_only',
        True,
        True,
      )
    return (
      'revalidation_required',
      'Saved candidate history was restored from persistence and requires a fresh candidate scan before submission.',
      'saved_only',
      True,
      True,
    )

  def _restored_review_workflow(payload: JSONDict, *, actionability_status: str) -> JSONDict:
    connection_posture = payload.get('connection_posture') if isinstance(payload.get('connection_posture'), dict) else {}
    connection_state = connection_posture.get('connection_state') if isinstance(connection_posture.get('connection_state'), dict) else {}
    mode_selected = bool(connection_posture.get('mode_selected'))
    operation_lane = str(connection_posture.get('operation_lane') or '').strip().lower()
    websocket_connected = bool(connection_state.get('websocket_connected'))
    requires_mode_change = (not mode_selected) or operation_lane == 'offline' or (operation_lane in {'sandbox', 'live'} and not websocket_connected)
    if requires_mode_change:
      return _workflow_state(
        'change_mode',
        auto_sequence=[],
        headline='Saved candidate history was restored, but the shell must reconnect before current actionability can be evaluated.',
        operator_message='Change mode or restore the connected lane first, then run Find candidates again before treating the restored set as actionable.',
        step_kind='review',
        can_run_next_step=True,
        next_actionable_step='mode_change',
        focus_target='pairs-section',
        focus_tone='focus-warn',
        deck_view='operator',
        button_emphasis_tone='warn',
      )
    headline = 'Saved candidate history was restored and now requires a fresh scan before submission.'
    if actionability_status == 'expired_actionability':
      headline = 'Saved candidate history was restored, but local time evidence says the set is no longer actionable.'
    return _workflow_state(
      'scan',
      auto_sequence=[],
      headline=headline,
      operator_message='Find candidates again to produce a current review set. The restored saved set remains visible for audit and comparison.',
      step_kind='review',
      can_run_next_step=True,
      next_actionable_step='scan',
      focus_target='pairs-section',
      focus_tone='focus-warn',
      deck_view='operator',
      button_emphasis_tone='warn',
    )

  def _clear_review_selection_state() -> None:
    review_selection_state.update(
      {
        'candidate_signature': '',
        'working_keys': [],
        'saved_keys': [],
        'saved_candidates': [],
        'saved_signature': '',
        'expired_missing_keys': [],
        'edit_mode_open': False,
        'saved_set_id': '',
        'saved_set_recorded_at_utc': '',
        'saved_set_operation_lane': '',
        'saved_set_status': '',
        'saved_set_status_reason': '',
        'saved_set_restored': False,
        'explicit_empty_save': False,
        'state_id': 'review_hold_empty_selection',
        'consumed_submit_terminal': None,
        'failed_submit_attempt': None,
      }
    )

  def _clear_persisted_run_state() -> None:
    review_selection_state.update({'persisted_run_id': '', 'persisted_run_recorded_at_utc': ''})

  def _saved_set_submit_guard_reason(
    *,
    saved_set_id: str,
    saved_member_count: int,
    state_id: str,
    saved_set_status: str,
    expired_missing_count: int,
    mode_selected: bool,
    active_lane: str | None,
    saved_lane: str | None,
  ) -> str | None:
    if not saved_set_id:
      return 'no_saved_set'
    if saved_member_count <= 0:
      return 'saved_set_empty'
    if (
      not mode_selected
      or active_lane not in ('sandbox', 'live')
      or (saved_lane and saved_lane != active_lane)
    ):
      return 'bridge_authorization_failed'
    return None

  def _review_selection_submit_order_guard_reason(payload: JSONDict) -> str | None:
    connection_posture = payload.get('connection_posture') if isinstance(payload.get('connection_posture'), dict) else {}
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    return _saved_set_submit_guard_reason(
      saved_set_id=str(review_selection_state.get('saved_set_id') or '').strip(),
      saved_member_count=_saved_selection_member_count(),
      state_id=str(review_selection_state.get('state_id') or '').strip().lower(),
      saved_set_status=str(review_selection_state.get('saved_set_status') or '').strip().lower(),
      expired_missing_count=len(list(review_selection_state.get('expired_missing_keys') or [])),
      mode_selected=bool(context_overlay_state.get('mode_selected')) or (
        bool(automation_overlay_state.get('enabled')) and not bool(automation_overlay_state.get('paused'))
      ),
      active_lane=_normalize_key_lane(connection_posture.get('operation_lane')) or _normalize_key_lane(settings_payload.get('operation_lane')),
      saved_lane=_normalize_key_lane(review_selection_state.get('saved_set_operation_lane')),
    )

  def _candidate_review_workflow(state_id: str, *, working_count: int) -> JSONDict:
    normalized_state = str(state_id or 'review_hold_empty_selection').strip().lower() or 'review_hold_empty_selection'
    if normalized_state == 'review_hold_candidates_available':
      return _workflow_state(
        'select_candidates',
        auto_sequence=[],
        headline='Candidate Pairs are ready for review in Candidates.',
        operator_message='Select one or more candidates to prepare a saved review set before submission.',
        step_kind='review',
        can_run_next_step=False,
        next_actionable_step='select_candidates',
        focus_target='pairs-section',
        focus_tone='focus-ok',
        deck_view='operator',
        button_emphasis_tone='',
      )
    if normalized_state == 'review_hold_with_active_selection':
      return _workflow_state(
        'save_candidates',
        auto_sequence=[],
        headline='The working selection is active in Candidates and must be saved before submission.',
        operator_message='Save candidates to lock the current working set before submission.',
        step_kind='execute',
        can_run_next_step=working_count > 0,
        next_actionable_step='save_candidates',
        focus_target='pairs-section',
        focus_tone='focus-ok',
        deck_view='operator',
        button_emphasis_tone='ok' if working_count > 0 else '',
      )
    if normalized_state == 'review_hold_saved_selection_locked':
      return _workflow_state(
        'submit_order',
        auto_sequence=[],
        headline='Candidates saved. The current working set is locked for review.',
        operator_message='Submit order when this saved set is final, change selection to revise it, or find candidates again to compare against a new scan.',
        step_kind='execute',
        can_run_next_step=True,
        next_actionable_step='submit_order',
        focus_target='pairs-section',
        focus_tone='focus-ok',
        deck_view='operator',
        button_emphasis_tone='ok',
      )
    if normalized_state == 'review_hold_saved_selection_review_required':
      return _workflow_state(
        'select_candidates',
        auto_sequence=[],
        headline='Saved candidates remain retained for review against the latest scan.',
        operator_message='Select candidates in the review panel to keep, remove, or add candidates before saving a revision.',
        step_kind='review',
        can_run_next_step=False,
        next_actionable_step='select_candidates',
        focus_target='pairs-section',
        focus_tone='focus-warn',
        deck_view='operator',
      )
    if normalized_state == 'review_hold_saved_selection_editing':
      return _workflow_state(
        'save_candidates',
        auto_sequence=[],
        headline='The saved set has been edited and must be saved again before submission.',
        operator_message='Save candidates again to relock the revised working set before submission.',
        step_kind='execute',
        can_run_next_step=working_count > 0,
        next_actionable_step='save_candidates',
        focus_target='pairs-section',
        focus_tone='focus-info',
        deck_view='operator',
        button_emphasis_tone='ok' if working_count > 0 else '',
      )
    if normalized_state == 'review_hold_saved_set_expired':
      return _workflow_state(
        'save_candidates',
        auto_sequence=[],
        headline='The saved set is no longer current and must be corrected before submission.',
        operator_message='Correct the saved selection in Candidates, then save candidates again before submission.',
        step_kind='review',
        can_run_next_step=working_count > 0,
        next_actionable_step='save_candidates',
        focus_target='pairs-section',
        focus_tone='focus-warn',
        deck_view='operator',
        button_emphasis_tone='ok' if working_count > 0 else '',
      )
    return _workflow_state(
      'select_candidates',
      auto_sequence=[],
      headline='The scan found candidates and the shell is holding on candidate review.',
      operator_message='Select candidates in the review panel to define the working set for this review hold.',
      step_kind='review',
      can_run_next_step=False,
      next_actionable_step='select_candidates',
      focus_target='pairs-section',
      focus_tone='focus-ok',
      deck_view='operator',
    )

  def _candidate_review_selection_locked(payload: JSONDict) -> bool:
    if not _payload_has_review_candidates(payload):
      return False
    connection_posture_candidate = payload.get('connection_posture')
    connection_posture = cast(JSONDict, connection_posture_candidate) if isinstance(connection_posture_candidate, dict) else {}
    if not connection_posture:
      return False
    connection_state_candidate = connection_posture.get('connection_state')
    connection_state = cast(JSONDict, connection_state_candidate) if isinstance(connection_state_candidate, dict) else {}
    operation_lane = str(connection_posture.get('operation_lane') or '').strip().lower()
    connection_status = str(connection_state.get('status') or '').strip().lower()
    websocket_connected = bool(connection_state.get('websocket_connected'))
    mode_selected = bool(connection_posture.get('mode_selected'))
    return (
      mode_selected
      and operation_lane in {'sandbox', 'live'}
      and not websocket_connected
      and connection_status in {'auth_failed', 'connection_failed', 'disconnected', 'error'}
    )

  def _apply_review_selection_projection(
    payload: JSONDict,
    *,
    selected_keys: list[str] | None = None,
    save_selection: bool = False,
    reopen_selection: bool = False,
  ) -> JSONDict:
    candidate_rows = _candidate_review_rows(payload)
    current_candidate_rows = [candidate for candidate in candidate_rows if not _candidate_is_previous(candidate)]
    restored_history_only_rows = not current_candidate_rows and any(_candidate_is_previous(candidate) for candidate in candidate_rows)
    execution_state = payload.get('execution_state') if isinstance(payload.get('execution_state'), dict) else {}
    scan_runtime = payload.get('scan_runtime') if isinstance(payload.get('scan_runtime'), dict) else {}
    processing_scan = (
      str(execution_state.get('kind') or '').strip().lower() == 'processing'
      and str(execution_state.get('action') or '').strip().lower() == 'scan'
    ) or str(scan_runtime.get('status') or '').strip().lower() in {'processing', 'canceling'}
    explicit_empty_saved_set = _review_selection_explicit_empty_saved_set()

    if not candidate_rows:
      empty_selection_locked = _candidate_review_selection_locked(payload) or processing_scan
      if not processing_scan:
        if explicit_empty_saved_set:
          review_selection_state.update(
            {
              'candidate_signature': '',
              'working_keys': [],
              'saved_keys': [],
              'saved_candidates': [],
              'expired_missing_keys': [],
              'edit_mode_open': False,
              'saved_set_status': str(review_selection_state.get('saved_set_status') or 'historical_only'),
              'saved_set_status_reason': str(
                review_selection_state.get('saved_set_status_reason')
                or 'Saved candidate selection cleared by operator.'
              ),
              'state_id': 'review_hold_empty_selection',
            }
          )
        elif not str(review_selection_state.get('saved_set_id') or '').strip():
          _clear_review_selection_state()
      _no_cands_mode_selected = bool(context_overlay_state.get('mode_selected'))
      _no_cands_state_id = (
        str(review_selection_state.get('state_id') or 'review_hold_empty_selection')
        if _no_cands_mode_selected
        else 'review_hold_empty_selection'
      )
      payload['review_selection'] = {
        'state_id': _no_cands_state_id,
        'candidate_signature': str(review_selection_state.get('candidate_signature') or ''),
        'working_keys': list(review_selection_state.get('working_keys') or []),
        'saved_keys': list(review_selection_state.get('saved_keys') or []),
        'saved_key_count': len(list(review_selection_state.get('saved_keys') or [])),
        'working_key_count': len(list(review_selection_state.get('working_keys') or [])),
        'submit_ready': _no_cands_state_id == 'review_hold_saved_selection_locked',
        'expired_missing_key_count': len(list(review_selection_state.get('expired_missing_keys') or [])),
        'saved_set_status': str(review_selection_state.get('saved_set_status') or ''),
        'saved_set_status_reason': str(review_selection_state.get('saved_set_status_reason') or ''),
        'saved_set_restored': bool(review_selection_state.get('saved_set_restored')),
        'selection_locked': empty_selection_locked,
        'selection_controls_enabled': not empty_selection_locked,
        'persisted_run_id': str(review_selection_state.get('persisted_run_id') or ''),
        'persisted_lane_session_id': str(review_selection_state.get('persisted_lane_session_id') or ''),
      }
      return payload

    all_keys = [
      str(candidate.get('candidate_key') or _candidate_review_key(candidate, index))
      for index, candidate in enumerate(candidate_rows)
    ]
    all_key_set = set(all_keys)
    current_keys = [
      str(candidate.get('candidate_key') or _candidate_review_key(candidate, index))
      for index, candidate in enumerate(current_candidate_rows)
    ]
    current_key_set = set(current_keys)
    signature = '|'.join(all_keys)
    selection_locked = processing_scan or (_candidate_review_selection_locked(payload) and not restored_history_only_rows)
    working_keys = list(review_selection_state.get('working_keys') or [])
    saved_keys = list(review_selection_state.get('saved_keys') or [])
    edit_mode_open = bool(review_selection_state.get('edit_mode_open'))

    # S1: if every saved candidate underlying a locked selection has expired past its
    # close time, RELEASE the lock instead of wedging the deck in Retry Wait -- the
    # zero-found-retry can then resume and the execution panel renders the candidates as
    # cancelled. Only the all-expired case releases (a partially-live saved set keeps the
    # operator's lock); fail closed -- a candidate whose close time cannot be parsed counts
    # as NOT expired (same detector _restored_saved_selection_status uses), so ambiguity
    # keeps the selection locked. The submit gate stays closed throughout.
    _saved_candidates_state = [
      _c for _c in review_selection_state.get('saved_candidates', []) if isinstance(_c, dict)
    ]
    _all_saved_expired = (
      bool(_saved_candidates_state)
      and all(_candidate_close_time_expired(_c) for _c in _saved_candidates_state)
    )

    if processing_scan and not current_candidate_rows and saved_keys and _all_saved_expired:
      _expired_reason = 'Saved candidates expired past their close time; selection released for re-scan.'
      review_selection_state.update({
        'state_id': 'review_hold_saved_set_expired',
        'saved_set_status': 'historical_only',
        'saved_set_status_reason': _expired_reason,
        'working_keys': [],
      })
      payload['review_selection'] = {
        'state_id': 'review_hold_saved_set_expired',
        'candidate_signature': signature,
        'working_keys': [],
        'saved_keys': list(saved_keys),
        'saved_key_count': len(saved_keys),
        'working_key_count': 0,
        'submit_ready': False,
        'expired_missing_key_count': len(saved_keys),
        'edit_mode_open': False,
        'selection_locked': False,
        'selection_controls_enabled': True,
        'saved_set_status': 'historical_only',
        'saved_set_status_reason': _expired_reason,
        'saved_set_restored': bool(review_selection_state.get('saved_set_restored')),
        'persisted_run_id': str(review_selection_state.get('persisted_run_id') or ''),
        'persisted_lane_session_id': str(review_selection_state.get('persisted_lane_session_id') or ''),
      }
      return payload

    if processing_scan and not current_candidate_rows and saved_keys:
      guard_reason = _review_selection_submit_order_guard_reason(payload)
      payload['review_selection'] = {
        'state_id': str(review_selection_state.get('state_id') or 'review_hold_saved_selection_locked'),
        'candidate_signature': signature,
        'working_keys': list(working_keys),
        'saved_keys': list(saved_keys),
        'saved_key_count': len(saved_keys),
        'working_key_count': len(working_keys),
        'submit_ready': (
          str(review_selection_state.get('state_id') or '') == 'review_hold_saved_selection_locked'
          and guard_reason is None
        ),
        'expired_missing_key_count': len(list(review_selection_state.get('expired_missing_keys') or [])),
        'edit_mode_open': edit_mode_open,
        'selection_locked': selection_locked,
        'selection_controls_enabled': not selection_locked,
        'saved_set_status': str(review_selection_state.get('saved_set_status') or ''),
        'saved_set_status_reason': str(review_selection_state.get('saved_set_status_reason') or ''),
        'saved_set_restored': bool(review_selection_state.get('saved_set_restored')),
        'persisted_run_id': str(review_selection_state.get('persisted_run_id') or ''),
        'persisted_lane_session_id': str(review_selection_state.get('persisted_lane_session_id') or ''),
      }
      return payload

    if restored_history_only_rows and selected_keys is None and not save_selection and not reopen_selection:
      actionability_status, status_reason, visibility_status, offline_verifiable, online_revalidation_required = _restored_saved_selection_status(payload)
      state_id = (
        'review_hold_saved_selection_offline_limited'
        if actionability_status == 'offline_limited'
        else 'review_hold_saved_selection_revalidation_required'
        if actionability_status == 'revalidation_required'
        else 'review_hold_saved_set_expired'
      )
      if str(review_selection_state.get('saved_set_status') or '') != actionability_status:
        _persist_saved_set_evaluation(
          payload,
          saved_set_id=str(review_selection_state.get('saved_set_id') or ''),
          actionability_status=actionability_status,
          status_reason=status_reason,
          visibility_status=visibility_status,
          offline_verifiable=offline_verifiable,
          online_revalidation_required=online_revalidation_required,
        )
      review_selection_state.update(
        {
          'candidate_signature': signature,
          'working_keys': list(all_keys),
          'saved_keys': list(all_keys),
          'expired_missing_keys': [],
          'edit_mode_open': False,
          'saved_set_status': actionability_status,
          'saved_set_status_reason': status_reason,
          'saved_set_restored': True,
          'state_id': state_id,
        }
      )
      payload['review_selection'] = {
        'state_id': state_id,
        'candidate_signature': signature,
        'working_keys': list(all_keys),
        'saved_keys': list(all_keys),
        'saved_key_count': len(all_keys),
        'working_key_count': len(all_keys),
        'submit_ready': False,
        'expired_missing_key_count': 0,
        'edit_mode_open': False,
        'selection_locked': False,
        'selection_controls_enabled': True,
        'saved_set_status': actionability_status,
        'saved_set_status_reason': status_reason,
        'saved_set_restored': True,
        'persisted_run_id': str(review_selection_state.get('persisted_run_id') or ''),
        'persisted_lane_session_id': str(review_selection_state.get('persisted_lane_session_id') or ''),
      }
      if not processing_scan:
        payload['workflow'] = _restored_review_workflow(payload, actionability_status=actionability_status)
      return payload

    if selection_locked:
      selected_keys = None
      save_selection = False
      reopen_selection = False

    if selected_keys is not None:
      alias_to_candidate_key: dict[str, str] = {}
      for index, candidate in enumerate(candidate_rows):
        candidate_key = str(candidate.get('candidate_key') or _candidate_review_key(candidate, index))
        for alias in _candidate_review_key_aliases(candidate, index):
          alias_to_candidate_key[alias] = candidate_key
      deduped_selected: list[str] = []
      seen_selected: set[str] = set()
      for key in selected_keys:
        normalized_key = str(key or '').strip()
        resolved_key = alias_to_candidate_key.get(normalized_key, normalized_key)
        if not resolved_key or resolved_key in seen_selected or resolved_key not in all_key_set:
          continue
        seen_selected.add(resolved_key)
        deduped_selected.append(resolved_key)
      working_keys = deduped_selected
      if saved_keys and working_keys != saved_keys:
        edit_mode_open = True
    else:
      working_keys = [key for key in working_keys if key in all_key_set]

    if reopen_selection and saved_keys:
      edit_mode_open = True
      if not working_keys:
        working_keys = [key for key in saved_keys if key in all_key_set]

    # A saved key has lapsed domain ownership if it is absent from current rows
    # or if its candidate's close time has passed.  The direct close-time check
    # aligns current-saved rows with the same expiry gate already applied to
    # restored/prior rows by _candidate_close_time_expired.
    current_candidate_map: dict[str, JSONDict] = {
      str(candidate.get('candidate_key') or _candidate_review_key(candidate, index)): dict(candidate)
      for index, candidate in enumerate(current_candidate_rows)
    }
    missing_saved_keys = [
      key for key in saved_keys
      if key not in current_key_set
      or _candidate_close_time_expired(current_candidate_map.get(key, {}))
    ]
    if save_selection:
      saved_keys = list(working_keys)
      saved_candidate_map = {
        str(candidate.get('candidate_key') or _candidate_review_key(candidate, index)): dict(candidate)
        for index, candidate in enumerate(candidate_rows)
      }
      review_selection_state['saved_candidates'] = [
        saved_candidate_map[key]
        for key in working_keys
        if key in saved_candidate_map
      ]
      if not working_keys:
        review_selection_state['saved_set_status'] = 'historical_only'
        review_selection_state['saved_set_status_reason'] = 'Saved candidate selection cleared by operator.'
        review_selection_state['explicit_empty_save'] = True
      else:
        review_selection_state['explicit_empty_save'] = False
      missing_saved_keys = []
      review_selection_state['saved_signature'] = signature
      edit_mode_open = False
      # Project the saved set back onto the payload candidate fields so the response
      # reflects the post-save state rather than the full scan cache.
      saved_rows = [saved_candidate_map[key] for key in working_keys if key in saved_candidate_map]
      payload['candidates'] = saved_rows
      payload['sandbox_candidates_extended'] = saved_rows
      payload['candidate_count'] = len(saved_rows)
      payload['sandbox_extended_count'] = len(saved_rows)

    saved_key_set = set(saved_keys)
    working_key_set = set(working_keys)
    if saved_keys:
      if edit_mode_open:
        state_id = 'review_hold_saved_selection_editing'
      elif missing_saved_keys:
        state_id = 'review_hold_saved_selection_review_required'
      elif working_key_set == saved_key_set:
        state_id = 'review_hold_saved_selection_locked'
      else:
        state_id = 'review_hold_saved_selection_editing'
    elif working_keys:
      state_id = 'review_hold_with_active_selection'
    elif save_selection:
      state_id = 'review_hold_empty_selection'
    elif current_candidate_rows:
      state_id = 'review_hold_candidates_available'
    else:
      state_id = 'review_hold_empty_selection'

    retained_empty_status = str(review_selection_state.get('saved_set_status') or '').strip()
    retained_empty_status_reason = str(review_selection_state.get('saved_set_status_reason') or '').strip()
    next_saved_set_status = 'expired_actionability' if missing_saved_keys else ('active_valid' if state_id == 'review_hold_saved_selection_locked' else '')
    next_saved_set_status_reason = (
      'One or more saved candidates are missing from the current scan result.'
      if missing_saved_keys
      else 'The current saved set matches the active scan result.'
      if state_id == 'review_hold_saved_selection_locked'
      else ''
    )
    if state_id == 'review_hold_empty_selection' and retained_empty_status == 'historical_only':
      next_saved_set_status = retained_empty_status
      next_saved_set_status_reason = retained_empty_status_reason

    review_selection_state.update(
      {
        'candidate_signature': signature,
        'working_keys': list(working_keys),
        'saved_keys': list(saved_keys),
        'expired_missing_keys': list(missing_saved_keys),
        'edit_mode_open': edit_mode_open,
        'saved_set_status': next_saved_set_status,
        'saved_set_status_reason': next_saved_set_status_reason,
        'saved_set_restored': False,
        'state_id': state_id,
      }
    )

    payload['review_selection'] = {
      'state_id': state_id,
      'candidate_signature': signature,
      'working_keys': list(working_keys),
      'saved_keys': list(saved_keys),
      'saved_key_count': len(saved_keys),
      'working_key_count': len(working_keys),
      'submit_ready': False,
      'expired_missing_key_count': len(missing_saved_keys),
      'edit_mode_open': edit_mode_open,
      'selection_locked': selection_locked,
      'selection_controls_enabled': not selection_locked,
      'saved_set_status': str(review_selection_state.get('saved_set_status') or ''),
      'saved_set_status_reason': str(review_selection_state.get('saved_set_status_reason') or ''),
      'saved_set_restored': False,
      'persisted_run_id': str(review_selection_state.get('persisted_run_id') or ''),
      'persisted_lane_session_id': str(review_selection_state.get('persisted_lane_session_id') or ''),
      'failed_submit_attempt': (
        dict(review_selection_state.get('failed_submit_attempt'))
        if isinstance(review_selection_state.get('failed_submit_attempt'), dict)
        else None
      ),
    }
    if processing_scan or selection_locked:
      return payload
    guard_reason = (
      _review_selection_submit_order_guard_reason(payload)
      if state_id == 'review_hold_saved_selection_locked'
      else None
    )
    payload['review_selection']['submit_ready'] = state_id == 'review_hold_saved_selection_locked' and guard_reason is None
    if _payload_preserves_action_workflow(payload):
      return payload
    payload['workflow'] = (
      _run_bridge_no_go_workflow(guard_reason)
      if guard_reason is not None
      else _candidate_review_workflow(state_id, working_count=len(working_keys))
    )
    return payload

  def _refresh_review_selection_projection(
    payload: JSONDict,
    *,
    selected_keys: list[str] | None = None,
    save_selection: bool = False,
    reopen_selection: bool = False,
  ) -> JSONDict:
    _apply_review_selection_projection(
      payload,
      selected_keys=selected_keys,
      save_selection=save_selection,
      reopen_selection=reopen_selection,
    )
    _rsp_projected_review_sel = payload.get('review_selection') if isinstance(payload.get('review_selection'), dict) else {}
    if _rsp_projected_review_sel:
      _rsp_projected_review_sel['saved_set_id'] = str(review_selection_state.get('saved_set_id') or '')
      _rsp_projected_review_sel['candidate_signature'] = str(
        _rsp_projected_review_sel.get('candidate_signature')
        or review_selection_state.get('candidate_signature')
        or ''
      )
      _rsp_consumed_submit_terminal = (
        dict(review_selection_state.get('consumed_submit_terminal'))
        if isinstance(review_selection_state.get('consumed_submit_terminal'), dict)
        else None
      )
      _rsp_projected_review_sel['consumed_submit_terminal'] = _rsp_consumed_submit_terminal
      _rsp_projected_review_sel['failed_submit_attempt'] = (
        dict(review_selection_state.get('failed_submit_attempt'))
        if isinstance(review_selection_state.get('failed_submit_attempt'), dict)
        else None
      )
      if _rsp_consumed_submit_terminal:
        _rsp_current_saved_set_id = str(_rsp_projected_review_sel.get('saved_set_id') or '').strip()
        _rsp_current_candidate_signature = str(_rsp_projected_review_sel.get('candidate_signature') or '').strip()
        if (
          _rsp_current_saved_set_id
          and _rsp_current_candidate_signature
          and str(_rsp_consumed_submit_terminal.get('consumed_saved_set_id') or '').strip() == _rsp_current_saved_set_id
          and str(_rsp_consumed_submit_terminal.get('consumed_candidate_signature') or '').strip() == _rsp_current_candidate_signature
        ):
          _rsp_projected_review_sel['submit_ready'] = False
          _rsp_projected_review_sel['saved_set_status'] = 'submitted_terminal'
          _rsp_projected_review_sel['saved_set_status_reason'] = (
            str(review_selection_state.get('saved_set_status_reason') or '')
            or 'Saved set was submitted and retired from current automation routing.'
          )
    _rsp_review_sel = payload.get('review_selection') if isinstance(payload.get('review_selection'), dict) else {}
    _rsp_settings = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
    _rsp_posture = payload.get('connection_posture') if isinstance(payload.get('connection_posture'), dict) else {}
    if _payload_preserves_action_workflow(payload):
      return payload
    _is_offline_posture = str(_rsp_settings.get('operation_lane') or '').strip().lower() == 'offline'
    if (
      str(_rsp_review_sel.get('state_id') or '') == 'review_hold_empty_selection'
      and bool(_rsp_settings.get('credential_ready'))
      and (bool(_rsp_posture.get('mode_selected')) or bool(_rsp_settings.get('mode_selected')))
      and str((payload.get('workflow') or {}).get('next_actionable_step') or '').strip() in ('-', 'mode_change')
        and not _payload_scan_processing_active(payload)
      and not _payload_has_live_interaction_hold(payload)
    ):
      payload['workflow'] = _workflow_state(
        'scan',
        auto_sequence=['scan', 'run'],
        headline='No candidates are saved; find candidates to begin a review cycle.',
        operator_message='Select Find candidates to start the candidate search.',
        step_kind='execute',
        can_run_next_step=True,
        next_actionable_step='scan',
        focus_target='notification-band-section',
        focus_tone='focus-ok',
        deck_view='workflow',
      )
    payload['startup_wizard'] = _build_startup_wizard_payload(payload)
    return payload

  def _merge_saved_candidate_rows_for_repeat_scan(payload: JSONDict) -> JSONDict:
    if not _payload_accepts_review_selection(payload):
      return payload
    saved_candidates = [
      dict(candidate)
      for candidate in review_selection_state.get('saved_candidates', [])
      if isinstance(candidate, dict)
    ]
    if not saved_candidates:
      return payload

    if isinstance(payload.get('sandbox_candidates_extended'), list):
      current_rows = [
        dict(candidate)
        for candidate in payload.get('sandbox_candidates_extended', [])
        if isinstance(candidate, dict)
      ]
    else:
      current_rows = [
        dict(candidate)
        for candidate in payload.get('candidates', [])
        if isinstance(candidate, dict)
      ] if isinstance(payload.get('candidates'), list) else []

    current_key_set = {
      _candidate_review_key(candidate, index)
      for index, candidate in enumerate(current_rows)
    }
    preserved_rows = []
    for saved_index, candidate in enumerate(saved_candidates):
      candidate_key = _candidate_review_key(candidate, saved_index)
      if candidate_key in current_key_set:
        continue
      review_row_origin = _saved_prior_review_row_origin(candidate)
      if review_row_origin == 'saved_prior_hidden_expired':
        continue
      preserved_rows.append({**candidate, 'review_row_origin': review_row_origin})

    if not preserved_rows:
      return payload

    merged_rows = current_rows + preserved_rows
    payload['sandbox_candidates_extended'] = merged_rows
    payload['sandbox_extended_count'] = len(merged_rows)
    payload['candidates'] = merged_rows
    payload['candidate_count'] = len(merged_rows)
    if not str(payload.get('resting_connection_posture') or '').strip():
      payload['resting_connection_posture'] = 'candidate_review_hold'
    _set_projection_contract(
      payload,
      projection_source='saved_set_repeat_scan_continuity',
      projection_reason='Saved prior rows blended with current scan rows for continuity-only review context.',
      recovery_mode=True,
    )
    return payload

  def _merge_saved_candidate_rows_for_processing_scan(payload: JSONDict) -> JSONDict:
    scan_runtime = payload.get('scan_runtime') if isinstance(payload.get('scan_runtime'), dict) else {}
    execution_state = payload.get('execution_state') if isinstance(payload.get('execution_state'), dict) else {}
    runtime_processing = str(scan_runtime.get('status') or '').strip().lower() in {'processing', 'canceling'}
    execution_processing = (
      str(execution_state.get('kind') or '').strip().lower() == 'processing'
      and str(execution_state.get('action') or '').strip().lower() == 'scan'
    )
    execution_run_processing = (
      str(execution_state.get('kind') or '').strip().lower() == 'processing'
      and str(execution_state.get('action') or '').strip().lower() == 'run'
    )
    scan_snapshot = _scan_runtime_snapshot()
    snapshot_processing = str(scan_snapshot.get('status') or '').strip().lower() in {'processing', 'canceling'}
    _automation_run_active = (
      bool(automation_overlay_state.get('enabled'))
      and not bool(automation_overlay_state.get('paused'))
      and execution_run_processing
    )
    if not runtime_processing and not execution_processing and not snapshot_processing and not _automation_run_active:
      return payload
    if str(scan_snapshot.get('stage') or '').strip().lower() == 'retry_wait':
      _automation_active = bool(automation_overlay_state.get('enabled')) and not bool(automation_overlay_state.get('paused'))
      if not _automation_active:
        return payload
    if _payload_has_review_candidates(payload):
      return payload
    if not _payload_accepts_review_selection(payload):
      return payload

    saved_candidates = [
      dict(candidate)
      for candidate in review_selection_state.get('saved_candidates', [])
      if isinstance(candidate, dict)
    ]
    if not saved_candidates:
      return payload

    payload['sandbox_candidates_extended'] = [
      {**candidate, 'review_row_origin': _saved_prior_review_row_origin(candidate)}
      for candidate in saved_candidates
      if _saved_prior_review_row_origin(candidate) != 'saved_prior_hidden_expired'
    ]
    payload['sandbox_extended_count'] = len(payload['sandbox_candidates_extended'])
    payload['candidates'] = list(payload['sandbox_candidates_extended'])
    payload['candidate_count'] = len(payload['sandbox_candidates_extended'])
    if not str(payload.get('resting_connection_posture') or '').strip():
      payload['resting_connection_posture'] = 'candidate_review_hold'
    _set_projection_contract(
      payload,
      projection_source='saved_set_processing_scan_recovery',
      projection_reason='Saved set projected while Find candidates is processing to avoid implicit snapshot hydration.',
      recovery_mode=True,
    )
    _emit_projection_recovery_event(payload, projection_source='saved_set_processing_scan_recovery')
    return payload

  def _augment_with_key_management(action_name: str, payload: JSONDict) -> JSONDict:
    merged_payload = _merge_preserved_review_hold_payload(action_name, payload)
    merged_payload = _merge_saved_candidate_rows_for_processing_scan(merged_payload)
    if str(action_name or '').strip().lower() == 'scan':
      merged_payload = _merge_saved_candidate_rows_for_repeat_scan(merged_payload)
    augmented = _augment_shell_payload(
      action_name,
      merged_payload,
      env_override=env_override,
      subaccount_override=subaccount_override,
      runtime_overlay=runtime_overlay_state,
      working_default_values=_runtime_working_default_values(
        env_override=env_override,
        subaccount_override=subaccount_override,
      ),
      working_default_state=runtime_working_default_state,
      working_default_sources=runtime_working_default_sources,
      analysis_recalculation=_analysis_recalculation_payload(),
      durable_overlay=context_overlay_state,
      durable_funds_cache=_header_funds_cache,
      operator_review_session_id=str(review_selection_state.get('persisted_lane_session_id') or '').strip() or None,
    )
    augmented['key_management'] = _key_management_payload(augmented)
    augmented['data_management'] = _data_management_payload(augmented)
    augmented['session_overlay'] = _session_overlay_payload(
      augmented,
      env_override=None,
      subaccount_override=None,
    )
    _apply_scan_runtime_payload(action_name, augmented)
    _refresh_review_selection_projection(augmented)
    _attach_scheduler_snapshot(
      augmented,
      action_name=action_name,
      source=f'{action_name}_projection',
      decision='noop',
      owner_reason='payload_projection',
    )
    _stage_data = _fetch_stage_columns(augmented)
    augmented['_stage_columns'] = _stage_data['stage_columns']
    augmented['_in_flight_candidate_count'] = _stage_data['in_flight_candidate_count']
    augmented['_total_stage_candidate_count'] = _stage_data.get('total_stage_candidate_count', _stage_data['in_flight_candidate_count'])
    augmented['_active_stage_candidate_count'] = _stage_data.get('active_stage_candidate_count', _stage_data['in_flight_candidate_count'])
    augmented['pair_monitor'] = _build_pair_monitor_payload(augmented)
    augmented['live_interaction'] = dict(augmented['pair_monitor'].get('live_interaction', {}))
    _apply_projection_contract_defaults(augmented, action_name=action_name)
    return augmented

  def _terminal_scan_refresh_payload(
    scan_snapshot: JSONDict,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict | None:
    if str(scan_snapshot.get('status') or '').lower() not in {'completed', 'failed', 'canceled'}:
      return None
    if not isinstance(scan_snapshot.get('result_payload'), dict):
      return None

    payload = dict(scan_snapshot['result_payload'])
    payload['workflow_source'] = 'terminal_scan_replay'
    candidate_rows = list(payload.get('candidates') or [])
    extended_rows = list(payload.get('sandbox_candidates_extended') or [])
    payload['candidate_count'] = max(int(payload.get('candidate_count', 0) or 0), len(candidate_rows))
    payload['sandbox_extended_count'] = max(int(payload.get('sandbox_extended_count', 0) or 0), len(extended_rows))
    if payload['candidate_count'] <= 0 and payload['sandbox_extended_count'] <= 0:
      replay_message = str(payload.get('message') or '').strip().lower()
      if replay_message and 'found candidates' in replay_message:
        payload['message'] = _empty_scan_operator_message(payload)
      replay_next_action = str(payload.get('next_action') or '').strip().lower()
      if replay_next_action and 'review candidates in pairs' in replay_next_action:
        payload['next_action'] = _empty_scan_operator_message(payload)
    if int(payload.get('candidate_count', 0) or 0) > 0 or int(payload.get('sandbox_extended_count', 0) or 0) > 0:
      payload['resting_connection_posture'] = 'candidate_review_hold'
    else:
      payload['resting_connection_posture'] = 'empty_scan_result_hold'
    _set_projection_contract(
      payload,
      projection_source='terminal_scan_replay',
      projection_reason='Terminal scan replay restored bounded retained scan evidence.',
      recovery_mode=True,
    )
    if 'settings' not in payload:
      active_settings = _effective_shell_settings(env_override, subaccount_override)
      with _private_key_file_env_overlay(str(key_management_state.get('overlay_key_path') or ''), lock=overlay_lock):
        payload['settings'] = _load_shell_settings_context(
          env_override=env_override,
          subaccount_override=subaccount_override,
          settings_override=active_settings,
        )[0]
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else None
    if not isinstance(settings_payload, dict) or not bool(settings_payload.get('settings_ready')):
      try:
        bootstrap_seed = _call_with_key_overlay(
          resolved_services.bootstrap,
          settings=_effective_shell_settings(env_override, subaccount_override),
          env_override=env_override,
          subaccount_override=subaccount_override,
          current_operating_session_id=str(review_selection_state.get('persisted_lane_session_id') or '').strip() or None,
        )
      except Exception:
        bootstrap_seed = {}
      seed_settings = bootstrap_seed.get('settings') if isinstance(bootstrap_seed.get('settings'), dict) else None
      if isinstance(seed_settings, dict) and bool(seed_settings.get('settings_ready')):
        payload['settings'] = dict(seed_settings)
      if not isinstance(payload.get('report'), dict):
        seed_report = bootstrap_seed.get('report') if isinstance(bootstrap_seed.get('report'), dict) else None
        if isinstance(seed_report, dict):
          payload['report'] = dict(seed_report)
    if isinstance(payload.get('settings'), dict):
      payload['credential_posture'] = _build_credential_posture_payload(payload['settings'])
    _apply_websocket_runtime_projection(
      payload,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    _attach_connection_posture(
      payload,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    # STUCK-2 Lane A: the replay reuses the frozen scan-result `report` block, whose
    # funds_posture / connection_state / latest_heartbeat are stuck at scan-termination
    # time. On a replay-dominant run this strands the STRICT submit gate — money_authorized
    # closes because the replayed report carries no LIVE funds block (available_funds None),
    # even though the FH heartbeat is fresh (packet T084228Z: 77.7% strict-unavailable) —
    # and freezes the handshake/connection cards. Refresh the report's live-truth fields
    # from the live sources (DB-only/cheap, same path F1 uses); the replayed CANDIDATES
    # stay. Fail-closed: with no fresh funds heartbeat the posture is truthfully
    # stale/unavailable (the gate stays closed), never fabricated fresh.
    _replay_report = payload.get('report') if isinstance(payload.get('report'), dict) else None
    if _replay_report is not None:
      _replay_settings = payload.get('settings') if isinstance(payload.get('settings'), dict) else {}
      _replay_db = str(_replay_settings.get('state_db_path') or '').strip()
      _replay_lane = str(_replay_settings.get('operation_lane') or '').strip().lower()
      if _replay_db and _replay_lane in {'sandbox', 'live'}:
        _replay_conn = None
        try:
          _replay_conn = open_database(_replay_db)
          _funds_hb = _latest_funds_heartbeat_payload(_replay_conn, operation_lane=_replay_lane)
          _any_hb = _latest_heartbeat_payload(_replay_conn, operation_lane=_replay_lane)
          _replay_report['funds_posture'] = _project_funds_posture(
            latest_heartbeat_payload=_funds_hb or _any_hb
          )
          if isinstance(_any_hb, dict):
            _replay_report['latest_heartbeat'] = _any_hb
        except Exception:
          pass
        finally:
          if _replay_conn is not None:
            try:
              _replay_conn.close()
            except Exception:
              pass
      # Carry the freshly-projected live connection_state (set just above) into the
      # report block the execution panel reads, so the handshake/green-glow reflect truth.
      if isinstance(payload.get('connection_state'), dict):
        _replay_report['connection_state'] = dict(payload['connection_state'])
    _persist_candidate_review_snapshot(payload, action_name='scan')
    payload['workflow'] = _follow_on_workflow('scan', payload)
    merged_payload = _merge_preserved_review_hold_payload('scan', payload)
    merged_payload = _merge_saved_candidate_rows_for_processing_scan(merged_payload)
    merged_payload = _merge_saved_candidate_rows_for_repeat_scan(merged_payload)
    augmented = _augment_shell_payload(
      'scan',
      merged_payload,
      env_override=env_override,
      subaccount_override=subaccount_override,
      runtime_overlay=runtime_overlay_state,
      working_default_values=_runtime_working_default_values(
        env_override=env_override,
        subaccount_override=subaccount_override,
      ),
      working_default_state=runtime_working_default_state,
      working_default_sources=runtime_working_default_sources,
      analysis_recalculation=_analysis_recalculation_payload(),
      durable_overlay=context_overlay_state,
      durable_funds_cache=_header_funds_cache,
      operator_review_session_id=str(review_selection_state.get('persisted_lane_session_id') or '').strip() or None,
    )
    if (
      (
        bool(scan_snapshot.get('mode_selected'))
        or _payload_has_review_candidates(payload)
      )
      and (payload.get('candidate_count', 0) or payload.get('sandbox_extended_count', 0))
    ):
      candidate_rows = list(payload.get('candidates') or [])
      extended_rows = list(payload.get('sandbox_candidates_extended') or candidate_rows)
      augmented['candidates'] = candidate_rows or extended_rows
      augmented['sandbox_candidates_extended'] = extended_rows or candidate_rows
      augmented['candidate_count'] = max(int(payload.get('candidate_count', 0) or 0), len(augmented['candidates']))
      augmented['sandbox_extended_count'] = max(int(payload.get('sandbox_extended_count', 0) or 0), len(augmented['sandbox_candidates_extended']))
      augmented['resting_connection_posture'] = 'candidate_review_hold'
      augmented['pair_monitor'] = _build_pair_monitor_payload(augmented)
      _replay_settings = augmented.get('settings') if isinstance(augmented.get('settings'), dict) else {}
      _replay_db_path = str(_replay_settings.get('state_db_path') or '').strip()
      _replay_pm = augmented.get('pair_monitor') if isinstance(augmented.get('pair_monitor'), dict) else {}
      if not _replay_db_path and int(_replay_pm.get('candidate_count', 0) or 0) == 0:
        _fallback_rows = [
          _candidate_review_row_with_identity(row, index)
          for index, row in enumerate(augmented['sandbox_candidates_extended'] or augmented['candidates'])
          if isinstance(row, dict)
        ]
        if _fallback_rows:
          _replay_pm['candidate_rows'] = _fallback_rows
          _replay_pm['candidate_count'] = len(_fallback_rows)
          augmented['pair_monitor'] = _replay_pm
    augmented['key_management'] = _key_management_payload(augmented)
    augmented['data_management'] = _data_management_payload(augmented)
    augmented['session_overlay'] = _session_overlay_payload(
      augmented,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    augmented['connection_posture'] = _build_connection_posture_payload(
      augmented,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    _apply_scan_runtime_payload('scan', augmented)
    if int(augmented.get('candidate_count', 0) or 0) > 0 or int(augmented.get('sandbox_extended_count', 0) or 0) > 0:
      _refresh_review_selection_projection(augmented)
      if str((augmented.get('workflow') or {}).get('recommended_step') or '').strip() == 'scan':
        augmented['workflow'] = _candidate_review_workflow('review_hold_candidates_available', working_count=0)
    report_payload = augmented.get('report') if isinstance(augmented.get('report'), dict) else {}
    terminal_status = str(scan_snapshot.get('status') or '').lower()
    terminal_result = scan_snapshot.get('result_payload') if isinstance(scan_snapshot.get('result_payload'), dict) else {}
    terminal_reason = str(terminal_result.get('reason') or '').strip().lower()
    if terminal_status in {'failed', 'canceled'} and terminal_reason in {'scan_failed', 'stage_timeout', 'scan_canceled'}:
      retry_message = str(terminal_result.get('message') or 'Find candidates did not complete and should be retried.')
      retry_next_action = str(
        terminal_result.get('next_action')
        or ('Find candidates when you are ready.' if terminal_reason == 'scan_canceled' else 'Find candidates again when you are ready.')
      )
      augmented['workflow'] = _workflow_state(
        'scan',
        auto_sequence=[],
        headline='Find candidates requires operator retry before execution can continue.',
        operator_message=retry_message,
        step_kind='review',
        can_run_next_step=True,
        next_actionable_step='scan',
        focus_target='boundary-panel',
        focus_tone='focus-warn',
        deck_view='operator',
        button_emphasis_tone='warn',
      )
      augmented['next_action'] = retry_next_action
    report_payload['latest_scan_terminal'] = {
      'status': terminal_status,
      'scan_session_id': str(scan_snapshot.get('scan_session_id') or ''),
      'lane_session_id': str(scan_snapshot.get('lane_session_id') or ''),
      'operation_lane': str(scan_snapshot.get('operation_lane') or ''),
      'recorded_at_utc': scan_snapshot.get('completed_at_utc') or scan_snapshot.get('last_progress_at_utc') or scan_snapshot.get('started_at_utc'),
      'result_reason': terminal_reason,
    }
    augmented['workflow_source'] = 'terminal_scan_replay'
    augmented['report'] = report_payload
    augmented['connection_posture'] = _build_connection_posture_payload(
      augmented,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    _refresh_review_selection_projection(augmented)
    _apply_orchestrator_highlight_envelope('scan', augmented)
    _replay_review_selection = (
      augmented.get('review_selection') if isinstance(augmented.get('review_selection'), dict) else {}
    )
    _replay_submit_ready = (
      str(_replay_review_selection.get('state_id') or '').strip().lower() == 'review_hold_saved_selection_locked'
      and bool(_replay_review_selection.get('submit_ready'))
    )
    _replay_saved_set_retired_by_submit = _current_saved_set_consumed_by_submit_terminal()
    if (
      bool(scan_snapshot.get('mode_selected'))
      and not _replay_submit_ready
      and not _replay_saved_set_retired_by_submit
      and (
        int(payload.get('candidate_count', 0) or 0) > 0
        or int(payload.get('sandbox_extended_count', 0) or 0) > 0
        or int(augmented.get('candidate_count', 0) or 0) > 0
        or int(augmented.get('sandbox_extended_count', 0) or 0) > 0
        or bool(((augmented.get('pair_monitor') or {}).get('candidate_rows') or []))
      )
    ):
      augmented['workflow'] = _candidate_review_workflow('review_hold_candidates_available', working_count=0)
    elif (
      _replay_saved_set_retired_by_submit
      and bool(automation_overlay_state.get('enabled'))
      and not bool(automation_overlay_state.get('paused'))
    ):
      augmented['_automation_posture'] = dict(automation_overlay_state)
      automation_workflow = _automation_follow_on_workflow(augmented)
      if automation_workflow is not None:
        augmented['workflow'] = automation_workflow
    _set_projection_contract(
      augmented,
      projection_source='terminal_scan_replay',
      projection_reason='Terminal scan replay restored bounded retained scan evidence.',
      recovery_mode=True,
    )
    _emit_projection_recovery_event(augmented, projection_source='terminal_scan_replay')
    return augmented

  def _bootstrap_replay_restore_availability_payload(
    scan_snapshot: JSONDict,
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> JSONDict:
    if not _lane_boundary_mode_selected(
      env_override=env_override,
      subaccount_override=subaccount_override,
    ):
      return {
        'available': False,
        'action': 'replay_restore',
        'message': 'Replay restore is unavailable until sandbox or live mode is selected.',
        'latest_terminal': None,
      }
    terminal_status = str(scan_snapshot.get('status') or '').strip().lower()
    terminal_result = scan_snapshot.get('result_payload') if isinstance(scan_snapshot.get('result_payload'), dict) else {}
    if not _terminal_scan_replay_available(scan_snapshot):
      return {
        'available': False,
        'action': 'replay_restore',
        'message': 'No prior terminal scan replay is currently available.',
        'latest_terminal': None,
      }
    return {
      'available': True,
      'action': 'replay_restore',
      'message': 'A prior terminal scan result is available and can be restored explicitly.',
      'latest_terminal': {
        'status': terminal_status,
        'scan_session_id': str(scan_snapshot.get('scan_session_id') or ''),
        'lane_session_id': str(scan_snapshot.get('lane_session_id') or ''),
        'operation_lane': str(scan_snapshot.get('operation_lane') or ''),
        'recorded_at_utc': scan_snapshot.get('completed_at_utc') or scan_snapshot.get('last_progress_at_utc') or scan_snapshot.get('started_at_utc'),
        'result_reason': str(terminal_result.get('reason') or '').strip().lower(),
      },
    }

  def _terminal_scan_replay_available(scan_snapshot: JSONDict) -> bool:
    terminal_status = str(scan_snapshot.get('status') or '').strip().lower()
    terminal_result = scan_snapshot.get('result_payload') if isinstance(scan_snapshot.get('result_payload'), dict) else {}
    return (
      terminal_status == 'completed'
      and isinstance(terminal_result, dict)
      and (
        bool(scan_snapshot.get('replay_candidate_source_available'))
        or _payload_has_review_candidates(cast(JSONDict, terminal_result))
      )
    )

  def _refresh_shell_payload(
    action_name: str,
    *,
    env_override: str | None,
    subaccount_override: int | None,
    allow_terminal_replay: bool = False,
    replay_requested_by: str | None = None,
  ) -> JSONDict:
    scan_snapshot = _scan_runtime_snapshot()
    # S1 diagnostic instrumentation (PLAN-POLYVENTURE-LIVE-AUTO-STABILITY-20260615):
    # attribute dashboard-rebuild latency to fast-path vs full-path and to the
    # bootstrap service call vs post-processing, under concurrent-scan conditions.
    _rebuild_t0 = time.monotonic()
    _LAST_CANONICAL_CANDIDATE_QUERY_STATUS.update({'ok': True, 'reason': '', 'elapsed_ms': 0.0})
    _rebuild_bootstrap_service_ms: float | None = None
    _rebuild_replay_build_ms: float | None = None
    _rebuild_breakdown_capture: JSONDict | None = None
    _rebuild_slow_emit_ms = 1000.0  # emit a runtime event for any rebuild at/over this duration
    _scan_status_at_rebuild = str(scan_snapshot.get('status') or '').strip().lower()
    _scan_stage_at_rebuild = str(scan_snapshot.get('stage') or '').strip().lower()
    _scan_active_at_rebuild = (
      _scan_status_at_rebuild in {'processing', 'canceling'}
      or _scan_stage_at_rebuild == 'retry_wait'
    )

    def _attach_rebuild_timing(target: Any, *, path: str) -> Any:
      if isinstance(target, dict):
        _attach_scheduler_snapshot(
          target,
          action_name=action_name,
          source='rebuild_projection',
          decision='degraded_projection' if str((_LAST_CANONICAL_CANDIDATE_QUERY_STATUS or {}).get('reason') or '') == 'rebuild_db_read_busy' else 'noop',
          owner_reason=str((_LAST_CANONICAL_CANDIDATE_QUERY_STATUS or {}).get('reason') or 'payload_projection'),
        )
        total_ms = round((time.monotonic() - _rebuild_t0) * 1000.0, 1)
        db_read_wait_ms = (
          _LAST_CANONICAL_CANDIDATE_QUERY_STATUS.get('elapsed_ms')
          if isinstance(_LAST_CANONICAL_CANDIDATE_QUERY_STATUS, dict)
          else None
        )
        known_ms = sum(
          float(value)
          for value in (
            _rebuild_bootstrap_service_ms,
            _rebuild_replay_build_ms,
            (_rebuild_breakdown_capture or {}).get('report_ms') if _rebuild_breakdown_capture else None,
            (_rebuild_breakdown_capture or {}).get('reconcile_ms') if _rebuild_breakdown_capture else None,
            (_rebuild_breakdown_capture or {}).get('funds_refresh_ms') if _rebuild_breakdown_capture else None,
            db_read_wait_ms,
          )
          if isinstance(value, (int, float))
        )
        timing: JSONDict = {
          'action': str(action_name or ''),
          'path': path,
          'scan_active': bool(_scan_active_at_rebuild),
          'scan_status': _scan_status_at_rebuild or None,
          'scan_stage': _scan_stage_at_rebuild or None,
          'total_ms': total_ms,
          'bootstrap_service_ms': _rebuild_bootstrap_service_ms,
          'replay_build_ms': _rebuild_replay_build_ms,
          'post_service_ms': (
            round(total_ms - _rebuild_bootstrap_service_ms, 1)
            if _rebuild_bootstrap_service_ms is not None else None
          ),
          # S2 split: report_ms / reconcile_ms / funds_refresh_ms — API vs DB attribution.
          'report_ms': (_rebuild_breakdown_capture or {}).get('report_ms') if _rebuild_breakdown_capture else None,
          'reconcile_ms': (_rebuild_breakdown_capture or {}).get('reconcile_ms') if _rebuild_breakdown_capture else None,
          'funds_refresh_ms': (_rebuild_breakdown_capture or {}).get('funds_refresh_ms') if _rebuild_breakdown_capture else None,
          'db_read_wait_ms': db_read_wait_ms,
          'db_write_wait_ms': None,
          'unattributed_ms': round(max(0.0, total_ms - known_ms), 1),
        }
        target['rebuild_timing'] = timing
        if str((_LAST_CANONICAL_CANDIDATE_QUERY_STATUS or {}).get('reason') or '') == 'rebuild_db_read_busy':
          target['rebuild_degraded'] = True
          target['reason'] = 'rebuild_db_read_busy'
          target['next_action'] = 'Wait for the active scan write to finish, then refresh.'
          _emit_rebuild_db_read_busy_event(target, timing)
        _stage_data = _fetch_stage_columns(target)
        target['_stage_columns'] = _stage_data['stage_columns']
        target['_in_flight_candidate_count'] = _stage_data['in_flight_candidate_count']
        target['_total_stage_candidate_count'] = _stage_data.get('total_stage_candidate_count', _stage_data['in_flight_candidate_count'])
        target['_active_stage_candidate_count'] = _stage_data.get('active_stage_candidate_count', _stage_data['in_flight_candidate_count'])
        target['pair_monitor'] = _build_pair_monitor_payload(target)
        target['live_interaction'] = dict(target['pair_monitor'].get('live_interaction', {}))
        # Emit out-of-band for every full-path rebuild and for any slow rebuild
        # (including the slow replay/fast-path rebuilds that exceed the monitor probe
        # window and so never appear in the in-band projection). Fast rebuilds under
        # the threshold are not written, to avoid perturbing DB contention.
        if path == 'full' or total_ms >= _rebuild_slow_emit_ms:
          _emit_rebuild_timing_event(target, timing)
      return target

    normalized_action = str(action_name or '').strip().lower()
    replay_allowed = bool(allow_terminal_replay or normalized_action == 'scan')
    scan_terminal_status = str(scan_snapshot.get('status') or '').strip().lower()
    scan_terminal_payload = scan_snapshot.get('result_payload') if isinstance(scan_snapshot.get('result_payload'), dict) else {}
    transient_terminal_replay_allowed = (
      normalized_action == 'bootstrap'
      and _terminal_scan_replay_available(scan_snapshot)
      and (
        bool(scan_snapshot.get('mode_selected'))
        or _lane_boundary_mode_selected(
          env_override=env_override,
          subaccount_override=subaccount_override,
          settings_override=_effective_shell_settings(env_override, subaccount_override),
        )
      )
      and not bool(scan_snapshot.get('hydrated_from_persistence'))
    )
    replay_allowed = bool(replay_allowed or transient_terminal_replay_allowed)
    if replay_allowed and normalized_action in {'bootstrap', 'scan'} and _terminal_scan_replay_available(scan_snapshot):
      _replay_t0 = time.monotonic()
      terminal_payload = _terminal_scan_refresh_payload(
        scan_snapshot,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      _rebuild_replay_build_ms = round((time.monotonic() - _replay_t0) * 1000.0, 1)
      if terminal_payload is not None:
        if replay_requested_by:
          terminal_payload['replay_restore'] = {
            'available': True,
            'active': True,
            'requested_by': str(replay_requested_by),
          }
        return _attach_rebuild_timing(terminal_payload, path='replay_fast')

    active_settings = _effective_shell_settings(env_override, subaccount_override)
    _svc_t0 = time.monotonic()
    payload = _call_with_key_overlay(
      resolved_services.bootstrap,
      settings=active_settings,
      env_override=env_override,
      subaccount_override=subaccount_override,
      suppress_live_funds_refresh=_scan_active_at_rebuild,
      current_operating_session_id=str(review_selection_state.get('persisted_lane_session_id') or '').strip() or None,
    )
    _rebuild_bootstrap_service_ms = round((time.monotonic() - _svc_t0) * 1000.0, 1)
    if isinstance(payload.get('rebuild_breakdown'), dict):
      _rebuild_breakdown_capture = cast(JSONDict, payload.get('rebuild_breakdown'))
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else None
    if settings_payload is not None:
      payload['credential_posture'] = _build_credential_posture_payload(settings_payload)
      _apply_websocket_runtime_projection(
        payload,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      report_payload = payload.get('report') if isinstance(payload.get('report'), dict) else None
      _ws_hb = (report_payload or {}).get('latest_heartbeat')
      if isinstance(_ws_hb, dict):
        payload['funds_posture'] = _project_funds_posture(latest_heartbeat_payload=_ws_hb)
      reconcile_payload = payload.get('reconcile') if isinstance(payload.get('reconcile'), dict) else None
      _attach_connection_posture(
        payload,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      _persist_candidate_review_snapshot(payload, action_name=action_name)
      _p2e_run_id = str(review_selection_state.get('persisted_run_id') or '').strip()
      if _p2e_run_id:
        if isinstance(payload.get('review_selection'), dict):
          payload['review_selection']['persisted_run_id'] = _p2e_run_id
        else:
          payload['review_selection'] = {'persisted_run_id': _p2e_run_id}
      _n2b_saved_set_id = str(review_selection_state.get('saved_set_id') or '').strip()
      _n2b_run_id = str(review_selection_state.get('persisted_run_id') or '').strip()
      _n2b_db_path = str(getattr(active_settings, 'state_db_path', None) or '').strip()
      if _n2b_saved_set_id and _n2b_run_id and _n2b_db_path:
        try:
          _n2b_conn = open_database(_n2b_db_path)
          with _n2b_conn:
            _sync_saved_set_candidate_lifecycle_from_execution(
              _n2b_conn,
              saved_set_id=_n2b_saved_set_id,
              run_id=_n2b_run_id,
            )
        except Exception:
          pass
      payload['workflow'] = _bootstrap_workflow(
        bool(settings_payload.get('settings_ready')),
        report_payload,
        reconcile_payload,
        next_action=str(payload.get('next_action') or 'Use the recommended next step in the control deck.'),
        settings_payload=settings_payload,
        mode_selected=bool((payload.get('connection_posture') or {}).get('mode_selected')),
        mode_change_hold_state=mode_change_guidance_state,
        context_overlay_state=context_overlay_state,
      )
    _p2e_lsid = str(review_selection_state.get('persisted_lane_session_id') or '').strip()
    if _p2e_lsid:
      if isinstance(payload.get('review_selection'), dict):
        payload['review_selection']['persisted_lane_session_id'] = _p2e_lsid
      else:
        payload['review_selection'] = {'persisted_lane_session_id': _p2e_lsid}
    merged_payload = _merge_preserved_review_hold_payload(action_name, payload)
    merged_payload = _merge_saved_candidate_rows_for_processing_scan(merged_payload)
    if str(action_name or '').strip().lower() == 'scan':
      merged_payload = _merge_saved_candidate_rows_for_repeat_scan(merged_payload)
    augmented = _augment_shell_payload(
      action_name,
      merged_payload,
      env_override=env_override,
      subaccount_override=subaccount_override,
      runtime_overlay=runtime_overlay_state,
      working_default_values=_runtime_working_default_values(
        env_override=env_override,
        subaccount_override=subaccount_override,
      ),
      working_default_state=runtime_working_default_state,
      working_default_sources=runtime_working_default_sources,
      analysis_recalculation=_analysis_recalculation_payload(),
      durable_overlay=context_overlay_state,
      durable_funds_cache=_header_funds_cache,
      operator_review_session_id=str(review_selection_state.get('persisted_lane_session_id') or '').strip() or None,
    )
    augmented['key_management'] = _key_management_payload(augmented)
    augmented['data_management'] = _data_management_payload(augmented)
    augmented['session_overlay'] = _session_overlay_payload(
      augmented,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    augmented['connection_posture'] = _build_connection_posture_payload(
      augmented,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    if normalized_action == 'bootstrap':
      augmented['replay_restore'] = _bootstrap_replay_restore_availability_payload(
        scan_snapshot,
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
    _apply_scan_runtime_payload(action_name, augmented)
    _refresh_review_selection_projection(augmented)
    _apply_orchestrator_highlight_envelope(action_name, augmented)
    augmented['workflow_source'] = 'bootstrap_workflow'
    _apply_projection_contract_defaults(augmented, action_name=action_name)
    return _attach_rebuild_timing(augmented, path='full')

  def _refresh_state_payload(
    action_name: str,
    *,
    env_override: str | None,
    subaccount_override: int | None,
    successful_transition: bool = False,
  ) -> JSONDict:
    if str(action_name or '').strip().lower() == 'scan':
      terminal_payload = _terminal_scan_refresh_payload(
        _scan_runtime_snapshot(),
        env_override=env_override,
        subaccount_override=subaccount_override,
      )
      if terminal_payload is not None:
        return terminal_payload

    active_settings = _effective_shell_settings(env_override, subaccount_override)
    with _private_key_file_env_overlay(str(key_management_state.get('overlay_key_path') or ''), lock=overlay_lock):
      settings_payload, settings_error = _load_shell_settings_context(
        env_override=env_override,
        subaccount_override=subaccount_override,
        settings_override=active_settings,
      )
    payload_credential_posture = _build_credential_posture_payload(settings_payload)

    websocket_management_actions = {
      'data_management',
      'websocket_management',
      'detect_available_datapacks',
      'select_datapack',
      'load_datapack',
      'load_sandbox_datapack',
      'load_live_datapack',
      'clear_loaded_datapack',
      'load_sandbox_websocket',
      'load_live_websocket',
      'clear_all_websocket_urls',
    }
    if settings_error is not None:
      if successful_transition or action_name in websocket_management_actions or _is_non_error_readiness_waiting_state(settings_payload):
        payload = {
          'decision': 'planned',
          'reason': 'planned',
          'message': 'Local session state updated.',
          'next_action': 'Review readiness and continue with the recommended next step.',
          'settings': settings_payload,
          'credential_posture': payload_credential_posture,
          'diagnostics_governance_context': _diagnostics_governance_context(),
          'report': None,
          'reconcile': None,
        }
      else:
        payload = {
          **_action_failure_payload(action_name, settings_error),
          'settings': settings_payload,
          'credential_posture': payload_credential_posture,
          'diagnostics_governance_context': _diagnostics_governance_context(),
          'report': None,
          'reconcile': None,
        }
    else:
      payload = {
        'decision': 'planned',
        'reason': 'planned',
        'message': 'Local session state updated.',
        'next_action': 'Review readiness and continue with the recommended next step.',
        'settings': settings_payload,
        'credential_posture': payload_credential_posture,
        'diagnostics_governance_context': _diagnostics_governance_context(),
        'report': None,
        'reconcile': None,
      }
    if successful_transition:
      payload['transition_outcome'] = 'success'
    _attach_connection_posture(
      payload,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    if str(action_name or '').strip().lower() == 'automation':
      payload['_automation_posture'] = dict(automation_overlay_state)
    if (
      active_settings is not None
      and str(getattr(active_settings, 'operation_lane', None) or '').strip().lower() == 'live'
    ):
      try:
        _hb_conn = open_database(getattr(active_settings, 'state_db_path'))
        _hb = _latest_heartbeat_payload(_hb_conn, operation_lane='live')
        payload['funds_posture'] = _project_funds_posture(latest_heartbeat_payload=_hb)
      except Exception:
        pass
    payload['workflow'] = _follow_on_workflow(action_name, payload)
    merged_payload = _merge_preserved_review_hold_payload(action_name, payload)
    merged_payload = _merge_saved_candidate_rows_for_processing_scan(merged_payload)
    if str(action_name or '').strip().lower() == 'scan':
      merged_payload = _merge_saved_candidate_rows_for_repeat_scan(merged_payload)
    augmented = _augment_shell_payload(
      action_name,
      merged_payload,
      env_override=env_override,
      subaccount_override=subaccount_override,
      runtime_overlay=runtime_overlay_state,
      working_default_values=_runtime_working_default_values(
        env_override=env_override,
        subaccount_override=subaccount_override,
      ),
      working_default_state=runtime_working_default_state,
      working_default_sources=runtime_working_default_sources,
      analysis_recalculation=_analysis_recalculation_payload(),
      durable_overlay=context_overlay_state,
      durable_funds_cache=_header_funds_cache,
      operator_review_session_id=str(review_selection_state.get('persisted_lane_session_id') or '').strip() or None,
    )
    augmented['key_management'] = _key_management_payload(augmented)
    augmented['data_management'] = _data_management_payload(augmented)
    augmented['session_overlay'] = _session_overlay_payload(
      augmented,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    augmented['connection_posture'] = _build_connection_posture_payload(
      augmented,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    augmented['operator_notifications'] = _operator_notifications_payload(
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    _apply_scan_runtime_payload(action_name, augmented)
    _refresh_review_selection_projection(augmented)
    _attach_scheduler_snapshot(
      augmented,
      action_name=action_name,
      source='state_projection',
      settings=active_settings,
      decision='noop',
      owner_reason='payload_projection',
    )
    _stage_data = _fetch_stage_columns(augmented)
    augmented['_stage_columns'] = _stage_data['stage_columns']
    augmented['_in_flight_candidate_count'] = _stage_data['in_flight_candidate_count']
    augmented['_total_stage_candidate_count'] = _stage_data.get('total_stage_candidate_count', _stage_data['in_flight_candidate_count'])
    augmented['_active_stage_candidate_count'] = _stage_data.get('active_stage_candidate_count', _stage_data['in_flight_candidate_count'])
    augmented['pair_monitor'] = _build_pair_monitor_payload(augmented)
    augmented['live_interaction'] = dict(augmented['pair_monitor'].get('live_interaction', {}))
    _apply_orchestrator_highlight_envelope(action_name, augmented)
    _apply_projection_contract_defaults(augmented, action_name=action_name)
    return augmented

  def _shell_resting_state_id(
    *,
    env_override: str | None,
    subaccount_override: int | None,
  ) -> str:
    active_settings = _effective_shell_settings(env_override, subaccount_override)
    payload = _call_with_key_overlay(
      resolved_services.bootstrap,
      settings=active_settings,
      env_override=env_override,
      subaccount_override=subaccount_override,
      current_operating_session_id=str(review_selection_state.get('persisted_lane_session_id') or '').strip() or None,
    )
    settings_payload = payload.get('settings') if isinstance(payload.get('settings'), dict) else None
    if not isinstance(settings_payload, dict):
      with _private_key_file_env_overlay(str(key_management_state.get('overlay_key_path') or ''), lock=overlay_lock):
        settings_payload, _ = _load_shell_settings_context(
          env_override=env_override,
          subaccount_override=subaccount_override,
          settings_override=active_settings,
        )
    else:
      settings_payload = dict(settings_payload)
    return _resting_state_id(settings_payload)

  def _mode_change_no_go_payload(
    *,
    reason: str,
    message: str,
    next_action: str,
    env_override: str | None,
    subaccount_override: int | None,
    lane_override: str | None = None,
    prev_resting_state_id: str | None = None,
  ) -> JSONDict:
    requested_lane = _normalize_key_lane(lane_override)
    active_settings = (
      _settings_for_lane(requested_lane, env_override=env_override, subaccount_override=subaccount_override)
      if requested_lane is not None
      else _effective_shell_settings(env_override, subaccount_override)
    )
    overlay_key_path = str(getattr(active_settings, 'private_key_file', None) or key_management_state.get('overlay_key_path') or '')
    with _private_key_file_env_overlay(overlay_key_path, lock=overlay_lock):
      settings_payload, _ = _load_shell_settings_context(
        env_override=env_override,
        subaccount_override=subaccount_override,
        settings_override=active_settings,
      )
    payload: JSONDict = {
      'decision': 'no-go',
      'reason': reason,
      'message': message,
      'next_action': next_action,
      'prev_resting_state_id': str(prev_resting_state_id or _resting_state_id(settings_payload) or 'unknown'),
      'settings': settings_payload,
      'credential_posture': _build_credential_posture_payload(settings_payload),
      'diagnostics_governance_context': _diagnostics_governance_context(),
      'report': None,
      'reconcile': None,
    }
    _attach_connection_posture(
      payload,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    payload['workflow'] = _follow_on_workflow('change_mode', payload)
    augmented = _augment_shell_payload(
      'change_mode',
      _merge_preserved_review_hold_payload('change_mode', payload),
      env_override=env_override,
      subaccount_override=subaccount_override,
      runtime_overlay=runtime_overlay_state,
      working_default_values=_runtime_working_default_values(
        env_override=env_override,
        subaccount_override=subaccount_override,
      ),
      working_default_state=runtime_working_default_state,
      working_default_sources=runtime_working_default_sources,
      analysis_recalculation=_analysis_recalculation_payload(),
      durable_overlay=context_overlay_state,
      durable_funds_cache=_header_funds_cache,
      operator_review_session_id=str(review_selection_state.get('persisted_lane_session_id') or '').strip() or None,
    )
    augmented['key_management'] = _key_management_payload(augmented)
    augmented['data_management'] = _data_management_payload(augmented)
    augmented['session_overlay'] = _session_overlay_payload(
      augmented,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    augmented['connection_posture'] = _build_connection_posture_payload(
      augmented,
      env_override=env_override,
      subaccount_override=subaccount_override,
    )
    _refresh_review_selection_projection(augmented)
    review_selection_payload = augmented.get('review_selection') if isinstance(augmented.get('review_selection'), dict) else {}
    pair_monitor_payload = augmented.get('pair_monitor') if isinstance(augmented.get('pair_monitor'), dict) else {}
    if (
      str(review_selection_payload.get('state_id') or '') == 'review_hold_empty_selection'
      and int(pair_monitor_payload.get('candidate_count', 0) or 0) == 0
      and not list(pair_monitor_payload.get('candidate_rows') or [])
    ):
      review_selection_payload['saved_set_status'] = 'historical_only'
      review_selection_payload['saved_set_status_reason'] = str(
        review_selection_payload.get('saved_set_status_reason')
        or 'Saved candidate selection cleared by operator.'
      )
      augmented['review_selection'] = review_selection_payload
    _apply_orchestrator_highlight_envelope('change_mode', augmented)
    return augmented

